type StudioScenarioExpectedOutputMatchMode =
  | "contains"
  | "notContains"
  | "startsWith"
  | "endsWith"
  | "exact"
  | "regex"
  | "jsonPathExists"
  | "jsonPathNotEmpty";

const studioScenarioExpectedOutputMatchModeLabels: Array<{ value: StudioScenarioExpectedOutputMatchMode; label: string }> = [
  { value: "contains", label: "Saída contém" },
  { value: "notContains", label: "Saída não contém" },
  { value: "startsWith", label: "Saída começa com" },
  { value: "endsWith", label: "Saída termina com" },
  { value: "exact", label: "Saída igual a" },
  { value: "regex", label: "Saída casa regex" },
  { value: "jsonPathExists", label: "JSON path existe" },
  { value: "jsonPathNotEmpty", label: "JSON path preenchido" },
];

const defaultStudioScenarioExpectedOutputMatchMode: StudioScenarioExpectedOutputMatchMode = "contains";

function isStudioScenarioExpectedOutputMatchMode(value: unknown): value is StudioScenarioExpectedOutputMatchMode {
  return (
    value === "contains" ||
    value === "notContains" ||
    value === "startsWith" ||
    value === "endsWith" ||
    value === "exact" ||
    value === "regex" ||
    value === "jsonPathExists" ||
    value === "jsonPathNotEmpty"
  );
}

function studioScenarioExpectedOutputModeLabel(mode: StudioScenarioExpectedOutputMatchMode): string {
  return studioScenarioExpectedOutputMatchModeLabels.find((item) => item.value === mode)?.label ?? "Saída contém";
}

function normalizeStudioScenarioEvaluatorKind(value: unknown): StudioScenarioEvaluatorKind {
  if (value === "external_http" || value === "llm_judge") {
    return value;
  }
  return "rules";
}

function formatStudioScenarioEvaluatorKind(kind: StudioScenarioEvaluatorKind): string {
  if (kind === "external_http") {
    return "HTTP externo";
  }
  if (kind === "llm_judge") {
    return "LLM-as-judge";
  }
  return "Regras locais";
}

function describeStudioScenarioExpectedOutputCriterion(scenario: StudioScenario): string | null {
  const kind = studioScenarioEvaluatorKindForScenario(scenario);
  if (kind !== "rules") {
    const external = studioScenarioExternalEvaluatorForScenario(scenario);
    if (!external) {
      return `${formatStudioScenarioEvaluatorKind(kind)} sem endpoint configurado`;
    }
    return `${formatStudioScenarioEvaluatorKind(kind)} em ${external.endpointUrl}`;
  }
  const rules = studioScenarioEvaluatorRulesForScenario(scenario);
  if (!rules.length) {
    return null;
  }
  if (rules.length === 1) {
    return describeStudioScenarioEvaluatorRule(rules[0]);
  }
  const operatorLabel = studioScenarioEvaluatorOperatorForScenario(scenario) === "all" ? "Todas as regras" : "Qualquer regra";
  return `${operatorLabel}: ${rules.map(describeStudioScenarioEvaluatorRule).join("; ")}`;
}

function normalizeExpectedTextMatch(value: string): string {
  return value.trim().toLocaleLowerCase("pt-BR");
}

function studioScenarioEvaluatorKindForScenario(scenario: StudioScenario): StudioScenarioEvaluatorKind {
  return normalizeStudioScenarioEvaluatorKind(scenario.evaluatorKind);
}

function studioScenarioExternalEvaluatorForScenario(scenario: StudioScenario): StudioScenarioExternalEvaluatorConfig | null {
  const kind = studioScenarioEvaluatorKindForScenario(scenario);
  if (kind === "rules") {
    return null;
  }
  const external = normalizeStudioScenarioExternalEvaluatorConfig(scenario.evaluatorExternal);
  return external.endpointUrl ? external : null;
}

function studioScenarioEvaluatorRulesForScenario(scenario: StudioScenario): StudioScenarioEvaluatorRule[] {
  if (studioScenarioEvaluatorKindForScenario(scenario) !== "rules") {
    return [];
  }
  const normalizedRules = (scenario.evaluatorRules ?? [])
    .map(normalizeStudioScenarioEvaluatorRule)
    .filter((rule): rule is StudioScenarioEvaluatorRule => rule !== null);
  if (normalizedRules.length) {
    return normalizedRules;
  }
  const expected = scenario.expectedOutputText.trim();
  if (!expected) {
    return [];
  }
  return [{
    id: "scenario-expected-output",
    matchMode: scenario.expectedOutputMatchMode,
    expectedText: expected,
    caseSensitive: scenario.expectedOutputCaseSensitive,
  }];
}

function studioScenarioEvaluatorOperatorForScenario(scenario: StudioScenario): StudioScenarioEvaluatorOperator {
  return normalizeStudioScenarioEvaluatorOperator(scenario.evaluatorOperator);
}

function describeStudioScenarioEvaluatorRule(rule: StudioScenarioEvaluatorRule): string {
  const matchMode = studioScenarioExpectedOutputModeLabel(rule.matchMode);
  if (rule.matchMode === "jsonPathExists" || rule.matchMode === "jsonPathNotEmpty") {
    return `${matchMode} "${rule.expectedText}"`;
  }
  return `${matchMode} "${rule.expectedText}" ${rule.caseSensitive ? "(case-sensitive)" : "(case-insensitive)"}`.trim();
}

function evaluateStudioScenarioEvaluatorRule(
  rule: StudioScenarioEvaluatorRule,
  observedText: string,
): { ok: boolean; message: string | null } {
  const expected = rule.expectedText.trim();
  if (!expected) {
    return { ok: true, message: null };
  }
  const value = rule.caseSensitive ? observedText : normalizeExpectedTextMatch(observedText);
  const target = rule.caseSensitive ? expected : normalizeExpectedTextMatch(expected);
  const regexFlags = rule.caseSensitive ? "" : "i";
  switch (rule.matchMode) {
    case "jsonPathExists":
    case "jsonPathNotEmpty": {
      const parsed = parseStudioScenarioObservedJson(observedText);
      if (!parsed.ok) {
        return { ok: false, message: `Critério JSON falhou: saída não é JSON válido (${parsed.error}).` };
      }
      const pathResult = readStudioScenarioJsonPath(parsed.value, expected);
      if (!pathResult.found) {
        return { ok: false, message: `Critério JSON falhou: path "${expected}" não existe.` };
      }
      if (rule.matchMode === "jsonPathNotEmpty" && !studioScenarioJsonValueIsPresent(pathResult.value)) {
        return { ok: false, message: `Critério JSON falhou: path "${expected}" está vazio.` };
      }
      return {
        ok: true,
        message: rule.matchMode === "jsonPathNotEmpty"
          ? `Critério JSON atendido: path "${expected}" está preenchido.`
          : `Critério JSON atendido: path "${expected}" existe.`,
      };
    }
    case "notContains":
      if (!value.includes(target)) {
        return {
          ok: true,
          message: `Critério textual atendido: saída não contém "${expected}".`,
        };
      }
      return { ok: false, message: `Critério textual falhou: saída contém "${expected}".` };
    case "startsWith":
      if (value.startsWith(target)) {
        return {
          ok: true,
          message: `Critério textual atendido: saída começa com "${expected}".`,
        };
      }
      return { ok: false, message: `Critério textual falhou: saída não começa com "${expected}".` };
    case "endsWith":
      if (value.endsWith(target)) {
        return {
          ok: true,
          message: `Critério textual atendido: saída termina com "${expected}".`,
        };
      }
      return { ok: false, message: `Critério textual falhou: saída não termina com "${expected}".` };
    case "exact":
      if (value === target) {
        return {
          ok: true,
          message: `Critério textual atendido: saída igual a "${expected}".`,
        };
      }
      return { ok: false, message: `Critério textual falhou: saída não é igual a "${expected}".` };
    case "regex":
      try {
        const pattern = new RegExp(expected, regexFlags);
        if (pattern.test(observedText)) {
          return {
            ok: true,
            message: `Critério textual atendido: saída casa regex "${expected}".`,
          };
        }
        return { ok: false, message: `Critério textual falhou: saída não casa regex "${expected}".` };
      } catch (error) {
        return { ok: false, message: `Critério textual inválido: regex "${expected}" inválida (${errorMessage(error)}).` };
      }
    case "contains":
    default:
      if (value.includes(target)) {
        return {
          ok: true,
          message: `Critério textual atendido: saída contém "${expected}".`,
        };
      }
      return { ok: false, message: `Critério textual falhou: saída não contém "${expected}".` };
  }
}

function parseStudioScenarioObservedJson(observedText: string): { ok: true; value: unknown } | { ok: false; error: string } {
  const trimmed = observedText.trim();
  const fenced = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  const source = fenced ? fenced[1].trim() : trimmed;
  try {
    return { ok: true, value: JSON.parse(source) };
  } catch (error) {
    return { ok: false, error: errorMessage(error) };
  }
}

function readStudioScenarioJsonPath(value: unknown, path: string): { found: boolean; value: unknown } {
  const segments = studioScenarioJsonPathSegments(path);
  if (!segments.length) {
    return { found: false, value: undefined };
  }
  let current = value;
  for (const segment of segments) {
    if (Array.isArray(current)) {
      const index = Number(segment);
      if (!Number.isInteger(index) || index < 0 || index >= current.length) {
        return { found: false, value: undefined };
      }
      current = current[index];
    } else if (isRecord(current) && Object.prototype.hasOwnProperty.call(current, segment)) {
      current = current[segment];
    } else {
      return { found: false, value: undefined };
    }
  }
  return { found: true, value: current };
}

function studioScenarioJsonPathSegments(path: string): string[] {
  return path
    .trim()
    .replace(/^\$\.?/, "")
    .replace(/\[(\d+)\]/g, ".$1")
    .split(".")
    .map((segment) => segment.trim())
    .filter(Boolean);
}

function studioScenarioJsonValueIsPresent(value: unknown): boolean {
  if (value === null || typeof value === "undefined") {
    return false;
  }
  if (typeof value === "string") {
    return value.trim().length > 0;
  }
  if (Array.isArray(value)) {
    return value.length > 0;
  }
  if (isRecord(value)) {
    return Object.keys(value).length > 0;
  }
  return true;
}

