const defaultStudioRegressionThresholds: StudioScenarioRegressionThresholds = {
  tokenGrowthPct: 20,
  costGrowthPct: 20,
  durationGrowthPct: 30,
  nodeTypeThresholds: defaultStudioScenarioNodeTypeThresholds(),
};

function buildStudioScenarioTemplateThresholds(
  overrides: Partial<Pick<StudioScenarioRegressionThresholds, "tokenGrowthPct" | "costGrowthPct" | "durationGrowthPct">> = {},
  nodeTypeThresholds: Record<string, StudioScenarioNodeTypeRegressionThresholds> = {},
): StudioScenarioRegressionThresholds {
  return {
    tokenGrowthPct: overrides.tokenGrowthPct ?? defaultStudioRegressionThresholds.tokenGrowthPct,
    costGrowthPct: overrides.costGrowthPct ?? defaultStudioRegressionThresholds.costGrowthPct,
    durationGrowthPct: overrides.durationGrowthPct ?? defaultStudioRegressionThresholds.durationGrowthPct,
    nodeTypeThresholds: {
      ...defaultStudioScenarioNodeTypeThresholds(),
      ...nodeTypeThresholds,
    },
  };
}

