function nextStudioTurnIdempotencyKey(): string {
  return `ui-turn-${Date.now()}`;
}

function formatRuntimeTurnTokenSource(source: string | null | undefined): string | null {
  if (!source) {
    return null;
  }
  if (source === "llm_callback") {
    return "callback do runtime";
  }
  if (source === "assistant_message") {
    return "fallback local";
  }
  return source;
}

