  async function handleExportCollaborationConflictOverview(): Promise<void> {
    setCollaborationConflictLoadState({ kind: "loading", message: "Exportando revisão agregada de colaboração." });
    try {
      const overview = collaborationConflictOverview ?? (await refreshCollaborationConflictOverview(true));
      if (!isCollaborationConflictOverviewPackage(overview)) {
        throw new Error("Visão agregada de colaboração veio em formato inválido.");
      }
      downloadJsonFile(`${collaborationConflictOverviewFileName(overview)}.afcollaboration-conflicts.json`, overview);
      setCollaborationConflictLoadState({
        kind: "ready",
        message: `${overview.filteredTotals.openConflictCount} conflito(s) aberto(s) no filtro; ${overview.totals.openConflictCount} no total.`,
      });
      setStatus({
        kind: "ok",
        message: `Revisão agregada de colaboração exportada com ${overview.totals.conflictCount} conflito(s), sem conteúdo bruto.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setCollaborationConflictLoadState({ kind: "error", message: `Erro ao exportar pendências de colaboração: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleCompareCollaborationConflictOverviewFile(file: File): Promise<void> {
    setCollaborationConflictLoadState({ kind: "loading", message: `Comparando revisão agregada ${file.name}.` });
    setStatus({ kind: "busy", message: `Comparando revisão agregada ${file.name}.` });
    try {
      const parsed = JSON.parse(await file.text()) as unknown;
      if (!isCollaborationConflictOverviewPackage(parsed) || containsRawCollaborationConflictOverviewPayload(parsed)) {
        throw new Error("Arquivo não é uma revisão agregada governada válida ou contém conteúdo bruto.");
      }
      const diff = await compareCollaborationConflictOverview({ overview: parsed }, {
        flowId: collaborationConflictFilters.flowId || null,
        area: collaborationConflictFilters.area || null,
        severity: collaborationConflictFilters.severity || null,
        responsible: collaborationConflictFilters.responsible || null,
        role: collaborationConflictFilters.role || null,
        status: collaborationConflictFilters.status || null,
      });
      if (!isCollaborationConflictOverviewDiffPackage(diff)) {
        throw new Error("Diff agregado de colaboração veio em formato inválido.");
      }
      downloadJsonFile(`${collaborationConflictOverviewDiffFileName(diff)}.afcollaboration-conflicts-diff.json`, diff);
      const changedCount = diff.sections.reduce((total, section) => total + section.changedCount, 0);
      setCollaborationConflictLoadState({
        kind: "ready",
        message: `Diff de colaboração: ${changedCount} mudança(s) em ${diff.sections.length} seção(ões).`,
      });
      setStatus({
        kind: "ok",
        message: `Diff agregado de colaboração exportado com ${changedCount} mudança(s), sem schemas, prompts, tokens, payloads ou IO bruto.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setCollaborationConflictLoadState({ kind: "error", message: `Erro ao comparar pendências de colaboração: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

