  async function handleProbeBuilderAuthExternalIntegrations(): Promise<void> {
    setBuilderAuthLoadState({ kind: "loading", message: "Testando integrações corporativas do Builder." });
    try {
      const result = await probeBuilderAuthExternalIntegrations();
      setBuilderAuthExternalProbeData(result);
      setBuilderAuthLoadState({
        kind: result.errorCount ? "error" : result.warningCount ? "ready" : "ready",
        message: `${result.okCount}/${result.checkedCount} integração(ões) externa(s) responderam; ${result.warningCount} aviso(s), ${result.errorCount} erro(s).`,
      });
      setStatus({
        kind: result.errorCount ? "error" : result.warningCount ? "ok" : "ok",
        message: "Probe de integrações corporativas do Builder concluído sem expor URLs, tokens ou headers.",
      });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthExternalProbeData(null);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao testar integrações corporativas: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleHomologateBuilderAuthCorporateIntegrations(): Promise<void> {
    setBuilderAuthLoadState({ kind: "loading", message: "Homologando auth corporativa do Builder." });
    try {
      const result = await homologateBuilderAuthCorporateIntegrations();
      setBuilderAuthCorporateHomologationData(result);
      setBuilderAuthExternalProbeData({
        format: "agent-flow-builder.builder-auth-external-probe.v1",
        generatedAt: result.generatedAt,
        configuredCount: result.configuredCount,
        checkedCount: result.checkedCount,
        okCount: result.okCount,
        warningCount: result.warningCount,
        errorCount: result.errorCount,
        components: result.components,
        governance: {
          excludesUrls: true,
          excludesSecretValues: true,
          excludesRawKeyValues: true,
          excludesHeaders: true,
          excludesSessionTokens: true,
          excludesProviderTokens: true,
          authTokensInHeaderOnly: true,
          authTokensInBody: false,
          usesSideEffectFreeProbe: true,
        },
      });
      const savedMessage = result.artifact.saved && result.artifact.relativePath
        ? ` Artefato salvo em ${result.artifact.relativePath}.`
        : "";
      setBuilderAuthLoadState({
        kind: result.status === "blocked" ? "error" : "ready",
        message: `Homologação corporativa ${result.status}; ${result.missingEvidence.length} evidência(s) pendente(s).${savedMessage}`,
      });
      setStatus({
        kind: result.status === "blocked" ? "error" : "ok",
        message: `Homologação corporativa do Builder gerada sem URLs, tokens, headers ou chaves brutas.${savedMessage}`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthCorporateHomologationData(null);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao homologar auth corporativa: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  useEffect(() => {
    function handleBuilderAuthOidcMessage(event: MessageEvent): void {
      const callback = parseBuilderAuthOidcCallbackMessage(event.data);
      const logoutCallback = callback ? null : parseBuilderAuthOidcLogoutCallbackMessage(event.data);
      if (!callback && !logoutCallback) {
        return;
      }
      let expectedOrigin = "";
      try {
        expectedOrigin = new URL(builderApiUrl()).origin;
      } catch {
        expectedOrigin = "";
      }
      if (expectedOrigin && event.origin !== expectedOrigin) {
        return;
      }
      if (logoutCallback) {
        builderAuthOidcLogoutPopupRef.current?.close();
        builderAuthOidcLogoutPopupRef.current = null;
        clearStoredBuilderAuthSession();
        setBuilderAuthSessionData(null);
        void refreshBuilderAuthState(true);
        setBuilderAuthLoadState({
          kind: "ready",
          message: logoutCallback.identity
            ? `Logout OIDC validado para ${logoutCallback.identity.actorId}; sessão local removida.`
            : "Logout OIDC validado; sessão local removida.",
        });
        setStatus({ kind: "idle", message: "Logout OIDC federado validado pelo state de retorno." });
        return;
      }
      if (!callback) {
        return;
      }
      saveStoredBuilderAuthSession(callback.session);
      saveStoredBuilderApiKey("");
      setBuilderApiKeyDraft("");
      setBuilderAuthSessionData(callback.session);
      builderAuthOidcLoginPopupRef.current?.close();
      builderAuthOidcLoginPopupRef.current = null;
      void refreshBuilderAuthState(true);
      setBuilderAuthLoadState({
        kind: "ready",
        message: `Sessão OIDC criada para ${callback.identity.actorId}; hint de logout guardado só em memória local.`,
      });
      setStatus({
        kind: "ok",
        message: `Login OIDC concluído para ${callback.identity.actorId}.`,
      });
    }
    window.addEventListener("message", handleBuilderAuthOidcMessage);
    return () => window.removeEventListener("message", handleBuilderAuthOidcMessage);
  }, [refreshBuilderAuthState]);

  function handleBuilderAuthAuditFilterChange(field: keyof BuilderAuthAuditFilterForm, value: string): void {
    setBuilderAuthAuditFilters((current) => {
      const next = { ...current, [field]: value } as BuilderAuthAuditFilterForm;
      builderAuthAuditFiltersRef.current = next;
      return next;
    });
  }

  function handleResetBuilderAuthAuditFilters(): void {
    const next: BuilderAuthAuditFilterForm = {
      limit: "20",
      status: "",
      actorId: "",
      keyId: "",
      route: "",
      q: "",
    };
    builderAuthAuditFiltersRef.current = next;
    setBuilderAuthAuditFilters(next);
  }

