  async function handleCreateBuilderAuthSession(): Promise<void> {
    setBuilderAuthLoadState({ kind: "loading", message: "Criando sessão local do Builder." });
    try {
      if (builderApiKeyDraft.trim()) {
        saveStoredBuilderApiKey(builderApiKeyDraft);
      }
      const session = await createBuilderAuthSession();
      saveStoredBuilderAuthSession(session);
      saveStoredBuilderApiKey("");
      setBuilderApiKeyDraft("");
      setBuilderAuthSessionData(session);
      await refreshBuilderAuthState(true);
      setStatus({ kind: "ok", message: `Sessão local do Builder criada até ${formatDateTime(session.expiresAt)}.` });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao criar sessão: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleRefreshBuilderAuthSession(): Promise<void> {
    if (!builderAuthSessionData) {
      setStatus({ kind: "idle", message: "Nenhuma sessão local do Builder ativa para renovar." });
      return;
    }
    const usesOidcRefresh = Boolean(builderAuthSessionData.governance.storesProviderRefreshToken);
    setBuilderAuthLoadState({
      kind: "loading",
      message: usesOidcRefresh ? "Renovando sessão OIDC no provedor." : "Renovando sessão local do Builder.",
    });
    try {
      const session = usesOidcRefresh ? await refreshBuilderAuthOidcSession() : await refreshBuilderAuthSession();
      saveStoredBuilderAuthSession(session);
      setBuilderAuthSessionData(session);
      await refreshBuilderAuthState(true);
      setStatus({
        kind: "ok",
        message: usesOidcRefresh
          ? `Sessão OIDC do Builder renovada no provedor até ${formatDateTime(session.expiresAt)}.`
          : `Sessão local do Builder renovada até ${formatDateTime(session.expiresAt)}.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao renovar sessão: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleStartBuilderOidcLogin(): Promise<void> {
    setBuilderAuthLoadState({ kind: "loading", message: "Preparando login OIDC local do Builder." });
    setStatus({ kind: "busy", message: "Preparando login OIDC do Builder." });
    try {
      const login = await createBuilderAuthOidcLoginUrl();
      const popup = window.open(
        login.authorizationUrl,
        "agent-flow-builder-oidc-login",
        "width=560,height=760,noopener=no,noreferrer=no,popup=yes",
      );
      if (!popup) {
        throw new Error("O navegador bloqueou a janela de login OIDC.");
      }
      builderAuthOidcLoginPopupRef.current = popup;
      popup.focus();
      setBuilderAuthLoadState({
        kind: "loading",
        message: `Login OIDC aberto; a sessão expira se não concluir até ${formatDateTime(login.expiresAt)}.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao iniciar OIDC: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleStartBuilderOidcLogout(): Promise<void> {
    setBuilderAuthLoadState({ kind: "loading", message: "Preparando logout OIDC federado." });
    setStatus({ kind: "busy", message: "Preparando logout OIDC federado." });
    try {
      const logout = await createBuilderAuthOidcLogoutUrl();
      let localSessionMessage = "Nenhuma sessão local ativa para revogar.";
      if (builderAuthSessionData) {
        try {
          const result = await logoutBuilderAuthSession();
          localSessionMessage = result.revoked
            ? "Sessão local revogada no backend."
            : "Sessão local removida deste navegador.";
        } catch (error) {
          localSessionMessage = `Sessão local removida deste navegador; backend respondeu: ${errorMessage(error)}.`;
        }
        clearStoredBuilderAuthSession();
        setBuilderAuthSessionData(null);
        await refreshBuilderAuthState(true);
      }
      const popup = window.open(
        logout.logoutUrl,
        "agent-flow-builder-oidc-logout",
        "width=560,height=680,noopener=no,noreferrer=no,popup=yes",
      );
      if (!popup) {
        throw new Error("O navegador bloqueou a janela de logout OIDC.");
      }
      builderAuthOidcLogoutPopupRef.current = popup;
      popup.focus();
      setBuilderAuthLoadState({
        kind: "ready",
        message: `Logout federado aberto${logout.governance.sendsIdTokenHint ? " com id_token_hint de sessão" : " em modo básico"}. ${localSessionMessage}`,
      });
      setStatus({ kind: "idle", message: "Logout OIDC federado iniciado; retorno será validado por state quando o provedor redirecionar." });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao iniciar logout OIDC: ${message}` });
      setStatus({ kind: "error", message });
    }
  }

  async function handleClearBuilderAuthSession(): Promise<void> {
    if (!builderAuthSessionData) {
      clearStoredBuilderAuthSession();
      setBuilderAuthSessionData(null);
      setStatus({ kind: "idle", message: "Nenhuma sessão local do Builder ativa." });
      return;
    }
    setBuilderAuthLoadState({ kind: "loading", message: "Encerrando sessão local do Builder." });
    let revoked = false;
    let logoutError = false;
    try {
      const result = await logoutBuilderAuthSession();
      revoked = result.revoked;
    } catch (error) {
      logoutError = true;
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Sessão removida do navegador; logout backend não confirmou: ${message}` });
      setStatus({ kind: "error", message: `Sessão local removida; backend respondeu: ${message}` });
    }
    clearStoredBuilderAuthSession();
    setBuilderAuthSessionData(null);
    await refreshBuilderAuthState(true);
    if (logoutError) {
      return;
    }
    if (revoked) {
      setStatus({ kind: "idle", message: "Sessão local do Builder encerrada e revogada no backend." });
    } else {
      setStatus({ kind: "idle", message: "Sessão local do Builder removida deste navegador." });
    }
  }

  async function handleGenerateBuilderAuthKey(): Promise<void> {
    setWorkspaceGovernanceBusy(true);
    setBuilderAuthLoadState({ kind: "loading", message: "Gerando chave local do Builder." });
    try {
      const result = await generateBuilderAuthKey({
        actorId: normalizeStudioAnnotationReviewerName(builderAuthRotationActorId || "local-studio"),
        name: normalizeStudioAnnotationReviewerName(builderAuthRotationActorId || "local-studio"),
        role: builderAuthRotationRole,
        areas: normalizeStringList(builderAuthRotationAreas),
        scopes: normalizeStringList(builderAuthRotationScopes),
        expiresAt: builderAuthExpiresAtPayload(builderAuthRotationExpiresAt),
      });
      setBuilderAuthRotationResult(result);
      setBuilderAuthStatusData(result.status);
      await refreshBuilderAuthState(true);
      setStatus({ kind: "ok", message: `Chave ${result.key.keyId} gerada. Copie o valor exibido uma única vez.` });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao gerar chave: ${message}` });
      setStatus({ kind: "error", message });
    } finally {
      setWorkspaceGovernanceBusy(false);
    }
  }

  async function handleDisableBuilderAuthKey(keyId: string): Promise<void> {
    setWorkspaceGovernanceBusy(true);
    setBuilderAuthLoadState({ kind: "loading", message: `Desativando chave ${keyId}.` });
    try {
      const statusResult = await disableBuilderAuthKey(keyId);
      setBuilderAuthStatusData(statusResult);
      await refreshBuilderAuthState(true);
      setStatus({ kind: "ok", message: `Chave ${keyId} desativada.` });
    } catch (error) {
      const message = errorMessage(error);
      setBuilderAuthLoadState({ kind: "error", message: `Erro ao desativar chave: ${message}` });
      setStatus({ kind: "error", message });
    } finally {
      setWorkspaceGovernanceBusy(false);
    }
  }

  async function handleCheckWorkspaceGovernanceAccess(): Promise<void> {
    const actorId = normalizeStudioAnnotationReviewerName(workspaceGovernanceActorId || "local-studio");
    setWorkspaceGovernanceActorId(actorId);
    setWorkspaceGovernanceBusy(true);
    setWorkspaceGovernanceDecisionLoadState({ kind: "loading", message: "Verificando acesso pela política do workspace." });
    try {
      const decision = await authorizeWorkspaceGovernance({
        actorId,
        area: workspaceGovernanceArea,
        action: workspaceGovernanceAction,
      });
      setWorkspaceGovernanceDecision(decision);
      setWorkspaceGovernanceDecisionLoadState({
        kind: decision.allowed ? "ready" : "error",
        message: decision.allowed
          ? `Ação permitida para ${decision.actorName}.`
          : `Ação seria bloqueada para ${decision.actorName}.`,
      });
      setStatus({
        kind: decision.allowed ? "ok" : "error",
        message: `${decision.actorName}: ${decision.effect} em ${decision.area}/${decision.action}.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setWorkspaceGovernanceDecision(null);
      setWorkspaceGovernanceDecisionLoadState({ kind: "error", message: `Erro ao verificar acesso: ${message}` });
      setStatus({ kind: "error", message });
    } finally {
      setWorkspaceGovernanceBusy(false);
    }
  }

