    const safetyPackage = buildSafetyPolicyProfilePackage(safetyPolicyProfiles);
    downloadJsonFile("safety-policy-profiles.afsafety.json", safetyPackage);
    setStatus({ kind: "ok", message: `Biblioteca de Safety exportada com ${safetyPackage.profileCount} política(s).` });
