  function handleSaveCodeSandboxPolicyProfile(node: FlowNode): void {
    if (node.type !== "code") {
      setStatus({ kind: "error", message: "Selecione um nó Code para salvar o perfil de sandbox." });
      return;
    }
    const existingByNode = codeSandboxPolicyProfiles.find((profile) => profile.name.toLowerCase() === node.id.toLowerCase());
    const defaultName = existingByNode?.name ?? `Sandbox ${node.id}`;
    const name = window.prompt("Nome do perfil de sandbox reutilizável", defaultName)?.trim();
    if (!name) {
      setStatus({ kind: "idle", message: "Criação de perfil de sandbox cancelada." });
      return;
    }
    const existing = codeSandboxPolicyProfiles.find((profile) => profile.name.toLowerCase() === name.toLowerCase());
    const now = new Date().toISOString();
    const profile: CodeSandboxPolicyProfile = {
      id: existing?.id ?? `code-sandbox-policy-${Date.now()}`,
      name,
      description: node.description?.trim() || `Perfil salvo a partir do nó ${node.id}.`,
      sandboxIsolation: normalizeCodeSandboxIsolation(node.sandboxIsolation),
      sandboxEnvAllowlist: normalizeStringList(node.sandboxEnvAllowlist),
      sandboxContainerImageId: node.sandboxContainerImageId ?? "",
      sandboxContainerImage: node.sandboxContainerImage ?? "",
      sandboxContainerEngine: node.sandboxContainerEngine ?? "",
      sandboxContainerProfile: node.sandboxContainerProfile ?? "",
      sandboxContainerMemory: node.sandboxContainerMemory ?? "",
      sandboxContainerCpus: node.sandboxContainerCpus ?? "",
      sandboxContainerPidsLimit: normalizeNullableInteger(node.sandboxContainerPidsLimit, 1, 4096),
      sandboxContainerReadOnlyRootfs: node.sandboxContainerReadOnlyRootfs === true,
      sandboxContainerDropCapabilities: node.sandboxContainerDropCapabilities === true,
      sandboxContainerNoNewPrivileges: node.sandboxContainerNoNewPrivileges === true,
      sandboxVmImageId: node.sandboxVmImageId ?? "",
      sandboxVmRunner: node.sandboxVmRunner ?? "",
      sandboxVmArgs: normalizeStringList(node.sandboxVmArgs),
      sandboxVmRunnerManifest: node.sandboxVmRunnerManifest ?? "",
      sandboxVmImage: node.sandboxVmImage ?? "",
      sandboxVmImageManifest: node.sandboxVmImageManifest ?? "",
      sandboxVmEngine: node.sandboxVmEngine ?? "",
      sandboxVmProfile: node.sandboxVmProfile ?? "",
      sandboxVmMemory: node.sandboxVmMemory ?? "",
      sandboxVmCpus: node.sandboxVmCpus ?? "",
      retryAttempts: normalizeNullableInteger(node.retryAttempts, 0, 5),
      payloadAllowPaths: normalizeStringList(node.payloadAllowPaths),
      redactPaths: normalizeStringList(node.redactPaths),
      maxPayloadBytes: normalizeNullableInteger(node.maxPayloadBytes, 1, 10_000_000),
      timeoutSeconds: normalizeNullableInteger(node.timeoutSeconds, 1, 120),
      sourceExecutionMode: node.codeExecution ?? "native",
      createdAt: existing?.createdAt ?? now,
      updatedAt: now,
      ...(draftFlow?.id ? { sourceFlowId: draftFlow.id } : {}),
    };
    persistCodeSandboxPolicyProfileLibrary([
      ...codeSandboxPolicyProfiles.filter((item) => item.id !== profile.id),
      profile,
    ]);
    setStatus({ kind: "ok", message: `Perfil de sandbox "${profile.name}" salvo na biblioteca local.` });
  }

  function handleApplyCodeSandboxPolicyProfile(nodeId: string, profileId: string): void {
    const profile = codeSandboxPolicyProfiles.find((item) => item.id === profileId);
    if (!profile) {
      setStatus({ kind: "error", message: "Perfil de sandbox selecionado não encontrado." });
      return;
    }
    updateDraft((flow) => ({
      ...flow,
      nodes: flow.nodes.map((node) => {
        if (node.id !== nodeId) {
          return node;
        }
        return {
          ...node,
          sandboxIsolation: profile.sandboxIsolation,
          sandboxEnvAllowlist: profile.sandboxEnvAllowlist.length ? [...profile.sandboxEnvAllowlist] : undefined,
          sandboxContainerImageId: profile.sandboxContainerImageId || undefined,
          sandboxContainerImage: profile.sandboxContainerImage || undefined,
          sandboxContainerEngine: profile.sandboxContainerEngine || undefined,
          sandboxContainerProfile: profile.sandboxContainerProfile || undefined,
          sandboxContainerMemory: profile.sandboxContainerMemory || undefined,
          sandboxContainerCpus: profile.sandboxContainerCpus || undefined,
          sandboxContainerPidsLimit: profile.sandboxContainerPidsLimit ?? undefined,
          sandboxContainerReadOnlyRootfs: profile.sandboxContainerReadOnlyRootfs || undefined,
          sandboxContainerDropCapabilities: profile.sandboxContainerDropCapabilities || undefined,
          sandboxContainerNoNewPrivileges: profile.sandboxContainerNoNewPrivileges || undefined,
          sandboxVmImageId: profile.sandboxVmImageId || undefined,
          sandboxVmRunner: profile.sandboxVmRunner || undefined,
          sandboxVmArgs: profile.sandboxVmArgs.length ? [...profile.sandboxVmArgs] : undefined,
          sandboxVmRunnerManifest: profile.sandboxVmRunnerManifest || undefined,
          sandboxVmImage: profile.sandboxVmImage || undefined,
          sandboxVmImageManifest: profile.sandboxVmImageManifest || undefined,
          sandboxVmEngine: profile.sandboxVmEngine || undefined,
          sandboxVmProfile: profile.sandboxVmProfile || undefined,
          sandboxVmMemory: profile.sandboxVmMemory || undefined,
          sandboxVmCpus: profile.sandboxVmCpus || undefined,
          retryAttempts: profile.retryAttempts ?? undefined,
          payloadAllowPaths: profile.payloadAllowPaths.length ? [...profile.payloadAllowPaths] : undefined,
          redactPaths: profile.redactPaths.length ? [...profile.redactPaths] : undefined,
          maxPayloadBytes: profile.maxPayloadBytes ?? undefined,
          timeoutSeconds: profile.timeoutSeconds ?? undefined,
        };
      }),
    }));
    setStatus({ kind: "ok", message: `Perfil de sandbox "${profile.name}" aplicado ao nó ${nodeId}.` });
  }

