  function handleConnectSelectedNodesInSequence() {
    if (!draftFlow || !canConnectCanvasSequence) {
      return;
    }
    const selectedIds = selectedCanvasNodeIds;
    updateDraft((flow) => {
      const orderedNodes = sortFlowNodesForConnectionSequence(flow, selectedIds);
      if (orderedNodes.length < 2) {
        setStatus({ kind: "error", message: "Selecione ao menos dois nós editáveis para conectar em sequência." });
        return flow;
      }
      const existingEdges = new Set(flow.edges.map((edge) => `${edge.from}->${edge.to}`));
      const missingEdges: FlowEdge[] = [];
      for (let index = 0; index < orderedNodes.length - 1; index += 1) {
        const from = orderedNodes[index].id;
        const to = orderedNodes[index + 1].id;
        if (from !== to && !existingEdges.has(`${from}->${to}`)) {
          missingEdges.push({ from, to });
          existingEdges.add(`${from}->${to}`);
        }
      }
      if (!missingEdges.length) {
        setStatus({ kind: "ok", message: "Seleção já está conectada em sequência." });
        return flow;
      }
      setStatus({
        kind: "ok",
        message: `${missingEdges.length} conexão${missingEdges.length === 1 ? "" : "ões"} criada${missingEdges.length === 1 ? "" : "s"} entre nós selecionados.`,
      });
      return {
        ...flow,
        edges: [...flow.edges, ...missingEdges],
      };
    });
    setSelectedEdgeId("");
    setSelectedBlockEdgeIds([]);
    window.requestAnimationFrame(() => {
      void reactFlowRef.current?.fitView({
        nodes: selectedIds.map((id) => ({ id })),
        duration: 220,
        padding: 0.38,
        maxZoom: 1.08,
      });
    });
  }

  function handleAddTagsToSelectedNodes(tags: string[]) {
    if (!selectedCanvasNodeIds.length) {
      return;
    }
    if (!tags.length) {
      setStatus({ kind: "error", message: "Informe ao menos uma tag para aplicar na seleção." });
      return;
    }
    const selectedIds = new Set(selectedCanvasNodeIds);
    updateDraft((flow) => ({
      ...flow,
      nodes: flow.nodes.map((node) => {
        if (!selectedIds.has(node.id)) {
          return node;
        }
        return {
          ...node,
          tags: uniqueTextList([...(node.tags ?? []), ...tags]),
        };
      }),
    }));
    setStatus({
      kind: "ok",
      message: `Tags ${tags.join(", ")} aplicadas em ${selectedCanvasNodeIds.length} nó${selectedCanvasNodeIds.length === 1 ? "" : "s"}.`,
    });
  }

  function handleApplyTagsToSelectedNodes() {
    if (!selectedCanvasNodeIds.length) {
      return;
    }
    const text = window.prompt("Tags para aplicar nos nós selecionados (separe por vírgula)", "");
    if (text === null) {
      return;
    }
    handleAddTagsToSelectedNodes(splitTags(text));
  }

  function handleClearTagsFromSelectedNodes() {
    if (!selectedCanvasNodeIds.length || !selectedCanvasNodesHaveTags) {
      return;
    }
    const selectedIds = new Set(selectedCanvasNodeIds);
    const affectedCount = selectedCanvasNodes.filter((node) => node.tags?.length).length;
    updateDraft((flow) => ({
      ...flow,
      nodes: flow.nodes.map((node) => {
        if (!selectedIds.has(node.id)) {
          return node;
        }
        return {
          ...node,
          tags: undefined,
        };
      }),
    }));
    setStatus({
      kind: "ok",
      message: `Tags removidas de ${affectedCount} nó${affectedCount === 1 ? "" : "s"}.`,
    });
  }

  function handleApplyCanvasBatchPatch(scope: CanvasBatchPatchScope, patch: Partial<FlowNode>, label: string) {
    if (!selectedCanvasNodeIds.length) {
      return;
    }
    const selectedIds = new Set(selectedCanvasNodeIds);
    const affectedCount = selectedCanvasNodes.filter((node) => isCanvasBatchPatchCompatibleNode(scope, node)).length;
    if (!affectedCount) {
      setStatus({ kind: "error", message: `Nenhum nó compatível com ${label} na seleção.` });
      return;
    }
    updateDraft((flow) => ({
      ...flow,
      nodes: flow.nodes.map((node) => {
        if (!selectedIds.has(node.id) || !isCanvasBatchPatchCompatibleNode(scope, node)) {
          return node;
        }
        return {
          ...node,
          ...patch,
        };
      }),
    }));
    setStatus({
      kind: "ok",
      message: `${label} em ${affectedCount} nó${affectedCount === 1 ? "" : "s"} ${affectedCount === 1 ? "compatível" : "compatíveis"}.`,
    });
  }

  function openNodeDebugInStudio(nodeId: string, eventSeq?: number | null) {
    if (!nodeId) {
      return;
    }
    setSelectedNodeId(nodeId);
    setSelectedEdgeId("");
    setSelectedBlockNodeIds([nodeId]);
    setSelectedBlockEdgeIds([]);
    setStudioTimelineNodeFilter(nodeId);
    const latestNodeEvent = runtimeEventsData.filter((event) => event.node === nodeId).at(-1);
    const targetEventSeq = eventSeq ?? latestNodeEvent?.seq ?? null;
    if (targetEventSeq !== null) {
      setSelectedStudioEventSeq(targetEventSeq);
    }
    if (latestNodeEvent) {
      setSelectedStudioEventSeq(targetEventSeq ?? latestNodeEvent.seq);
    }
    setInspectorTab("sandbox");
    setStatus({
      kind: "ok",
      message: latestNodeEvent
        ? `Studio aberto para depurar ${nodeId} no evento #${targetEventSeq ?? latestNodeEvent.seq}.`
        : `Studio aberto para ${nodeId}; execute ou carregue uma run para ver eventos desse nó.`,
    });
  }

