  async function handleCompareSharedStudioScenarioConflictReviewFile(file: File): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar a revisão de conflitos." });
      return;
    }
    setStudioScenariosSharedSyncState("syncing");
    setStudioScenariosSharedSyncMessage(`Comparando revisão governada ${file.name}.`);
    setStatus({ kind: "busy", message: `Comparando revisão governada ${file.name}.` });
    try {
      const parsed = JSON.parse(await file.text()) as unknown;
      const review = normalizeStudioScenariosConflictReviewPackage(parsed);
      if (!review) {
        throw new Error("Arquivo não é uma revisão governada válida ou contém candidatos completos.");
      }
      const diff = normalizeStudioScenariosConflictReviewDiffPackage(
        await compareSharedStudioScenariosConflictReview(selectedFlowId, { review }),
      );
      if (!diff) {
        throw new Error("Diff de revisão de conflitos veio em formato inválido.");
      }
      downloadJsonFile(
        `studio-scenario-conflicts-diff-${sanitizeFileNamePart(diff.flowId || selectedFlowId)}-${diff.packageHash}.afscenario-conflicts-diff.json`,
        diff,
      );
      setStudioScenariosSharedSyncState("synced");
      setStudioScenariosSharedSyncMessage(`Diff de revisão exportado: ${diff.summary.headline}.`);
      setStatus({
        kind: "ok",
        message: `Diff de revisão exportado sem candidatos ou payload bruto: ${diff.summary.headline}.`,
      });
    } catch (error) {
      setStudioScenariosSharedSyncState("error");
      setStudioScenariosSharedSyncMessage(errorMessage(error));
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

