  async function handleRecordLangSmithCloudDeployment() {
    if (!selectedFlowId) {
      return;
    }
    const recordedBy = normalizeStudioAnnotationReviewerName(studioAnnotationReviewerName);
    const recordedRole = studioAnnotationReviewerRoleFor(studioAnnotationPermissionPolicy, recordedBy);
    if (recordedRole === "viewer") {
      setStatus({ kind: "error", message: "Viewer não pode registrar evidência de deploy cloud." });
      return;
    }
    const deploymentName = langSmithCloudDeploymentName.trim() || "LangSmith/LangGraph Cloud";
    setStatus({ kind: "busy", message: `Registrando evidência cloud de ${selectedFlowId}.` });
    try {
      const deployments = await recordLangSmithCloudDeployment(selectedFlowId, {
        status: langSmithCloudDeploymentStatus,
        deploymentName,
        deploymentUrl: langSmithCloudDeploymentUrl,
        note: langSmithCloudDeploymentNote,
        recordedBy,
        recordedRole,
      });
      setLangSmithCloudDeployments(deployments);
      setLangSmithCloudDeploymentName("");
      setLangSmithCloudDeploymentUrl("");
      setLangSmithCloudDeploymentNote("");
      setStatus({ kind: "ok", message: `Deploy cloud registrado: ${deployments.latestStatus} · ${deployments.deploymentCount} registro(s).` });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

