  async function handleRefreshRuntimeJobs() {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para carregar jobs." });
      return;
    }
    setStatus({ kind: "busy", message: "Atualizando jobs pós-finalização." });
    try {
      const jobs = await refreshRuntimeJobsState(sandbox.url);
      setStatus({ kind: "ok", message: `${jobs.length} job(s) pós-finalização carregados.` });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

  async function handleSaveRuntimeJobMetricsSnapshot() {
    if (!draftFlow) {
      setStatus({ kind: "error", message: "Selecione um flow para salvar métricas de jobs." });
      return;
    }
    if (!runtimeJobMetricsData) {
      setStatus({ kind: "error", message: "Atualize jobs antes de salvar um snapshot de métricas." });
      return;
    }
    const snapshot = buildRuntimeJobMetricsHistorySnapshot(draftFlow, runtimeJobMetricsData);
    try {
      const historyPackage = normalizeRuntimeJobMetricsHistoryPackage(
        await saveSharedRuntimeJobMetricsSnapshot(draftFlow.id, snapshot),
      );
      if (!historyPackage) {
        throw new Error("Histórico de jobs retornou formato inválido.");
      }
      const nextHistory = persistRuntimeJobMetricsHistory(draftFlow, historyPackage.snapshots);
      setRuntimeJobMetricsHistory(nextHistory);
      setRuntimeJobsLoadState({
        kind: "ready",
        message: `Histórico compartilhado de jobs salvo: ${historyPackage.snapshotCount} snapshot(s).`,
      });
      setStatus({ kind: "ok", message: `Snapshot de jobs salvo no workspace (${historyPackage.snapshotCount}).` });
    } catch (error) {
      const nextHistory = persistRuntimeJobMetricsHistory(draftFlow, [snapshot, ...runtimeJobMetricsHistory]);
      setRuntimeJobMetricsHistory(nextHistory);
      setRuntimeJobsLoadState({
        kind: "ready",
        message: `Histórico local de jobs salvo; backend indisponível: ${errorMessage(error)}`,
      });
      setStatus({ kind: "ok", message: `Snapshot de jobs salvo no histórico local (${nextHistory.length}).` });
    }
  }

  function handleExportRuntimeJobMetricsHistory() {
    if (!draftFlow) {
      setStatus({ kind: "error", message: "Selecione um flow para exportar histórico de jobs." });
      return;
    }
    if (!runtimeJobMetricsHistory.length) {
      setStatus({ kind: "error", message: "Nenhum snapshot de jobs salvo para exportar." });
      return;
    }
    const packageValue = buildRuntimeJobMetricsHistoryPackage(draftFlow, runtimeJobMetricsHistory);
    downloadJsonFile(`${draftFlow.id}-runtime-job-metrics.afjobmetrics.json`, packageValue);
    setStatus({ kind: "ok", message: `Histórico de jobs exportado com ${packageValue.snapshotCount} snapshot(s).` });
  }

  function handleCompareRuntimeJobMetricsHistory(): void {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar histórico de jobs." });
      return;
    }
    runtimeJobMetricsHistoryInputRef.current?.click();
  }

  async function handleCompareRuntimeJobMetricsHistoryFile(file: File): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar histórico de jobs." });
      return;
    }
    setRuntimeJobsLoadState({ kind: "loading", message: `Comparando histórico de jobs ${file.name}.` });
    try {
      const parsed = JSON.parse(await file.text()) as unknown;
      const history = normalizeRuntimeJobMetricsHistoryPackage(parsed);
      if (!history) {
        throw new Error("Arquivo não é um histórico governado de métricas de jobs.");
      }
      const diff = normalizeRuntimeJobMetricsHistoryDiffPackage(
        await compareSharedRuntimeJobMetricsHistory(selectedFlowId, { history }),
      );
      if (!diff) {
        throw new Error("Diff de histórico de jobs veio em formato inválido.");
      }
      downloadJsonFile(
        `${selectedFlowId}-runtime-job-metrics-diff-${diff.packageHash}.afjobmetrics-diff.json`,
        diff,
      );
      setRuntimeJobsLoadState({ kind: "ready", message: `Diff governado de jobs exportado: ${diff.summary.headline}` });
      setStatus({
        kind: "ok",
        message: `Diff de jobs exportado sem payload, resultado ou erro bruto: ${diff.summary.headline}`,
      });
    } catch (error) {
      const message = `Falha ao comparar histórico de jobs: ${errorMessage(error)}`;
      setRuntimeJobsLoadState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handleLoadRuntimeJobMetricsHistoryCentralStatus(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para consultar a central de jobs." });
      return;
    }
    setRuntimeJobsLoadState({ kind: "loading", message: "Consultando central de métricas de jobs." });
    try {
      const central = normalizeRuntimeJobMetricsHistoryCentralStatus(
        await loadSharedRuntimeJobMetricsHistoryCentralStatus(selectedFlowId),
      );
      if (!central) {
        throw new Error("Status central de jobs veio em formato inválido.");
      }
      const message = central.configured
        ? `Central de jobs configurada${central.tokenConfigured ? " com token no header" : ""}. Último HTTP: ${central.statusCode ?? "-"}.`
        : central.invalidReason
          ? `Central de jobs inválida: ${central.invalidReason}.`
          : "Central de jobs não configurada.";
      setRuntimeJobsLoadState({ kind: central.configured ? "ready" : "idle", message });
      setStatus({ kind: central.configured ? "ok" : "idle", message });
    } catch (error) {
      const message = `Falha ao consultar central de jobs: ${errorMessage(error)}`;
      setRuntimeJobsLoadState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handleSyncCentralRuntimeJobMetricsHistory(): Promise<void> {
    if (!selectedFlowId || !draftFlow) {
      setStatus({ kind: "error", message: "Selecione um flow para sincronizar histórico de jobs." });
      return;
    }
    setRuntimeJobsLoadState({ kind: "loading", message: "Sincronizando histórico central de jobs." });
    try {
      if (runtimeJobMetricsHistory.length) {
        await mergeSharedRuntimeJobMetricsHistory(
          selectedFlowId,
          buildRuntimeJobMetricsHistoryPackage(draftFlow, runtimeJobMetricsHistory),
        );
      }
      const result = await syncSharedCentralRuntimeJobMetricsHistory(selectedFlowId);
      const historyPayload = isRecord(result) && result.history !== undefined ? result.history : result;
      const historyPackage = normalizeRuntimeJobMetricsHistoryPackage(historyPayload);
      if (!historyPackage) {
        throw new Error("Histórico sincronizado de jobs veio em formato inválido.");
      }
      const pushed = isRecord(result) ? readNumberValue(result.pushedSnapshotCount) : 0;
      const pulled = isRecord(result) ? readNumberValue(result.pulledSnapshotCount) : 0;
      const nextHistory = persistRuntimeJobMetricsHistory(draftFlow, historyPackage.snapshots);
      setRuntimeJobMetricsHistory(nextHistory);
      setRuntimeJobsLoadState({
        kind: "ready",
        message: `Central de jobs sincronizada: ${pushed} enviado(s), ${pulled} recebido(s), ${nextHistory.length} no histórico.`,
      });
      setStatus({ kind: "ok", message: `Histórico de jobs sincronizado com a central (${nextHistory.length} snapshot(s)).` });
    } catch (error) {
      const message = `Falha ao sincronizar central de jobs: ${errorMessage(error)}`;
      setRuntimeJobsLoadState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handlePreviewRuntimeJobCleanup() {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para calcular limpeza de jobs." });
      return;
    }
    const sessionId = runtimeJobScope === "session" ? runtimeSession?.session_id : undefined;
    setRuntimeJobBusyId("cleanup:preview");
    setStatus({ kind: "busy", message: "Calculando prévia de limpeza de jobs antigos." });
    try {
      const preview = await cleanupRuntimeJobs(
        sandbox.url,
        {
          statuses: ["succeeded", "failed"],
          older_than_hours: 168,
          session_id: sessionId,
          limit: 100,
          dry_run: true,
        },
        studioRuntimeApiKey,
      );
      setRuntimeJobCleanupPreview(preview);
      setStatus({
        kind: "ok",
        message: `Prévia de limpeza: ${preview.matched} job(s) terminal(is) antigo(s) encontrados.`,
      });
    } catch (error) {
      setRuntimeJobCleanupPreview(null);
      setStatus({ kind: "error", message: errorMessage(error) });
    } finally {
      setRuntimeJobBusyId("");
    }
  }

  async function handleRunRuntimeJobCleanup() {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para limpar jobs." });
      return;
    }
    if (!runtimeJobCleanupPreview || runtimeJobCleanupPreview.matched <= 0) {
      setStatus({ kind: "error", message: "Gere uma prévia com jobs antigos antes de executar a limpeza." });
      return;
    }
    const sessionId = runtimeJobScope === "session" ? runtimeSession?.session_id : undefined;
    setRuntimeJobBusyId("cleanup:run");
    setStatus({ kind: "busy", message: `Limpando ${runtimeJobCleanupPreview.matched} job(s) terminal(is) antigo(s).` });
    try {
      const result = await cleanupRuntimeJobs(
        sandbox.url,
        {
          statuses: ["succeeded", "failed"],
          older_than_hours: runtimeJobCleanupPreview.older_than_hours || 168,
          session_id: sessionId,
          limit: Math.max(1, runtimeJobCleanupPreview.job_ids.length || runtimeJobCleanupPreview.matched),
          dry_run: false,
        },
        studioRuntimeApiKey,
      );
      await refreshRuntimeJobsState(sandbox.url);
      if (runtimeSession) {
        await refreshRuntimeData(runtimeSession);
      }
      setRuntimeJobCleanupPreview(result);
      setStatus({ kind: "ok", message: `${result.deleted} job(s) antigo(s) removido(s).` });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    } finally {
      setRuntimeJobBusyId("");
    }
  }

