    setStatus({ kind: "busy", message: "Gerando relatório de prontidão de entrega dos alertas." });
    try {
      const readiness = await loadSharedProviderTelemetryAlertDeliveryReadiness(draftFlow.id);
      if (
        !isRecord(readiness) ||
        readiness.format !== "agent-flow-builder.provider-telemetry-alert-delivery-readiness.v1"
      ) {
        throw new Error("Relatório de prontidão de entrega retornou formato inválido.");
      }
      downloadJsonFile(
        `provider-telemetry-alert-delivery-${sanitizeFileNamePart(draftFlow.id)}.afproviderdelivery.json`,
        readiness,
      );
      const statusText = readStringValue(readiness.status) || "desconhecido";
      const deliverable = normalizeNonNegativeNumber(readiness.deliverableAlertCount);
      const open = normalizeNonNegativeNumber(readiness.openAlertCount);
      setStatus({
        kind: "ok",
        message: `Prontidão de entrega exportada: ${statusText}, ${deliverable}/${open} alerta(s) entregáveis.`,
      });
    } catch (error) {
      setStatus({ kind: "error", message: `Falha ao exportar prontidão de entrega: ${errorMessage(error)}` });
    }
