  function handlePrepareRuntimeAuthKeyRevocation(keyId: string, source: string) {
    if (!selectedFlowId) {
      return;
    }
    const identifier = runtimeAuthRevocationIdentifier(keyId, source);
    const existingValue = studioLocalSecrets.find((secret) => secret.name === "AGENT_API_REVOKED_KEY_IDS")?.value ?? "";
    const nextRevokedKeyIds = mergeRuntimeAuthRevokedKeyIds(existingValue, identifier);
    handleStudioLocalSecretChange("AGENT_API_REVOKED_KEY_IDS", JSON.stringify(nextRevokedKeyIds));
    setStatus({
      kind: "ok",
      message: `${identifier} preparado em AGENT_API_REVOKED_KEY_IDS. Reinicie o sandbox para aplicar a revogação.`,
    });
  }

  async function handleRuntimeJobAction(jobId: string, action: "run" | "retry") {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para operar jobs." });
      return;
    }
    const actionLabel = action === "run" ? "Executando" : "Reprocessando";
    setRuntimeJobBusyId(`${action}:${jobId}`);
    setStatus({ kind: "busy", message: `${actionLabel} job ${jobId}.` });
    try {
      const response =
        action === "run"
          ? await runRuntimeJob(sandbox.url, jobId, studioRuntimeApiKey)
          : await retryRuntimeJob(sandbox.url, jobId, studioRuntimeApiKey);
      await refreshRuntimeJobsState(sandbox.url);
      if (runtimeSession) {
        await refreshRuntimeData(runtimeSession);
      }
      setStatus({
        kind: "ok",
        message: `Job ${response.job.job_id} ${action === "run" ? "executado" : "reenfileirado"} (${response.job.status}).`,
      });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    } finally {
      setRuntimeJobBusyId("");
    }
  }

  async function handleScheduleRuntimeJob(jobId: string, delaySeconds: number) {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para reagendar jobs." });
      return;
    }
    const delayLabel = delaySeconds >= 3600 ? `${Math.round(delaySeconds / 3600)} h` : `${Math.round(delaySeconds / 60)} min`;
    setRuntimeJobBusyId(`schedule:${jobId}:${delaySeconds}`);
    setStatus({ kind: "busy", message: `Reagendando job ${jobId} para +${delayLabel}.` });
    try {
      const response = await scheduleRuntimeJob(sandbox.url, jobId, delaySeconds, studioRuntimeApiKey);
      await refreshRuntimeJobsState(sandbox.url);
      if (runtimeSession) {
        await refreshRuntimeData(runtimeSession);
      }
      setStatus({
        kind: "ok",
        message: `Job ${response.job.job_id} reagendado para ${response.job.next_run_at ?? "agora"}.`,
      });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    } finally {
      setRuntimeJobBusyId("");
    }
  }

