  async function handleRuntimeJobBatchAction(action: "run-pending" | "retry-failed") {
    if (!sandbox?.url) {
      setStatus({ kind: "error", message: "Runtime local indisponível para operar jobs." });
      return;
    }
    const jobs =
      action === "run-pending"
        ? runtimeJobsData.filter(runtimeJobCanRunNow)
        : runtimeJobsData.filter(runtimeJobCanRetry);
    if (!jobs.length) {
      setStatus({
        kind: "error",
        message: action === "run-pending" ? "Não há jobs pendentes na lista atual." : "Não há jobs falhos na lista atual.",
      });
      return;
    }
    const label = action === "run-pending" ? "Executando pendentes" : "Reprocessando falhos";
    setRuntimeJobBusyId(`batch:${action}`);
    setStatus({ kind: "busy", message: `${label}: ${jobs.length} job(s).` });
    const sessionId = runtimeJobScope === "session" ? runtimeSession?.session_id : undefined;
    const limit = Math.max(1, Math.min(200, jobs.length));
    try {
      const result =
        action === "run-pending"
          ? await runPendingRuntimeJobs(sandbox.url, sessionId, limit, studioRuntimeApiKey)
          : await retryFailedRuntimeJobs(sandbox.url, sessionId, limit, studioRuntimeApiKey);
      await refreshRuntimeJobsState(sandbox.url);
      if (runtimeSession) {
        await refreshRuntimeData(runtimeSession);
      }
      setStatus({
        kind: result.failed ? "error" : "ok",
        message: `${label}: ${result.succeeded} ok, ${result.failed} falha(s).`,
      });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    } finally {
      setRuntimeJobBusyId("");
    }
  }

  function closeStudioEventStream(message = "Stream de eventos desconectado.", status: StudioEventStreamStatus = "closed") {
    studioEventStreamRef.current?.close();
    studioEventStreamRef.current = null;
    setStudioEventStream((current) => ({
      ...current,
      status,
      message,
      url: status === "idle" ? null : current.url,
      closedReason: status === "closed" ? message : current.closedReason,
    }));
  }

  function startStudioEventStream(
    targetSession = runtimeSession,
    fromSeq?: number,
    runtimeUrl = sandbox?.url ?? "",
    resourceName = draftFlow?.api.resourceName ?? "",
    transport = studioEventStreamTransport,
    runtimeApiKey = studioRuntimeApiKey,
  ) {
    if (!draftFlow || !runtimeUrl || !resourceName || !targetSession?.session_id) {
      setStudioEventStream({
        ...defaultStudioEventStreamState,
        transport,
        status: "error",
        message: "Runtime, flow ou sessão indisponível para stream.",
      });
      return;
    }
    if (transport === "sse" && (typeof window === "undefined" || typeof window.EventSource === "undefined")) {
      setStudioEventStream({
        ...defaultStudioEventStreamState,
        transport,
        status: "error",
        message: "Este navegador não suporta EventSource/SSE.",
      });
      return;
    }
    if (transport === "websocket" && (typeof window === "undefined" || typeof window.WebSocket === "undefined")) {
      setStudioEventStream({
        ...defaultStudioEventStreamState,
        transport,
        status: "error",
        message: "Este navegador não suporta WebSocket.",
      });
      return;
    }
    studioEventStreamRef.current?.close();
    const nextSeq = fromSeq ?? nextRuntimeEventSeq(runtimeEventsData);
    const url =
      transport === "websocket"
        ? buildRuntimeEventWebSocketUrl(runtimeUrl, resourceName, targetSession.session_id, nextSeq, runtimeApiKey)
        : buildRuntimeEventStreamUrl(runtimeUrl, resourceName, targetSession.session_id, nextSeq, runtimeApiKey);

    if (transport === "websocket") {
      const socket = new window.WebSocket(url);
      let socketHadError = false;
      let closeReason: string | null = null;
      studioEventStreamRef.current = socket;
      setStudioEventStream({
        status: "connecting",
        transport,
        message: `Conectando WebSocket de eventos a partir de #${nextSeq}.`,
        url,
        lastSeq: nextSeq > 1 ? nextSeq - 1 : null,
        received: 0,
        closedReason: null,
      });

      socket.onopen = () => {
        if (studioEventStreamRef.current !== socket) {
          return;
        }
        setStudioEventStream((current) => ({
          ...current,
          status: "live",
          message: "Eventos ao vivo conectados por WebSocket.",
        }));
      };

      socket.onmessage = (event) => {
        if (studioEventStreamRef.current !== socket) {
          return;
        }
        const parsed = parseRuntimeWebSocketMessage(event.data);
        if (!parsed) {
          return;
        }
        if (parsed.event === "agent_event") {
          const runtimeEvent = parseRuntimeEventPayload(parsed.data);
          if (!runtimeEvent) {
            return;
          }
          setRuntimeEventsData((current) => mergeRuntimeEvents(current, [runtimeEvent]));
          setSelectedStudioEventSeq(runtimeEvent.seq);
          setStudioRunCausalAnalysis(null);
          setStudioEventStream((current) => ({
            ...current,
            status: "live",
            message: `Evento #${runtimeEvent.seq} recebido por WebSocket.`,
            lastSeq: runtimeEvent.seq,
            received: current.received + 1,
          }));
          return;
        }
        if (parsed.event === "stream_closed") {
          closeReason = readStreamCloseReason(parsed.data);
          setStudioEventStream((current) => ({
            ...current,
            status: "closed",
            message: `Stream WebSocket encerrado: ${closeReason}.`,
            closedReason: closeReason,
          }));
          socket.close(1000, closeReason);
        }
      };

      socket.onerror = () => {
        if (studioEventStreamRef.current !== socket) {
          return;
        }
        socketHadError = true;
        socket.close();
        studioEventStreamRef.current = null;
        setStudioEventStream((current) => ({
          ...current,
          status: "error",
          message: "Stream WebSocket indisponível; altere para SSE ou use Atualizar.",
        }));
      };

      socket.onclose = (event) => {
        if (studioEventStreamRef.current !== socket || socketHadError) {
          return;
        }
        studioEventStreamRef.current = null;
        const reason = closeReason || event.reason || "websocket_closed";
        setStudioEventStream((current) => ({
          ...current,
          status: "closed",
          message: `Stream WebSocket encerrado: ${reason}.`,
          closedReason: reason,
        }));
      };
      return;
    }

    const source = new window.EventSource(url);
    studioEventStreamRef.current = source;
    setStudioEventStream({
      status: "connecting",
      transport,
      message: `Conectando eventos ao vivo a partir de #${nextSeq}.`,
      url,
      lastSeq: nextSeq > 1 ? nextSeq - 1 : null,
      received: 0,
      closedReason: null,
    });

    source.onopen = () => {
      if (studioEventStreamRef.current !== source) {
        return;
      }
      setStudioEventStream((current) => ({
        ...current,
        status: "live",
        message: "Eventos ao vivo conectados.",
      }));
    };

    source.addEventListener("agent_event", (event) => {
      if (studioEventStreamRef.current !== source) {
        return;
      }
      const parsed = parseRuntimeStreamEvent(event);
      if (!parsed) {
        return;
      }
      setRuntimeEventsData((current) => mergeRuntimeEvents(current, [parsed]));
      setSelectedStudioEventSeq(parsed.seq);
      setStudioRunCausalAnalysis(null);
      setStudioEventStream((current) => ({
        ...current,
        status: "live",
        message: `Evento #${parsed.seq} recebido por SSE.`,
        lastSeq: parsed.seq,
        received: current.received + 1,
      }));
    });

    source.addEventListener("stream_closed", (event) => {
      if (studioEventStreamRef.current !== source) {
        return;
      }
      source.close();
      studioEventStreamRef.current = null;
      const data = parseSseJson(event.data);
      const reason = isRecord(data) ? readStringValue(data.reason) || "stream_closed" : "stream_closed";
      setStudioEventStream((current) => ({
        ...current,
        status: "closed",
        message: `Stream encerrado: ${reason}.`,
        closedReason: reason,
      }));
    });

    source.onerror = () => {
      if (studioEventStreamRef.current !== source) {
        return;
      }
      source.close();
      studioEventStreamRef.current = null;
      setStudioEventStream((current) => ({
        ...current,
        status: "error",
        message: "Stream SSE indisponível; use Atualizar para buscar transcript/events.",
      }));
    };
  }

  function handleStartStudioEventStream() {
    startStudioEventStream(runtimeSession, undefined, sandbox?.url ?? "", draftFlow?.api.resourceName ?? "", studioEventStreamTransport);
  }

  function handleStopStudioEventStream() {
    closeStudioEventStream("Stream de eventos desconectado manualmente.");
  }

  async function refreshRuntimeData(nextSession?: SessionView): Promise<StudioRunRecord | null> {
    const session = nextSession ?? runtimeSession;
    if (!draftFlow || !sandbox?.url || !session) {
      return null;
    }
    const [nextTranscript, nextEvents] = await Promise.all([
      runtimeTranscript(sandbox.url, draftFlow.api.resourceName, session.session_id, studioRuntimeApiKey),
      runtimeEvents(sandbox.url, draftFlow.api.resourceName, session.session_id, studioRuntimeApiKey),
    ]);
    setTranscript(nextTranscript);
    setRuntimeEventsData(nextEvents);
    setStudioTimelineAgentFilter(session.agent_id || draftFlow.id);
    setStudioRunCausalAnalysis(null);
    setSelectedStudioEventSeq(nextEvents.at(-1)?.seq ?? null);
    try {
      const saved = await saveStudioRun(draftFlow.id, {
        runtimeUrl: sandbox.url,
        resourceName: draftFlow.api.resourceName,
        session,
        transcript: nextTranscript,
        events: nextEvents,
        logs: sandbox.logs ?? [],
      });
      setStudioStateSnapshots(saved.stateSnapshots);
      await refreshStudioRuns(draftFlow.id, buildStudioRunQuery());
      setSelectedStudioRunId(saved.id);
      return saved;
    } catch {
      // Runtime execution should stay usable even if local trace persistence fails.
      return null;
    }
  }

  function buildStudioRunQuery(): StudioRunQuery {
    const minDurationMs = parseStudioRunDurationInput(studioRunMinDurationMsFilter);
    const maxDurationMs = parseStudioRunDurationInput(studioRunMaxDurationMsFilter);
    const isComplete =
      studioRunCompletionFilter === "complete"
        ? true
        : studioRunCompletionFilter === "incomplete"
          ? false
          : undefined;
    return {
      q: studioRunSearch.trim() || undefined,
      agentId: studioRunAgentFilter.trim() || undefined,
      node: studioRunNodeFilter.trim() || undefined,
      status: studioRunStatusFilter || undefined,
      phase: studioRunPhaseFilter || undefined,
      hasErrors: studioRunHasErrorsOnly ? true : undefined,
      isComplete,
      minDurationMs,
      maxDurationMs,
    };
  }

  function buildStudioProviderTelemetryQuery(): StudioProviderTelemetryQuery {
    return {
      windowHours: parsePositiveNumber(studioProviderTelemetryWindowHours),
      providerTokenBudget: parsePositiveNumber(studioProviderTelemetryTokenBudget),
      providerCostBudgetUsd: parsePositiveNumber(studioProviderTelemetryCostBudget),
    };
  }

  function buildStudioSandboxTelemetryQuery(): StudioSandboxTelemetryQuery {
    return {
      windowHours: parsePositiveNumber(studioSandboxTelemetryWindowHours),
      onlyFailures: studioSandboxTelemetryFailuresOnly,
    };
  }

