  function handleStudioAnnotationReviewerNameChange(value: string): void {
    const normalized = normalizeStudioAnnotationReviewerName(value);
    window.localStorage.setItem(studioAnnotationReviewerNameStorageKey, normalized);
    setStudioAnnotationReviewerName(normalized);
  }

  function handleStudioAnnotationPermissionModeChange(mode: StudioAnnotationPermissionMode): void {
    if (!selectedFlowId) {
      return;
    }
    const reviewerName = normalizeStudioAnnotationReviewerName(studioAnnotationReviewerName);
    const nextPolicy: StudioAnnotationQueuePermissionPolicy = {
      mode,
      reviewers: studioAnnotationPermissionPolicy.reviewers,
      updatedAt: new Date().toISOString(),
      updatedBy: reviewerName,
    };
    const nextAuditEntries = [
      buildStudioAnnotationAuditEntry({
        action: "queue_synced",
        itemId: null,
        conflictId: null,
        actor: reviewerName,
        at: nextPolicy.updatedAt,
        summary: `Política da fila alterada para ${formatStudioAnnotationPermissionMode(mode)}.`,
      }),
      ...studioAnnotationAuditEntries,
    ];
    persistStudioAnnotationQueue(
      selectedFlowId,
      studioAnnotationQueue,
      studioAnnotationQueueConflicts,
      nextAuditEntries,
      nextPolicy,
    );
  }

  function handleStudioAnnotationReviewerRoleChange(role: StudioAnnotationReviewerRole): void {
    if (!selectedFlowId) {
      return;
    }
    const reviewerName = normalizeStudioAnnotationReviewerName(studioAnnotationReviewerName);
    const now = new Date().toISOString();
    const nextPolicy = upsertStudioAnnotationReviewerRole(
      {
        ...studioAnnotationPermissionPolicy,
        updatedAt: now,
        updatedBy: reviewerName,
      },
      reviewerName,
      role,
      now,
    );
    const nextAuditEntries = [
      buildStudioAnnotationAuditEntry({
        action: "queue_synced",
        itemId: null,
        conflictId: null,
        actor: reviewerName,
        at: now,
        summary: `Papel local alterado para ${formatStudioAnnotationReviewerRole(role)}.`,
      }),
      ...studioAnnotationAuditEntries,
    ];
    persistStudioAnnotationQueue(
      selectedFlowId,
      studioAnnotationQueue,
      studioAnnotationQueueConflicts,
      nextAuditEntries,
      nextPolicy,
    );
  }

  function persistStudioScenarios(flowId: string, scenarios: StudioScenario[]): void {
    window.localStorage.setItem(scenarioStorageKey(flowId), JSON.stringify(scenarios));
    setStudioScenarios(scenarios);
  }

  function persistStudioScenarioDatasets(
    flowId: string,
    datasets: StudioScenarioDataset[],
    scenarios: StudioScenario[] = studioScenarios,
  ): StudioScenarioDataset[] {
    const normalized = syncStudioScenarioDatasets(datasets, scenarios);
    window.localStorage.setItem(scenarioDatasetStorageKey(flowId), JSON.stringify(normalized));
    setStudioScenarioDatasets(normalized);
    if (selectedStudioScenarioDatasetId && !normalized.some((dataset) => dataset.id === selectedStudioScenarioDatasetId)) {
      setSelectedStudioScenarioDatasetId(normalized[0]?.id ?? "");
    }
    return normalized;
  }

  function persistStudioAnnotationQueueLocal(
    flowId: string,
    items: StudioAnnotationQueueItem[],
    conflicts: StudioAnnotationQueueConflict[] = studioAnnotationQueueConflicts,
    auditEntries: StudioAnnotationQueueAuditEntry[] = studioAnnotationAuditEntries,
    permissionPolicy: StudioAnnotationQueuePermissionPolicy = studioAnnotationPermissionPolicy,
  ): StudioAnnotationQueueItem[] {
    const normalized = syncStudioAnnotationQueue(items);
    const normalizedConflicts = syncStudioAnnotationQueueConflicts(conflicts, normalized);
    const normalizedAuditEntries = syncStudioAnnotationQueueAuditEntries(auditEntries);
    const normalizedPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(permissionPolicy);
    window.localStorage.setItem(studioAnnotationQueueStorageKey(flowId), JSON.stringify(normalized));
    setStudioAnnotationQueue(normalized);
    setStudioAnnotationQueueConflicts(normalizedConflicts);
    setStudioAnnotationAuditEntries(normalizedAuditEntries);
    setStudioAnnotationPermissionPolicy(normalizedPermissionPolicy);
    return normalized;
  }

  function persistStudioAnnotationQueue(
    flowId: string,
    items: StudioAnnotationQueueItem[],
    conflicts: StudioAnnotationQueueConflict[] = studioAnnotationQueueConflicts,
    auditEntries: StudioAnnotationQueueAuditEntry[] = studioAnnotationAuditEntries,
    permissionPolicy: StudioAnnotationQueuePermissionPolicy = studioAnnotationPermissionPolicy,
  ): StudioAnnotationQueueItem[] {
    const normalized = persistStudioAnnotationQueueLocal(flowId, items, conflicts, auditEntries, permissionPolicy);
    const normalizedConflicts = syncStudioAnnotationQueueConflicts(conflicts, normalized);
    const normalizedAuditEntries = syncStudioAnnotationQueueAuditEntries(auditEntries);
    const normalizedPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(permissionPolicy);
    void saveStudioAnnotationQueueShared(
      flowId,
      normalized,
      normalizedConflicts,
      normalizedAuditEntries,
      normalizedPermissionPolicy,
    );
    return normalized;
  }

  function buildStudioAnnotationQueueBackendPayload(
    flowId: string,
    items: StudioAnnotationQueueItem[],
    conflicts: StudioAnnotationQueueConflict[] = studioAnnotationQueueConflicts,
    auditEntries: StudioAnnotationQueueAuditEntry[] = studioAnnotationAuditEntries,
    permissionPolicy: StudioAnnotationQueuePermissionPolicy = studioAnnotationPermissionPolicy,
  ): unknown {
    const normalized = syncStudioAnnotationQueue(items);
    const normalizedConflicts = syncStudioAnnotationQueueConflicts(conflicts, normalized);
    const normalizedAuditEntries = syncStudioAnnotationQueueAuditEntries(auditEntries);
    const normalizedPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(permissionPolicy);
    return draftFlow && draftFlow.id === flowId
      ? buildStudioAnnotationQueueExport(
          draftFlow,
          normalized,
          normalizedConflicts,
          normalizedAuditEntries,
          normalizedPermissionPolicy,
        )
      : {
          items: normalized,
          conflicts: normalizedConflicts,
          auditEntries: normalizedAuditEntries,
          permissionPolicy: normalizedPermissionPolicy,
        };
  }

  async function saveStudioAnnotationQueueShared(
    flowId: string,
    items: StudioAnnotationQueueItem[],
    conflicts: StudioAnnotationQueueConflict[] = studioAnnotationQueueConflicts,
    auditEntries: StudioAnnotationQueueAuditEntry[] = studioAnnotationAuditEntries,
    permissionPolicy: StudioAnnotationQueuePermissionPolicy = studioAnnotationPermissionPolicy,
  ): Promise<void> {
    setStudioAnnotationQueueSyncState("syncing");
    setStudioAnnotationQueueSyncMessage("Salvando fila compartilhada no workspace.");
    try {
      const response = normalizeStudioAnnotationQueueExport(
        await saveSharedStudioAnnotationQueue(
          flowId,
          buildStudioAnnotationQueueBackendPayload(flowId, items, conflicts, auditEntries, permissionPolicy),
        ),
      );
      if (!response) {
        throw new Error("Resposta da fila compartilhada veio em formato inválido.");
      }
      const normalizedConflicts = syncStudioAnnotationQueueConflicts(response.conflicts, response.items);
      const normalizedAuditEntries = syncStudioAnnotationQueueAuditEntries(response.auditEntries);
      const normalizedPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(response.permissionPolicy);
      setStudioAnnotationQueueConflicts(normalizedConflicts);
      setStudioAnnotationAuditEntries(normalizedAuditEntries);
      setStudioAnnotationPermissionPolicy(normalizedPermissionPolicy);
      setStudioAnnotationQueueSyncState("synced");
      setStudioAnnotationQueueSyncMessage(
        `Fila compartilhada salva: ${formatStudioAnnotationQueueSyncMessage(response.itemCount, normalizedConflicts.length)}`,
      );
    } catch (error) {
      setStudioAnnotationQueueSyncState("error");
      setStudioAnnotationQueueSyncMessage(`Fila local salva; backend pendente: ${errorMessage(error)}`);
    }
  }

  async function handleSyncStudioAnnotationQueue(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para sincronizar a fila." });
      return;
    }
    setStudioAnnotationQueueSyncState("syncing");
    setStudioAnnotationQueueSyncMessage("Mesclando fila local com a fila compartilhada.");
    try {
      const reviewerName = normalizeStudioAnnotationReviewerName(studioAnnotationReviewerName);
      const now = new Date().toISOString();
      const outgoingAuditEntries = [
        buildStudioAnnotationAuditEntry({
          action: "queue_synced",
          itemId: null,
          conflictId: null,
          actor: reviewerName,
          at: now,
          summary: `Sincronização manual enviada com ${studioAnnotationQueue.length} item(ns).`,
        }),
        ...studioAnnotationAuditEntries,
      ];
      const response = normalizeStudioAnnotationQueueExport(
        await mergeSharedStudioAnnotationQueue(
          selectedFlowId,
          buildStudioAnnotationQueueBackendPayload(
            selectedFlowId,
            studioAnnotationQueue,
            studioAnnotationQueueConflicts,
            outgoingAuditEntries,
            studioAnnotationPermissionPolicy,
          ),
        ),
      );
      if (!response) {
        throw new Error("Resposta da fila compartilhada veio em formato inválido.");
      }
      const nextConflicts = syncStudioAnnotationQueueConflicts(response.conflicts, response.items);
      const nextAuditEntries = syncStudioAnnotationQueueAuditEntries(response.auditEntries);
      const nextPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(response.permissionPolicy);
      const nextItems = persistStudioAnnotationQueueLocal(
        selectedFlowId,
        response.items,
        nextConflicts,
        nextAuditEntries,
        nextPermissionPolicy,
      );
      setStudioAnnotationQueueSyncState("synced");
      setStudioAnnotationQueueSyncMessage(formatStudioAnnotationQueueSyncMessage(nextItems.length, nextConflicts.length));
      setStatus({
        kind: "ok",
        message: `Fila de revisão sincronizada com ${nextItems.length} item(ns) e ${nextConflicts.length} conflito(s).`,
      });
    } catch (error) {
      setStudioAnnotationQueueSyncState("error");
      setStudioAnnotationQueueSyncMessage(`Falha ao sincronizar fila compartilhada: ${errorMessage(error)}`);
      setStatus({ kind: "error", message: `Falha ao sincronizar fila de revisão: ${errorMessage(error)}` });
    }
  }

  async function handleLoadStudioAnnotationQueueCentralStatus(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para consultar a central da fila." });
      return;
    }
    setStudioAnnotationQueueSyncState("syncing");
    setStudioAnnotationQueueSyncMessage("Consultando central da fila de revisão.");
    try {
      const centralStatus = normalizeStudioAnnotationQueueCentralSyncStatus(
        await loadSharedStudioAnnotationQueueCentralSyncStatus(selectedFlowId),
      );
      if (!centralStatus) {
        throw new Error("Status central da fila veio em formato inválido.");
      }
      setStudioAnnotationQueueCentralStatus(centralStatus);
      setStudioAnnotationQueueSyncState(centralStatus.invalidReason ? "error" : "synced");
      const summary = formatStudioAnnotationQueueCentralStatusSummary(centralStatus);
      setStudioAnnotationQueueSyncMessage(summary);
      setStatus({ kind: centralStatus.invalidReason ? "error" : "ok", message: summary });
    } catch (error) {
      setStudioAnnotationQueueSyncState("error");
      setStudioAnnotationQueueCentralStatus(null);
      setStudioAnnotationQueueSyncMessage(`Falha ao consultar central da fila: ${errorMessage(error)}`);
      setStatus({ kind: "error", message: `Falha ao consultar central da fila: ${errorMessage(error)}` });
    }
  }

  async function handleSyncCentralStudioAnnotationQueue(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para sincronizar a fila central." });
      return;
    }
    setStudioAnnotationQueueSyncState("syncing");
    setStudioAnnotationQueueSyncMessage("Sincronizando fila de revisão com a central.");
    try {
      const result = normalizeStudioAnnotationQueueCentralSyncResult(
        await syncSharedCentralStudioAnnotationQueue(selectedFlowId),
      );
      if (!result) {
        throw new Error("Resposta central da fila veio em formato inválido.");
      }
      const nextConflicts = syncStudioAnnotationQueueConflicts(result.queue.conflicts, result.queue.items);
      const nextAuditEntries = syncStudioAnnotationQueueAuditEntries(result.queue.auditEntries);
      const nextPermissionPolicy = normalizeStudioAnnotationPermissionPolicy(result.queue.permissionPolicy);
      const nextItems = persistStudioAnnotationQueueLocal(
        selectedFlowId,
        result.queue.items,
        nextConflicts,
        nextAuditEntries,
        nextPermissionPolicy,
      );
      setStudioAnnotationQueueCentralStatus(result.central);
      setStudioAnnotationQueueSyncState("synced");
      setStudioAnnotationQueueSyncMessage(formatStudioAnnotationQueueCentralSyncSummary(result));
      setStatus({
        kind: "ok",
        message: `Fila central sincronizada com ${nextItems.length} item(ns) e ${nextConflicts.length} conflito(s).`,
      });
    } catch (error) {
      setStudioAnnotationQueueSyncState("error");
      setStudioAnnotationQueueSyncMessage(`Falha ao sincronizar fila central: ${errorMessage(error)}`);
      setStatus({ kind: "error", message: `Falha ao sincronizar fila central: ${errorMessage(error)}` });
    }
  }

  async function handleSaveExperimentDashboardSnapshot(): Promise<void> {
    if (!selectedFlowId || !draftFlow) {
      setStatus({ kind: "error", message: "Selecione um flow para salvar snapshot do dashboard." });
      return;
    }
    const dashboard = buildStudioScenarioExperimentDashboardReport(draftFlow, studioScenarioDatasets);
    setStudioExperimentDashboardHistoryState({ kind: "loading", message: "Salvando snapshot histórico do dashboard." });
    try {
      const historyPackage = normalizeStudioExperimentDashboardHistoryPackage(
        await saveStudioExperimentDashboardSnapshot(selectedFlowId, dashboard),
      );
      if (!historyPackage) {
        throw new Error("Histórico de dashboard retornou formato inválido.");
      }
      setStudioExperimentDashboardSnapshots(historyPackage.snapshots);
      setStudioExperimentDashboardHistoryState({
        kind: "ready",
        message: `Snapshot salvo: ${historyPackage.snapshotCount} snapshot(s) no histórico.`,
      });
      setStatus({
        kind: "ok",
        message: `Snapshot do dashboard salvo no histórico compartilhado (${historyPackage.snapshotCount}).`,
      });
    } catch (error) {
      setStudioExperimentDashboardHistoryState({
        kind: "error",
        message: `Falha ao salvar snapshot do dashboard: ${errorMessage(error)}`,
      });
      setStatus({ kind: "error", message: `Falha ao salvar snapshot do dashboard: ${errorMessage(error)}` });
    }
  }

  function handleExportExperimentDashboardHistory(): void {
    if (!draftFlow) {
      setStatus({ kind: "error", message: "Selecione um flow para exportar o histórico do dashboard." });
      return;
    }
    if (!studioExperimentDashboardSnapshots.length) {
      setStatus({ kind: "error", message: "Salve ao menos um snapshot antes de exportar o histórico do dashboard." });
      return;
    }
    const payload: StudioExperimentDashboardHistoryPackage = {
      format: "agent-flow-builder.experiment-dashboard-history.v1",
      exportedAt: new Date().toISOString(),
      flow: {
        id: draftFlow.id,
        name: draftFlow.name,
        version: draftFlow.version,
      },
      snapshotCount: studioExperimentDashboardSnapshots.length,
      analysis: buildStudioExperimentDashboardHistoryAnalysis(studioExperimentDashboardSnapshots),
      snapshots: studioExperimentDashboardSnapshots,
    };
    downloadJsonFile(
      `studio-experiment-dashboard-history-${sanitizeFileNamePart(draftFlow.id)}.afexperiment-dashboard-history.json`,
      payload,
    );
    setStatus({
      kind: "ok",
      message: `Histórico do dashboard exportado com ${payload.snapshotCount} snapshot(s).`,
    });
  }

  function handleCompareStudioExperimentDashboardHistory(): void {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar o histórico do dashboard." });
      return;
    }
    experimentDashboardHistoryInputRef.current?.click();
  }

  async function handleCompareStudioExperimentDashboardHistoryFile(file: File): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar o histórico do dashboard." });
      return;
    }
    setStudioExperimentDashboardHistoryState({
      kind: "loading",
      message: `Comparando histórico de dashboard ${file.name}.`,
    });
    try {
      const parsed = JSON.parse(await file.text()) as unknown;
      const history = normalizeStudioExperimentDashboardHistoryPackage(parsed);
      if (!history) {
        throw new Error("Arquivo não é um histórico governado de dashboard experimental.");
      }
      const diff = normalizeStudioExperimentDashboardHistoryDiffPackage(
        await compareSharedStudioExperimentDashboardHistory(selectedFlowId, { history }),
      );
      if (!diff) {
        throw new Error("Diff de histórico experimental veio em formato inválido.");
      }
      downloadJsonFile(
        `studio-experiment-dashboard-history-diff-${sanitizeFileNamePart(diff.flow.id || selectedFlowId)}-${diff.packageHash}.afexperiment-dashboard-history-diff.json`,
        diff,
      );
      setStudioExperimentDashboardHistoryState({
        kind: "ready",
        message: `Diff governado exportado: ${diff.summary.headline}`,
      });
      setStatus({
        kind: "ok",
        message: `Diff do histórico exportado sem runs brutas ou saídas observadas: ${diff.summary.headline}`,
      });
    } catch (error) {
      const message = `Falha ao comparar histórico do dashboard: ${errorMessage(error)}`;
      setStudioExperimentDashboardHistoryState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handleLoadExperimentDashboardHistoryCentralStatus(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para consultar a central do dashboard." });
      return;
    }
    setStudioExperimentDashboardHistoryState({ kind: "loading", message: "Consultando central do dashboard experimental." });
    try {
      const central = normalizeStudioExperimentDashboardHistoryCentralStatus(
        await loadStudioExperimentDashboardHistoryCentralStatus(selectedFlowId),
      );
      if (!central) {
        throw new Error("Status central do dashboard veio em formato inválido.");
      }
      const message = central.configured
        ? `Central configurada${central.tokenConfigured ? " com token no header" : ""}. Último HTTP: ${central.statusCode ?? "-"}.`
        : central.invalidReason
          ? `Central inválida: ${central.invalidReason}.`
          : "Central do dashboard não configurada.";
      setStudioExperimentDashboardHistoryState({ kind: central.configured ? "ready" : "idle", message });
      setStatus({ kind: central.configured ? "ok" : "idle", message });
    } catch (error) {
      const message = `Falha ao consultar central do dashboard: ${errorMessage(error)}`;
      setStudioExperimentDashboardHistoryState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handleSyncCentralExperimentDashboardHistory(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para sincronizar o dashboard central." });
      return;
    }
    setStudioExperimentDashboardHistoryState({ kind: "loading", message: "Sincronizando dashboard experimental central." });
    try {
      const result = await syncSharedCentralStudioExperimentDashboardHistory(selectedFlowId);
      const historyPayload = isRecord(result) && result.history !== undefined ? result.history : result;
      const historyPackage = normalizeStudioExperimentDashboardHistoryPackage(historyPayload);
      if (!historyPackage) {
        throw new Error("Histórico sincronizado veio em formato inválido.");
      }
      const pushed = isRecord(result) ? readNumberValue(result.pushedSnapshotCount) : 0;
      const pulled = isRecord(result) ? readNumberValue(result.pulledSnapshotCount) : 0;
      setStudioExperimentDashboardSnapshots(historyPackage.snapshots);
      setStudioExperimentDashboardHistoryState({
        kind: "ready",
        message: `Central sincronizada: ${pushed} enviado(s), ${pulled} recebido(s), ${historyPackage.snapshotCount} no histórico.`,
      });
      setStatus({
        kind: "ok",
        message: `Histórico do dashboard sincronizado com a central (${historyPackage.snapshotCount} snapshot(s)).`,
      });
    } catch (error) {
      const message = `Falha ao sincronizar central do dashboard: ${errorMessage(error)}`;
      setStudioExperimentDashboardHistoryState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

