  async function handleLoadProviderTelemetryDashboardCentralStatus(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para consultar a central de provider." });
      return;
    }
    setStudioProviderTelemetryDashboardHistoryState({
      kind: "loading",
      message: "Consultando central do dashboard de provider.",
    });
    try {
      const central = normalizeStudioProviderTelemetryDashboardCentralStatus(
        await loadProviderTelemetryDashboardHistoryCentralStatus(selectedFlowId),
      );
      if (!central) {
        throw new Error("Status central de provider veio em formato inválido.");
      }
      const message = central.configured
        ? `Central de provider configurada${central.tokenConfigured ? " com token no header" : ""}. Último HTTP: ${central.statusCode ?? "-"}.`
        : central.invalidReason
          ? `Central de provider inválida: ${central.invalidReason}.`
          : "Central de provider não configurada.";
      setStudioProviderTelemetryDashboardHistoryState({ kind: central.configured ? "ready" : "idle", message });
      setStatus({ kind: central.configured ? "ok" : "idle", message });
    } catch (error) {
      const message = `Falha ao consultar central de provider: ${errorMessage(error)}`;
      setStudioProviderTelemetryDashboardHistoryState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  async function handleSyncCentralProviderTelemetryDashboardHistory(): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para sincronizar a central de provider." });
      return;
    }
    setStudioProviderTelemetryDashboardHistoryState({
      kind: "loading",
      message: "Sincronizando dashboard de provider central.",
    });
    try {
      const result = await syncSharedCentralProviderTelemetryDashboardHistory(selectedFlowId);
      const historyPayload = isRecord(result) && result.history !== undefined ? result.history : result;
      const historyPackage = normalizeStudioProviderTelemetryDashboardHistoryPackage(historyPayload);
      if (!historyPackage) {
        throw new Error("Histórico de provider sincronizado veio em formato inválido.");
      }
      const pushed = isRecord(result) ? readNumberValue(result.pushedSnapshotCount) : 0;
      const pulled = isRecord(result) ? readNumberValue(result.pulledSnapshotCount) : 0;
      setStudioProviderTelemetryDashboardSnapshots(historyPackage.snapshots);
      setStudioProviderTelemetryDashboardHistoryState({
        kind: "ready",
        message: `Central de provider sincronizada: ${pushed} enviado(s), ${pulled} recebido(s), ${historyPackage.snapshotCount} no histórico.`,
      });
      setStatus({
        kind: "ok",
        message: `Histórico de provider sincronizado com a central (${historyPackage.snapshotCount} snapshot(s)).`,
      });
    } catch (error) {
      const message = `Falha ao sincronizar central de provider: ${errorMessage(error)}`;
      setStudioProviderTelemetryDashboardHistoryState({ kind: "error", message });
      setStatus({ kind: "error", message });
    }
  }

  function handleSaveStudioReplayGovernanceHistorySnapshot(
    snapshot: StudioScenarioReplayGovernanceHistorySnapshot,
  ): void {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para salvar snapshot de replay." });
      return;
    }
    const nextHistory = persistStudioReplayGovernanceHistory(selectedFlowId, [
      snapshot,
      ...studioReplayGovernanceHistory,
    ]);
    setStudioReplayGovernanceHistory(nextHistory);
    void mergeSharedReplayGovernanceHistory(
      selectedFlowId,
      buildStudioReplayGovernanceHistoryPackage(
        selectedFlowId,
        nextHistory,
        studioReplayGovernanceHistoryResolutionHistory,
      ),
    ).then((response) => {
      const sharedHistory = normalizeStudioReplayGovernanceHistoryPackage(response);
      if (sharedHistory) {
        const mergedHistory = persistStudioReplayGovernanceHistory(
          selectedFlowId,
          mergeStudioReplayGovernanceHistorySnapshots(nextHistory, sharedHistory.snapshots),
        );
        setStudioReplayGovernanceHistory(mergedHistory);
        setStudioReplayGovernanceHistoryConflicts(sharedHistory.conflicts);
        setStudioReplayGovernanceHistoryResolutionHistory(sharedHistory.resolutionHistory);
      }
    }).catch(() => null);
    setStatus({
      kind: "ok",
      message: `Snapshot de governança do replay salvo (${nextHistory.length} no histórico).`,
    });
  }

