  async function handleResolveStudioReplayGovernanceHistoryConflict(
    conflictId: string,
    keepSnapshotHash: string,
  ): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para resolver conflitos de replay." });
      return;
    }
    setStatus({ kind: "busy", message: "Resolvendo conflito do histórico de replay." });
    try {
      const actor = normalizeStudioAnnotationReviewerName(studioAnnotationReviewerName);
      const role = studioAnnotationReviewerRoleFor(studioAnnotationPermissionPolicy, actor);
      if (role === "viewer") {
        throw new Error("Revisor Viewer não pode resolver conflitos de replay.");
      }
      const resolved = normalizeStudioReplayGovernanceHistoryPackage(
        await resolveSharedReplayGovernanceHistoryConflict(selectedFlowId, conflictId, {
          keepSnapshotHash,
          resolvedBy: actor,
          resolvedRole: role,
          resolutionNote: "Resolveu conflito de replay no Studio.",
        }),
      );
      if (!resolved) {
        throw new Error("Resposta de resolução do histórico de replay veio em formato inválido.");
      }
      const nextHistory = persistStudioReplayGovernanceHistory(selectedFlowId, resolved.snapshots);
      setStudioReplayGovernanceHistory(nextHistory);
      setStudioReplayGovernanceHistoryConflicts(resolved.conflicts);
      setStudioReplayGovernanceHistoryResolutionHistory(resolved.resolutionHistory);
      setStatus({
        kind: "ok",
        message: `Conflito de replay resolvido: ${resolved.openConflictCount} aberto(s).`,
      });
    } catch (error) {
      setStatus({ kind: "error", message: `Falha ao resolver conflito de replay: ${errorMessage(error)}` });
    }
  }

