  async function handleCompareStudioAnnotationConflictReviewFile(file: File): Promise<void> {
    if (!selectedFlowId) {
      setStatus({ kind: "error", message: "Selecione um flow para comparar a revisão de conflitos da fila." });
      return;
    }
    setStudioAnnotationQueueSyncState("syncing");
    setStudioAnnotationQueueSyncMessage(`Comparando revisão governada da fila ${file.name}.`);
    try {
      const parsed = JSON.parse(await file.text()) as unknown;
      const review = normalizeStudioAnnotationQueueConflictReviewPackage(parsed);
      if (!review) {
        throw new Error("Arquivo não é uma revisão governada válida da fila ou contém payload bruto.");
      }
      const diff = normalizeStudioAnnotationQueueConflictReviewDiffPackage(
        await compareSharedStudioAnnotationQueueConflictReview(selectedFlowId, { review }),
      );
      if (!diff) {
        throw new Error("Diff de revisão da fila veio em formato inválido.");
      }
      downloadJsonFile(
        `studio-annotation-conflicts-diff-${sanitizeFileNamePart(diff.flow.id || selectedFlowId)}-${diff.packageHash}.afannotation-conflicts-diff.json`,
        diff,
      );
      setStudioAnnotationQueueSyncState("synced");
      setStudioAnnotationQueueSyncMessage(`Diff de revisão da fila exportado: ${diff.summary.headline}.`);
      setStatus({
        kind: "ok",
        message: `Diff de revisão da fila exportado sem itens, snapshots ou saídas brutas: ${diff.summary.headline}.`,
      });
    } catch (error) {
      const message = errorMessage(error);
      setStudioAnnotationQueueSyncState("error");
      setStudioAnnotationQueueSyncMessage(`Falha ao comparar revisão da fila: ${message}`);
      setStatus({ kind: "error", message });
    }
  }

  async function findLatestScenarioRunId(scenarioId: string): Promise<string | null> {
    if (!selectedFlowId) {
      return null;
    }
    try {
      const result = await listStudioRuns(selectedFlowId, {});
      for (const run of result.runs) {
        const record = await loadStudioRun(selectedFlowId, run.id);
        if (studioRunScenarioId(record) === scenarioId) {
          return record.id;
        }
      }
    } catch {
      return null;
    }
    return null;
  }

  async function evaluateStudioScenarioExpectedOutput(
    scenario: StudioScenario,
    observedText: string,
    context: Record<string, unknown> = {},
  ): Promise<StudioScenarioExpectedEvaluation> {
    const kind = studioScenarioEvaluatorKindForScenario(scenario);
    if (kind !== "rules") {
      const external = studioScenarioExternalEvaluatorForScenario(scenario);
      if (!external) {
        return {
          ok: false,
          message: `${formatStudioScenarioEvaluatorKind(kind)} sem endpoint configurado para o cenário "${scenario.label}".`,
        };
      }
      try {
        const result = await evaluateExternalEvaluator({
          endpointUrl: external.endpointUrl,
          passPath: external.passPath,
          reasonPath: external.reasonPath,
          scorePath: external.scorePath,
          verdictPath: external.verdictPath,
          timeoutMs: external.timeoutMs,
          minScore: external.minScore,
          payload: {
            evaluator: {
              kind,
              rubric: external.rubric,
              minScore: external.minScore,
            },
            scenario: {
              id: scenario.id,
              label: scenario.label,
              input: scenario.input,
              tags: scenario.tags,
              expectedOutputText: scenario.expectedOutputText,
              expectedOutputMatchMode: scenario.expectedOutputMatchMode,
            },
            observedOutput: observedText,
            context,
          },
        });
        const scoreLabel = typeof result.score === "number" ? ` score ${result.score}` : "";
        const reason = result.reason ? ` · ${result.reason}` : "";
        return {
          ok: result.pass,
          message: `${formatStudioScenarioEvaluatorKind(kind)} ${result.pass ? "aprovou" : "reprovou"}:${scoreLabel} ${result.verdict}${reason}`.trim(),
          externalResult: result,
        };
      } catch (error) {
        return {
          ok: false,
          message: `${formatStudioScenarioEvaluatorKind(kind)} falhou: ${errorMessage(error)}`,
        };
      }
    }
    const rules = studioScenarioEvaluatorRulesForScenario(scenario);
    if (!rules.length) {
      return { ok: true, message: null };
    }
    const evaluations = rules.map((rule) => evaluateStudioScenarioEvaluatorRule(rule, observedText));
    if (rules.length === 1) {
      return evaluations[0];
    }
    const operator = studioScenarioEvaluatorOperatorForScenario(scenario);
    const passedCount = evaluations.filter((evaluation) => evaluation.ok).length;
    if (operator === "any") {
      if (passedCount > 0) {
        return {
          ok: true,
          message: `Evaluator composto atendido: ${passedCount}/${rules.length} regra(s) passaram.`,
        };
      }
      return {
        ok: false,
        message: `Evaluator composto falhou: nenhuma das ${rules.length} regra(s) passou. ${evaluations.map((evaluation) => evaluation.message).filter(Boolean).join(" ")}`,
      };
    }
    if (passedCount === rules.length) {
      return {
        ok: true,
        message: `Evaluator composto atendido: ${passedCount}/${rules.length} regra(s) passaram.`,
      };
    }
    const failedMessages = evaluations.filter((evaluation) => !evaluation.ok).map((evaluation) => evaluation.message).filter(Boolean);
    return {
      ok: false,
      message: `Evaluator composto falhou: ${passedCount}/${rules.length} regra(s) passaram. ${failedMessages.join(" ")}`,
    };
  }

  async function applyStudioScenarioExpectedOutputToComparison(
    scenario: StudioScenario,
    observedText: string,
    comparison: StudioScenarioBatchComparison,
  ): Promise<StudioScenarioBatchComparison> {
    const criterion = describeStudioScenarioExpectedOutputCriterion(scenario);
    if (!criterion) {
      return comparison;
    }
    const expectation = await evaluateStudioScenarioExpectedOutput(scenario, observedText, {
      comparison: {
        baselineRunId: comparison.baselineRunId,
        candidateRunId: comparison.candidateRunId,
        severity: comparison.severity,
        verdict: comparison.verdict,
        reasons: comparison.reasons,
      },
    });
    const isRulesEvaluator = studioScenarioEvaluatorKindForScenario(scenario) === "rules";
    if (!expectation.ok) {
      return {
        ...comparison,
        severity: "fail",
        verdict: isRulesEvaluator ? "Critério textual do cenário não foi atendido." : "Evaluator externo do cenário reprovou a saída.",
        reasons: [expectation.message ?? `Critério não atendido: ${criterion}.`, ...comparison.reasons],
      };
    }
    if (comparison.severity === "missing") {
      return {
        ...comparison,
        severity: "pass",
        verdict: isRulesEvaluator ? "Critério textual atendido sem baseline anterior." : "Evaluator externo aprovou sem baseline anterior.",
        reasons: [expectation.message ?? `Critério atendido: ${criterion}.`],
      };
    }
    return {
      ...comparison,
      reasons: [expectation.message ?? `Critério atendido: ${criterion}.`, ...comparison.reasons],
    };
  }

  async function compareScenarioBatchRun(
    scenario: StudioScenario,
    baselineRunId: string | null,
    candidateRunId: string | null,
    candidateMessage: string,
  ): Promise<{ summary: StudioScenarioBatchComparison; fullComparison: StudioRunComparison | null }> {
    if (!selectedFlowId || !candidateRunId) {
      return {
        summary: await applyStudioScenarioExpectedOutputToComparison(scenario, candidateMessage, {
          baselineRunId,
          candidateRunId,
          severity: "error",
          verdict: "Run candidate não foi persistido.",
          reasons: ["Persistência local do run não retornou ID."],
        }),
        fullComparison: null,
      };
    }
    if (!baselineRunId) {
      return {
        summary: await applyStudioScenarioExpectedOutputToComparison(scenario, candidateMessage, {
          baselineRunId: null,
          candidateRunId,
          severity: "missing",
          verdict: "Sem baseline anterior para este cenário.",
          reasons: [`Primeira execução registrada para ${scenario.id}.`],
        }),
        fullComparison: null,
      };
    }
    try {
      const comparison = await compareStudioRuns(selectedFlowId, baselineRunId, candidateRunId);
      return {
        summary: await applyStudioScenarioExpectedOutputToComparison(scenario, candidateMessage, {
          baselineRunId,
          candidateRunId,
          severity: comparison.regression.severity,
          verdict: comparison.regression.verdict,
          reasons: comparison.regression.reasons,
        }),
        fullComparison: comparison,
      };
    } catch (error) {
      return {
        summary: {
          baselineRunId,
          candidateRunId,
          severity: "error",
          verdict: "Falha ao comparar baseline e candidate.",
          reasons: [errorMessage(error)],
        },
        fullComparison: null,
      };
    }
  }

  function handleRunPinnedScenario() {
    const pinned = studioScenarios.find((scenario) => scenario.isPinned);
    if (!pinned) {
      setStatus({ kind: "error", message: "Não há cenário fixado para execução rápida." });
      return;
    }
    setStudioSelectedScenarioId(pinned.id);
    setStatus({ kind: "busy", message: `Executando cenário fixado "${pinned.label}".` });
    void runStudioScenario(pinned)
      .then(async (result) => {
        const expectation = await evaluateStudioScenarioExpectedOutput(pinned, result.message);
        persistStudioScenarioUsage([pinned.id], new Date().toISOString());
        setStatus({ kind: expectation.ok ? "ok" : "error", message: expectation.message ?? result.message });
      })
      .catch((error: unknown) => {
        setStatus({ kind: "error", message: errorMessage(error) });
      });
  }

