  async function handleCreateRuntimeSession() {
    if (!draftFlow || !sandbox?.url) {
      return;
    }
    setStatus({ kind: "busy", message: "Criando sessão no runtime." });
    try {
      const created = await createRuntimeSession(
        sandbox.url,
        draftFlow.api.resourceName,
        runtimeAgentMetadata(draftFlow),
        studioRuntimeApiKey,
      );
      const started = await startRuntimeSession(
        sandbox.url,
        draftFlow.api.resourceName,
        created.session.session_id,
        studioRuntimeApiKey,
      );
      setRuntimeSession(started.session);
      setTranscript(started.messages);
      setStudioTurnStream({ ...defaultStudioTurnStreamState });
      setRuntimeTurnIdempotencyKey(nextStudioTurnIdempotencyKey());
      const savedRun = await refreshRuntimeData(started.session);
      await refreshRuntimeJobsState(sandbox.url, started.session.session_id);
      startStudioEventStream(started.session, nextRuntimeEventSeq(savedRun?.events ?? []));
      await refreshSandboxState(selectedFlowId, true);
      setStatus({ kind: "ok", message: `Sessão ${started.session.session_id} iniciada.` });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

  async function handleSendRuntimeTurn() {
    if (!draftFlow || !sandbox?.url || !runtimeSession || !userMessage.trim()) {
      return;
    }
    const payloadResult = buildStudioTurnPayload(stateSchemaContent, userMessage.trim(), studioTurnPayloadDraft);
    if (payloadResult.errors.length > 0) {
      setStatus({ kind: "error", message: payloadResult.errors[0] });
      return;
    }
    const turnStreamTransportLabel = studioTurnStreamTransport === "websocket" ? "WebSocket" : "SSE";
    setStatus({ kind: "busy", message: `Enviando turno ao runtime com streaming ${turnStreamTransportLabel}.` });
    setStudioTurnStream({
      status: "streaming",
      text: "",
      tokens: 0,
      tokenSource: null,
      message: `Aguardando primeiros tokens do runtime por ${turnStreamTransportLabel}.`,
      completedAt: null,
    });
    const turnIdempotencyKey = runtimeTurnIdempotencyKey.trim() || nextStudioTurnIdempotencyKey();
    setRuntimeTurnIdempotencyKey(turnIdempotencyKey);
    try {
      let activeSession = runtimeSession;
      if (activeSession.status !== "active") {
        setStudioTurnStream((current) => ({
          ...current,
          message: `Sessão ${activeSession.session_id} ainda está ${activeSession.status}; iniciando antes do turno.`,
        }));
        const started = await startRuntimeSession(
          sandbox.url,
          draftFlow.api.resourceName,
          activeSession.session_id,
          studioRuntimeApiKey,
        );
        activeSession = started.session;
        setRuntimeSession(started.session);
        setTranscript(started.messages);
      }
      startStudioEventStream(activeSession, nextRuntimeEventSeq(runtimeEventsData));
      const sendTurnStream =
        studioTurnStreamTransport === "websocket" ? sendRuntimeTurnStreamWebSocket : sendRuntimeTurnStream;
      const result = await sendTurnStream(
        sandbox.url,
        draftFlow.api.resourceName,
        activeSession.session_id,
        payloadResult.payload,
        {
          onToken: (token: RuntimeTurnStreamToken) => {
            setStudioTurnStream((current) => ({
              ...current,
              status: "streaming",
              text: `${current.text}${token.text}`,
              tokens: current.tokens + 1,
              tokenSource: token.source ?? current.tokenSource,
              message: `Recebendo resposta incremental por ${turnStreamTransportLabel}: ${current.tokens + 1} token(s).`,
            }));
          },
          onCompleted: (completed) => {
            setStudioTurnStream((current) => ({
              ...current,
              status: "completed",
              text: completed.assistant_message.text || current.text,
              message: `Turno concluído pelo stream ${turnStreamTransportLabel}.`,
              completedAt: new Date().toISOString(),
            }));
          },
          onClosed: (payload) => {
            const reason = typeof payload.reason === "string" ? payload.reason : "stream_closed";
            setStudioTurnStream((current) => ({
              ...current,
              message: current.status === "completed" ? `Stream encerrado: ${reason}.` : current.message,
            }));
          },
        },
        turnIdempotencyKey,
        studioRuntimeApiKey,
      );
      setRuntimeSession(result.session);
      setUserMessage("");
      setStudioTurnPayloadDraft({});
      setRuntimeTurnIdempotencyKey(nextStudioTurnIdempotencyKey());
      await refreshRuntimeData(result.session);
      await refreshSandboxState(selectedFlowId, true);
      setStatus({ kind: "ok", message: result.assistant_message.text });
    } catch (error) {
      setStudioTurnStream((current) => ({
        ...current,
        status: "error",
        message: errorMessage(error),
      }));
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

  async function handleFinishRuntimeSession() {
    if (!draftFlow || !sandbox?.url || !runtimeSession) {
      return;
    }
    setStatus({ kind: "busy", message: "Finalizando sessão no runtime." });
    try {
      startStudioEventStream(runtimeSession, nextRuntimeEventSeq(runtimeEventsData));
      const result = await finishRuntimeSession(
        sandbox.url,
        draftFlow.api.resourceName,
        runtimeSession.session_id,
        studioRuntimeApiKey,
      );
      setRuntimeSession(result.session);
      await refreshRuntimeData(result.session);
      await refreshRuntimeJobsState(sandbox.url, result.session.session_id);
      await refreshSandboxState(selectedFlowId, true);
      setStatus({ kind: "ok", message: "Sessão finalizada." });
    } catch (error) {
      setStatus({ kind: "error", message: errorMessage(error) });
    }
  }

