function NodeDebugSummary({
  node,
  context,
  pinStatus,
  onOpenNodeDebug,
}: {
  node: FlowNode;
  context: StudioNodeDebugContext | null;
  pinStatus: StudioToolManagerItem["pinStatus"];
  onOpenNodeDebug: (nodeId: string, eventSeq?: number | null) => void;
}) {
  const latestEvent = context?.latestEvent ?? null;
  const eventCount = context?.events.length ?? 0;
  const diagnosis = context?.diagnosis ?? null;
  const recentEvents = context?.events.slice(-4) ?? [];
  const graphContext = context?.graphContext ?? { upstream: [], downstream: [], causalPath: [], impactPath: [] };
  const pinLabel = pinStatus === "current" ? "pin atual" : pinStatus === "stale" ? "pin stale" : "sem pin";
  const statusLabel = context?.status ?? "sem evento";
  const causalRole = context?.causalRole ?? "sem cadeia";
  const nextActions = diagnosis?.nextActions.slice(0, 2) ?? ["Execute ou carregue uma run para observar este nó."];

  return (
    <section className="node-debug-summary" aria-label="Debug guiado do nó">
      <div className="node-debug-header">
        <div>
          <strong>Debug guiado</strong>
          <span>{eventCount ? `${eventCount} evento(s) observados` : "sem execução observada"}</span>
        </div>
        <button type="button" className="command-button" onClick={() => onOpenNodeDebug(node.id, latestEvent?.seq ?? null)}>
          Abrir no Studio
        </button>
      </div>

      <div className="node-debug-grid">
        <article className="node-context-card">
          <strong>Status</strong>
          <span className={nodeContextStatusClass(statusLabel)}>{statusLabel}</span>
          <small>último #{latestEvent?.seq ?? "-"}</small>
        </article>
        <article className="node-context-card">
          <strong>Causalidade</strong>
          <span>{causalRole}</span>
          <small>{diagnosis?.severity ?? "warning"}</small>
        </article>
        <article className="node-context-card">
          <strong>Pin</strong>
          <span>{pinLabel}</span>
          <small>mock/replay local</small>
        </article>
        <article className="node-context-card">
          <strong>Snapshot</strong>
          <span>#{context?.latestSnapshot?.seq ?? "-"}</span>
          <small>{context?.diffs.length ?? 0} diff(s)</small>
        </article>
      </div>

      <div className={`node-debug-diagnosis ${diagnosis?.severity ?? "warning"}`}>
        <strong>{diagnosis?.title ?? "Sem diagnóstico"}</strong>
        <p>{diagnosis?.probableCause ?? "Nenhuma execução local carregada para este nó."}</p>
        <ul>
          {nextActions.map((action) => (
            <li key={action}>{action}</li>
          ))}
        </ul>
      </div>

      <div className="node-debug-path" aria-label="Caminho do nó">
        <div className="node-context-section-header">
          <strong>Caminho do nó</strong>
          <span>
            {graphContext.upstream.length} upstream · {graphContext.downstream.length} downstream
          </span>
        </div>
        <div className="node-debug-path-grid">
          <NodeDebugNeighborList
            title="Upstream"
            emptyLabel="Sem nó anterior"
            neighbors={graphContext.upstream}
            onOpenNodeDebug={onOpenNodeDebug}
          />
          <NodeDebugNeighborList
            title="Downstream"
            emptyLabel="Sem próximo nó"
            neighbors={graphContext.downstream}
            onOpenNodeDebug={onOpenNodeDebug}
          />
          <article className="node-debug-path-card">
            <strong>Cadeia</strong>
            <span>
              {graphContext.causalPath.length ? `Falha: ${graphContext.causalPath.join(" -> ")}` : "Sem falha upstream carregada"}
            </span>
            <small>
              {graphContext.impactPath.length ? `Impacto: ${graphContext.impactPath.join(" -> ")}` : "Sem impacto downstream observado"}
            </small>
          </article>
        </div>
      </div>

      {recentEvents.length ? (
        <div className="node-debug-events" aria-label="Eventos recentes do nó">
          {recentEvents.map((event) => (
            <button type="button" key={event.seq} onClick={() => onOpenNodeDebug(node.id, event.seq)}>
              <span>#{event.seq}</span>
              <strong>{event.event_type}</strong>
              <small>{String(event.payload.status ?? event.payload.phase ?? "-")}</small>
            </button>
          ))}
        </div>
      ) : null}
    </section>
  );
}

function NodeDebugNeighborList({
  title,
  emptyLabel,
  neighbors,
  onOpenNodeDebug,
}: {
  title: string;
  emptyLabel: string;
  neighbors: StudioNodeGraphNeighbor[];
  onOpenNodeDebug: (nodeId: string, eventSeq?: number | null) => void;
}) {
  return (
    <article className="node-debug-path-card">
      <strong>{title}</strong>
      {neighbors.length ? (
        <div className="node-debug-neighbor-list">
          {neighbors.map((neighbor) => (
            <button
              type="button"
              key={`${neighbor.relation}-${neighbor.nodeId}-${neighbor.condition}`}
              onClick={() => onOpenNodeDebug(neighbor.nodeId, neighbor.lastSeq)}
            >
              <span>{neighbor.nodeId}</span>
              <small>
                {neighbor.type} · {neighbor.status}
                {neighbor.lastSeq !== null ? ` #${neighbor.lastSeq}` : ""}
              </small>
              {neighbor.condition ? <em>{neighbor.condition}</em> : null}
            </button>
          ))}
        </div>
      ) : (
        <span>{emptyLabel}</span>
      )}
    </article>
  );
}

function StudioDebugReplayArtifactsPanel({
  artifacts,
  importMessage,
  scenarios,
  onImport,
  onRemove,
  onClear,
  onLoadRun,
  onTimelineNodeFilterChange,
  onScenarioSelect,
  onPromoteArtifact,
}: {
  artifacts: StudioDebugReplayArtifactPackage[];
  importMessage: string;
  scenarios: StudioScenario[];
  onImport: () => void;
  onRemove: (packageHash: string) => void;
  onClear: () => void;
  onLoadRun: (runId: string) => void;
  onTimelineNodeFilterChange: (value: string) => void;
  onScenarioSelect: (scenarioId: string) => void;
  onPromoteArtifact: (artifact: StudioDebugReplayArtifactPackage) => void;
}) {
  return (
    <div className="debug-replay-panel" role="region" aria-label="Artefatos de replay governado">
      <div className="sandbox-header">
        <strong>Artefatos de replay</strong>
        <span>{artifacts.length}</span>
      </div>
      <div className="sandbox-actions">
        <button type="button" className="command-button" onClick={onImport}>
          <Upload size={16} aria-hidden="true" />
          Importar replay
        </button>
        <button type="button" className="command-button danger" onClick={onClear} disabled={artifacts.length === 0}>
          <Trash2 size={16} aria-hidden="true" />
          Limpar
        </button>
      </div>
      {importMessage ? <small className="debug-replay-message">{importMessage}</small> : null}
      {artifacts.length ? (
        <div className="debug-replay-list">
          {artifacts.map((artifact) => {
            const promotedScenario = studioDebugReplayScenarioForArtifact(artifact, scenarios);
            const guideItems = studioDebugReplayGuideItems(artifact, promotedScenario);
            return (
              <article className="debug-replay-card" key={artifact.packageHash}>
                <div className="debug-replay-card-header">
                  <div>
                    <strong>{artifact.selectedNode.nodeId}</strong>
                    <span>{studioDebugReplayRecommendedActionLabel(artifact.replay.recommendedAction)}</span>
                  </div>
                  <code>{artifact.packageHash}</code>
                </div>
                <div className="debug-replay-grid">
                  <span>
                    <strong>Base</strong>
                    {artifact.runComparison.leftRunId}
                  </span>
                  <span>
                    <strong>Candidato</strong>
                    {artifact.runComparison.rightRunId}
                  </span>
                  <span>
                    <strong>Diffs</strong>
                    state {artifact.selectedNode.stateDiffCount} · output {artifact.selectedNode.outputDiffCount}
                  </span>
                  <span>
                    <strong>Pins</strong>
                    {artifact.replay.activePins.length} ativo(s) · {artifact.replay.stalePins.length} stale
                  </span>
                  <span>
                    <strong>Checkpoints</strong>
                    {artifact.replay.candidateCheckpointScenarioCount}/{artifact.replay.checkpointScenarioCount}
                  </span>
                  <span>
                    <strong>Cenário</strong>
                    {promotedScenario ? promotedScenario.label : "não criado"}
                  </span>
                  <span>
                    <strong>Governança</strong>
                    sem payload bruto
                  </span>
                </div>
                <div className="debug-replay-guide" aria-label={`Roteiro de replay ${artifact.selectedNode.nodeId}`}>
                  {guideItems.map((item) => (
                    <span className={item.status} key={item.label}>
                      <strong>{item.label}</strong>
                      <small>{item.detail}</small>
                    </span>
                  ))}
                </div>
                <small>
                  Regressão: {artifact.runComparison.regressionSeverity} · {artifact.runComparison.regressionVerdict}
                </small>
                <small>
                  Causalidade: falha {artifact.causal.failedNode ?? "-"} #{artifact.causal.failedEventSeq ?? "-"} · upstream{" "}
                  {artifact.causal.upstreamPath.join(" -> ") || "-"} · impacto {artifact.causal.impactPath.join(" -> ") || "-"}
                </small>
                {artifact.replay.selectedCheckpoint ? (
                  <small>
                    Checkpoint selecionado: {artifact.replay.selectedCheckpoint.label} #{artifact.replay.selectedCheckpoint.eventSeq} ·{" "}
                    {artifact.replay.selectedCheckpoint.restoreStrategy}
                  </small>
                ) : null}
                <div className="debug-replay-actions">
                  <button type="button" className="command-button" onClick={() => onLoadRun(artifact.runComparison.leftRunId)}>
                    Carregar base
                  </button>
                  <button type="button" className="command-button" onClick={() => onLoadRun(artifact.runComparison.rightRunId)}>
                    Carregar candidato
                  </button>
                  <button
                    type="button"
                    className="command-button"
                    onClick={() => onTimelineNodeFilterChange(artifact.selectedNode.nodeId)}
                  >
                    Focar nó
                  </button>
                  {promotedScenario ? (
                    <button type="button" className="command-button" onClick={() => onScenarioSelect(promotedScenario.id)}>
                      Selecionar cenário
                    </button>
                  ) : (
                    <button type="button" className="command-button" onClick={() => onPromoteArtifact(artifact)}>
                      Criar cenário
                    </button>
                  )}
                  <button type="button" className="command-button danger" onClick={() => onRemove(artifact.packageHash)}>
                    Remover
                  </button>
                </div>
              </article>
            );
          })}
        </div>
      ) : (
        <article className="runtime-item">
          <strong>Nenhum replay importado</strong>
          <span>Importe um `.afdebugreplay.json` para revisar comparação, pins, checkpoints e próxima ação sem payload bruto.</span>
        </article>
      )}
    </div>
  );
}

function studioDebugReplayScenarioForArtifact(
  artifact: StudioDebugReplayArtifactPackage,
  scenarios: StudioScenario[],
): StudioScenario | null {
  return (
    scenarios.find((scenario) => {
      const debugReplay = isRecord(scenario.payload?.debug_replay) ? scenario.payload.debug_replay : null;
      return (
        isRecord(debugReplay) &&
        debugReplay.packageHash === artifact.packageHash &&
        debugReplay.nodeId === artifact.selectedNode.nodeId
      );
    }) ?? null
  );
}

function studioDebugReplayGuideItems(
  artifact: StudioDebugReplayArtifactPackage,
  promotedScenario: StudioScenario | null,
): Array<{ label: string; status: "ok" | "warning" | "pending"; detail: string }> {
  const checkpoint = artifact.replay.candidateCheckpoint;
  return [
    {
      label: "Pacote",
      status: "ok",
      detail: "importado e validado",
    },
    {
      label: "Checkpoint",
      status: checkpoint ? "ok" : "warning",
      detail: checkpoint
        ? `${checkpoint.sourceRunId} #${checkpoint.eventSeq} · ${checkpoint.nodeId ?? "runtime"}`
        : "sem checkpoint candidato",
    },
    {
      label: "Pins",
      status: artifact.replay.stalePins.length > 0 ? "warning" : "ok",
      detail: `${artifact.replay.activePins.length} ativo(s) · ${artifact.replay.stalePins.length} stale`,
    },
    {
      label: "Cenário",
      status: promotedScenario ? "ok" : "pending",
      detail: promotedScenario ? promotedScenario.label : "crie cenário de revisão",
    },
  ];
}

function studioDebugReplayRecommendedActionLabel(action: StudioDebugReplayArtifactPackage["replay"]["recommendedAction"]): string {
  if (action === "create_debug_scenario") {
    return "criar cenário de debug";
  }
  if (action === "run_existing_checkpoint") {
    return "executar checkpoint existente";
  }
  if (action === "refresh_stale_pins") {
    return "atualizar pins stale";
  }
  return "inspecionar evidência";
}

function formatStudioReplayGovernanceReviewStatus(status: StudioScenarioReplayGovernanceReview["status"]): string {
  if (status === "approved") {
    return "aprovada";
  }
  if (status === "needs_review") {
    return "precisa revisão";
  }
  return "monitoramento";
}

function StudioScenarioReplayGuide({
  scenario,
  compatibility,
  checkpointRestorePayload,
  activeNodePinCount,
  staleNodePinCount,
  replayGovernanceHistory,
  replayGovernanceHistoryConflicts,
  replayGovernanceHistoryResolutionHistory,
  replayGovernanceHistoryCentralStatus,
  reviewerName,
  reviewerRole,
  onFocusOrigin,
  onFilterOrigin,
  onRunScenario,
  onUsePins,
  onExportFixture,
  onExportGovernance,
  onSaveGovernanceHistory,
  onExportGovernanceHistory,
  onExportGovernanceHistoryConflictReview,
  onCompareGovernanceHistoryConflictReview,
  onLoadGovernanceHistoryCentralStatus,
  onSyncGovernanceHistoryCentral,
  onResolveGovernanceHistoryConflict,
  onUpdateGovernanceHistoryConflictCuration,
  onExportGovernanceHistoryComparison,
}: {
  scenario: StudioScenario;
  compatibility: StudioScenarioCheckpointCompatibilityStatus;
  checkpointRestorePayload: Record<string, unknown> | null;
  activeNodePinCount: number;
  staleNodePinCount: number;
  replayGovernanceHistory: StudioScenarioReplayGovernanceHistorySnapshot[];
  replayGovernanceHistoryConflicts: StudioReplayGovernanceHistoryConflict[];
  replayGovernanceHistoryResolutionHistory: StudioReplayGovernanceHistoryResolutionRecord[];
  replayGovernanceHistoryCentralStatus: StudioReplayGovernanceHistoryCentralSyncStatus | null;
  reviewerName: string;
  reviewerRole: StudioReplayGovernanceHistoryConflictCuratorRole;
  onFocusOrigin: () => void;
  onFilterOrigin: () => void;
  onRunScenario: () => void;
  onUsePins: () => void;
  onExportFixture: () => void;
  onExportGovernance: () => void;
  onSaveGovernanceHistory: () => void;
  onExportGovernanceHistory: () => void;
  onExportGovernanceHistoryConflictReview: () => void;
  onCompareGovernanceHistoryConflictReview: () => void;
  onLoadGovernanceHistoryCentralStatus: () => void;
  onSyncGovernanceHistoryCentral: () => void;
  onResolveGovernanceHistoryConflict: (conflictId: string, keepSnapshotHash: string) => void | Promise<void>;
  onUpdateGovernanceHistoryConflictCuration: (
    conflictId: string,
    action: StudioReplayGovernanceHistoryConflictCurationAction,
  ) => void | Promise<void>;
  onExportGovernanceHistoryComparison: () => void;
}) {
  const hasCheckpoint = Boolean(scenario.checkpoint);
  const restoreObserved = Boolean(checkpointRestorePayload);
  const canFocusOrigin = Boolean(scenario.sourceContext.nodeId || scenario.sourceContext.eventSeq !== null);
  const nextAction = studioScenarioReplayNextAction({
    scenario,
    compatibility,
    hasCheckpoint,
    restoreObserved,
    activeNodePinCount,
  });
  const executionSteps = studioScenarioReplayExecutionSteps({
    scenario,
    compatibility,
    hasCheckpoint,
    restoreObserved,
    activeNodePinCount,
    checkpointRestorePayload,
  });
  const governedComparison = studioScenarioReplayGovernanceComparison({
    scenario,
    compatibility,
    hasCheckpoint,
    restoreObserved,
    activeNodePinCount,
    staleNodePinCount,
    checkpointRestorePayload,
  });
  const historyComparison = buildStudioReplayGovernanceHistoryComparison(replayGovernanceHistory);
  const currentReview = buildStudioScenarioReplayGovernanceReview(
    governedComparison,
    {
      compatibilityLabel: compatibility.label,
      hasCheckpoint,
      restoreObserved,
      activePinCount: activeNodePinCount,
      stalePinCount: staleNodePinCount,
    },
    reviewerName,
  );
  const guideItems = [
    {
      label: "Origem",
      status: "ok" as const,
      detail: formatStudioScenarioSourceContext(scenario.sourceContext),
    },
    {
      label: "Compatibilidade",
      status: compatibility.level === "error" || compatibility.level === "warning" ? "warning" as const : "ok" as const,
      detail: compatibility.label,
    },
    {
      label: "Restore",
      status: hasCheckpoint ? (restoreObserved ? "ok" as const : "pending" as const) : "ok" as const,
      detail: hasCheckpoint
        ? restoreObserved
          ? `${restoreEventSourceLabel(checkpointRestorePayload?.source)} · turno ${formatRestoreTurn(checkpointRestorePayload?.turn)}`
          : restoreStrategyLabel(scenario.checkpoint)
        : "sem checkpoint",
    },
    {
      label: "Pins",
      status: scenario.useNodePins ? (activeNodePinCount > 0 ? "ok" as const : "warning" as const) : activeNodePinCount > 0 ? "pending" as const : "ok" as const,
      detail: scenario.useNodePins
        ? `${activeNodePinCount} pin(s) enviados como mock`
        : activeNodePinCount > 0
          ? `${activeNodePinCount} pin(s) disponíveis`
          : "sem pins ativos",
    },
    {
      label: "Execução",
      status: scenario.lastUsedAt ? "ok" as const : "pending" as const,
      detail: scenario.lastUsedAt ? `último uso ${formatDateTime(scenario.lastUsedAt)}` : "ainda não executado",
    },
  ];
  return (
    <div className="scenario-replay-guide" aria-label="Roteiro guiado do cenário">
      <div className="scenario-replay-guide-header">
        <strong>Roteiro guiado do replay</strong>
        <span>{hasCheckpoint ? "checkpoint + restore" : "execução direta"}</span>
      </div>
      <div className="debug-replay-guide">
        {guideItems.map((item) => (
          <span className={item.status} key={`scenario-guide-${item.label}`}>
            <strong>{item.label}</strong>
            <small>{item.detail}</small>
          </span>
        ))}
      </div>
      <div className={`scenario-replay-next-action ${nextAction.status}`} aria-label="Próxima ação do replay">
        <strong>Próxima ação</strong>
        <span>{nextAction.label}</span>
        <small>{nextAction.detail}</small>
      </div>
      <div className="scenario-replay-execution" aria-label="Execução guiada do replay">
        {executionSteps.map((step) => (
          <span className={step.status} key={`scenario-execution-step-${step.label}`}>
            <strong>{step.label}</strong>
            <small>{step.detail}</small>
            <em>{step.action}</em>
          </span>
        ))}
      </div>
      <div className={`scenario-replay-governance ${governedComparison.status}`} aria-label="Comparação governada do replay">
        <div className="scenario-replay-governance-header">
          <div>
            <strong>Comparação governada</strong>
            <span>
              {governedComparison.statusLabel} · {governedComparison.summary} · histórico{" "}
              {replayGovernanceHistory.length}
            </span>
            {replayGovernanceHistoryCentralStatus ? (
              <small>{formatStudioReplayGovernanceHistoryCentralUiDetails(replayGovernanceHistoryCentralStatus)}</small>
            ) : null}
          </div>
          <div className="scenario-replay-governance-actions">
            <button type="button" className="command-button" onClick={onSaveGovernanceHistory}>
              Salvar snapshot
            </button>
            <button type="button" className="command-button" onClick={onExportGovernance}>
              Exportar governança
            </button>
            <button
              type="button"
              className="command-button"
              onClick={onExportGovernanceHistory}
              disabled={replayGovernanceHistory.length === 0}
            >
              Exportar histórico
            </button>
            <button
              type="button"
              className="command-button"
              onClick={onExportGovernanceHistoryConflictReview}
              disabled={replayGovernanceHistoryConflicts.length === 0 && replayGovernanceHistoryResolutionHistory.length === 0}
            >
              Exportar revisão
            </button>
            <button
              type="button"
              className="command-button"
              onClick={onCompareGovernanceHistoryConflictReview}
            >
              Comparar revisão
            </button>
            <button type="button" className="command-button" onClick={onLoadGovernanceHistoryCentralStatus}>
              Central
            </button>
            <button
              type="button"
              className="command-button"
              onClick={onSyncGovernanceHistoryCentral}
              disabled={
                replayGovernanceHistoryCentralStatus !== null && !replayGovernanceHistoryCentralStatus.configured
              }
            >
              Sync central
            </button>
          </div>
        </div>
        <div className="scenario-replay-governance-grid">
          {governedComparison.items.map((item) => (
            <span className={item.status} key={`scenario-governance-${item.id}`}>
              <strong>{item.label}</strong>
              <small>Esperado: {item.expected}</small>
              <small>Observado: {item.observed}</small>
              <em>{item.action}</em>
            </span>
          ))}
        </div>
        <div className={`scenario-replay-review ${currentReview.status}`} aria-label="Curadoria governada do replay">
          <strong>Curadoria {currentReview.statusLabel}</strong>
          <span>revisor {currentReview.reviewer} · {currentReview.summary}</span>
          <small>{currentReview.reasons.join(" · ")}</small>
          <em>{currentReview.nextAction}</em>
        </div>
        {replayGovernanceHistoryConflicts.length ? (
          <div className="scenario-replay-history-conflicts" aria-label="Conflitos do histórico de replay">
            <strong>Conflitos de replay</strong>
            <small>
              {replayGovernanceHistoryConflicts.length} evidência(s) com curadorias divergentes. Escolha o snapshot que deve
              representar a revisão compartilhada.
            </small>
            {replayGovernanceHistoryConflicts.slice(0, 3).map((conflict) => (
              <div className="scenario-replay-history-conflict" key={conflict.conflictId}>
                <div className={`schema-pattern-curation-thread ${conflict.curationThread.status}`}>
                  <span>{replayGovernanceHistoryConflictCurationStatusLabel(conflict.curationThread)}</span>
                  <small>{replayGovernanceHistoryConflictCurationDetail(conflict.curationThread)}</small>
                  {conflict.curationThread.events.slice(0, 3).map((event) => (
                    <small key={event.id}>
                      {formatDateTime(event.at)} · {event.actor} ·{" "}
                      {formatStudioAnnotationReviewerRole(event.role)} ·{" "}
                      {replayGovernanceHistoryConflictCurationEventLabel(event.action)}
                    </small>
                  ))}
                </div>
                <div className="inline-actions">
                  <button
                    type="button"
                    className="command-button"
                    disabled={
                      reviewerRole === "viewer" ||
                      conflict.curationThread.assignee === normalizeStudioAnnotationReviewerName(reviewerName)
                    }
                    onClick={() => void onUpdateGovernanceHistoryConflictCuration(conflict.conflictId, "assign")}
                  >
                    Assumir
                  </button>
                  <button
                    type="button"
                    className="command-button ghost"
                    disabled={reviewerRole === "viewer" || !conflict.curationThread.assignee}
                    onClick={() => void onUpdateGovernanceHistoryConflictCuration(conflict.conflictId, "release")}
                  >
                    Liberar
                  </button>
                </div>
                <small>
                  {conflict.scenarioLabel} · {conflict.snapshotCount} snapshot(s) · mais recente{" "}
                  {formatDateTime(conflict.latestCapturedAt)}
                </small>
                {conflict.refs.slice(0, 4).map((ref) => (
                  <div className="scenario-replay-history-conflict-ref" key={`${conflict.conflictId}-${ref.snapshotHash}`}>
                    <small>
                      {ref.snapshotHash === conflict.latestSnapshotHash ? "mais recente" : "alternativa"} ·{" "}
                      {formatStudioReplayGovernanceReviewStatus(ref.reviewStatus)} · {ref.reviewer} ·{" "}
                      {formatDateTime(ref.capturedAt)}
                    </small>
                    <button
                      type="button"
                      className="command-button"
                      disabled={reviewerRole === "viewer"}
                      onClick={() => void onResolveGovernanceHistoryConflict(conflict.conflictId, ref.snapshotHash)}
                    >
                      {ref.snapshotHash === conflict.latestSnapshotHash ? "Manter mais recente" : "Manter snapshot"}
                    </button>
                  </div>
                ))}
              </div>
            ))}
          </div>
        ) : null}
        {replayGovernanceHistoryResolutionHistory.length ? (
          <div className="scenario-replay-history-conflicts" aria-label="Histórico de resolução do replay">
            <strong>Histórico de resolução</strong>
            <small>
              {replayGovernanceHistoryResolutionHistory.length} decisão(ões) governadas. Snapshots descartados idênticos não reabrem o conflito quando voltam por sync.
            </small>
            {replayGovernanceHistoryResolutionHistory.slice(0, 4).map((record) => (
              <div className="scenario-replay-history-conflict" key={record.resolutionId}>
                <small>
                  {formatDateTime(record.resolvedAt)} · {record.resolvedBy} ·{" "}
                  {formatStudioAnnotationReviewerRole(record.resolvedRole)} · {record.scenarioLabel}
                </small>
                <span>
                  mantido {record.keptSnapshotHash} · descartado(s) {record.discardedRefs.length} de{" "}
                  {record.candidateCount}
                </span>
                {record.resolutionNote ? <em>{record.resolutionNote}</em> : null}
              </div>
            ))}
          </div>
        ) : null}
        <div className={`scenario-replay-history-diff ${historyComparison.status}`} aria-label="Comparação histórica do replay">
          <div className="scenario-replay-history-diff-header">
            <div>
              <strong>Comparação histórica</strong>
              <span>{historyComparison.statusLabel} · {historyComparison.summary}</span>
              {historyComparison.latestSnapshot ? (
                <small>
                  última curadoria {historyComparison.latestSnapshot.reviewStatus} por {historyComparison.latestSnapshot.reviewer}
                </small>
              ) : null}
            </div>
            <button
              type="button"
              className="command-button"
              onClick={onExportGovernanceHistoryComparison}
              disabled={!historyComparison.previousSnapshot || !historyComparison.latestSnapshot}
            >
              Exportar diff histórico
            </button>
          </div>
          {historyComparison.itemChanges.length > 0 ? (
            <div className="scenario-replay-history-diff-grid">
              {historyComparison.itemChanges.map((item) => (
                <span className={item.status} key={`scenario-history-diff-${item.id}`}>
                  <strong>{item.label}</strong>
                  <small>{item.evidence}</small>
                  <em>{item.action}</em>
                </span>
              ))}
            </div>
          ) : (
            <small>Salve dois snapshots do mesmo cenário para comparar evolução de checkpoint, pins, restore e evaluator.</small>
          )}
        </div>
        <small>Sem payload bruto de cenário, pins ou checkpoint; use o pacote para revisão de evidência.</small>
      </div>
      <div className="scenario-replay-guide-actions">
        <button type="button" className="command-button" onClick={onFocusOrigin} disabled={!canFocusOrigin}>
          Focar origem
        </button>
        <button type="button" className="command-button" onClick={onFilterOrigin}>
          Filtrar origem
        </button>
        <button type="button" className="command-button" onClick={onRunScenario}>
          Executar replay
        </button>
        <button type="button" className="command-button" onClick={onUsePins} disabled={activeNodePinCount === 0 || scenario.useNodePins}>
          Ativar pins
        </button>
        <button type="button" className="command-button" onClick={onExportFixture}>
          Exportar fixture guiada
        </button>
      </div>
    </div>
  );
}

type StudioScenarioReplayGuideStatus = "ok" | "warning" | "pending";

interface StudioScenarioReplayExecutionStep {
  label: string;
  status: StudioScenarioReplayGuideStatus;
  detail: string;
  action: string;
}

function studioScenarioReplayNextAction({
  scenario,
  compatibility,
  hasCheckpoint,
  restoreObserved,
  activeNodePinCount,
}: {
  scenario: StudioScenario;
  compatibility: StudioScenarioCheckpointCompatibilityStatus;
  hasCheckpoint: boolean;
  restoreObserved: boolean;
  activeNodePinCount: number;
}): StudioScenarioReplayExecutionStep {
  if (compatibility.level === "error") {
    return {
      label: "Resolver compatibilidade",
      status: "warning",
      detail: compatibility.reasons[0] ?? compatibility.label,
      action: "atualize o checkpoint ou gere outro cenário",
    };
  }
  if (!scenario.input.trim()) {
    return {
      label: "Preencher entrada",
      status: "warning",
      detail: "o replay precisa de input para executar o turno",
      action: "defina input ou importe fixture válida",
    };
  }
  if (scenario.useNodePins && activeNodePinCount === 0) {
    return {
      label: "Atualizar pins",
      status: "warning",
      detail: "o cenário pede mocks, mas não há pin atual",
      action: "fixe IO de nós ou desative pins",
    };
  }
  if (!scenario.useNodePins && activeNodePinCount > 0) {
    return {
      label: "Decidir pins",
      status: "pending",
      detail: `${activeNodePinCount} pin(s) disponíveis para mock determinístico`,
      action: "ative pins se quiser replay controlado",
    };
  }
  if (!scenario.lastUsedAt) {
    return {
      label: "Executar replay",
      status: "pending",
      detail: hasCheckpoint ? "rode o cenário e confirme restore/eventos" : "rode o cenário e observe saída/eventos",
      action: "use Executar replay",
    };
  }
  if (hasCheckpoint && !restoreObserved) {
    return {
      label: "Confirmar restore",
      status: "warning",
      detail: "o run carregado ainda não mostra checkpoint_restored",
      action: "carregue o run novo ou execute novamente",
    };
  }
  return {
    label: "Comparar resultado",
    status: "ok",
    detail: `último uso ${formatDateTime(scenario.lastUsedAt)}`,
    action: "revise saída, comparação e evaluators",
  };
}

function studioScenarioReplayExecutionSteps({
  scenario,
  compatibility,
  hasCheckpoint,
  restoreObserved,
  activeNodePinCount,
  checkpointRestorePayload,
}: {
  scenario: StudioScenario;
  compatibility: StudioScenarioCheckpointCompatibilityStatus;
  hasCheckpoint: boolean;
  restoreObserved: boolean;
  activeNodePinCount: number;
  checkpointRestorePayload: Record<string, unknown> | null;
}): StudioScenarioReplayExecutionStep[] {
  const sourceRun =
    scenario.sourceContext.candidateRunId ??
    scenario.sourceContext.primaryRunId ??
    scenario.sourceContext.baselineRunId ??
    scenario.checkpoint?.sourceRunId ??
    "-";
  const evaluatorSummary = describeStudioScenarioExpectedOutputCriterion(scenario) ?? "sem critério automatizado";
  const checkpointLabel = scenario.checkpoint
    ? `${scenario.checkpoint.sourceRunId} #${scenario.checkpoint.eventSeq} · ${scenario.checkpoint.nodeId ?? "runtime"}`
    : "sem checkpoint";
  return [
    {
      label: "Preparar fixture",
      status: scenario.input.trim() ? "ok" : "warning",
      detail: `${scenario.payload ? "payload estruturado" : "input textual"} · origem ${sourceRun}`,
      action: scenario.input.trim() ? "fixture pronta" : "defina a entrada antes da execução",
    },
    {
      label: "Restaurar checkpoint",
      status: !hasCheckpoint ? "ok" : restoreObserved ? "ok" : "pending",
      detail: hasCheckpoint
        ? restoreObserved
          ? `${restoreEventSourceLabel(checkpointRestorePayload?.source)} · turno ${formatRestoreTurn(checkpointRestorePayload?.turn)}`
          : checkpointLabel
        : "execução direta",
      action: hasCheckpoint
        ? restoreObserved
          ? "restore observado"
          : `confirmar ${restoreStrategyLabel(scenario.checkpoint)}`
        : "sem restauração necessária",
    },
    {
      label: "Aplicar pins",
      status: scenario.useNodePins ? (activeNodePinCount > 0 ? "ok" : "warning") : activeNodePinCount > 0 ? "pending" : "ok",
      detail: scenario.useNodePins
        ? `${activeNodePinCount} pin(s) enviados como mock`
        : activeNodePinCount > 0
          ? `${activeNodePinCount} pin(s) disponíveis, desativados`
          : "sem mock de nó",
      action: scenario.useNodePins
        ? activeNodePinCount > 0
          ? "mocks entram no metadata"
          : "fixe IO ou desative pins"
        : activeNodePinCount > 0
          ? "ative para replay determinístico"
          : "usar comportamento real",
    },
    {
      label: "Executar e observar",
      status: scenario.lastUsedAt ? "ok" : compatibility.level === "error" ? "warning" : "pending",
      detail: scenario.lastUsedAt ? `último uso ${formatDateTime(scenario.lastUsedAt)}` : compatibility.label,
      action: scenario.lastUsedAt ? "carregue o run gerado para comparar" : "acionar execução do cenário",
    },
    {
      label: "Avaliar resultado",
      status: scenario.lastUsedAt ? "ok" : "pending",
      detail: evaluatorSummary,
      action: scenario.lastUsedAt ? "comparar regressão e revisar pendências" : "avaliar após execução",
    },
  ];
}

function studioScenarioReplayGovernanceComparison({
  scenario,
  compatibility,
  hasCheckpoint,
  restoreObserved,
  activeNodePinCount,
  staleNodePinCount,
  checkpointRestorePayload,
}: {
  scenario: StudioScenario;
  compatibility: StudioScenarioCheckpointCompatibilityStatus;
  hasCheckpoint: boolean;
  restoreObserved: boolean;
  activeNodePinCount: number;
  staleNodePinCount: number;
  checkpointRestorePayload: Record<string, unknown> | null;
}): StudioScenarioReplayGovernanceComparison {
  const evaluatorSummary = describeStudioScenarioExpectedOutputCriterion(scenario) ?? "sem critério automatizado";
  const restoreObservedLabel = restoreObserved
    ? `${restoreEventSourceLabel(checkpointRestorePayload?.source)} · estado ${restorePayloadStateKeys(checkpointRestorePayload)}`
    : "não observado no run carregado";
  const items: StudioScenarioReplayGovernanceItem[] = [
    {
      id: "checkpoint",
      label: "Checkpoint vs flow",
      status: compatibility.level === "error" || compatibility.level === "warning" ? "warning" : "ok",
      expected: hasCheckpoint ? "hash/versão compatíveis" : "sem restauração",
      observed: hasCheckpoint ? compatibility.label : "execução direta",
      evidence: compatibility.reasons.join("; ") || compatibility.label,
      action: compatibility.reasons[0] ?? (hasCheckpoint ? "checkpoint pode ser usado" : "sem ação"),
    },
    {
      id: "pins",
      label: "Pins vs grafo atual",
      status: staleNodePinCount > 0 || (scenario.useNodePins && activeNodePinCount === 0)
        ? "warning"
        : scenario.useNodePins || activeNodePinCount === 0
          ? "ok"
          : "pending",
      expected: scenario.useNodePins ? "pins atuais para mock" : "execução real sem mock",
      observed: `${activeNodePinCount} ativo(s) · ${staleNodePinCount} stale`,
      evidence: scenario.useNodePins ? "useNodePins=true" : "useNodePins=false",
      action: staleNodePinCount > 0
        ? "atualize pins stale"
        : scenario.useNodePins
          ? "mocks governados entram no metadata"
          : activeNodePinCount > 0
            ? "decida se quer replay determinístico"
            : "sem pin para comparar",
    },
    {
      id: "restore",
      label: "Restore vs run carregado",
      status: !hasCheckpoint ? "ok" : restoreObserved ? "ok" : "pending",
      expected: hasCheckpoint ? restoreStrategyLabel(scenario.checkpoint) : "não aplicável",
      observed: hasCheckpoint ? restoreObservedLabel : "sem checkpoint",
      evidence: hasCheckpoint ? `checkpoint #${scenario.checkpoint?.eventSeq ?? "-"}` : "execução direta",
      action: hasCheckpoint
        ? restoreObserved
          ? "restore confirmado por evento"
          : "execute/carregue o run do replay"
        : "seguir para avaliação",
    },
    {
      id: "evaluation",
      label: "Critério e thresholds",
      status: scenario.lastUsedAt ? "ok" : "pending",
      expected: evaluatorSummary,
      observed: scenario.lastUsedAt ? `último uso ${formatDateTime(scenario.lastUsedAt)}` : "sem execução observada",
      evidence: `${countConfiguredStudioNodeTypeThresholds(scenario.regressionThresholds.nodeTypeThresholds)} threshold(s) por tipo`,
      action: scenario.lastUsedAt ? "comparar regressão e revisar pendências" : "executar antes da decisão",
    },
  ];
  const status = mergeStudioScenarioReplayGovernanceStatus(items.map((item) => item.status));
  return {
    status,
    statusLabel: studioScenarioReplayGovernanceStatusLabel(status),
    summary: `${items.filter((item) => item.status === "ok").length}/${items.length} camada(s) prontas`,
    items,
  };
}

function mergeStudioScenarioReplayGovernanceStatus(statuses: StudioScenarioReplayGuideStatus[]): StudioScenarioReplayGuideStatus {
  if (statuses.includes("warning")) {
    return "warning";
  }
  if (statuses.includes("pending")) {
    return "pending";
  }
  return "ok";
}

function studioScenarioReplayGovernanceStatusLabel(status: StudioScenarioReplayGuideStatus): string {
  if (status === "warning") {
    return "atenção";
  }
  if (status === "pending") {
    return "pendente";
  }
  return "pronto";
}

