function replayGovernanceHistoryConflictCurationStatusLabel(
  thread: StudioReplayGovernanceHistoryConflictCurationThread,
): string {
  if (thread.status === "assigned") {
    const lease = thread.leaseExpiresAt ? ` até ${formatDateTime(thread.leaseExpiresAt)}` : "";
    return `Em curadoria${lease}`;
  }
  return thread.leaseExpired ? "Lease expirado" : "Sem responsável";
}

function replayGovernanceHistoryConflictCurationDetail(
  thread: StudioReplayGovernanceHistoryConflictCurationThread,
): string {
  if (thread.leaseExpired) {
    const expiredAt = thread.updatedAt ? formatDateTime(thread.updatedAt) : "data não registrada";
    return `Liberado automaticamente após lease vencido em ${expiredAt}`;
  }
  const assignee = thread.assignee ? `Responsável: ${thread.assignee}` : "Sem responsável";
  const updated = thread.updatedAt ? formatDateTime(thread.updatedAt) : "sem movimentação";
  const action = thread.lastAction ? ` · ${replayGovernanceHistoryConflictCurationEventLabel(thread.lastAction)}` : "";
  return `${assignee} · ${updated}${action}`;
}

function replayGovernanceHistoryConflictCurationEventLabel(
  action: StudioReplayGovernanceHistoryConflictCurationLastAction,
): string {
  if (action === "assign") {
    return "assumiu";
  }
  if (action === "lease_expired") {
    return "lease expirou";
  }
  return "liberou";
}

function StudioDebugLayerSnapshotConflictsPanel({
  conflicts,
  onResolve,
  onCurationUpdate,
  reviewerName,
  reviewerRole,
}: {
  conflicts: StudioDebugLayerSnapshotsPackage["conflicts"];
  onResolve: (conflictId: string, keepPackageHash: string) => void | Promise<void>;
  onCurationUpdate: (
    conflictId: string,
    action: StudioDebugLayerSnapshotConflictCurationAction,
  ) => void | Promise<void>;
  reviewerName: string;
  reviewerRole: StudioDebugLayerSnapshotConflictCuratorRole;
}) {
  const openConflicts = conflicts.filter((conflict) => conflict.status === "open");
  if (!openConflicts.length) {
    return null;
  }
  return (
    <article className="runtime-item studio-debug-layer-conflicts warning" aria-label="Conflitos de camadas de debug">
      <strong>Conflitos de camadas</strong>
      <small>
        {openConflicts.length} conflito(s) aberto(s). O Studio detectou snapshots do mesmo contexto com hashes
        diferentes; escolha a evidência que deve ficar no pacote compartilhado.
      </small>
      {openConflicts.slice(0, 4).map((conflict) => (
        <div className="studio-debug-layer-conflict" key={conflict.conflictId}>
          <div className={`schema-pattern-curation-thread ${conflict.curationThread.status}`}>
            <span>{debugLayerSnapshotConflictCurationStatusLabel(conflict.curationThread)}</span>
            <small>{debugLayerSnapshotConflictCurationDetail(conflict.curationThread)}</small>
            {conflict.curationThread.events.slice(0, 3).map((event) => (
              <small key={event.id}>
                {formatDateTime(event.at)} · {event.actor} ·{" "}
                {formatStudioAnnotationReviewerRole(event.role)} ·{" "}
                {debugLayerSnapshotConflictCurationEventLabel(event.action)}
              </small>
            ))}
          </div>
          <div className="inline-actions">
            <button
              type="button"
              className="command-button"
              disabled={reviewerRole === "viewer" || conflict.curationThread.assignee === reviewerName}
              onClick={() => void onCurationUpdate(conflict.conflictId, "assign")}
            >
              Assumir
            </button>
            <button
              type="button"
              className="command-button ghost"
              disabled={reviewerRole === "viewer" || !conflict.curationThread.assignee}
              onClick={() => void onCurationUpdate(conflict.conflictId, "release")}
            >
              Liberar
            </button>
          </div>
          <small>
            {conflict.scope === "scenario_batch" ? "Lote" : "Comparação"} · {conflict.snapshotCount} snapshot(s) ·
            mais recente {formatDateTime(conflict.latestExportedAt)}
          </small>
          {conflict.refs.slice(0, 4).map((ref) => (
            <div className="studio-debug-layer-conflict-ref" key={`${conflict.conflictId}-${ref.packageHash}`}>
              <small>
                {ref.packageHash === conflict.latestPackageHash ? "mais recente" : "alternativa"} ·{" "}
                {ref.selectedNodeId || ref.batchReportHash || `${ref.leftRunId} -> ${ref.rightRunId}` || ref.scope} ·{" "}
                {ref.statusLabel || "-"} · {ref.packageHash.slice(0, 12)}
              </small>
              <button
                type="button"
                className="command-button"
                disabled={reviewerRole === "viewer"}
                onClick={() => void onResolve(conflict.conflictId, ref.packageHash)}
              >
                {ref.packageHash === conflict.latestPackageHash ? "Manter mais recente" : "Manter este snapshot"}
              </button>
            </div>
          ))}
        </div>
      ))}
    </article>
  );
}

