function StudioNodeRunComparisonCard({
  nodeId,
  runComparison,
  nodeComparison,
  onLoadRun,
  onTimelineNodeFilterChange,
  onCreateDebugScenario,
  onExportReplayArtifact,
}: {
  nodeId: string;
  runComparison: StudioRunComparison | null;
  nodeComparison: StudioSelectedNodeRunComparison | null;
  onLoadRun: (runId: string) => void;
  onTimelineNodeFilterChange: (value: string) => void;
  onCreateDebugScenario: (nodeId: string) => void;
  onExportReplayArtifact: () => void;
}) {
  if (!runComparison) {
    return (
      <div className="node-run-comparison empty" aria-label="Comparação do nó selecionado">
        <div className="node-context-section-header">
          <strong>Comparação do nó</strong>
          <span>sem par de runs</span>
        </div>
        <p>Escolha um run base em Runs locais e clique em Comparar para ver este nó entre as duas execuções.</p>
      </div>
    );
  }
  if (!nodeComparison) {
    return null;
  }
  const hasDiffPreview = nodeComparison.stateDiffPreview.length > 0 || nodeComparison.outputDiffPreview.length > 0;
  return (
    <div className={`node-run-comparison ${nodeComparison.status}`} aria-label="Comparação do nó selecionado">
      <div className="node-context-section-header">
        <strong>Comparação do nó</strong>
        <span>{nodeComparison.statusLabel}</span>
      </div>
      <p>{nodeComparison.statusDetail}</p>
      <div className="node-run-comparison-grid">
        <article>
          <strong>Base</strong>
          <span>{runComparison.leftRunId}</span>
          <small>
            #{nodeComparison.leftSeq ?? "-"} · {nodeComparison.leftStatus ?? "-"} · {nodeComparison.leftPhase ?? "-"}
          </small>
          <button type="button" className="command-button" onClick={() => onLoadRun(runComparison.leftRunId)}>
            Carregar base
          </button>
        </article>
        <article>
          <strong>Candidato</strong>
          <span>{runComparison.rightRunId}</span>
          <small>
            #{nodeComparison.rightSeq ?? "-"} · {nodeComparison.rightStatus ?? "-"} · {nodeComparison.rightPhase ?? "-"}
          </small>
          <button type="button" className="command-button" onClick={() => onLoadRun(runComparison.rightRunId)}>
            Carregar candidato
          </button>
        </article>
        <article>
          <strong>Diferenças</strong>
          <span>
            state {nodeComparison.stateDiffCount} · output {nodeComparison.outputDiffCount}
          </span>
          <small>{nodeComparison.statusLabel}</small>
          <button type="button" className="command-button" onClick={() => onTimelineNodeFilterChange(nodeId)}>
            Focar nó
          </button>
        </article>
      </div>
      <div className="node-run-comparison-actions">
        <button
          type="button"
          className="command-button"
          onClick={() => onCreateDebugScenario(nodeId)}
          disabled={nodeComparison.status === "missing" || nodeComparison.status === "left_only"}
        >
          Criar cenário de debug
        </button>
        <button
          type="button"
          className="command-button"
          onClick={onExportReplayArtifact}
          disabled={nodeComparison.status === "missing"}
        >
          <Download size={14} aria-hidden="true" />
          Exportar replay
        </button>
        <small>Cria um cenário local com checkpoint ou exporta evidência governada para replay sem payload bruto.</small>
      </div>
      {hasDiffPreview ? (
        <details>
          <summary>Ver diffs deste nó</summary>
          <pre className="mini-json">
            {formatInspectorValue({
              stateDiff: nodeComparison.stateDiffPreview,
              outputDiff: nodeComparison.outputDiffPreview,
            })}
          </pre>
        </details>
      ) : (
        <small>Sem diff de estado ou output para este nó na comparação carregada.</small>
      )}
    </div>
  );
}

function makeFlowTriggerId(triggers: FlowTrigger[]): string {
  const existing = new Set(triggers.map((trigger) => trigger.id));
  for (let index = 1; index < 1000; index += 1) {
    const candidate = `flow_trigger_${index}`;
    if (!existing.has(candidate)) {
      return candidate;
    }
  }
  return `flow_trigger_${Date.now()}`;
}

function createDefaultFlowTrigger(triggers: FlowTrigger[]): FlowTrigger {
  return {
    id: makeFlowTriggerId(triggers),
    label: "Worker periódico",
    kind: "interval",
    enabled: true,
    intervalSeconds: 300,
    userMessage: "Executar rotina agendada.",
    input: {},
    maxTurns: 3,
    maxAttempts: 3,
    autoFinish: false,
  };
}

function parseObjectJson(value: string): Record<string, unknown> | null {
  const trimmed = value.trim();
  if (!trimmed) {
    return {};
  }
  const parsed = JSON.parse(trimmed);
  return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? (parsed as Record<string, unknown>) : null;
}

function FlowTriggersEditor({ flow, onChange }: { flow: AgentFlow; onChange: (triggers: FlowTrigger[]) => void }) {
  const triggers = [...(flow.triggers ?? [])];
  const updateTrigger = (triggerId: string, patch: Partial<FlowTrigger>) => {
    onChange(triggers.map((trigger) => (trigger.id === triggerId ? { ...trigger, ...patch } : trigger)));
  };
  const removeTrigger = (triggerId: string) => {
    onChange(triggers.filter((trigger) => trigger.id !== triggerId));
  };
  return (
    <section className="flow-trigger-editor">
      <div className="flow-trigger-editor-header">
        <div>
          <strong>Workers do flow</strong>
          <span>Executam sessões em background quando o runtime/worker estiver rodando.</span>
        </div>
        <button type="button" className="icon-button" onClick={() => onChange([...triggers, createDefaultFlowTrigger(triggers)])} title="Adicionar worker">
          <Plus size={15} aria-hidden="true" />
        </button>
      </div>
      {triggers.length ? (
        <div className="flow-trigger-list">
          {triggers.map((trigger) => (
            <div className="flow-trigger-card" key={trigger.id}>
              <div className="flow-trigger-card-title">
                <label className="flow-trigger-enabled">
                  <input
                    type="checkbox"
                    checked={trigger.enabled !== false}
                    onChange={(event) => updateTrigger(trigger.id, { enabled: event.target.checked })}
                  />
                  <span>{trigger.label || trigger.id}</span>
                </label>
                <button type="button" className="icon-button danger" onClick={() => removeTrigger(trigger.id)} title="Remover worker">
                  <Trash2 size={14} aria-hidden="true" />
                </button>
              </div>
              <label>
                <span>ID</span>
                <input value={trigger.id} onChange={(event) => updateTrigger(trigger.id, { id: event.target.value })} />
              </label>
              <label>
                <span>Label</span>
                <input value={trigger.label ?? ""} onChange={(event) => updateTrigger(trigger.id, { label: event.target.value })} />
              </label>
              <label>
                <span>Tipo</span>
                <select value={trigger.kind} onChange={(event) => updateTrigger(trigger.id, { kind: event.target.value as FlowTrigger["kind"] })}>
                  <option value="interval">Intervalo</option>
                  <option value="cron">Cron</option>
                  <option value="event">Evento</option>
                  <option value="manual">Manual</option>
                </select>
              </label>
              {trigger.kind === "interval" ? (
                <label>
                  <span>Intervalo (s)</span>
                  <input
                    type="number"
                    min={60}
                    value={trigger.intervalSeconds ?? 300}
                    onChange={(event) => updateTrigger(trigger.id, { intervalSeconds: Number(event.target.value) || 300 })}
                  />
                </label>
              ) : null}
              {trigger.kind === "cron" ? (
                <label>
                  <span>Cron</span>
                  <input
                    value={trigger.cronExpression ?? ""}
                    placeholder="*/15 * * * *"
                    onChange={(event) => updateTrigger(trigger.id, { cronExpression: event.target.value })}
                  />
                </label>
              ) : null}
              {trigger.kind === "event" ? (
                <label>
                  <span>Evento</span>
                  <input
                    value={trigger.eventType ?? ""}
                    placeholder="catalog.updated"
                    onChange={(event) => updateTrigger(trigger.id, { eventType: event.target.value })}
                  />
                </label>
              ) : null}
              <label>
                <span>Mensagem</span>
                <textarea
                  value={trigger.userMessage ?? ""}
                  rows={2}
                  onChange={(event) => updateTrigger(trigger.id, { userMessage: event.target.value })}
                />
              </label>
              <label>
                <span>Input JSON</span>
                <textarea
                  key={`${trigger.id}-input-${JSON.stringify(trigger.input ?? {})}`}
                  defaultValue={JSON.stringify(trigger.input ?? {}, null, 2)}
                  rows={3}
                  onBlur={(event) => {
                    try {
                      const parsed = parseObjectJson(event.currentTarget.value);
                      if (!parsed) {
                        event.currentTarget.setCustomValidity("Use um objeto JSON.");
                        event.currentTarget.reportValidity();
                        return;
                      }
                      event.currentTarget.setCustomValidity("");
                      updateTrigger(trigger.id, { input: parsed });
                    } catch {
                      event.currentTarget.setCustomValidity("JSON inválido.");
                      event.currentTarget.reportValidity();
                    }
                  }}
                />
              </label>
              <div className="flow-trigger-grid">
                <label>
                  <span>Max turns</span>
                  <input
                    type="number"
                    min={1}
                    max={50}
                    value={trigger.maxTurns ?? 3}
                    onChange={(event) => updateTrigger(trigger.id, { maxTurns: Number(event.target.value) || 3 })}
                  />
                </label>
                <label>
                  <span>Tentativas</span>
                  <input
                    type="number"
                    min={1}
                    max={10}
                    value={trigger.maxAttempts ?? 3}
                    onChange={(event) => updateTrigger(trigger.id, { maxAttempts: Number(event.target.value) || 3 })}
                  />
                </label>
              </div>
              <label className="flow-trigger-enabled">
                <input
                  type="checkbox"
                  checked={Boolean(trigger.autoFinish)}
                  onChange={(event) => updateTrigger(trigger.id, { autoFinish: event.target.checked })}
                />
                <span>Finalizar sessão automaticamente</span>
              </label>
            </div>
          ))}
        </div>
      ) : (
        <span className="flow-trigger-empty">Nenhum worker configurado.</span>
      )}
    </section>
  );
}

