function parseSchemaObject(content: string): SchemaParseResult {
  try {
    const value = JSON.parse(content) as unknown;
    if (!isRecord(value)) {
      return { ok: false, message: "Schema precisa ser um objeto JSON." };
    }
    return { ok: true, schema: value };
  } catch (error) {
    return { ok: false, message: `Corrija o JSON para usar o editor visual: ${error instanceof Error ? error.message : "erro desconhecido"}` };
  }
}

function cloneJsonObject(value: Record<string, unknown>): Record<string, unknown> {
  return JSON.parse(JSON.stringify(value)) as Record<string, unknown>;
}

const studioTurnOperationalFields = new Set([
  "session_id",
  "status",
  "phase",
  "turn",
  "max_turns",
  "assistant_message",
  "recent_messages",
  "messages",
  "transcript",
  "events",
  "executed_nodes",
  "safety",
  "llm",
  "metadata",
]);

function buildStudioTurnInputFields(schemaContent: string): StudioTurnInputField[] {
  const fallback: StudioTurnInputField = {
    name: "user_message",
    path: ["user_message"],
    draftKey: "user_message",
    type: "string",
    inputKind: "text",
    required: true,
    description: "Mensagem enviada no turno atual.",
    enumValues: [],
    schemaBacked: false,
    children: [],
    arrayItem: null,
  };
  if (!schemaContent.trim()) {
    return [fallback];
  }
  const parsed = parseSchemaObject(schemaContent);
  if (!parsed.ok) {
    return [fallback];
  }
  const required = new Set(readSchemaRequired(parsed.schema));
  const fields = readSchemaProperties(parsed.schema)
    .filter(([name]) => name === "user_message" || !studioTurnOperationalFields.has(name))
    .map(([name, schema]) => buildStudioTurnInputField(name, schema, required.has(name), []));
  if (!fields.some((field) => field.name === "user_message")) {
    fields.unshift(fallback);
  }
  return sortStudioTurnInputFields(fields);
}

function buildStudioTurnInputField(
  name: string,
  schema: Record<string, unknown>,
  required: boolean,
  parentPath: string[],
): StudioTurnInputField {
  const path = [...parentPath, name];
  const type = readSchemaPropertyType(schema) || (readSchemaProperties(schema).length ? "object" : "string");
  const enumValues = readSchemaPropertyEnum(schema);
  const nestedRequired = new Set(readSchemaRequired(schema));
  const children =
    type === "object"
      ? sortStudioTurnInputFields(
          readSchemaProperties(schema).map(([childName, childSchema]) =>
            buildStudioTurnInputField(childName, childSchema, nestedRequired.has(childName), path),
          ),
        )
      : [];
  const arrayItem = type === "array" ? buildStudioTurnArrayItemField(schema, path, required) : null;

  return {
    name: formatStudioTurnFieldName(path),
    path,
    draftKey: path.join("."),
    type,
    inputKind: arrayItem ? "array" : children.length ? "group" : studioTurnInputKind(type, enumValues),
    required,
    description: readSchemaPropertyDescription(schema),
    enumValues,
    schemaBacked: true,
    children,
    arrayItem,
  };
}

function buildStudioTurnArrayItemField(
  arraySchema: Record<string, unknown>,
  arrayPath: string[],
  arrayRequired: boolean,
): StudioTurnInputField {
  const itemSchema = isRecord(arraySchema.items) ? arraySchema.items : { type: "string" };
  const itemPath = [...arrayPath, "[]"];
  const type = readSchemaPropertyType(itemSchema) || (readSchemaProperties(itemSchema).length ? "object" : "string");
  const enumValues = readSchemaPropertyEnum(itemSchema);
  const nestedRequired = new Set(readSchemaRequired(itemSchema));
  const children =
    type === "object"
      ? sortStudioTurnInputFields(
          readSchemaProperties(itemSchema).map(([childName, childSchema]) =>
            buildStudioTurnInputField(childName, childSchema, nestedRequired.has(childName), itemPath),
          ),
        )
      : [];
  return {
    name: formatStudioTurnFieldName(itemPath),
    path: itemPath,
    draftKey: itemPath.join("."),
    type,
    inputKind: children.length ? "group" : studioTurnInputKind(type, enumValues),
    required: arrayRequired,
    description: readSchemaPropertyDescription(itemSchema),
    enumValues,
    schemaBacked: true,
    children,
    arrayItem: null,
  };
}

function formatStudioTurnFieldName(path: string[]): string {
  return path.reduce((label, segment) => {
    if (segment === "[]") {
      return `${label}[]`;
    }
    if (/^\d+$/.test(segment)) {
      return `${label}[${segment}]`;
    }
    return label ? `${label}.${segment}` : segment;
  }, "");
}

function sortStudioTurnInputFields(fields: StudioTurnInputField[]): StudioTurnInputField[] {
  return [...fields].sort((left, right) => {
    if (left.name === "user_message") {
      return -1;
    }
    if (right.name === "user_message") {
      return 1;
    }
    if (left.required !== right.required) {
      return left.required ? -1 : 1;
    }
    return left.name.localeCompare(right.name);
  });
}

function studioTurnInputKind(type: string, enumValues: string[]): StudioTurnInputField["inputKind"] {
  if (enumValues.length > 0) {
    return "enum";
  }
  if (type === "number" || type === "integer") {
    return "number";
  }
  if (type === "boolean") {
    return "boolean";
  }
  if (type === "object") {
    return "json";
  }
  return "text";
}

function buildStudioTurnPayload(
  schemaContent: string,
  userMessage: string,
  draft: Record<string, string>,
): StudioTurnPayloadBuildResult {
  const fields = buildStudioTurnInputFields(schemaContent);
  const errors: string[] = [];
  const payload: Record<string, unknown> = { user_message: userMessage };

  for (const field of fields) {
    if (field.name === "user_message") {
      continue;
    }
    const parsedField = parseStudioTurnPayloadField(field, draft, errors);
    if (parsedField.sent) {
      payload[field.path[0]] = parsedField.value;
    }
  }

  return { fields, payload, errors };
}

function parseStudioTurnPayloadField(
  field: StudioTurnInputField,
  draft: Record<string, string>,
  errors: string[],
): { sent: true; value: unknown } | { sent: false } {
  if (field.inputKind === "group") {
    const value: Record<string, unknown> = {};
    const errorsBefore = errors.length;
    let hasValue = false;
    for (const child of field.children) {
      const parsedChild = parseStudioTurnPayloadField(child, draft, errors);
      if (parsedChild.sent) {
        value[child.path[child.path.length - 1]] = parsedChild.value;
        hasValue = true;
      }
    }
    if (!hasValue && field.required && errors.length === errorsBefore) {
      errors.push(`Campo obrigatório ausente no payload: ${field.name}.`);
    }
    return hasValue ? { sent: true, value } : { sent: false };
  }

  if (field.inputKind === "array") {
    const itemField = field.arrayItem;
    const rowCount = studioTurnArrayRowCount(field, draft);
    const errorsBefore = errors.length;
    const value: unknown[] = [];
    if (!itemField || rowCount === 0) {
      if (field.required) {
        errors.push(`Campo obrigatório ausente no payload: ${field.name}.`);
      }
      return { sent: false };
    }
    for (let index = 0; index < rowCount; index += 1) {
      const indexedItem = indexStudioTurnArrayItemField(itemField, index);
      const parsedItem = parseStudioTurnPayloadField(indexedItem, draft, errors);
      if (parsedItem.sent) {
        value.push(parsedItem.value);
      }
    }
    if (!value.length && field.required && errors.length === errorsBefore) {
      errors.push(`Campo obrigatório ausente no payload: ${field.name}.`);
    }
    return value.length ? { sent: true, value } : { sent: false };
  }

  const raw = draft[field.draftKey] ?? "";
  const trimmed = raw.trim();
  if (!trimmed && field.inputKind !== "boolean") {
    if (field.required) {
      errors.push(`Campo obrigatório ausente no payload: ${field.name}.`);
    }
    return { sent: false };
  }
  if (field.inputKind === "boolean") {
    if (raw === "") {
      if (field.required) {
        errors.push(`Campo obrigatório ausente no payload: ${field.name}.`);
      }
      return { sent: false };
    }
    return { sent: true, value: raw === "true" };
  }
  if (field.inputKind === "number") {
    const numeric = Number(trimmed);
    if (!Number.isFinite(numeric)) {
      errors.push(`Campo ${field.name} precisa ser numérico.`);
      return { sent: false };
    }
    return { sent: true, value: field.type === "integer" ? Math.trunc(numeric) : numeric };
  }
  if (field.inputKind === "json") {
    try {
      return { sent: true, value: JSON.parse(trimmed) as unknown };
    } catch (error) {
      errors.push(`Campo ${field.name} precisa ser JSON válido: ${error instanceof Error ? error.message : "erro desconhecido"}.`);
      return { sent: false };
    }
  }
  return { sent: true, value: trimmed };
}

function studioTurnArrayRowCount(field: StudioTurnInputField, draft: Record<string, string>): number {
  const countKey = studioTurnArrayCountKey(field);
  const directCount = Number(draft[countKey] ?? "");
  const discoveredCount = Object.keys(draft).reduce((max, key) => {
    const prefix = `${field.draftKey}.`;
    if (!key.startsWith(prefix)) {
      return max;
    }
    const index = Number(key.slice(prefix.length).split(".")[0]);
    return Number.isInteger(index) && index >= 0 ? Math.max(max, index + 1) : max;
  }, 0);
  return Math.max(field.required ? 1 : 0, Number.isFinite(directCount) ? Math.max(0, Math.trunc(directCount)) : 0, discoveredCount);
}

function studioTurnArrayCountKey(field: StudioTurnInputField): string {
  return `${field.draftKey}.__count`;
}

function indexStudioTurnArrayItemField(field: StudioTurnInputField, index: number): StudioTurnInputField {
  const path = field.path.map((segment) => (segment === "[]" ? String(index) : segment));
  return {
    ...field,
    name: formatStudioTurnFieldName(path),
    path,
    draftKey: path.join("."),
    children: field.children.map((child) => indexStudioTurnArrayItemField(child, index)),
    arrayItem: field.arrayItem ? indexStudioTurnArrayItemField(field.arrayItem, index) : null,
  };
}

function studioTurnPayloadToDraft(payload: Record<string, unknown> | null): Record<string, string> {
  if (!payload) {
    return {};
  }
  const draft: Record<string, string> = {};
  for (const [key, value] of Object.entries(payload)) {
    if (key === "user_message") {
      continue;
    }
    writeStudioTurnPayloadDraftValue(draft, [key], value);
  }
  return draft;
}

function writeStudioTurnPayloadDraftValue(draft: Record<string, string>, path: string[], value: unknown): void {
  const key = path.join(".");
  if (Array.isArray(value)) {
    draft[key] = JSON.stringify(value, null, 2);
    draft[`${key}.__count`] = String(value.length);
    value.forEach((item, index) => writeStudioTurnPayloadDraftValue(draft, [...path, String(index)], item));
    return;
  }
  if (typeof value === "string") {
    draft[key] = value;
    return;
  }
  if (typeof value === "number" || typeof value === "boolean") {
    draft[key] = String(value);
    return;
  }
  if (value === undefined) {
    return;
  }
  draft[key] = JSON.stringify(value, null, 2);
  if (isRecord(value)) {
    for (const [childKey, childValue] of Object.entries(value)) {
      writeStudioTurnPayloadDraftValue(draft, [...path, childKey], childValue);
    }
  }
}

function focusSchemaSemanticIssue(issue: SchemaSemanticIssue): void {
  if (!issue.focus) {
    return;
  }
  const targetKey = schemaPathKey(issue.focus.targetPath);
  const targets = Array.from(document.querySelectorAll<HTMLElement>("[data-schema-focus-target]")).filter(
    (target) => target.getAttribute("data-schema-focus-target") === targetKey,
  );
  if (!targets.length) {
    return;
  }
  const field = findSchemaFocusField(targets, issue.focus.field);
  const target = field?.closest<HTMLElement>("[data-schema-focus-target]") ?? targets[0];
  target.setAttribute("data-schema-focus-active", "true");
  window.setTimeout(() => {
    target.removeAttribute("data-schema-focus-active");
  }, 1200);
  target.scrollIntoView({ block: "center", behavior: "smooth" });
  window.setTimeout(() => {
    (field ?? target).focus({ preventScroll: true });
  }, 120);
}

function findSchemaFocusField(targets: HTMLElement[], field: string): HTMLElement | undefined {
  for (const target of targets) {
    const candidates = Array.from(target.querySelectorAll<HTMLElement>("[data-schema-focus-field]"));
    const match = candidates.find((candidate) => candidate.getAttribute("data-schema-focus-field") === field);
    if (match) {
      return match;
    }
  }
  return undefined;
}

function validateSchemaSemantics(schema: Record<string, unknown>): SchemaSemanticIssue[] {
  const issues: SchemaSemanticIssue[] = [];
  const definitionNames = new Set(readSchemaDefinitions(schema).map(([name]) => name));
  const visited = new Set<Record<string, unknown>>();

  visitSchemaObject(schema, "schema", []);

  if (schema.$defs !== undefined && !isRecord(schema.$defs)) {
    issues.push({
      severity: "error",
      path: "schema.$defs",
      message: "$defs precisa ser um objeto com definições nomeadas.",
      focus: { targetPath: [], field: "definition" },
    });
  }

  if (isRecord(schema.$defs)) {
    Object.entries(schema.$defs).forEach(([name, value]) => {
      if (!isValidSchemaPropertyName(name)) {
        issues.push({
          severity: "warning",
          path: `schema.$defs.${name}`,
          message: "Nome de definição fora do padrão visual. Use letras, números, _ ou - e comece por letra ou _.",
          focus: { targetPath: [], field: "definition" },
        });
      }
      if (!isRecord(value)) {
        issues.push({
          severity: "error",
          path: `schema.$defs.${name}`,
          message: "Definição precisa ser um objeto JSON Schema.",
          focus: { targetPath: ["$defs", name], field: "type" },
        });
        return;
      }
      visitSchemaObject(value, `schema.$defs.${name}`, ["$defs", name]);
    });
  }

  return issues;

  function visitSchemaObject(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    if (visited.has(current)) {
      return;
    }
    visited.add(current);

    validateRef(current, path, targetPath);
    validateRequired(current, path, targetPath);
    validateEnum(current, path, targetPath);
    validateAdditionalProperties(current, path, targetPath);
    validateArrayItems(current, path, targetPath);
    validateComposition(current, path, targetPath);

    if (isRecord(current.properties)) {
      Object.entries(current.properties).forEach(([propertyName, propertyValue]) => {
        const propertyPath = `${path}.properties.${propertyName}`;
        if (!isRecord(propertyValue)) {
          issues.push({
            severity: "error",
            path: propertyPath,
            message: "Propriedade precisa ser um objeto JSON Schema.",
            focus: { targetPath: [...targetPath, "properties", propertyName], field: "type" },
          });
          return;
        }
        visitSchemaObject(propertyValue, propertyPath, [...targetPath, "properties", propertyName]);
      });
    } else if (current.properties !== undefined) {
      issues.push({
        severity: "error",
        path: `${path}.properties`,
        message: "properties precisa ser um objeto.",
        focus: { targetPath, field: "addProperty" },
        action: {
          type: "initialize-properties",
          label: "Inicializar properties",
          targetPath,
        },
      });
    }

    if (isRecord(current.items)) {
      visitSchemaObject(current.items, `${path}.items`, [...targetPath, "items"]);
    } else if (current.items !== undefined && !Array.isArray(current.items)) {
      issues.push({
        severity: "error",
        path: `${path}.items`,
        message: "items precisa ser um schema ou uma lista de schemas.",
        focus: { targetPath, field: "items" },
        action: {
          type: "normalize-array-items",
          label: "Corrigir items",
          targetPath,
        },
      });
    } else if (Array.isArray(current.items)) {
      current.items.forEach((item, index) => {
        if (isRecord(item)) {
          visitSchemaObject(item, `${path}.items[${index}]`, [...targetPath, "items", index]);
        } else {
          issues.push({
            severity: "error",
            path: `${path}.items[${index}]`,
            message: "Item de array precisa ser um objeto JSON Schema.",
            focus: { targetPath, field: "items" },
            action: {
              type: "normalize-array-items",
              label: "Corrigir items",
              targetPath,
            },
          });
        }
      });
    }

    if (isRecord(current.additionalProperties)) {
      visitSchemaObject(current.additionalProperties, `${path}.additionalProperties`, [...targetPath, "additionalProperties"]);
    }

    schemaCompositionKeys.forEach((key) => {
      const entries = current[key];
      if (!Array.isArray(entries)) {
        return;
      }
      entries.forEach((entry, index) => {
        if (isRecord(entry)) {
          visitSchemaObject(entry, `${path}.${key}[${index}]`, [...targetPath, key, index]);
        }
      });
    });
  }

  function validateRef(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    if (current.$ref === undefined) {
      return;
    }
    if (typeof current.$ref !== "string" || !current.$ref.trim()) {
      issues.push({
        severity: "error",
        path: `${path}.$ref`,
        message: "$ref precisa ser uma string não vazia.",
        focus: { targetPath, field: "ref" },
      });
      return;
    }
    const ref = current.$ref.trim();
    if (ref.startsWith("#/$defs/")) {
      const refName = safeDecodeSchemaRef(ref.slice("#/$defs/".length));
      if (!refName) {
        issues.push({
          severity: "error",
          path: `${path}.$ref`,
          message: `Referência local inválida: ${ref}.`,
          focus: { targetPath, field: "ref" },
        });
        return;
      }
      if (!definitionNames.has(refName)) {
        issues.push({
          severity: "error",
          path: `${path}.$ref`,
          message: `Referência local não encontrada: ${ref}. Crie a definição em $defs ou ajuste o $ref.`,
          focus: { targetPath, field: "ref" },
          action: {
            type: "create-definition",
            label: `Criar $defs.${refName}`,
            definitionName: refName,
            sourcePath: targetPath,
          },
        });
      }
      return;
    }
    if (ref.startsWith("#/definitions/")) {
      issues.push({
        severity: "warning",
        path: `${path}.$ref`,
        message: "Este editor resolve localmente $defs. Migre definitions para $defs para validação visual completa.",
        focus: { targetPath, field: "ref" },
      });
    } else if (ref.startsWith("#/")) {
      issues.push({
        severity: "warning",
        path: `${path}.$ref`,
        message: "Referência local fora de $defs não é resolvida pelo editor visual.",
        focus: { targetPath, field: "ref" },
      });
    }
  }

  function safeDecodeSchemaRef(value: string): string {
    try {
      return decodeURIComponent(value);
    } catch {
      return "";
    }
  }

  function validateRequired(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    if (current.required === undefined) {
      return;
    }
    if (!Array.isArray(current.required)) {
      issues.push({
        severity: "error",
        path: `${path}.required`,
        message: "required precisa ser uma lista de nomes de propriedades.",
        focus: { targetPath, field: "addProperty" },
        action: {
          type: "normalize-required-list",
          label: "Converter required em lista",
          targetPath,
        },
      });
      return;
    }
    const propertyNames = isRecord(current.properties) ? new Set(Object.keys(current.properties)) : new Set<string>();
    const seenRequired = new Set<string>();
    current.required.forEach((item, index) => {
      const itemPath = `${path}.required[${index}]`;
      if (typeof item !== "string" || !item.trim()) {
        issues.push({
          severity: "error",
          path: itemPath,
          message: "Cada item de required precisa ser uma string não vazia.",
          focus: { targetPath, field: "addProperty" },
        });
        return;
      }
      if (seenRequired.has(item)) {
        issues.push({
          severity: "warning",
          path: itemPath,
          message: `Campo obrigatório duplicado: ${item}.`,
          focus: { targetPath, field: "addProperty" },
          action: {
            type: "dedupe-required",
            label: "Deduplicar required",
            targetPath,
          },
        });
      }
      seenRequired.add(item);
      if (!propertyNames.has(item)) {
        issues.push({
          severity: "warning",
          path: itemPath,
          message: `Campo obrigatório sem propriedade correspondente: ${item}.`,
          focus: { targetPath, field: "addProperty" },
          action: {
            type: "remove-required",
            label: `Remover required ${item}`,
            targetPath,
            propertyName: item,
          },
        });
      }
    });
  }

  function validateEnum(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    if (current.enum === undefined) {
      return;
    }
    if (!Array.isArray(current.enum)) {
      issues.push({
        severity: "error",
        path: `${path}.enum`,
        message: "enum precisa ser uma lista.",
        focus: { targetPath, field: "enum" },
        action: {
          type: "normalize-enum-list",
          label: "Converter enum em lista",
          targetPath,
        },
      });
      return;
    }
    const seenValues = new Set<string>();
    current.enum.forEach((item, index) => {
      const key = JSON.stringify(item);
      if (seenValues.has(key)) {
        issues.push({
          severity: "warning",
          path: `${path}.enum[${index}]`,
          message: "Valor duplicado no enum.",
          focus: { targetPath, field: "enum" },
          action: {
            type: "dedupe-enum",
            label: "Deduplicar enum",
            targetPath,
          },
        });
      }
      seenValues.add(key);
    });
  }

  function validateAdditionalProperties(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    const additional = current.additionalProperties;
    if (additional === undefined || typeof additional === "boolean" || isRecord(additional)) {
      return;
    }
    issues.push({
      severity: "error",
      path: `${path}.additionalProperties`,
      message: "additionalProperties precisa ser true, false ou um schema.",
      focus: { targetPath, field: "additionalProperties" },
      action: {
        type: "normalize-additional-properties",
        label: "Corrigir additionalProperties",
        targetPath,
      },
    });
  }

  function validateArrayItems(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    const type = current.type;
    if (type === "array" && current.items === undefined) {
      issues.push({
        severity: "warning",
        path: `${path}.items`,
        message: "Array sem items deixa o formato de cada item indefinido.",
        focus: { targetPath, field: "items" },
        action: {
          type: "add-array-items",
          label: "Adicionar items",
          targetPath,
        },
      });
    }
  }

  function validateComposition(current: Record<string, unknown>, path: string, targetPath: SchemaPathSegment[]) {
    schemaCompositionKeys.forEach((key) => {
      const entries = current[key];
      if (entries === undefined) {
        return;
      }
      if (!Array.isArray(entries)) {
        issues.push({
          severity: "error",
          path: `${path}.${key}`,
          message: `${key} precisa ser uma lista de schemas.`,
          focus: { targetPath, field: `composition:${key}` },
          action: {
            type: "normalize-composition-list",
            label: `Converter ${key} em lista`,
            targetPath,
            key,
          },
        });
        return;
      }
      if (!entries.length) {
        issues.push({
          severity: "warning",
          path: `${path}.${key}`,
          message: `${key} vazio não adiciona uma alternativa válida.`,
          focus: { targetPath, field: `composition:${key}` },
          action: {
            type: "remove-empty-composition",
            label: `Remover ${key}`,
            targetPath,
            key,
          },
        });
      }
      entries.forEach((entry, index) => {
        if (!isRecord(entry)) {
          issues.push({
            severity: "error",
            path: `${path}.${key}[${index}]`,
            message: `Entrada de ${key} precisa ser um objeto JSON Schema.`,
            focus: { targetPath, field: `composition:${key}` },
            action: {
              type: "normalize-composition-list",
              label: `Corrigir ${key}`,
              targetPath,
              key,
            },
          });
        }
      });
    });
  }
}

function applySchemaSemanticAction(schema: Record<string, unknown>, action: SchemaSemanticAction): void {
  if (action.type === "create-definition") {
    const definitions = ensureSchemaDefinitions(schema);
    if (!definitions[action.definitionName]) {
      definitions[action.definitionName] = createSchemaDefinitionFromSource(readSchemaObjectAtPath(schema, action.sourcePath), action.sourcePath);
    }
    return;
  }

  const target = "targetPath" in action ? readSchemaObjectAtPath(schema, action.targetPath) : undefined;
  if (!target) {
    return;
  }

  if (action.type === "remove-required") {
    target.required = readSchemaRequired(target).filter((item) => item !== action.propertyName);
    if (!readSchemaRequired(target).length) {
      delete target.required;
    }
    return;
  }

  if (action.type === "dedupe-required") {
    const deduped = uniqueJsonValues(readSchemaRequired(target));
    if (deduped.length) {
      target.required = deduped;
    } else {
      delete target.required;
    }
    return;
  }

  if (action.type === "normalize-required-list") {
    const current = target.required;
    if (typeof current === "string" && current.trim()) {
      target.required = [current.trim()];
    } else if (Array.isArray(current)) {
      target.required = current.filter((item): item is string => typeof item === "string" && item.trim().length > 0);
    } else {
      delete target.required;
    }
    if (!readSchemaRequired(target).length) {
      delete target.required;
    }
    return;
  }

  if (action.type === "add-array-items") {
    target.type = "array";
    if (!isRecord(target.items) && !Array.isArray(target.items)) {
      target.items = { type: "string" };
    }
    return;
  }

  if (action.type === "normalize-array-items") {
    target.type = "array";
    if (Array.isArray(target.items)) {
      const validItems = target.items.filter(isRecord);
      target.items = validItems.length ? validItems : [{ type: "string" }];
    } else if (!isRecord(target.items)) {
      target.items = { type: "string" };
    }
    return;
  }

  if (action.type === "initialize-properties") {
    target.type = "object";
    target.properties = {};
    return;
  }

  if (action.type === "normalize-additional-properties") {
    const additional = target.additionalProperties;
    if (additional === "true") {
      target.additionalProperties = true;
    } else if (additional === "false") {
      target.additionalProperties = false;
    } else if (isRecord(additional)) {
      target.additionalProperties = additional;
    } else {
      target.additionalProperties = { type: "string" };
    }
    return;
  }

  if (action.type === "remove-empty-composition") {
    const entries = target[action.key];
    if (Array.isArray(entries) && !entries.length) {
      delete target[action.key];
    }
    return;
  }

  if (action.type === "normalize-composition-list") {
    const entries = target[action.key];
    if (Array.isArray(entries)) {
      const validEntries = entries.filter(isRecord);
      if (validEntries.length) {
        target[action.key] = validEntries;
      } else {
        delete target[action.key];
      }
      return;
    }
    if (isRecord(entries)) {
      target[action.key] = [entries];
    } else {
      delete target[action.key];
    }
    return;
  }

  if (action.type === "normalize-enum-list") {
    if (target.enum !== undefined && !Array.isArray(target.enum)) {
      target.enum = [target.enum];
    }
    return;
  }

  if (action.type === "dedupe-enum" && Array.isArray(target.enum)) {
    target.enum = uniqueJsonValues(target.enum);
  }
}

function applySchemaReusablePattern(schema: Record<string, unknown>, pattern: SchemaReusablePattern): void {
  schema.type = "object";
  const definitions = ensureSchemaDefinitions(schema);
  if (!definitions[pattern.definitionName]) {
    definitions[pattern.definitionName] = cloneJsonObject(pattern.definitionSchema);
  }
  const properties = ensureSchemaProperties(schema);
  if (!properties[pattern.propertyName]) {
    properties[pattern.propertyName] = cloneJsonObject(pattern.propertySchema);
  }
}

function buildSchemaReusablePatternLibraryItem(
  schema: Record<string, unknown>,
  name: string,
  description: string,
  tags: string[],
): SchemaReusablePatternLibraryItem {
  const clonedSchema = cloneJsonObject(schema);
  const now = new Date().toISOString();
  const schemaHash = simpleHash(stableStringify(clonedSchema));
  const summary = collectSchemaGovernanceSummary(clonedSchema);
  const itemWithoutAssessment: Omit<SchemaReusablePatternLibraryItem, "curationAssessment"> = {
    id: `schema-pattern-${simpleHash([name, schemaHash, now].join("|"))}`,
    name: name.trim(),
    description: description.trim(),
    tags: Array.from(new Set(tags.map((tag) => tag.trim()).filter(Boolean))).sort((left, right) =>
      left.localeCompare(right),
    ),
    curationStatus: "draft",
    curationReviews: [],
    curationThread: defaultSchemaPatternCurationThread(schemaHash),
    createdAt: now,
    updatedAt: now,
    usageCount: 0,
    schemaHash,
    summary,
    schema: clonedSchema,
  };
  return {
    ...itemWithoutAssessment,
    curationAssessment: assessSchemaPatternCuration(itemWithoutAssessment),
  };
}

function applySchemaReusablePatternLibraryItem(
  schema: Record<string, unknown>,
  pattern: SchemaReusablePatternLibraryItem,
): void {
  mergeSchemaReusablePatternSchema(schema, pattern.schema);
}

function mergeSchemaReusablePatternSchema(
  target: Record<string, unknown>,
  source: Record<string, unknown>,
): void {
  target.type = target.type || source.type || "object";
  if (typeof target.title !== "string" && typeof source.title === "string") {
    target.title = source.title;
  }
  if (typeof target.description !== "string" && typeof source.description === "string") {
    target.description = source.description;
  }

  const sourceDefinitions = readSchemaDefinitions(source);
  if (sourceDefinitions.length) {
    const targetDefinitions = ensureSchemaDefinitions(target);
    for (const [name, definition] of sourceDefinitions) {
      if (!targetDefinitions[name]) {
        targetDefinitions[name] = cloneJsonObject(definition);
      }
    }
  }

  const sourceProperties = readSchemaProperties(source);
  if (sourceProperties.length) {
    const targetProperties = ensureSchemaProperties(target);
    for (const [name, property] of sourceProperties) {
      if (!targetProperties[name]) {
        targetProperties[name] = cloneJsonObject(property);
      }
    }
  }

  const nextRequired = Array.from(new Set([...readSchemaRequired(target), ...readSchemaRequired(source)]));
  if (nextRequired.length) {
    target.required = nextRequired;
  }

  for (const key of schemaCompositionKeys) {
    const sourceEntries = Array.isArray(source[key]) ? source[key].filter(isRecord) : [];
    if (!sourceEntries.length) {
      continue;
    }
    const existingEntries = Array.isArray(target[key]) ? target[key].filter(isRecord) : [];
    const existingHashes = new Set(existingEntries.map((entry) => stableStringify(entry)));
    const mergedEntries = [...existingEntries];
    for (const entry of sourceEntries) {
      const hash = stableStringify(entry);
      if (!existingHashes.has(hash)) {
        mergedEntries.push(cloneJsonObject(entry));
        existingHashes.add(hash);
      }
    }
    target[key] = mergedEntries;
  }

  if (target.additionalProperties === undefined && source.additionalProperties !== undefined) {
    target.additionalProperties = isRecord(source.additionalProperties)
      ? cloneJsonObject(source.additionalProperties)
      : source.additionalProperties;
  }
}

function schemaFromReusablePattern(pattern: SchemaReusablePattern): Record<string, unknown> {
  return {
    type: "object",
    properties: {
      [pattern.propertyName]: cloneJsonObject(pattern.propertySchema),
    },
    $defs: {
      [pattern.definitionName]: cloneJsonObject(pattern.definitionSchema),
    },
  };
}

function buildSchemaPatternApplicationPreview(
  target: Record<string, unknown>,
  source: Record<string, unknown>,
): SchemaPatternApplicationPreview {
  const targetProperties = new Map(readSchemaProperties(target));
  const sourceProperties = readSchemaProperties(source);
  const propertyAdditions: string[] = [];
  const propertyConflicts: string[] = [];
  for (const [name, property] of sourceProperties) {
    const existing = targetProperties.get(name);
    if (!existing) {
      propertyAdditions.push(name);
    } else if (stableStringify(existing) !== stableStringify(property)) {
      propertyConflicts.push(name);
    }
  }

  const targetDefinitions = new Map(readSchemaDefinitions(target));
  const sourceDefinitions = readSchemaDefinitions(source);
  const definitionAdditions: string[] = [];
  const definitionConflicts: string[] = [];
  for (const [name, definition] of sourceDefinitions) {
    const existing = targetDefinitions.get(name);
    if (!existing) {
      definitionAdditions.push(name);
    } else if (stableStringify(existing) !== stableStringify(definition)) {
      definitionConflicts.push(name);
    }
  }

  const targetRequired = new Set(readSchemaRequired(target));
  const requiredAdditions = readSchemaRequired(source).filter((name) => !targetRequired.has(name));
  let compositionAdditions = 0;
  for (const key of schemaCompositionKeys) {
    const targetEntries = new Set(readSchemaCompositionList(target, key).map((entry) => stableStringify(entry)));
    compositionAdditions += readSchemaCompositionList(source, key).filter((entry) => !targetEntries.has(stableStringify(entry))).length;
  }

  return {
    propertyAdditions,
    propertyConflicts,
    definitionAdditions,
    definitionConflicts,
    requiredAdditions,
    compositionAdditions,
    additionalPropertiesChange: target.additionalProperties === undefined && source.additionalProperties !== undefined,
    titleOrDescriptionChange:
      (typeof target.title !== "string" && typeof source.title === "string") ||
      (typeof target.description !== "string" && typeof source.description === "string"),
  };
}

function buildSchemaPatternApplicationDiffPackage(
  currentSchema: Record<string, unknown>,
  pattern: SchemaReusablePatternLibraryItem,
  preview: SchemaPatternApplicationPreview,
): SchemaPatternApplicationDiffPackage {
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-application-diff.v1" as const,
    exportedAt: new Date().toISOString(),
    currentSchema: {
      hash: simpleHash(stableStringify(currentSchema)),
      summary: collectSchemaGovernanceSummary(currentSchema),
    },
    pattern: {
      id: pattern.id,
      name: pattern.name,
      description: pattern.description,
      tags: pattern.tags,
      curationStatus: pattern.curationStatus,
      schemaHash: pattern.schemaHash,
      reviewedAt: pattern.reviewedAt ?? null,
      reviewedBy: pattern.reviewedBy ?? null,
      usageCount: pattern.usageCount,
      summary: pattern.summary,
    },
    preview,
    governance: {
      mergeMode: "non_destructive_additive" as const,
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  return {
    ...withoutHash,
    packageHash: simpleHash(stableStringify(withoutHash)),
  };
}

function normalizeSchemaPatternApplicationDiffPackage(value: unknown): SchemaPatternApplicationDiffPackage | null {
  if (!isRecord(value) || value.format !== "agent-flow-builder.schema-pattern-application-diff.v1" || !isRecord(value.currentSchema) || !isRecord(value.pattern)) {
    return null;
  }
  const currentHash = typeof value.currentSchema.hash === "string" && value.currentSchema.hash.trim() ? value.currentSchema.hash.trim() : "";
  const patternId = typeof value.pattern.id === "string" && value.pattern.id.trim() ? value.pattern.id.trim() : "";
  const patternName = typeof value.pattern.name === "string" && value.pattern.name.trim() ? value.pattern.name.trim() : "";
  if (!currentHash || !patternId || !patternName) {
    return null;
  }
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-application-diff.v1" as const,
    exportedAt: typeof value.exportedAt === "string" && value.exportedAt.trim() ? value.exportedAt.trim() : new Date().toISOString(),
    currentSchema: {
      hash: currentHash,
      summary: normalizeSchemaGovernanceSummarySnapshot(value.currentSchema.summary),
    },
    pattern: {
      id: patternId,
      name: patternName,
      description: typeof value.pattern.description === "string" ? value.pattern.description.trim() : "",
      tags: Array.isArray(value.pattern.tags)
        ? Array.from(new Set(value.pattern.tags.filter((tag): tag is string => typeof tag === "string").map((tag) => tag.trim()).filter(Boolean)))
        : [],
      curationStatus: normalizeSchemaPatternCurationStatus(value.pattern.curationStatus),
      schemaHash: typeof value.pattern.schemaHash === "string" && value.pattern.schemaHash.trim() ? value.pattern.schemaHash.trim() : "",
      reviewedAt: typeof value.pattern.reviewedAt === "string" && value.pattern.reviewedAt.trim() ? value.pattern.reviewedAt.trim() : null,
      reviewedBy: typeof value.pattern.reviewedBy === "string" && value.pattern.reviewedBy.trim() ? value.pattern.reviewedBy.trim() : null,
      usageCount: typeof value.pattern.usageCount === "number" && Number.isFinite(value.pattern.usageCount) && value.pattern.usageCount > 0 ? Math.floor(value.pattern.usageCount) : 0,
      summary: normalizeSchemaGovernanceSummarySnapshot(value.pattern.summary),
    },
    preview: normalizeSchemaPatternApplicationPreview(value.preview),
    governance: {
      mergeMode: "non_destructive_additive" as const,
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  const declaredHash =
    typeof value.packageHash === "string" && value.packageHash.trim()
      ? value.packageHash.trim()
      : null;
  const computedHash = simpleHash(stableStringify(withoutHash));
  return {
    ...withoutHash,
    packageHash: declaredHash ?? computedHash,
    integrity: {
      declaredHash,
      computedHash,
      status: declaredHash ? (declaredHash === computedHash ? "verified" : "mismatch") : "missing",
    },
  };
}

function normalizeSchemaPatternApplicationPreview(value: unknown): SchemaPatternApplicationPreview {
  const source = isRecord(value) ? value : {};
  return {
    propertyAdditions: normalizeStringArray(source.propertyAdditions),
    propertyConflicts: normalizeStringArray(source.propertyConflicts),
    definitionAdditions: normalizeStringArray(source.definitionAdditions),
    definitionConflicts: normalizeStringArray(source.definitionConflicts),
    requiredAdditions: normalizeStringArray(source.requiredAdditions),
    compositionAdditions: typeof source.compositionAdditions === "number" && Number.isFinite(source.compositionAdditions) && source.compositionAdditions > 0 ? Math.floor(source.compositionAdditions) : 0,
    additionalPropertiesChange: source.additionalPropertiesChange === true,
    titleOrDescriptionChange: source.titleOrDescriptionChange === true,
  };
}

function normalizeSchemaGovernanceSummarySnapshot(value: unknown): SchemaGovernanceSummary {
  const source = isRecord(value) ? value : {};
  return {
    propertyCount: normalizeNonNegativeNumber(source.propertyCount),
    requiredCount: normalizeNonNegativeNumber(source.requiredCount),
    definitionCount: normalizeNonNegativeNumber(source.definitionCount),
    refCount: normalizeNonNegativeNumber(source.refCount),
    enumCount: normalizeNonNegativeNumber(source.enumCount),
    enumValueCount: normalizeNonNegativeNumber(source.enumValueCount),
    objectCount: normalizeNonNegativeNumber(source.objectCount),
    arrayCount: normalizeNonNegativeNumber(source.arrayCount),
    compositionCount: normalizeNonNegativeNumber(source.compositionCount),
    openAdditionalPropertiesCount: normalizeNonNegativeNumber(source.openAdditionalPropertiesCount),
    lockedAdditionalPropertiesCount: normalizeNonNegativeNumber(source.lockedAdditionalPropertiesCount),
    schemaAdditionalPropertiesCount: normalizeNonNegativeNumber(source.schemaAdditionalPropertiesCount),
    maxDepth: normalizeNonNegativeNumber(source.maxDepth),
  };
}

function normalizeNonNegativeNumber(value: unknown): number {
  return typeof value === "number" && Number.isFinite(value) && value > 0 ? Math.floor(value) : 0;
}

function normalizeStringArray(value: unknown): string[] {
  return Array.isArray(value)
    ? Array.from(new Set(value.filter((item): item is string => typeof item === "string").map((item) => item.trim()).filter(Boolean)))
    : [];
}

function buildSchemaReusablePatternLibraryPackage(
  items: SchemaReusablePatternLibraryItem[],
): SchemaReusablePatternLibraryPackage {
  const normalized = syncSchemaReusablePatternLibrary(items);
  return {
    format: "agent-flow-builder.schema-pattern-library.v1",
    exportedAt: new Date().toISOString(),
    itemCount: normalized.length,
    items: normalized,
  };
}

function buildSchemaPatternLibraryHistorySnapshot(
  patterns: SchemaReusablePatternLibraryItem[],
  currentSchemaHash: string,
): SchemaPatternLibraryHistorySnapshot {
  const capturedAt = new Date().toISOString();
  const items = syncSchemaReusablePatternLibrary(patterns).map(schemaPatternLibraryHistoryItemFromPattern);
  const tagCount = new Set(items.flatMap((item) => item.tags)).size;
  const draftCount = items.filter((item) => item.curationStatus === "draft").length;
  const approvedCount = items.filter((item) => item.curationStatus === "approved").length;
  const deprecatedCount = items.filter((item) => item.curationStatus === "deprecated").length;
  const baseHash = simpleHash(stableStringify({
    capturedAt,
    currentSchemaHash,
    items,
  }));
  const withoutHash = {
    id: `schema-pattern-history-${baseHash}`,
    capturedAt,
    currentSchemaHash,
    itemCount: items.length,
    draftCount,
    approvedCount,
    deprecatedCount,
    totalUsageCount: items.reduce((total, item) => total + item.usageCount, 0),
    tagCount,
    items,
  };
  return {
    ...withoutHash,
    snapshotHash: simpleHash(stableStringify(withoutHash)),
  };
}

function schemaPatternLibraryHistoryItemFromPattern(
  pattern: SchemaReusablePatternLibraryItem,
): SchemaPatternLibraryHistoryItem {
  return {
    id: pattern.id,
    name: pattern.name,
    tags: pattern.tags,
    curationStatus: pattern.curationStatus,
    curationAssessment: pattern.curationAssessment,
    curationReviews: pattern.curationReviews,
    curationThread: pattern.curationThread,
    schemaHash: pattern.schemaHash,
    reviewedAt: pattern.reviewedAt ?? null,
    reviewedBy: pattern.reviewedBy ?? null,
    lastUsedAt: pattern.lastUsedAt ?? null,
    usageCount: pattern.usageCount,
    summary: pattern.summary,
  };
}

function buildSchemaPatternLibraryHistoryPackage(
  snapshots: SchemaPatternLibraryHistorySnapshot[],
): SchemaPatternLibraryHistoryPackage {
  const normalized = syncSchemaPatternLibraryHistory(snapshots);
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-library-history.v1" as const,
    exportedAt: new Date().toISOString(),
    snapshotCount: normalized.length,
    snapshots: normalized,
    governance: {
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  return {
    ...withoutHash,
    packageHash: simpleHash(stableStringify(withoutHash)),
  };
}

function buildSchemaPatternLibraryHistoryDiffPackage(
  fromSnapshot: SchemaPatternLibraryHistorySnapshot,
  toSnapshot: SchemaPatternLibraryHistorySnapshot,
): SchemaPatternLibraryHistoryDiffPackage {
  const fromItems = new Map(fromSnapshot.items.map((item) => [item.id, item]));
  const toItems = new Map(toSnapshot.items.map((item) => [item.id, item]));
  const added = toSnapshot.items.filter((item) => !fromItems.has(item.id));
  const removed = fromSnapshot.items.filter((item) => !toItems.has(item.id));
  const changed: SchemaPatternLibraryHistoryDiffEntry[] = [];
  for (const [id, toItem] of toItems) {
    const fromItem = fromItems.get(id);
    if (!fromItem) {
      continue;
    }
    const tagsBefore = fromItem.tags;
    const tagsAfter = toItem.tags;
    const hasChange =
      fromItem.schemaHash !== toItem.schemaHash ||
      fromItem.curationStatus !== toItem.curationStatus ||
      fromItem.usageCount !== toItem.usageCount ||
      fromItem.reviewedBy !== toItem.reviewedBy ||
      fromItem.lastUsedAt !== toItem.lastUsedAt ||
      stableStringify(fromItem.curationReviews) !== stableStringify(toItem.curationReviews) ||
      stableStringify(fromItem.curationThread) !== stableStringify(toItem.curationThread) ||
      stableStringify(tagsBefore) !== stableStringify(tagsAfter);
    if (!hasChange) {
      continue;
    }
    changed.push({
      id,
      name: toItem.name || fromItem.name,
      schemaHashBefore: fromItem.schemaHash,
      schemaHashAfter: toItem.schemaHash,
      curationStatusBefore: fromItem.curationStatus,
      curationStatusAfter: toItem.curationStatus,
      usageCountBefore: fromItem.usageCount,
      usageCountAfter: toItem.usageCount,
      usageDelta: toItem.usageCount - fromItem.usageCount,
      tagsBefore,
      tagsAfter,
      reviewedByBefore: fromItem.reviewedBy,
      reviewedByAfter: toItem.reviewedBy,
      lastUsedAtBefore: fromItem.lastUsedAt,
      lastUsedAtAfter: toItem.lastUsedAt,
      reviewCountBefore: fromItem.curationReviews.length,
      reviewCountAfter: toItem.curationReviews.length,
      latestReviewDecisionBefore: fromItem.curationReviews[0]?.decision ?? null,
      latestReviewDecisionAfter: toItem.curationReviews[0]?.decision ?? null,
      curationThreadStatusBefore: fromItem.curationThread.status,
      curationThreadStatusAfter: toItem.curationThread.status,
      curationThreadAssigneeBefore: fromItem.curationThread.assignee,
      curationThreadAssigneeAfter: toItem.curationThread.assignee,
      curationThreadUpdatedAtBefore: fromItem.curationThread.updatedAt,
      curationThreadUpdatedAtAfter: toItem.curationThread.updatedAt,
    });
  }
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-library-history-diff.v1" as const,
    exportedAt: new Date().toISOString(),
    fromSnapshot: schemaPatternLibraryHistorySnapshotRef(fromSnapshot),
    toSnapshot: schemaPatternLibraryHistorySnapshotRef(toSnapshot),
    summary: {
      addedCount: added.length,
      removedCount: removed.length,
      changedCount: changed.length,
      statusChangedCount: changed.filter((item) => item.curationStatusBefore !== item.curationStatusAfter).length,
      usageChangedCount: changed.filter((item) => item.usageCountBefore !== item.usageCountAfter).length,
      tagChangedCount: changed.filter((item) => stableStringify(item.tagsBefore) !== stableStringify(item.tagsAfter)).length,
      schemaHashChangedCount: changed.filter((item) => item.schemaHashBefore !== item.schemaHashAfter).length,
      curationThreadChangedCount: changed.filter((item) =>
        item.curationThreadStatusBefore !== item.curationThreadStatusAfter ||
        item.curationThreadAssigneeBefore !== item.curationThreadAssigneeAfter ||
        item.curationThreadUpdatedAtBefore !== item.curationThreadUpdatedAtAfter
      ).length,
    },
    added,
    removed,
    changed,
    governance: {
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  return {
    ...withoutHash,
    packageHash: simpleHash(stableStringify(withoutHash)),
  };
}

function schemaPatternLibraryHistorySnapshotRef(snapshot: SchemaPatternLibraryHistorySnapshot) {
  return {
    snapshotHash: snapshot.snapshotHash,
    capturedAt: snapshot.capturedAt,
    currentSchemaHash: snapshot.currentSchemaHash,
    itemCount: snapshot.itemCount,
  };
}

function normalizeSchemaPatternLibraryHistoryDiffPackage(
  value: unknown,
): SchemaPatternLibraryHistoryDiffPackage | null {
  if (
    !isRecord(value) ||
    value.format !== "agent-flow-builder.schema-pattern-library-history-diff.v1" ||
    !isRecord(value.fromSnapshot) ||
    !isRecord(value.toSnapshot)
  ) {
    return null;
  }
  const fromSnapshot = normalizeSchemaPatternLibraryHistorySnapshotRef(value.fromSnapshot);
  const toSnapshot = normalizeSchemaPatternLibraryHistorySnapshotRef(value.toSnapshot);
  if (!fromSnapshot || !toSnapshot) {
    return null;
  }
  const added = Array.isArray(value.added)
    ? value.added
        .map(normalizeSchemaPatternLibraryHistoryItem)
        .filter((entry): entry is SchemaPatternLibraryHistoryItem => entry !== null)
    : [];
  const removed = Array.isArray(value.removed)
    ? value.removed
        .map(normalizeSchemaPatternLibraryHistoryItem)
        .filter((entry): entry is SchemaPatternLibraryHistoryItem => entry !== null)
    : [];
  const changed = Array.isArray(value.changed)
    ? value.changed
        .map(normalizeSchemaPatternLibraryHistoryDiffEntry)
        .filter((entry): entry is SchemaPatternLibraryHistoryDiffEntry => entry !== null)
    : [];
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-library-history-diff.v1" as const,
    exportedAt: typeof value.exportedAt === "string" && value.exportedAt.trim()
      ? value.exportedAt.trim()
      : new Date().toISOString(),
    fromSnapshot,
    toSnapshot,
    summary: {
      addedCount: added.length,
      removedCount: removed.length,
      changedCount: changed.length,
      statusChangedCount: changed.filter((item) => item.curationStatusBefore !== item.curationStatusAfter).length,
      usageChangedCount: changed.filter((item) => item.usageCountBefore !== item.usageCountAfter).length,
      tagChangedCount: changed.filter((item) => stableStringify(item.tagsBefore) !== stableStringify(item.tagsAfter)).length,
      schemaHashChangedCount: changed.filter((item) => item.schemaHashBefore !== item.schemaHashAfter).length,
      curationThreadChangedCount: changed.filter((item) =>
        item.curationThreadStatusBefore !== item.curationThreadStatusAfter ||
        item.curationThreadAssigneeBefore !== item.curationThreadAssigneeAfter ||
        item.curationThreadUpdatedAtBefore !== item.curationThreadUpdatedAtAfter
      ).length,
    },
    added,
    removed,
    changed,
    governance: {
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  const declaredHash =
    typeof value.packageHash === "string" && value.packageHash.trim()
      ? value.packageHash.trim()
      : null;
  const computedHash = simpleHash(stableStringify(withoutHash));
  return {
    ...withoutHash,
    packageHash: declaredHash ?? computedHash,
    integrity: {
      declaredHash,
      computedHash,
      status: declaredHash ? (declaredHash === computedHash ? "verified" : "mismatch") : "missing",
    },
  };
}

function normalizeSchemaPatternLibraryHistorySnapshotRef(value: unknown) {
  if (!isRecord(value)) {
    return null;
  }
  const snapshotHash =
    typeof value.snapshotHash === "string" && value.snapshotHash.trim()
      ? value.snapshotHash.trim()
      : "";
  if (!snapshotHash) {
    return null;
  }
  return {
    snapshotHash,
    capturedAt: typeof value.capturedAt === "string" && value.capturedAt.trim()
      ? value.capturedAt.trim()
      : new Date().toISOString(),
    currentSchemaHash: typeof value.currentSchemaHash === "string" && value.currentSchemaHash.trim()
      ? value.currentSchemaHash.trim()
      : "",
    itemCount: normalizeNonNegativeNumber(value.itemCount),
  };
}

function normalizeSchemaPatternLibraryHistoryDiffEntry(value: unknown): SchemaPatternLibraryHistoryDiffEntry | null {
  if (!isRecord(value)) {
    return null;
  }
  const id = typeof value.id === "string" && value.id.trim() ? value.id.trim() : "";
  const name = typeof value.name === "string" && value.name.trim() ? value.name.trim() : "";
  if (!id || !name) {
    return null;
  }
  const usageCountBefore = normalizeNonNegativeNumber(value.usageCountBefore);
  const usageCountAfter = normalizeNonNegativeNumber(value.usageCountAfter);
  return {
    id,
    name,
    schemaHashBefore: typeof value.schemaHashBefore === "string" && value.schemaHashBefore.trim() ? value.schemaHashBefore.trim() : "",
    schemaHashAfter: typeof value.schemaHashAfter === "string" && value.schemaHashAfter.trim() ? value.schemaHashAfter.trim() : "",
    curationStatusBefore: normalizeSchemaPatternCurationStatus(value.curationStatusBefore),
    curationStatusAfter: normalizeSchemaPatternCurationStatus(value.curationStatusAfter),
    usageCountBefore,
    usageCountAfter,
    usageDelta: typeof value.usageDelta === "number" && Number.isFinite(value.usageDelta)
      ? Math.trunc(value.usageDelta)
      : usageCountAfter - usageCountBefore,
    tagsBefore: normalizeStringArray(value.tagsBefore).sort((left, right) => left.localeCompare(right)),
    tagsAfter: normalizeStringArray(value.tagsAfter).sort((left, right) => left.localeCompare(right)),
    reviewedByBefore: typeof value.reviewedByBefore === "string" && value.reviewedByBefore.trim() ? value.reviewedByBefore.trim() : null,
    reviewedByAfter: typeof value.reviewedByAfter === "string" && value.reviewedByAfter.trim() ? value.reviewedByAfter.trim() : null,
    lastUsedAtBefore: typeof value.lastUsedAtBefore === "string" && value.lastUsedAtBefore.trim() ? value.lastUsedAtBefore.trim() : null,
    lastUsedAtAfter: typeof value.lastUsedAtAfter === "string" && value.lastUsedAtAfter.trim() ? value.lastUsedAtAfter.trim() : null,
    reviewCountBefore: normalizeNonNegativeNumber(value.reviewCountBefore),
    reviewCountAfter: normalizeNonNegativeNumber(value.reviewCountAfter),
    latestReviewDecisionBefore: normalizeSchemaPatternCurationReviewDecision(value.latestReviewDecisionBefore),
    latestReviewDecisionAfter: normalizeSchemaPatternCurationReviewDecision(value.latestReviewDecisionAfter),
    curationThreadStatusBefore: normalizeSchemaPatternCurationThreadStatus(value.curationThreadStatusBefore) ?? "unassigned",
    curationThreadStatusAfter: normalizeSchemaPatternCurationThreadStatus(value.curationThreadStatusAfter) ?? "unassigned",
    curationThreadAssigneeBefore: typeof value.curationThreadAssigneeBefore === "string" && value.curationThreadAssigneeBefore.trim()
      ? value.curationThreadAssigneeBefore.trim()
      : "",
    curationThreadAssigneeAfter: typeof value.curationThreadAssigneeAfter === "string" && value.curationThreadAssigneeAfter.trim()
      ? value.curationThreadAssigneeAfter.trim()
      : "",
    curationThreadUpdatedAtBefore: typeof value.curationThreadUpdatedAtBefore === "string" && value.curationThreadUpdatedAtBefore.trim()
      ? value.curationThreadUpdatedAtBefore.trim()
      : null,
    curationThreadUpdatedAtAfter: typeof value.curationThreadUpdatedAtAfter === "string" && value.curationThreadUpdatedAtAfter.trim()
      ? value.curationThreadUpdatedAtAfter.trim()
      : null,
  };
}

function normalizeSchemaPatternLibraryHistoryPackage(
  value: unknown,
): SchemaPatternLibraryHistoryPackage | null {
  if (
    !isRecord(value) ||
    value.format !== "agent-flow-builder.schema-pattern-library-history.v1" ||
    !Array.isArray(value.snapshots)
  ) {
    return null;
  }
  const normalized = syncSchemaPatternLibraryHistory(value.snapshots);
  const withoutHash = {
    format: "agent-flow-builder.schema-pattern-library-history.v1" as const,
    exportedAt: typeof value.exportedAt === "string" && value.exportedAt.trim()
      ? value.exportedAt.trim()
      : new Date().toISOString(),
    snapshotCount: normalized.length,
    snapshots: normalized,
    governance: {
      excludesRawSchemaContent: true as const,
      excludesSecretValues: true as const,
    },
  };
  const sharedSync = normalizeSchemaPatternSharedSyncInfo(value.sharedSync);
  return {
    ...withoutHash,
    packageHash:
      typeof value.packageHash === "string" && value.packageHash.trim()
        ? value.packageHash.trim()
        : simpleHash(stableStringify(withoutHash)),
    ...(sharedSync ? { sharedSync } : {}),
  };
}

function syncSchemaPatternLibraryHistory(
  snapshots: unknown[],
): SchemaPatternLibraryHistorySnapshot[] {
  const byHash = new Map<string, SchemaPatternLibraryHistorySnapshot>();
  for (const snapshot of snapshots
    .map(normalizeSchemaPatternLibraryHistorySnapshot)
    .filter((entry): entry is SchemaPatternLibraryHistorySnapshot => entry !== null)) {
    const existing = byHash.get(snapshot.snapshotHash);
    if (!existing || Date.parse(existing.capturedAt) <= Date.parse(snapshot.capturedAt)) {
      byHash.set(snapshot.snapshotHash, snapshot);
    }
  }
  return Array.from(byHash.values()).sort((left, right) => {
    const leftTime = Date.parse(left.capturedAt);
    const rightTime = Date.parse(right.capturedAt);
    if (leftTime !== rightTime) {
      return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
    }
    return left.snapshotHash.localeCompare(right.snapshotHash);
  });
}

function normalizeSchemaPatternLibraryHistorySnapshot(
  value: unknown,
): SchemaPatternLibraryHistorySnapshot | null {
  if (!isRecord(value) || !Array.isArray(value.items)) {
    return null;
  }
  const items = value.items
    .map(normalizeSchemaPatternLibraryHistoryItem)
    .filter((entry): entry is SchemaPatternLibraryHistoryItem => entry !== null);
  const capturedAt =
    typeof value.capturedAt === "string" && value.capturedAt.trim()
      ? value.capturedAt.trim()
      : new Date().toISOString();
  const currentSchemaHash =
    typeof value.currentSchemaHash === "string" && value.currentSchemaHash.trim()
      ? value.currentSchemaHash.trim()
      : "";
  const id =
    typeof value.id === "string" && value.id.trim()
      ? value.id.trim()
      : `schema-pattern-history-${simpleHash(stableStringify({ capturedAt, currentSchemaHash, items }))}`;
  const draftCount = items.filter((item) => item.curationStatus === "draft").length;
  const approvedCount = items.filter((item) => item.curationStatus === "approved").length;
  const deprecatedCount = items.filter((item) => item.curationStatus === "deprecated").length;
  const withoutHash = {
    id,
    capturedAt,
    currentSchemaHash,
    itemCount: items.length,
    draftCount,
    approvedCount,
    deprecatedCount,
    totalUsageCount: items.reduce((total, item) => total + item.usageCount, 0),
    tagCount: new Set(items.flatMap((item) => item.tags)).size,
    items,
  };
  return {
    ...withoutHash,
    snapshotHash: simpleHash(stableStringify(withoutHash)),
  };
}

function normalizeSchemaPatternLibraryHistoryItem(value: unknown): SchemaPatternLibraryHistoryItem | null {
  if (!isRecord(value)) {
    return null;
  }
  const id = typeof value.id === "string" && value.id.trim() ? value.id.trim() : "";
  const name = typeof value.name === "string" && value.name.trim() ? value.name.trim() : "";
  if (!id || !name) {
    return null;
  }
  const tags = normalizeStringArray(value.tags).sort((left, right) => left.localeCompare(right));
  const curationStatus = normalizeSchemaPatternCurationStatus(value.curationStatus);
  const reviewedAt = typeof value.reviewedAt === "string" && value.reviewedAt.trim() ? value.reviewedAt.trim() : null;
  const usageCount = normalizeNonNegativeNumber(value.usageCount);
  const summary = normalizeSchemaGovernanceSummarySnapshot(value.summary);
  const curationReviews = syncSchemaPatternCurationReviews(value.curationReviews);
  const schemaHash = typeof value.schemaHash === "string" && value.schemaHash.trim() ? value.schemaHash.trim() : "";
  return {
    id,
    name,
    tags,
    curationStatus,
    curationAssessment: normalizeSchemaPatternCurationAssessment(value.curationAssessment) ?? assessSchemaPatternCuration({
      name,
      description: "",
      tags,
      curationStatus,
      reviewedAt,
      usageCount,
      summary,
    }),
    curationReviews,
    curationThread: normalizeSchemaPatternCurationThread(value.curationThread, schemaHash, curationReviews),
    schemaHash,
    reviewedAt,
    reviewedBy: typeof value.reviewedBy === "string" && value.reviewedBy.trim() ? value.reviewedBy.trim() : null,
    lastUsedAt: typeof value.lastUsedAt === "string" && value.lastUsedAt.trim() ? value.lastUsedAt.trim() : null,
    usageCount,
    summary,
  };
}

function persistSchemaReusablePatternLibrary(
  items: SchemaReusablePatternLibraryItem[],
): SchemaReusablePatternLibraryItem[] {
  const normalized = syncSchemaReusablePatternLibrary(items).slice(0, 64);
  if (typeof window !== "undefined") {
    window.localStorage.setItem(
      schemaReusablePatternLibraryStorageKey,
      JSON.stringify(buildSchemaReusablePatternLibraryPackage(normalized)),
    );
  }
  return normalized;
}

function persistSchemaPatternLibraryHistory(
  snapshots: SchemaPatternLibraryHistorySnapshot[],
): SchemaPatternLibraryHistorySnapshot[] {
  const normalized = syncSchemaPatternLibraryHistory(snapshots).slice(0, 32);
  if (typeof window !== "undefined") {
    window.localStorage.setItem(
      schemaPatternLibraryHistoryStorageKey,
      JSON.stringify(buildSchemaPatternLibraryHistoryPackage(normalized)),
    );
  }
  return normalized;
}

function loadSchemaReusablePatternLibrary(): SchemaReusablePatternLibraryItem[] {
  if (typeof window === "undefined") {
    return [];
  }
  const raw = window.localStorage.getItem(schemaReusablePatternLibraryStorageKey);
  if (!raw) {
    return [];
  }
  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      return syncSchemaReusablePatternLibrary(parsed);
    }
    return normalizeSchemaReusablePatternLibraryPackage(parsed)?.items ?? [];
  } catch {
    return [];
  }
}

function loadSchemaPatternLibraryHistory(): SchemaPatternLibraryHistorySnapshot[] {
  if (typeof window === "undefined") {
    return [];
  }
  const raw = window.localStorage.getItem(schemaPatternLibraryHistoryStorageKey);
  if (!raw) {
    return [];
  }
  try {
    const packageValue = normalizeSchemaPatternLibraryHistoryPackage(JSON.parse(raw) as unknown);
    return packageValue?.snapshots ?? [];
  } catch {
    return [];
  }
}

function loadSchemaPatternCuratorName(): string {
  if (typeof window === "undefined") {
    return "local-user";
  }
  return normalizeStudioAnnotationReviewerName(
    window.localStorage.getItem(schemaPatternCuratorNameStorageKey) ?? "local-user",
  );
}

function loadSchemaPatternCuratorRole(): StudioAnnotationReviewerRole {
  if (typeof window === "undefined") {
    return "reviewer";
  }
  return normalizeStudioAnnotationReviewerRole(window.localStorage.getItem(schemaPatternCuratorRoleStorageKey));
}

function loadCatalogCuratorName(): string {
  if (typeof window === "undefined") {
    return "local-user";
  }
  return normalizeStudioAnnotationReviewerName(
    window.localStorage.getItem(catalogCuratorNameStorageKey) ?? "local-user",
  );
}

function loadCatalogCuratorRole(): StudioAnnotationReviewerRole {
  if (typeof window === "undefined") {
    return "reviewer";
  }
  return normalizeStudioAnnotationReviewerRole(window.localStorage.getItem(catalogCuratorRoleStorageKey));
}

function normalizeSchemaReusablePatternLibraryPackage(
  value: unknown,
): SchemaReusablePatternLibraryPackage | null {
  if (
    !isRecord(value) ||
    value.format !== "agent-flow-builder.schema-pattern-library.v1" ||
    !Array.isArray(value.items)
  ) {
    return null;
  }
  const items = syncSchemaReusablePatternLibrary(value.items);
  const sharedSync = normalizeSchemaPatternSharedSyncInfo(value.sharedSync);
  const conflicts = Array.isArray(value.conflicts)
    ? value.conflicts
        .map(normalizeSchemaPatternLibraryConflict)
        .filter((entry): entry is SchemaPatternLibraryConflict => entry !== null)
    : [];
  return {
    format: "agent-flow-builder.schema-pattern-library.v1",
    exportedAt: typeof value.exportedAt === "string" ? value.exportedAt : new Date().toISOString(),
    itemCount: items.length,
    items,
    conflictCount: conflicts.length,
    openConflictCount: conflicts.filter((conflict) => conflict.status === "open").length,
    conflicts,
    ...(typeof value.packageHash === "string" && value.packageHash.trim() ? { packageHash: value.packageHash.trim() } : {}),
    ...(sharedSync ? { sharedSync } : {}),
  };
}

function normalizeSchemaPatternLibraryConflict(value: unknown): SchemaPatternLibraryConflict | null {
  if (!isRecord(value)) {
    return null;
  }
  const id = typeof value.id === "string" && value.id.trim() ? value.id.trim() : "";
  const itemId = typeof value.itemId === "string" && value.itemId.trim() ? value.itemId.trim() : "";
  const existingSnapshot = normalizeSchemaPatternLibraryConflictSnapshot(value.existingSnapshot);
  const incomingSnapshot = normalizeSchemaPatternLibraryConflictSnapshot(value.incomingSnapshot);
  if (!id || !itemId || !existingSnapshot || !incomingSnapshot) {
    return null;
  }
  return {
    id,
    itemId,
    status: value.status === "resolved" ? "resolved" : "open",
    reason: typeof value.reason === "string" && value.reason.trim() ? value.reason.trim() : "metadados",
    existingSnapshot,
    incomingSnapshot,
    schemaMergePlan: normalizeSchemaPatternConflictMergePlan(value.schemaMergePlan, existingSnapshot, incomingSnapshot),
    existingUpdatedAt: typeof value.existingUpdatedAt === "string" && value.existingUpdatedAt.trim() ? value.existingUpdatedAt.trim() : existingSnapshot.updatedAt,
    incomingUpdatedAt: typeof value.incomingUpdatedAt === "string" && value.incomingUpdatedAt.trim() ? value.incomingUpdatedAt.trim() : incomingSnapshot.updatedAt,
    createdAt: typeof value.createdAt === "string" && value.createdAt.trim() ? value.createdAt.trim() : new Date().toISOString(),
    resolvedAt: typeof value.resolvedAt === "string" && value.resolvedAt.trim() ? value.resolvedAt.trim() : null,
    resolvedBy: typeof value.resolvedBy === "string" && value.resolvedBy.trim() ? value.resolvedBy.trim() : "",
    resolution: normalizeSchemaPatternConflictResolution(value.resolution),
    resolutionNote: typeof value.resolutionNote === "string" && value.resolutionNote.trim() ? value.resolutionNote.trim() : "",
    resolutionPlan: normalizeSchemaPatternConflictResolutionPlan(value.resolutionPlan),
    rawSchemaTextDiff: normalizeSchemaPatternRawSchemaTextDiff(value.rawSchemaTextDiff),
  };
}

function normalizeSchemaPatternRawSchemaTextDiff(value: unknown): SchemaPatternRawSchemaTextDiff | undefined {
  if (
    !isRecord(value) ||
    value.format !== "agent-flow-builder.schema-pattern-raw-text-diff.local.v1" ||
    !Array.isArray(value.rows)
  ) {
    return undefined;
  }
  const rows = value.rows
    .map(normalizeSchemaPatternRawSchemaTextDiffRow)
    .filter((row): row is SchemaPatternRawSchemaTextDiffRow => row !== null);
  return {
    format: "agent-flow-builder.schema-pattern-raw-text-diff.local.v1",
    generatedAt: typeof value.generatedAt === "string" && value.generatedAt.trim() ? value.generatedAt.trim() : "",
    existingSchemaHash: typeof value.existingSchemaHash === "string" && value.existingSchemaHash.trim() ? value.existingSchemaHash.trim() : "",
    incomingSchemaHash: typeof value.incomingSchemaHash === "string" && value.incomingSchemaHash.trim() ? value.incomingSchemaHash.trim() : "",
    rowCount: normalizeNonNegativeNumber(value.rowCount) || rows.length,
    changedRowCount: normalizeNonNegativeNumber(value.changedRowCount) || rows.filter((row) => row.status !== "same").length,
    rows,
    governance: {
      localOnly: true,
      excludedFromSharedStorage: true,
      excludedFromExportsByDefault: true,
      containsRawSchemaContent: true,
      excludesSecretValues: false,
    },
  };
}

function normalizeSchemaPatternRawSchemaTextDiffRow(value: unknown): SchemaPatternRawSchemaTextDiffRow | null {
  if (!isRecord(value)) {
    return null;
  }
  const status = normalizeSchemaPatternRawSchemaTextDiffStatus(value.status);
  if (!status) {
    return null;
  }
  return {
    leftLine: typeof value.leftLine === "number" && Number.isFinite(value.leftLine) && value.leftLine > 0
      ? Math.floor(value.leftLine)
      : null,
    rightLine: typeof value.rightLine === "number" && Number.isFinite(value.rightLine) && value.rightLine > 0
      ? Math.floor(value.rightLine)
      : null,
    leftText: typeof value.leftText === "string" ? value.leftText : "",
    rightText: typeof value.rightText === "string" ? value.rightText : "",
    status,
  };
}

function normalizeSchemaPatternRawSchemaTextDiffStatus(
  value: unknown,
): SchemaPatternRawSchemaTextDiffRow["status"] | null {
  return value === "same" || value === "changed" || value === "added" || value === "removed" ? value : null;
}

function normalizeSchemaPatternConflictMergePlan(
  value: unknown,
  existingSnapshot: SchemaPatternLibraryConflictSnapshot,
  incomingSnapshot: SchemaPatternLibraryConflictSnapshot,
): SchemaPatternLibraryConflictMergePlan {
  if (!isRecord(value)) {
    return {
      canAutoMerge: false,
      schemaChanged: existingSnapshot.schemaHash !== incomingSnapshot.schemaHash,
      propertyAdditions: [],
      propertyExistingOnly: [],
      propertyConflicts: [],
      definitionAdditions: [],
      definitionExistingOnly: [],
      definitionConflicts: [],
      requiredAdditions: [],
      requiredExistingOnly: [],
      compositionAdditions: 0,
      compositionExistingOnly: 0,
      additionalPropertiesChange: false,
      additionalPropertiesExistingOnly: false,
      additionalPropertiesConflict: existingSnapshot.schemaHash !== incomingSnapshot.schemaHash,
      governance: {
        excludesRawSchemaContent: true,
        excludesSecretValues: true,
      },
    };
  }
  return {
    canAutoMerge: value.canAutoMerge === true,
    schemaChanged: value.schemaChanged === true || existingSnapshot.schemaHash !== incomingSnapshot.schemaHash,
    propertyAdditions: normalizeStringArray(value.propertyAdditions).sort((left, right) => left.localeCompare(right)),
    propertyExistingOnly: normalizeStringArray(value.propertyExistingOnly).sort((left, right) => left.localeCompare(right)),
    propertyConflicts: normalizeStringArray(value.propertyConflicts).sort((left, right) => left.localeCompare(right)),
    definitionAdditions: normalizeStringArray(value.definitionAdditions).sort((left, right) => left.localeCompare(right)),
    definitionExistingOnly: normalizeStringArray(value.definitionExistingOnly).sort((left, right) => left.localeCompare(right)),
    definitionConflicts: normalizeStringArray(value.definitionConflicts).sort((left, right) => left.localeCompare(right)),
    requiredAdditions: normalizeStringArray(value.requiredAdditions).sort((left, right) => left.localeCompare(right)),
    requiredExistingOnly: normalizeStringArray(value.requiredExistingOnly).sort((left, right) => left.localeCompare(right)),
    compositionAdditions: normalizeNonNegativeNumber(value.compositionAdditions),
    compositionExistingOnly: normalizeNonNegativeNumber(value.compositionExistingOnly),
    additionalPropertiesChange: value.additionalPropertiesChange === true,
    additionalPropertiesExistingOnly: value.additionalPropertiesExistingOnly === true,
    additionalPropertiesConflict: value.additionalPropertiesConflict === true,
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function normalizeSchemaPatternConflictResolution(value: unknown): SchemaPatternLibraryConflictResolution | null {
  return value === "accept_current_library" ||
    value === "accept_existing_snapshot" ||
    value === "accept_incoming_snapshot" ||
    value === "apply_manual_schema_merge"
    ? value
    : null;
}

function normalizeSchemaPatternConflictResolutionPlan(
  value: unknown,
): SchemaPatternLibraryConflictResolutionPlan | null {
  if (!isRecord(value)) {
    return null;
  }
  const selectedSnapshot = normalizeSchemaPatternConflictSelectedSnapshot(value.selectedSnapshot);
  const requestedResolution = normalizeSchemaPatternConflictResolution(value.requestedResolution);
  const schemaContentAction = normalizeSchemaPatternConflictSchemaAction(value.schemaContentAction);
  const metadataAction = normalizeSchemaPatternConflictMetadataAction(value.metadataAction);
  if (!selectedSnapshot || !requestedResolution || !schemaContentAction || !metadataAction) {
    return null;
  }
  return {
    selectedSnapshot,
    requestedResolution,
    currentSchemaHash: typeof value.currentSchemaHash === "string" && value.currentSchemaHash.trim() ? value.currentSchemaHash.trim() : "",
    selectedSchemaHash: typeof value.selectedSchemaHash === "string" && value.selectedSchemaHash.trim() ? value.selectedSchemaHash.trim() : "",
    schemaContentAction,
    metadataAction,
    metadataFieldsChanged: normalizeStringArray(value.metadataFieldsChanged).sort((left, right) => left.localeCompare(right)),
    requiresManualSchemaReview: value.requiresManualSchemaReview === true,
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function normalizeSchemaPatternConflictSelectedSnapshot(
  value: unknown,
): SchemaPatternLibraryConflictSelectedSnapshot | null {
  return value === "current_library" || value === "existing_snapshot" || value === "incoming_snapshot" ? value : null;
}

function normalizeSchemaPatternConflictSchemaAction(value: unknown): SchemaPatternLibraryConflictSchemaAction | null {
  return value === "current_schema_retained" ||
    value === "selected_schema_already_current" ||
    value === "manual_schema_reapply_required" ||
    value === "manual_schema_merge_applied"
    ? value
    : null;
}

function normalizeSchemaPatternConflictMetadataAction(value: unknown): SchemaPatternLibraryConflictMetadataAction | null {
  return value === "current_metadata_retained" ||
    value === "selected_metadata_already_current" ||
    value === "selected_metadata_applied" ||
    value === "manual_schema_review_first"
    ? value
    : null;
}

function normalizeSchemaPatternLibraryConflictSnapshot(value: unknown): SchemaPatternLibraryConflictSnapshot | null {
  if (!isRecord(value)) {
    return null;
  }
  const id = typeof value.id === "string" && value.id.trim() ? value.id.trim() : "";
  const name = typeof value.name === "string" && value.name.trim() ? value.name.trim() : "";
  if (!id || !name) {
    return null;
  }
  const schemaHash = typeof value.schemaHash === "string" && value.schemaHash.trim() ? value.schemaHash.trim() : "";
  return {
    id,
    name,
    tags: normalizeStringArray(value.tags).sort((left, right) => left.localeCompare(right)),
    curationStatus: normalizeSchemaPatternCurationStatus(value.curationStatus),
    curationThread: normalizeSchemaPatternCurationThread(value.curationThread, schemaHash, []),
    schemaHash,
    updatedAt: typeof value.updatedAt === "string" && value.updatedAt.trim() ? value.updatedAt.trim() : "",
    reviewedAt: typeof value.reviewedAt === "string" && value.reviewedAt.trim() ? value.reviewedAt.trim() : null,
    reviewedBy: typeof value.reviewedBy === "string" && value.reviewedBy.trim() ? value.reviewedBy.trim() : null,
    lastUsedAt: typeof value.lastUsedAt === "string" && value.lastUsedAt.trim() ? value.lastUsedAt.trim() : null,
    usageCount: normalizeNonNegativeNumber(value.usageCount),
    summary: isRecord(value.summary) ? normalizeSchemaGovernanceSummarySnapshot(value.summary) : null,
  };
}

function normalizeSchemaPatternSharedSyncInfo(value: unknown): SchemaPatternSharedSyncInfo | null {
  if (!isRecord(value)) {
    return null;
  }
  const action = normalizeSchemaPatternSharedSyncAction(value.action);
  const subject = value.subject === "library" || value.subject === "history" ? value.subject : null;
  const updatedAt = typeof value.updatedAt === "string" && value.updatedAt.trim() ? value.updatedAt.trim() : "";
  const storage = typeof value.storage === "string" && value.storage.trim() ? value.storage.trim() : "";
  const contentHash = typeof value.contentHash === "string" && value.contentHash.trim() ? value.contentHash.trim() : "";
  if (!action || !subject || !updatedAt || !storage || !contentHash) {
    return null;
  }
  const governance = isRecord(value.governance) ? value.governance : {};
  return {
    action,
    subject,
    updatedAt,
    storage,
    contentHash,
    incomingCount: normalizeNonNegativeNumber(value.incomingCount),
    existingCount: normalizeNonNegativeNumber(value.existingCount),
    addedCount: normalizeNonNegativeNumber(value.addedCount),
    updatedCount: normalizeNonNegativeNumber(value.updatedCount),
    unchangedCount: normalizeNonNegativeNumber(value.unchangedCount),
    conflictCount: normalizeNonNegativeNumber(value.conflictCount),
    finalCount: normalizeNonNegativeNumber(value.finalCount),
    governance: {
      excludesSecretValues: governance.excludesSecretValues === true,
      excludesRawSchemaContent: governance.excludesRawSchemaContent === true,
    },
  };
}

function normalizeSchemaPatternSharedSyncAction(value: unknown): SchemaPatternSharedSyncAction | null {
  return value === "empty" || value === "save" || value === "merge" || value === "resolve_conflict" ? value : null;
}

function normalizeSchemaPatternCentralSyncStatus(value: unknown): SchemaPatternCentralSyncStatus | null {
  if (!isRecord(value) || value.format !== "agent-flow-builder.schema-pattern-central-sync-status.v1") {
    return null;
  }
  const governance = isRecord(value.governance) ? value.governance : {};
  return {
    format: "agent-flow-builder.schema-pattern-central-sync-status.v1",
    generatedAt: typeof value.generatedAt === "string" && value.generatedAt.trim() ? value.generatedAt.trim() : new Date().toISOString(),
    configured: value.configured === true,
    urlConfigured: value.urlConfigured === true,
    tokenConfigured: value.tokenConfigured === true,
    timeoutMs:
      typeof value.timeoutMs === "number" && Number.isFinite(value.timeoutMs) && value.timeoutMs >= 100
        ? Math.floor(value.timeoutMs)
        : 5000,
    invalidReason: typeof value.invalidReason === "string" && value.invalidReason.trim() ? value.invalidReason.trim() : null,
    lastSyncedAt: typeof value.lastSyncedAt === "string" && value.lastSyncedAt.trim() ? value.lastSyncedAt.trim() : null,
    statusCode: normalizeNullableNonNegativeNumber(value.statusCode),
    pushedLibraryItemCount: normalizeNullableNonNegativeNumber(value.pushedLibraryItemCount),
    pulledLibraryItemCount: normalizeNullableNonNegativeNumber(value.pulledLibraryItemCount),
    pushedHistorySnapshotCount: normalizeNullableNonNegativeNumber(value.pushedHistorySnapshotCount),
    pulledHistorySnapshotCount: normalizeNullableNonNegativeNumber(value.pulledHistorySnapshotCount),
    error: typeof value.error === "string" && value.error.trim() ? value.error.trim() : null,
    governance: {
      excludesSecretValues: true,
      sendsRawSchemaContent: true,
      sendsHistoryRawSchemaContent: false,
      centralAuthTokenInHeaderOnly: true,
      centralAuthTokenInBody: false,
      storesCentralToken: false,
      configuredUrlEnv:
        typeof governance.configuredUrlEnv === "string" && governance.configuredUrlEnv.trim()
          ? governance.configuredUrlEnv.trim()
          : "AGENT_FLOW_SCHEMA_PATTERN_CENTRAL_URL",
      configuredTokenEnv:
        typeof governance.configuredTokenEnv === "string" && governance.configuredTokenEnv.trim()
          ? governance.configuredTokenEnv.trim()
          : "AGENT_FLOW_SCHEMA_PATTERN_CENTRAL_TOKEN",
      configuredTimeoutEnv:
        typeof governance.configuredTimeoutEnv === "string" && governance.configuredTimeoutEnv.trim()
          ? governance.configuredTimeoutEnv.trim()
          : "AGENT_FLOW_SCHEMA_PATTERN_CENTRAL_TIMEOUT_MS",
      maxPayloadBytes: normalizeNonNegativeNumber(governance.maxPayloadBytes),
    },
  };
}

function normalizeSchemaPatternCentralSyncResult(value: unknown): SchemaPatternCentralSyncResult | null {
  if (!isRecord(value) || value.format !== "agent-flow-builder.schema-pattern-central-sync-result.v1") {
    return null;
  }
  const library = normalizeSchemaReusablePatternLibraryPackage(value.library);
  const history = normalizeSchemaPatternLibraryHistoryPackage(value.history);
  const central = normalizeSchemaPatternCentralSyncStatus(value.central);
  if (!library || !history || !central) {
    return null;
  }
  return {
    format: "agent-flow-builder.schema-pattern-central-sync-result.v1",
    flowId: typeof value.flowId === "string" && value.flowId.trim() ? value.flowId.trim() : "",
    library,
    history,
    central,
    pushedLibraryItemCount: normalizeNonNegativeNumber(value.pushedLibraryItemCount),
    pulledLibraryItemCount: normalizeNonNegativeNumber(value.pulledLibraryItemCount),
    pushedHistorySnapshotCount: normalizeNonNegativeNumber(value.pushedHistorySnapshotCount),
    pulledHistorySnapshotCount: normalizeNonNegativeNumber(value.pulledHistorySnapshotCount),
    governance: {
      excludesSecretValues: true,
      centralAuthTokenInHeaderOnly: true,
      centralAuthTokenInBody: false,
    },
  };
}

function normalizeNullableNonNegativeNumber(value: unknown): number | null {
  return typeof value === "number" && Number.isFinite(value) && value >= 0 ? Math.floor(value) : null;
}

function formatSchemaPatternSharedSyncSummary(
  libraryPackage: SchemaReusablePatternLibraryPackage,
  historyPackage: SchemaPatternLibraryHistoryPackage,
): string {
  const librarySync = libraryPackage.sharedSync;
  const historySync = historyPackage.sharedSync;
  const libraryAction = librarySync ? schemaPatternSharedSyncActionLabel(librarySync.action) : "sem auditoria";
  const historyAction = historySync ? schemaPatternSharedSyncActionLabel(historySync.action) : "sem auditoria";
  const libraryHash = librarySync?.contentHash ?? libraryPackage.packageHash ?? "-";
  const historyHash = historySync?.contentHash ?? historyPackage.packageHash ?? "-";
  return `Compartilhado: biblioteca ${libraryAction} (${libraryPackage.itemCount} padrão(ões), +${librarySync?.addedCount ?? 0}/~${librarySync?.updatedCount ?? 0}, ${librarySync?.conflictCount ?? 0} conflito(s), ${libraryHash}) · histórico ${historyAction} (${historyPackage.snapshotCount} snapshot(s), +${historySync?.addedCount ?? 0}, ${historyHash})`;
}

function formatSchemaPatternCentralStatusSummary(status: SchemaPatternCentralSyncStatus): string {
  if (status.invalidReason) {
    return `Central de padrões: inválida (${status.invalidReason})`;
  }
  if (!status.configured) {
    return "Central de padrões: desligada.";
  }
  return `Central de padrões: configurada (${status.timeoutMs}ms, token ${status.tokenConfigured ? "on" : "off"}, sem token no pacote/status).`;
}

function formatSchemaPatternCentralSyncSummary(result: SchemaPatternCentralSyncResult): string {
  return `Central de padrões: enviada biblioteca ${result.pushedLibraryItemCount}, recebido ${result.pulledLibraryItemCount}; histórico enviado ${result.pushedHistorySnapshotCount}, recebido ${result.pulledHistorySnapshotCount}; token somente no header.`;
}

function formatSchemaPatternSharedConflictSummary(conflicts: SchemaPatternLibraryConflict[]): string {
  const openConflicts = conflicts.filter((conflict) => conflict.status === "open");
  const visible = openConflicts.slice(0, 3);
  const names = visible.map((conflict) => `${conflict.incomingSnapshot.name} (${conflict.reason})`).join(", ");
  const resolvedCount = conflicts.filter((conflict) => conflict.status === "resolved").length;
  const lastResolved = conflicts.find((conflict) => conflict.status === "resolved");
  const resolvedSuffix = resolvedCount
    ? ` · ${resolvedCount} resolvido(s)${lastResolved?.resolvedBy ? ` · último por ${lastResolved.resolvedBy}` : ""}${
        lastResolved?.resolution ? ` · ${formatSchemaPatternConflictResolutionLabel(lastResolved.resolution)}` : ""
      }`
    : "";
  return `Conflitos compartilhados: ${openConflicts.length} aberto(s)${resolvedSuffix}${names ? ` · ${names}` : ""}`;
}

function formatSchemaPatternConflictResolutionLabel(resolution: SchemaPatternLibraryConflictResolution): string {
  if (resolution === "accept_existing_snapshot") {
    return "voltar ao anterior";
  }
  if (resolution === "accept_incoming_snapshot") {
    return "aceitar recebido";
  }
  if (resolution === "apply_manual_schema_merge") {
    return "usar schema visual";
  }
  return "aceitar atual";
}

function formatSchemaPatternConflictResolutionPreview(conflict: SchemaPatternLibraryConflict): string {
  const schemaChanged = conflict.existingSnapshot.schemaHash !== conflict.incomingSnapshot.schemaHash;
  const metadataHints = [
    conflict.existingSnapshot.curationStatus !== conflict.incomingSnapshot.curationStatus ? "status" : "",
    stableStringify(conflict.existingSnapshot.tags) !== stableStringify(conflict.incomingSnapshot.tags) ? "tags" : "",
    conflict.existingSnapshot.usageCount !== conflict.incomingSnapshot.usageCount ? "uso" : "",
    conflict.existingSnapshot.reviewedBy !== conflict.incomingSnapshot.reviewedBy ? "revisor" : "",
  ].filter(Boolean);
  const manualHint = schemaChanged ? "schema mudou; voltar ao anterior pode exigir reaplicação manual" : "schema igual; metadados podem ser escolhidos";
  return `Plano: ${manualHint}${metadataHints.length ? ` · diferenças: ${metadataHints.join(", ")}` : ""}`;
}

function formatSchemaPatternConflictMergePlan(plan: SchemaPatternLibraryConflictMergePlan): string {
  if (!plan.schemaChanged) {
    return "Merge estrutural: sem diferença de schema bruto detectada.";
  }
  const additions: string[] = [];
  if (plan.propertyAdditions.length) {
    additions.push(`${plan.propertyAdditions.length} campo(s) novo(s)`);
  }
  if (plan.definitionAdditions.length) {
    additions.push(`${plan.definitionAdditions.length} $defs novo(s)`);
  }
  if (plan.requiredAdditions.length) {
    additions.push(`${plan.requiredAdditions.length} required`);
  }
  if (plan.compositionAdditions) {
    additions.push(`${plan.compositionAdditions} composição(ões)`);
  }
  if (plan.additionalPropertiesChange) {
    additions.push("additionalProperties novo");
  }
  const retained: string[] = [];
  if (plan.propertyExistingOnly.length) {
    retained.push(`${plan.propertyExistingOnly.length} campo(s) só no atual`);
  }
  if (plan.definitionExistingOnly.length) {
    retained.push(`${plan.definitionExistingOnly.length} $defs só no atual`);
  }
  if (plan.requiredExistingOnly.length) {
    retained.push(`${plan.requiredExistingOnly.length} required só no atual`);
  }
  if (plan.compositionExistingOnly) {
    retained.push(`${plan.compositionExistingOnly} composição(ões) só no atual`);
  }
  if (plan.additionalPropertiesExistingOnly) {
    retained.push("additionalProperties só no atual");
  }
  const conflicts: string[] = [];
  if (plan.propertyConflicts.length) {
    conflicts.push(`campos: ${plan.propertyConflicts.slice(0, 3).join(", ")}`);
  }
  if (plan.definitionConflicts.length) {
    conflicts.push(`$defs: ${plan.definitionConflicts.slice(0, 3).join(", ")}`);
  }
  if (plan.additionalPropertiesConflict) {
    conflicts.push("additionalProperties");
  }
  const readiness = plan.canAutoMerge
    ? "merge automático seguro"
    : conflicts.length
      ? "merge assistido necessário"
      : "revisão manual recomendada";
  return `Merge estrutural: ${readiness}${additions.length ? ` · adições ${additions.join(", ")}` : ""}${
    retained.length ? ` · mantém ${retained.join(", ")}` : ""
  }${
    conflicts.length ? ` · colisões ${conflicts.join("; ")}` : ""
  }`;
}

function schemaPatternSharedSyncActionLabel(action: SchemaPatternSharedSyncAction): string {
  if (action === "save") {
    return "salva";
  }
  if (action === "merge") {
    return "sincronizada";
  }
  if (action === "resolve_conflict") {
    return "resolvida";
  }
  return "vazia";
}

function syncSchemaReusablePatternLibrary(items: unknown[]): SchemaReusablePatternLibraryItem[] {
  const byId = new Map<string, SchemaReusablePatternLibraryItem>();
  for (const item of items
    .map(normalizeSchemaReusablePatternLibraryItem)
    .filter((entry): entry is SchemaReusablePatternLibraryItem => entry !== null)) {
    const existing = byId.get(item.id);
    if (!existing) {
      byId.set(item.id, item);
      continue;
    }
    const winner = Date.parse(existing.updatedAt) <= Date.parse(item.updatedAt) ? item : existing;
    byId.set(item.id, {
      ...winner,
      curationReviews: syncSchemaPatternCurationReviews([
        ...existing.curationReviews,
        ...item.curationReviews,
      ]),
      curationThread: mergeSchemaPatternCurationThreads(
        existing.curationThread,
        item.curationThread,
        syncSchemaPatternCurationReviews([...existing.curationReviews, ...item.curationReviews]),
        winner.schemaHash,
      ),
    });
  }
  return Array.from(byId.values()).sort((left, right) => {
    const leftTime = Date.parse(left.updatedAt);
    const rightTime = Date.parse(right.updatedAt);
    if (leftTime !== rightTime) {
      return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
    }
    return left.name.localeCompare(right.name);
  });
}

function normalizeSchemaReusablePatternLibraryItem(value: unknown): SchemaReusablePatternLibraryItem | null {
  if (!isRecord(value) || !isRecord(value.schema)) {
    return null;
  }
  const name = typeof value.name === "string" && value.name.trim() ? value.name.trim() : "";
  if (!name) {
    return null;
  }
  const schema = cloneJsonObject(value.schema);
  const schemaHash = simpleHash(stableStringify(schema));
  const id =
    typeof value.id === "string" && value.id.trim()
      ? value.id.trim()
      : `schema-pattern-${simpleHash([name, schemaHash].join("|"))}`;
  const curationReviews = syncSchemaPatternCurationReviews(value.curationReviews);
  const normalizedWithoutAssessment = {
    id,
    name,
    description: typeof value.description === "string" ? value.description.trim() : "",
    tags: Array.isArray(value.tags)
      ? Array.from(
          new Set(value.tags.filter((tag): tag is string => typeof tag === "string").map((tag) => tag.trim()).filter(Boolean)),
        ).sort((left, right) => left.localeCompare(right))
      : [],
    curationStatus: normalizeSchemaPatternCurationStatus(value.curationStatus),
    createdAt: typeof value.createdAt === "string" && value.createdAt.trim() ? value.createdAt.trim() : new Date().toISOString(),
    updatedAt: typeof value.updatedAt === "string" && value.updatedAt.trim() ? value.updatedAt.trim() : new Date().toISOString(),
    reviewedAt: typeof value.reviewedAt === "string" && value.reviewedAt.trim() ? value.reviewedAt.trim() : undefined,
    reviewedBy: typeof value.reviewedBy === "string" && value.reviewedBy.trim() ? value.reviewedBy.trim() : undefined,
    lastUsedAt: typeof value.lastUsedAt === "string" && value.lastUsedAt.trim() ? value.lastUsedAt.trim() : undefined,
    curationReviews,
    curationThread: normalizeSchemaPatternCurationThread(value.curationThread, schemaHash, curationReviews),
    usageCount: typeof value.usageCount === "number" && Number.isFinite(value.usageCount) && value.usageCount > 0
      ? Math.floor(value.usageCount)
      : 0,
    schemaHash,
    summary: collectSchemaGovernanceSummary(schema),
    schema,
  };
  return {
    ...normalizedWithoutAssessment,
    curationAssessment: assessSchemaPatternCuration(normalizedWithoutAssessment),
  };
}

function defaultSchemaPatternCurationThread(schemaHash: string): SchemaPatternCurationThread {
  return {
    status: "unassigned",
    assignee: "",
    openedAt: null,
    updatedAt: null,
    schemaHash,
    lastReviewer: "",
    lastDecision: null,
    leaseExpiresAt: null,
    leaseDurationHours: null,
    leaseExpired: false,
    reviewCount: 0,
    requestChangesCount: 0,
    events: [],
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
      autoReleasesExpiredAssignments: true,
      configuredLeaseHoursEnv: schemaPatternCurationLeaseHoursEnv,
    },
  };
}

function normalizeSchemaPatternCurationThread(
  value: unknown,
  schemaHash: string,
  reviews: SchemaPatternCurationReview[],
): SchemaPatternCurationThread {
  const source = isRecord(value) ? value : {};
  const latestReview = reviews[0] ?? null;
  const explicitStatus = normalizeSchemaPatternCurationThreadStatus(source.status);
  const assignee = typeof source.assignee === "string" && source.assignee.trim()
    ? source.assignee.trim().slice(0, 80)
    : "";
  const normalizedEvents = Array.isArray(source.events)
    ? source.events
        .map(normalizeSchemaPatternCurationEvent)
        .filter((event): event is SchemaPatternCurationEvent => event !== null)
    : [];
  const reviewCount = reviews.length || normalizeNonNegativeNumber(source.reviewCount);
  const requestChangesCount = reviews.length
    ? reviews.filter((review) => review.decision === "request_changes").length
    : normalizeNonNegativeNumber(source.requestChangesCount);
  const updatedAt = normalizeSchemaPatternDateString(source.updatedAt) || latestReview?.createdAt || null;
  const derivedStatus: SchemaPatternCurationThreadStatus =
    explicitStatus ??
    (latestReview?.decision === "approve" || latestReview?.decision === "deprecate"
      ? "resolved"
      : latestReview?.decision === "request_changes"
        ? "blocked"
        : assignee
          ? "assigned"
          : "unassigned");
  const leaseDurationHours = normalizeSchemaPatternCurationLeaseHours(source.leaseDurationHours);
  const leaseExpiresAt =
    derivedStatus === "assigned"
      ? normalizeSchemaPatternDateString(source.leaseExpiresAt) ||
        (updatedAt ? addHoursIsoLocal(updatedAt, leaseDurationHours) : null)
      : null;
  return expireSchemaPatternCurationThreadIfNeeded({
    status: derivedStatus,
    assignee,
    openedAt: normalizeSchemaPatternDateString(source.openedAt),
    updatedAt,
    schemaHash,
    lastReviewer: latestReview?.reviewer ?? (typeof source.lastReviewer === "string" && source.lastReviewer.trim() ? source.lastReviewer.trim().slice(0, 80) : ""),
    lastDecision: latestReview?.decision ?? normalizeSchemaPatternCurationReviewDecision(source.lastDecision),
    leaseExpiresAt,
    leaseDurationHours: derivedStatus === "assigned" ? leaseDurationHours : null,
    leaseExpired: derivedStatus !== "assigned" && source.leaseExpired === true,
    reviewCount,
    requestChangesCount,
    events: mergeSchemaPatternCurationEvents(
      normalizedEvents,
      reviews.map((review) => buildSchemaPatternCurationReviewEvent(review, assignee)),
    ),
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
      autoReleasesExpiredAssignments: true,
      configuredLeaseHoursEnv: schemaPatternCurationLeaseHoursEnv,
    },
  });
}

function normalizeSchemaPatternCurationThreadStatus(value: unknown): SchemaPatternCurationThreadStatus | null {
  return value === "unassigned" || value === "assigned" || value === "blocked" || value === "resolved" ? value : null;
}

function normalizeSchemaPatternDateString(value: unknown): string | null {
  const raw = readStringValue(value);
  if (!raw) {
    return null;
  }
  const timestamp = Date.parse(raw);
  return Number.isFinite(timestamp) ? new Date(timestamp).toISOString() : null;
}

function normalizeSchemaPatternCurationLeaseHours(value: unknown): number {
  const numeric = typeof value === "number" ? value : typeof value === "string" ? Number(value) : Number.NaN;
  if (!Number.isFinite(numeric) || numeric <= 0) {
    return schemaPatternCurationLeaseHours;
  }
  return Math.min(Math.max(Math.floor(numeric), 1), 168);
}

function expireSchemaPatternCurationThreadIfNeeded(thread: SchemaPatternCurationThread): SchemaPatternCurationThread {
  if (thread.status !== "assigned" || !thread.leaseExpiresAt) {
    return thread;
  }
  const expiresAt = Date.parse(thread.leaseExpiresAt);
  if (!Number.isFinite(expiresAt) || expiresAt > Date.now()) {
    return thread;
  }
  const actor = thread.assignee || thread.lastReviewer || "schema-curator";
  const event = buildSchemaPatternCurationEvent(
    "lease_expired",
    actor,
    "",
    thread.schemaHash,
    "Lease de curadoria do padrão expirado.",
    thread.leaseExpiresAt,
  );
  return {
    ...thread,
    status: "unassigned",
    assignee: "",
    updatedAt: thread.leaseExpiresAt,
    leaseExpiresAt: null,
    leaseDurationHours: null,
    leaseExpired: true,
    events: mergeSchemaPatternCurationEvents([event], thread.events),
  };
}

function mergeSchemaPatternCurationThreads(
  left: SchemaPatternCurationThread,
  right: SchemaPatternCurationThread,
  reviews: SchemaPatternCurationReview[],
  schemaHash: string,
): SchemaPatternCurationThread {
  const leftTime = left.updatedAt ? Date.parse(left.updatedAt) : 0;
  const rightTime = right.updatedAt ? Date.parse(right.updatedAt) : 0;
  const winner = rightTime >= leftTime ? right : left;
  return normalizeSchemaPatternCurationThread({
    ...winner,
    events: mergeSchemaPatternCurationEvents(left.events, right.events),
  }, schemaHash, reviews);
}

function normalizeSchemaPatternCurationEvent(value: unknown): SchemaPatternCurationEvent | null {
  if (!isRecord(value)) {
    return null;
  }
  const action = value.action === "assign" || value.action === "release" || value.action === "review" || value.action === "lease_expired"
    ? value.action
    : null;
  const actor = typeof value.actor === "string" && value.actor.trim() ? value.actor.trim().slice(0, 120) : "";
  const at = typeof value.at === "string" && value.at.trim() ? value.at.trim() : "";
  if (!action || !actor || !at) {
    return null;
  }
  const decision = normalizeSchemaPatternCurationReviewDecision(value.decision);
  return {
    id: typeof value.id === "string" && value.id.trim()
      ? value.id.trim().slice(0, 160)
      : `schema-pattern-curation-event-${simpleHash(stableStringify({ action, actor, at, decision }))}`,
    at,
    actor,
    action,
    assignee: typeof value.assignee === "string" && value.assignee.trim() ? value.assignee.trim().slice(0, 120) : "",
    decision,
    note: typeof value.note === "string" && value.note.trim() ? value.note.trim().slice(0, 240) : "",
    schemaHash: typeof value.schemaHash === "string" && value.schemaHash.trim() ? value.schemaHash.trim().slice(0, 80) : "",
  };
}

function mergeSchemaPatternCurationEvents(
  existing: SchemaPatternCurationEvent[],
  incoming: SchemaPatternCurationEvent[],
): SchemaPatternCurationEvent[] {
  const byId = new Map<string, SchemaPatternCurationEvent>();
  for (const event of [...existing, ...incoming]) {
    byId.set(event.id, event);
  }
  return Array.from(byId.values())
    .sort((left, right) => Date.parse(right.at) - Date.parse(left.at) || left.id.localeCompare(right.id))
    .slice(0, 12);
}

function buildSchemaPatternCurationEvent(
  action: SchemaPatternCurationEventAction,
  actor: string,
  assignee: string,
  schemaHash: string,
  note: string,
  at: string,
  decision: SchemaPatternCurationReviewDecision | null = null,
): SchemaPatternCurationEvent {
  return {
    id: `schema-pattern-curation-event-${simpleHash([
      action,
      actor,
      assignee,
      schemaHash,
      decision ?? "",
      at,
    ].join("|"))}`,
    at,
    actor,
    action,
    assignee,
    decision,
    note: note.slice(0, 240),
    schemaHash,
  };
}

function buildSchemaPatternCurationReviewEvent(
  review: SchemaPatternCurationReview,
  currentAssignee: string,
): SchemaPatternCurationEvent {
  return buildSchemaPatternCurationEvent(
    "review",
    review.reviewer,
    currentAssignee || review.reviewer,
    review.schemaHash,
    review.note,
    review.createdAt,
    review.decision,
  );
}

function assignSchemaPatternCurationThread(
  thread: SchemaPatternCurationThread,
  assignee: string,
  now: string,
  schemaHash: string,
  reviews: SchemaPatternCurationReview[],
): SchemaPatternCurationThread {
  const leaseDurationHours = schemaPatternCurationLeaseHours;
  const event = buildSchemaPatternCurationEvent("assign", assignee, assignee, schemaHash, "Assumiu curadoria do padrão.", now);
  return normalizeSchemaPatternCurationThread({
    ...thread,
    assignee,
    status: "assigned",
    openedAt: thread.openedAt ?? now,
    updatedAt: now,
    schemaHash,
    leaseExpiresAt: addHoursIsoLocal(now, leaseDurationHours),
    leaseDurationHours,
    leaseExpired: false,
    events: mergeSchemaPatternCurationEvents([event], thread.events),
  }, schemaHash, reviews);
}

function releaseSchemaPatternCurationThread(
  thread: SchemaPatternCurationThread,
  now: string,
  schemaHash: string,
  reviews: SchemaPatternCurationReview[],
): SchemaPatternCurationThread {
  const actor = thread.assignee || "curador-local";
  const event = buildSchemaPatternCurationEvent("release", actor, "", schemaHash, "Liberou curadoria do padrão.", now);
  return normalizeSchemaPatternCurationThread({
    ...thread,
    assignee: "",
    status: reviews[0]?.decision === "request_changes" ? "blocked" : "unassigned",
    updatedAt: now,
    schemaHash,
    leaseExpiresAt: null,
    leaseDurationHours: null,
    leaseExpired: false,
    events: mergeSchemaPatternCurationEvents([event], thread.events),
  }, schemaHash, reviews);
}

function updateSchemaPatternCurationThreadAfterReview(
  thread: SchemaPatternCurationThread,
  review: SchemaPatternCurationReview,
  reviews: SchemaPatternCurationReview[],
): SchemaPatternCurationThread {
  const status: SchemaPatternCurationThreadStatus =
    review.decision === "approve" || review.decision === "deprecate"
      ? "resolved"
      : review.decision === "request_changes"
        ? "blocked"
        : thread.assignee
          ? "assigned"
          : "unassigned";
  return normalizeSchemaPatternCurationThread({
    ...thread,
    status,
    assignee: thread.assignee || review.reviewer,
    openedAt: thread.openedAt ?? review.createdAt,
    updatedAt: review.createdAt,
    schemaHash: review.schemaHash,
    leaseExpiresAt: status === "assigned" ? thread.leaseExpiresAt : null,
    leaseDurationHours: status === "assigned" ? thread.leaseDurationHours : null,
    leaseExpired: false,
  }, review.schemaHash, reviews);
}

function buildSchemaPatternCurationReview(
  pattern: SchemaReusablePatternLibraryItem,
  decision: SchemaPatternCurationReviewDecision,
  reviewer: string,
  role: StudioAnnotationReviewerRole,
  createdAt: string,
): SchemaPatternCurationReview {
  const note = schemaPatternCurationReviewNote(pattern, decision);
  return {
    id: `schema-pattern-review-${simpleHash([pattern.id, pattern.schemaHash, reviewer, decision, createdAt].join("|"))}`,
    reviewer,
    role,
    decision,
    note,
    createdAt,
    schemaHash: pattern.schemaHash,
    assessmentStatus: pattern.curationAssessment.status,
    assessmentScore: pattern.curationAssessment.score,
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function schemaPatternCurationReviewNote(
  pattern: SchemaReusablePatternLibraryItem,
  decision: SchemaPatternCurationReviewDecision,
): string {
  const assessment = pattern.curationAssessment;
  const mainSignal = assessment.blockers[0] ?? assessment.warnings[0] ?? assessment.strengths[0] ?? "sem sinal adicional";
  if (decision === "approve") {
    return `Aprovado com score ${assessment.score}/100; ${mainSignal}.`;
  }
  if (decision === "request_changes") {
    return `Ajustes solicitados com score ${assessment.score}/100; ${mainSignal}.`;
  }
  if (decision === "deprecate") {
    return `Deprecado com score ${assessment.score}/100; ${mainSignal}.`;
  }
  return `Comentário registrado com score ${assessment.score}/100; ${mainSignal}.`;
}

function syncSchemaPatternCurationReviews(value: unknown): SchemaPatternCurationReview[] {
  const reviews = Array.isArray(value)
    ? value.map(normalizeSchemaPatternCurationReview).filter((entry): entry is SchemaPatternCurationReview => entry !== null)
    : [];
  const byId = new Map<string, SchemaPatternCurationReview>();
  for (const review of reviews) {
    byId.set(review.id, review);
  }
  return Array.from(byId.values())
    .sort((left, right) => Date.parse(right.createdAt) - Date.parse(left.createdAt) || left.id.localeCompare(right.id))
    .slice(0, 24);
}

function normalizeSchemaPatternCurationReview(value: unknown): SchemaPatternCurationReview | null {
  if (!isRecord(value)) {
    return null;
  }
  const decision = normalizeSchemaPatternCurationReviewDecision(value.decision);
  const reviewer = typeof value.reviewer === "string" && value.reviewer.trim()
    ? value.reviewer.trim().slice(0, 80)
    : "local-curator";
  const createdAt = typeof value.createdAt === "string" && value.createdAt.trim() ? value.createdAt.trim() : new Date().toISOString();
  const schemaHash = typeof value.schemaHash === "string" && value.schemaHash.trim() ? value.schemaHash.trim().slice(0, 120) : "";
  if (!decision || !schemaHash) {
    return null;
  }
  const status = normalizeSchemaPatternCurationReadiness(value.assessmentStatus) ?? "review";
  const note = typeof value.note === "string" && value.note.trim() ? value.note.trim().slice(0, 220) : "";
  return {
    id: typeof value.id === "string" && value.id.trim()
      ? value.id.trim().slice(0, 160)
      : `schema-pattern-review-${simpleHash([reviewer, decision, schemaHash, createdAt].join("|"))}`,
    reviewer,
    role: normalizeStudioAnnotationReviewerRole(value.role),
    decision,
    note,
    createdAt,
    schemaHash,
    assessmentStatus: status,
    assessmentScore: Math.max(0, Math.min(100, Math.round(normalizeNonNegativeNumber(value.assessmentScore)))),
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function normalizeSchemaPatternCurationReviewDecision(value: unknown): SchemaPatternCurationReviewDecision | null {
  return value === "approve" || value === "request_changes" || value === "deprecate" || value === "comment"
    ? value
    : null;
}

function normalizeSchemaPatternCurationAssessment(value: unknown): SchemaPatternCurationAssessment | null {
  if (!isRecord(value)) {
    return null;
  }
  const status = normalizeSchemaPatternCurationReadiness(value.status);
  if (!status) {
    return null;
  }
  return {
    status,
    score: Math.max(0, Math.min(100, Math.round(normalizeNonNegativeNumber(value.score)))),
    blockers: normalizeStringArray(value.blockers).slice(0, 8),
    warnings: normalizeStringArray(value.warnings).slice(0, 8),
    strengths: normalizeStringArray(value.strengths).slice(0, 8),
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function normalizeSchemaPatternCurationReadiness(value: unknown): SchemaPatternCurationReadiness | null {
  return value === "ready" || value === "review" || value === "blocked" ? value : null;
}

function assessSchemaPatternCuration(input: {
  name: string;
  description: string;
  tags: string[];
  curationStatus: SchemaPatternCurationStatus;
  reviewedAt?: string | null;
  usageCount: number;
  summary: SchemaGovernanceSummary;
}): SchemaPatternCurationAssessment {
  const blockers: string[] = [];
  const warnings: string[] = [];
  const strengths: string[] = [];
  const description = input.description.trim();
  const tags = input.tags.map((tag) => tag.trim()).filter(Boolean);
  const summary = input.summary;
  if (input.curationStatus === "deprecated") {
    blockers.push("Padrão marcado como deprecado");
  }
  if (summary.propertyCount === 0 && summary.definitionCount === 0 && summary.compositionCount === 0) {
    blockers.push("Sem campos, $defs ou composições reutilizáveis");
  }
  if (description.length < 16) {
    warnings.push("Descrição curta para curadoria");
  } else {
    strengths.push("Descrição útil");
  }
  if (!tags.length) {
    warnings.push("Sem tags de descoberta");
  } else if (tags.length >= 2) {
    strengths.push("Tags suficientes");
  }
  if (!input.reviewedAt) {
    warnings.push("Ainda sem revisão registrada");
  } else {
    strengths.push("Revisado por curador");
  }
  if (summary.openAdditionalPropertiesCount > 0) {
    warnings.push("Possui additionalProperties aberto");
  } else if (summary.schemaAdditionalPropertiesCount > 0) {
    strengths.push("additionalProperties governado");
  }
  if (summary.maxDepth > 7) {
    warnings.push("Profundidade alta para revisão visual");
  }
  if (summary.refCount > summary.definitionCount + 2) {
    warnings.push("Muitos refs externos em relação aos $defs");
  }
  if (summary.propertyCount > 0) {
    strengths.push("Campos nomeados");
  }
  if (summary.definitionCount > 0) {
    strengths.push("$defs reutilizáveis");
  }
  if (input.usageCount > 0) {
    strengths.push("Já usado em flow");
  }
  const rawScore = 100 - blockers.length * 34 - warnings.length * 9 + Math.min(12, strengths.length * 3);
  const score = Math.max(0, Math.min(100, Math.round(rawScore)));
  const status: SchemaPatternCurationReadiness = blockers.length ? "blocked" : score >= 82 ? "ready" : "review";
  return {
    status,
    score,
    blockers,
    warnings,
    strengths: strengths.slice(0, 6),
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
    },
  };
}

function normalizeSchemaPatternCurationStatus(value: unknown): SchemaPatternCurationStatus {
  return value === "approved" || value === "deprecated" || value === "draft" ? value : "draft";
}

function schemaPatternCurationStatusLabel(status: SchemaPatternCurationStatus): string {
  if (status === "approved") {
    return "Aprovado";
  }
  if (status === "deprecated") {
    return "Deprecado";
  }
  return "Rascunho";
}

function schemaPatternCurationReadinessLabel(status: SchemaPatternCurationReadiness): string {
  if (status === "ready") {
    return "Pronto";
  }
  if (status === "blocked") {
    return "Bloqueado";
  }
  return "Revisar";
}

function schemaPatternCurationReviewDecisionLabel(decision: SchemaPatternCurationReviewDecision): string {
  if (decision === "approve") {
    return "Aprovar";
  }
  if (decision === "request_changes") {
    return "Pedir ajustes";
  }
  if (decision === "deprecate") {
    return "Deprecar";
  }
  return "Comentar";
}

function schemaPatternCurationThreadStatusLabel(thread: SchemaPatternCurationThread): string {
  if (thread.status === "assigned") {
    const lease = thread.leaseExpiresAt ? ` até ${formatDateTime(thread.leaseExpiresAt)}` : "";
    return `Em curadoria${lease}`;
  }
  if (thread.status === "blocked") {
    return "Ajustes pendentes";
  }
  if (thread.status === "resolved") {
    return "Resolvido";
  }
  return thread.leaseExpired ? "Lease expirado" : "Sem responsável";
}

function schemaPatternCurationThreadDetail(thread: SchemaPatternCurationThread): string {
  if (thread.leaseExpired) {
    const expiredAt = thread.updatedAt ? formatDateTime(thread.updatedAt) : "data não registrada";
    return `Liberado automaticamente após lease vencido em ${expiredAt}`;
  }
  const assignee = thread.assignee ? `Responsável: ${thread.assignee}` : "Sem responsável";
  const updated = thread.updatedAt ? formatDateTime(thread.updatedAt) : "sem movimentação";
  return `${assignee} · ${updated}`;
}

function schemaPatternCurationEventLabel(event: SchemaPatternCurationEvent): string {
  if (event.action === "assign") {
    return "assumiu";
  }
  if (event.action === "release") {
    return "liberou";
  }
  if (event.action === "lease_expired") {
    return "lease expirou";
  }
  return event.decision
    ? `revisou: ${schemaPatternCurationReviewDecisionLabel(event.decision)}`
    : "revisou";
}

function schemaPatternDiffIntegrityLabel(status: SchemaPatternDiffIntegrityStatus): string {
  if (status === "verified") {
    return "Hash verificado";
  }
  if (status === "mismatch") {
    return "Hash divergente";
  }
  return "Hash ausente, recalculado";
}

function buildSchemaGovernanceReport(
  flow: AgentFlow,
  schemaRef: SchemaRef,
  schema: Record<string, unknown>,
  issues: SchemaSemanticIssue[],
): SchemaGovernanceReport {
  const definitions = new Set(readSchemaDefinitions(schema).map(([name]) => name));
  const properties = new Set(readSchemaProperties(schema).map(([name]) => name));
  const applied = schemaReusablePatterns
    .filter((pattern) => definitions.has(pattern.definitionName) && properties.has(pattern.propertyName))
    .map(schemaGovernancePatternRef);
  const missing = schemaReusablePatterns
    .filter((pattern) => !definitions.has(pattern.definitionName) || !properties.has(pattern.propertyName))
    .map(schemaGovernancePatternRef);
  const base = {
    format: "agent-flow-builder.schema-governance.v1" as const,
    exportedAt: new Date().toISOString(),
    flow: {
      id: flow.id,
      name: flow.name,
      version: flow.version,
    },
    schema: {
      id: schemaRef.id,
      path: schemaRef.path,
      version: schemaRef.version ?? null,
      description: schemaRef.description ?? null,
      tags: schemaRef.tags ?? [],
    },
    summary: collectSchemaGovernanceSummary(schema),
    patterns: {
      availableCount: schemaReusablePatterns.length,
      applied,
      missing,
    },
    diagnostics: {
      errorCount: issues.filter((issue) => issue.severity === "error").length,
      warningCount: issues.filter((issue) => issue.severity === "warning").length,
      issues: issues.map((issue) => ({
        severity: issue.severity,
        path: issue.path,
        message: issue.message,
        actionLabel: issue.action?.label ?? null,
      })),
    },
    governance: {
      excludesRawSchemaContent: true,
      excludesSecretValues: true,
      source: "schema-visual-editor" as const,
    },
  };
  return {
    ...base,
    packageHash: simpleHash(stableStringify(base)),
  };
}

function schemaGovernancePatternRef(pattern: SchemaReusablePattern): SchemaGovernancePatternRef {
  return {
    id: pattern.id,
    title: pattern.title,
    definitionName: pattern.definitionName,
    propertyName: pattern.propertyName,
  };
}

function collectSchemaGovernanceSummary(schema: Record<string, unknown>): SchemaGovernanceSummary {
  const summary: SchemaGovernanceSummary = {
    propertyCount: 0,
    requiredCount: 0,
    definitionCount: 0,
    refCount: 0,
    enumCount: 0,
    enumValueCount: 0,
    objectCount: 0,
    arrayCount: 0,
    compositionCount: 0,
    openAdditionalPropertiesCount: 0,
    lockedAdditionalPropertiesCount: 0,
    schemaAdditionalPropertiesCount: 0,
    maxDepth: 0,
  };
  collectSchemaGovernanceFromObject(schema, summary, 0);
  return summary;
}

function collectSchemaGovernanceFromObject(
  schema: Record<string, unknown>,
  summary: SchemaGovernanceSummary,
  depth: number,
): void {
  summary.maxDepth = Math.max(summary.maxDepth, depth);
  const type = readSchemaPropertyType(schema);
  const properties = readSchemaProperties(schema);
  if (type === "object" || properties.length > 0) {
    summary.objectCount += 1;
  }
  if (type === "array") {
    summary.arrayCount += 1;
  }
  if (readSchemaRef(schema)) {
    summary.refCount += 1;
  }
  if (Array.isArray(schema.enum)) {
    summary.enumCount += 1;
    summary.enumValueCount += schema.enum.length;
  }
  const required = readSchemaRequired(schema);
  summary.requiredCount += required.length;
  summary.propertyCount += properties.length;
  for (const [, property] of properties) {
    collectSchemaGovernanceFromObject(property, summary, depth + 1);
  }
  const definitions = readSchemaDefinitions(schema);
  summary.definitionCount += definitions.length;
  for (const [, definition] of definitions) {
    collectSchemaGovernanceFromObject(definition, summary, depth + 1);
  }
  if (isRecord(schema.items)) {
    collectSchemaGovernanceFromObject(schema.items, summary, depth + 1);
  } else if (Array.isArray(schema.items)) {
    schema.items.filter(isRecord).forEach((item) => collectSchemaGovernanceFromObject(item, summary, depth + 1));
  }
  if (schema.additionalProperties === true) {
    summary.openAdditionalPropertiesCount += 1;
  } else if (schema.additionalProperties === false) {
    summary.lockedAdditionalPropertiesCount += 1;
  } else if (isRecord(schema.additionalProperties)) {
    summary.schemaAdditionalPropertiesCount += 1;
    collectSchemaGovernanceFromObject(schema.additionalProperties, summary, depth + 1);
  }
  for (const key of schemaCompositionKeys) {
    const entries = readSchemaCompositionList(schema, key);
    summary.compositionCount += entries.length;
    entries.forEach((entry) => collectSchemaGovernanceFromObject(entry, summary, depth + 1));
  }
}

function readSchemaObjectAtPath(schema: Record<string, unknown>, path: SchemaPathSegment[]): Record<string, unknown> | undefined {
  let current: unknown = schema;
  for (const segment of path) {
    if (typeof segment === "number") {
      if (!Array.isArray(current)) {
        return undefined;
      }
      current = current[segment];
    } else {
      if (!isRecord(current)) {
        return undefined;
      }
      current = current[segment];
    }
  }
  return isRecord(current) ? current : undefined;
}

function schemaPathKey(path: SchemaPathSegment[]): string {
  return path.length ? path.map((segment) => encodeURIComponent(String(segment))).join("/") : "schema";
}

function createSchemaDefinitionFromSource(source: Record<string, unknown> | undefined, sourcePath: SchemaPathSegment[]): Record<string, unknown> {
  if (!source) {
    return { type: "object", properties: {} };
  }
  if (!sourcePath.length) {
    return createDefaultSchemaProperty(readSchemaPropertyType(source) || "object");
  }
  const definition = cloneJsonObject(source);
  delete definition.$ref;
  delete definition.$defs;
  if (!Object.keys(definition).length) {
    return { type: "object", properties: {} };
  }
  if (definition.type === "object" && !isRecord(definition.properties)) {
    definition.properties = {};
  }
  if (definition.type === "array" && !isRecord(definition.items) && !Array.isArray(definition.items)) {
    definition.items = { type: "string" };
  }
  return definition;
}

function uniqueJsonValues<T>(items: T[]): T[] {
  const seen = new Set<string>();
  return items.filter((item) => {
    const key = JSON.stringify(item);
    if (seen.has(key)) {
      return false;
    }
    seen.add(key);
    return true;
  });
}

function readSchemaProperties(schema: Record<string, unknown>): Array<[string, Record<string, unknown>]> {
  if (!isRecord(schema.properties)) {
    return [];
  }
  return Object.entries(schema.properties).map(([name, value]) => [name, isRecord(value) ? value : {}]);
}

function ensureSchemaProperties(schema: Record<string, unknown>): Record<string, unknown> {
  if (!isRecord(schema.properties)) {
    schema.properties = {};
  }
  return schema.properties as Record<string, unknown>;
}

function readSchemaDefinitions(schema: Record<string, unknown>): Array<[string, Record<string, unknown>]> {
  if (!isRecord(schema.$defs)) {
    return [];
  }
  return Object.entries(schema.$defs).map(([name, value]) => [name, isRecord(value) ? value : {}]);
}

function ensureSchemaDefinitions(schema: Record<string, unknown>): Record<string, unknown> {
  if (!isRecord(schema.$defs)) {
    schema.$defs = {};
  }
  return schema.$defs as Record<string, unknown>;
}

function createDefaultSchemaProperty(type: string): Record<string, unknown> {
  if (type === "object") {
    return { type, properties: {} };
  }
  if (type === "array") {
    return { type, items: { type: "string" } };
  }
  return { type };
}

function readSchemaRequired(schema: Record<string, unknown>): string[] {
  return Array.isArray(schema.required) ? schema.required.filter((item): item is string => typeof item === "string") : [];
}

function readSchemaPropertyType(property: Record<string, unknown>): string {
  return typeof property.type === "string" ? property.type : "";
}

function readSchemaPropertyDescription(property: Record<string, unknown>): string {
  return typeof property.description === "string" ? property.description : "";
}

function readSchemaPropertyEnum(property: Record<string, unknown>): string[] {
  return Array.isArray(property.enum)
    ? property.enum
        .map((item) => (typeof item === "string" || typeof item === "number" || typeof item === "boolean" ? String(item) : ""))
        .filter(Boolean)
    : [];
}

function readSchemaArrayItemType(property: Record<string, unknown>): string {
  return isRecord(property.items) && typeof property.items.type === "string" ? property.items.type : "";
}

function readSchemaArrayItemsObject(property: Record<string, unknown>): Record<string, unknown> {
  return isRecord(property.items) ? property.items : { type: "object", properties: {} };
}

const schemaCompositionKeys = ["oneOf", "allOf", "anyOf"] as const;
type SchemaCompositionKey = (typeof schemaCompositionKeys)[number];

function readSchemaRef(schema: Record<string, unknown>): string {
  return typeof schema.$ref === "string" ? schema.$ref : "";
}

function readSchemaAdditionalPropertiesMode(schema: Record<string, unknown>): "unset" | "true" | "false" | "schema" {
  if (schema.additionalProperties === undefined) {
    return "unset";
  }
  if (schema.additionalProperties === true) {
    return "true";
  }
  if (schema.additionalProperties === false) {
    return "false";
  }
  if (isRecord(schema.additionalProperties)) {
    return "schema";
  }
  return "unset";
}

function readSchemaAdditionalPropertiesObject(schema: Record<string, unknown>): Record<string, unknown> {
  return isRecord(schema.additionalProperties) ? schema.additionalProperties : { type: "string" };
}

function updateSchemaAdditionalPropertiesMode(schema: Record<string, unknown>, mode: string): void {
  if (mode === "true") {
    schema.additionalProperties = true;
    return;
  }
  if (mode === "false") {
    schema.additionalProperties = false;
    return;
  }
  if (mode === "schema") {
    schema.additionalProperties = readSchemaAdditionalPropertiesObject(schema);
    return;
  }
  delete schema.additionalProperties;
}

function readSchemaCompositionList(schema: Record<string, unknown>, key: SchemaCompositionKey): Record<string, unknown>[] {
  return Array.isArray(schema[key]) ? schema[key].filter(isRecord) : [];
}

function addSchemaCompositionEntry(schema: Record<string, unknown>, key: SchemaCompositionKey): void {
  schema[key] = [...readSchemaCompositionList(schema, key), { type: "object", properties: {} }];
}

function removeSchemaCompositionEntry(schema: Record<string, unknown>, key: SchemaCompositionKey): void {
  const entries = readSchemaCompositionList(schema, key).slice(0, -1);
  if (entries.length) {
    schema[key] = entries;
  } else {
    delete schema[key];
  }
}

function updateSchemaPropertyType(property: Record<string, unknown>, type: string): void {
  if (type) {
    property.type = type;
  } else {
    delete property.type;
  }
  if (type === "object") {
    if (!isRecord(property.properties)) {
      property.properties = {};
    }
    return;
  }
  delete property.properties;
  delete property.required;
  if (type === "array") {
    if (!isRecord(property.items)) {
      property.items = { type: "string" };
    }
    return;
  }
  delete property.items;
}

function updateSchemaArrayItemType(property: Record<string, unknown>, type: string): void {
  if (!type) {
    delete property.items;
    return;
  }
  const nextItems: Record<string, unknown> = {
    ...(isRecord(property.items) ? property.items : {}),
    type,
  };
  if (type === "object") {
    if (!isRecord(nextItems.properties)) {
      nextItems.properties = {};
    }
  } else {
    delete nextItems.properties;
    delete nextItems.required;
  }
  property.items = nextItems;
}

function isValidSchemaPropertyName(value: string): boolean {
  return /^[A-Za-z_][A-Za-z0-9_-]*$/.test(value.trim());
}

function PanelNotice({ state }: { state: PanelLoadState }) {
  if (state.kind === "idle" || state.kind === "ready") {
    return null;
  }
  const isError = state.kind === "error";
  return (
    <div
      className={`panel-notice ${state.kind}`}
      role={isError ? "alert" : "status"}
      aria-busy={state.kind === "loading" ? "true" : undefined}
      data-state={state.kind}
    >
      {isError ? <AlertCircle size={16} aria-hidden="true" /> : <RefreshCw size={16} aria-hidden="true" />}
      <span>{state.message}</span>
    </div>
  );
}

function buildLocalCatalogSharedLibraryPackage(catalog: LocalCatalog) {
  const items = catalog.items.filter((item) => item.source === "local");
  return {
    format: "agent-flow-builder.catalog-library.v1",
    exportedAt: new Date().toISOString(),
    itemCount: items.length,
    items,
  };
}

function formatCatalogSharedSyncSummary(result: LocalCatalogSharedSyncResult): string {
  return formatCatalogSharedLibrarySummary(result.sharedLibrary, result.catalog);
}

function formatCatalogCentralSyncSummary(result: LocalCatalogCentralSyncResult): string {
  return `Central: enviados ${result.pushedItemCount} item(ns), recebidos ${result.pulledItemCount}; biblioteca ${result.sharedLibrary.itemCount} item(ns), ${result.sharedLibrary.openConflictCount} conflito(s) aberto(s); token somente no header.`;
}

function formatCatalogSharedLibrarySummary(
  sharedLibrary: LocalCatalogSharedLibraryPackage,
  catalog: LocalCatalog | null,
): string {
  const sync = sharedLibrary.sharedSync;
  const localCount = catalog?.items.length ?? 0;
  const action =
    sync.action === "load"
      ? "carregada"
      : sync.action === "merge"
        ? "sincronizada"
        : sync.action === "resolve"
          ? "revisada"
          : sync.action === "curate_conflict"
            ? "curadoria atualizada"
          : "vazia";
  return `Compartilhado: biblioteca ${action} (${sharedLibrary.itemCount} item(ns), +${sync.addedCount}/~${sync.updatedCount}, ${sync.conflictCount} conflito(s), ${sharedLibrary.openConflictCount} aberto(s), ${sync.contentHash}) · local ${localCount} item(ns)`;
}

function catalogConflictResolutionLabel(resolution: LocalCatalogLibraryConflictResolution): string {
  if (resolution === "use_incoming") {
    return "aceitar recebido";
  }
  if (resolution === "restore_existing_snapshot") {
    return "voltar anterior";
  }
  return "manter biblioteca";
}

function catalogConflictDecisionHint(conflict: LocalCatalogLibraryConflict): string {
  if (conflict.incomingSnapshot.itemHash && conflict.incomingSnapshot.itemHash === conflict.existingSnapshot.itemHash) {
    return "Snapshots equivalentes";
  }
  if (conflict.incomingUpdatedAt >= conflict.existingUpdatedAt) {
    return "Recebido mais recente";
  }
  return "Atual mais recente";
}

function catalogConflictResolutionPreview(conflict: LocalCatalogLibraryConflict): string {
  const contentChanged =
    conflict.existingSnapshot.contentHash !== conflict.incomingSnapshot.contentHash ||
    conflict.existingSnapshot.itemHash !== conflict.incomingSnapshot.itemHash;
  const differences = [
    conflict.existingSnapshot.name !== conflict.incomingSnapshot.name ? "nome" : "",
    conflict.existingSnapshot.description !== conflict.incomingSnapshot.description ? "descrição" : "",
    stableStringify(conflict.existingSnapshot.tags) !== stableStringify(conflict.incomingSnapshot.tags) ? "tags" : "",
    conflict.existingSnapshot.version !== conflict.incomingSnapshot.version ||
    conflict.existingSnapshot.revision !== conflict.incomingSnapshot.revision
      ? "versão"
      : "",
  ].filter(Boolean);
  const contentHint = contentChanged
    ? "conteúdo mudou; voltar anterior pode exigir reimportar conteúdo bruto"
    : "conteúdo igual; metadados podem ser aplicados";
  return `Plano: ${contentHint}${differences.length ? ` · diferenças: ${differences.join(", ")}` : ""}`;
}

function catalogConflictCurationStatusLabel(conflict: LocalCatalogLibraryConflict): string {
  const thread = conflict.curationThread;
  if (!thread) {
    return "Sem responsável";
  }
  if (thread.status === "unassigned") {
    return thread.leaseExpired ? "Lease expirado" : "Sem responsável";
  }
  if (thread.status === "resolved") {
    return "Resolvido";
  }
  const lease = thread.leaseExpiresAt ? ` até ${formatDateTime(thread.leaseExpiresAt)}` : "";
  return `Em curadoria${lease}`;
}

function catalogConflictCurationDetail(conflict: LocalCatalogLibraryConflict): string {
  const thread = conflict.curationThread;
  if (!thread) {
    return "Sem movimentação de curadoria";
  }
  if (thread.leaseExpired) {
    const expiredAt = thread.updatedAt ? formatDateTime(thread.updatedAt) : "data não registrada";
    return `Liberado automaticamente após lease vencido em ${expiredAt}`;
  }
  const assignee = thread.assignee ? `Responsável: ${thread.assignee}` : "Sem responsável";
  const updated = thread.updatedAt ? formatDateTime(thread.updatedAt) : "sem movimentação";
  const action = thread.lastAction ? ` · ${catalogConflictCurationEventLabel(thread.lastAction)}` : "";
  return `${assignee} · ${updated}${action}`;
}

function catalogConflictCurationEventLabel(
  action: LocalCatalogLibraryConflictCurationLastAction,
): string {
  if (action === "assign") {
    return "assumiu";
  }
  if (action === "release") {
    return "liberou";
  }
  if (action === "lease_expired") {
    return "lease expirou";
  }
  return "resolveu";
}

function mergeLocalCatalogWithSharedLibrary(
  catalog: LocalCatalog,
  sharedLibrary: LocalCatalogSharedLibraryPackage,
): LocalCatalog {
  const byKey = new Map(catalog.items.map((item) => [localCatalogItemKey(item), item]));
  for (const item of sharedLibrary.items) {
    byKey.set(localCatalogItemKey(item), item);
  }
  return {
    ...catalog,
    items: Array.from(byKey.values()).sort((left, right) => {
      const sourceDelta = left.source.localeCompare(right.source);
      return sourceDelta === 0 ? left.name.localeCompare(right.name) : sourceDelta;
    }),
  };
}

function CatalogPanel({
  flow,
  selectedNodeId,
  selectedBlockNodeCount,
  selectedBlockEdgeCount,
  selectedPromptId,
  selectedSchemaId,
  catalog,
  loadState,
  onRefresh,
  onApply,
  onRestoreRevision,
  onCreateAgentTemplate,
  onSavePrompt,
  onSaveSchema,
  onSaveTool,
  onSaveToolBlock,
  onSaveSkill,
  onSaveSkillBlock,
  onSaveCatalogEdit,
  onExportItem,
  onImportPackageFile,
  sharedSyncSummary,
  sharedLibrary,
  sharedSyncing,
  centralStatus,
  curatorName,
  curatorRole,
  onLoadSharedCatalog,
  onSyncSharedCatalog,
  onLoadCentralCatalogStatus,
  onSyncCentralCatalog,
  onExportSharedCatalogConflictReview,
  onCompareSharedCatalogConflictReviewFile,
  onResolveSharedCatalogConflict,
  onUpdateSharedCatalogConflictCuration,
  onCuratorNameChange,
  onCuratorRoleChange,
}: {
  flow: AgentFlow | null;
  selectedNodeId: string;
  selectedBlockNodeCount: number;
  selectedBlockEdgeCount: number;
  selectedPromptId: string;
  selectedSchemaId: string;
  catalog: LocalCatalog | null;
  loadState: PanelLoadState;
  onRefresh: () => void;
  onApply: (item: LocalCatalogItem, targetNodeId?: string) => void;
  onRestoreRevision: (item: LocalCatalogItem, revision: LocalCatalogRevision) => void;
  onCreateAgentTemplate: (item: LocalCatalogItem) => void;
  onSavePrompt: () => void;
  onSaveSchema: () => void;
  onSaveTool: () => void;
  onSaveToolBlock: () => void;
  onSaveSkill: () => void;
  onSaveSkillBlock: () => void;
  onSaveCatalogEdit: (draft: CatalogEditDraft) => Promise<LocalCatalogItem | null>;
  onExportItem: (item: LocalCatalogItem) => void;
  onImportPackageFile: (file: File) => void;
  sharedSyncSummary: string;
  sharedLibrary: LocalCatalogSharedLibraryPackage | null;
  sharedSyncing: boolean;
  centralStatus: LocalCatalogCentralSyncStatus | null;
  curatorName: string;
  curatorRole: StudioAnnotationReviewerRole;
  onLoadSharedCatalog: () => void;
  onSyncSharedCatalog: () => void;
  onLoadCentralCatalogStatus: () => void;
  onSyncCentralCatalog: () => void;
  onExportSharedCatalogConflictReview: () => void;
  onCompareSharedCatalogConflictReviewFile: (file: File) => void | Promise<void>;
  onResolveSharedCatalogConflict: (
    conflict: LocalCatalogLibraryConflict,
    resolution: LocalCatalogLibraryConflictResolution,
  ) => void;
  onUpdateSharedCatalogConflictCuration: (
    conflict: LocalCatalogLibraryConflict,
    action: "assign" | "release",
  ) => void;
  onCuratorNameChange: (value: string) => void;
  onCuratorRoleChange: (role: StudioAnnotationReviewerRole) => void;
}) {
  const [kindFilter, setKindFilter] = useState<LocalCatalogItemKind | "">("");
  const [sourceFilter, setSourceFilter] = useState<LocalCatalogItem["source"] | "">("");
  const [tagFilter, setTagFilter] = useState("");
  const [query, setQuery] = useState("");
  const [compareRevisionByItem, setCompareRevisionByItem] = useState<Record<string, number>>({});
  const [editDraft, setEditDraft] = useState<CatalogEditDraft | null>(null);
  const [editSaving, setEditSaving] = useState(false);
  const catalogImportInputRef = useRef<HTMLInputElement | null>(null);
  const catalogConflictReviewInputRef = useRef<HTMLInputElement | null>(null);
  const availableTags = useMemo(() => {
    const tags = new Set<string>();
    for (const item of catalog?.items ?? []) {
      for (const tag of item.tags) {
        tags.add(tag);
      }
    }
    return Array.from(tags).sort((left, right) => left.localeCompare(right));
  }, [catalog]);
  const libraryGovernanceReport = useMemo(
    () => (catalog ? buildCatalogLibraryGovernanceReport(catalog) : null),
    [catalog],
  );
  const items = useMemo(
    () => {
      const normalizedQuery = query.trim().toLowerCase();
      return (catalog?.items ?? []).filter((item) => {
        if (kindFilter && item.kind !== kindFilter) {
          return false;
        }
        if (sourceFilter && item.source !== sourceFilter) {
          return false;
        }
        if (tagFilter && !item.tags.includes(tagFilter)) {
          return false;
        }
        if (!normalizedQuery) {
          return true;
        }
        const searchable = [item.id, item.name, item.description, item.kind, item.source, ...item.tags]
          .concat([item.version, `rev-${item.revision}`, item.contentHash])
          .concat(
            (item.history ?? []).flatMap((revision) => [
              revision.version,
              `rev-${revision.revision}`,
              revision.contentHash,
              revision.name,
              revision.description,
              ...revision.tags,
            ]),
          )
          .join(" ")
          .toLowerCase();
        return searchable.includes(normalizedQuery);
      });
    },
    [catalog, kindFilter, query, sourceFilter, tagFilter],
  );
  const totalItems = catalog?.items.length ?? 0;
  const openSharedCatalogConflicts = (sharedLibrary?.conflicts ?? []).filter((conflict) => conflict.status === "open");
  const sharedCatalogResolutionHistory = sharedLibrary?.resolutionHistory ?? [];
  const curatorCanResolve = curatorRole !== "viewer";
  const normalizedCatalogCuratorName = normalizeStudioAnnotationReviewerName(curatorName);

  useEffect(() => {
    if (!editDraft) {
      return;
    }
    if (!catalog?.items.some((item) => localCatalogItemKey(item) === editDraft.itemKey)) {
      setEditDraft(null);
    }
  }, [catalog, editDraft]);

  async function handleSaveCatalogEdit() {
    if (!editDraft) {
      return;
    }
    setEditSaving(true);
    try {
      const savedItem = await onSaveCatalogEdit(editDraft);
      if (savedItem) {
        setEditDraft(catalogEditDraftFromItem(savedItem));
      }
    } finally {
      setEditSaving(false);
    }
  }

  function handleExportCatalogGovernance(item: LocalCatalogItem, visualSummary: CatalogVisualSummary | null): void {
    const report = buildCatalogGovernanceReport(item, visualSummary);
    downloadJsonFile(`${catalogGovernanceFileName(report)}.afcataloggovernance.json`, report);
  }

  function handleExportCatalogLibraryGovernance(report: CatalogLibraryGovernanceReport): void {
    downloadJsonFile(`${catalogLibraryGovernanceFileName(report)}.afcataloglibrarygovernance.json`, report);
  }

  if (!flow) {
    return (
      <div className="empty-state">
        <AlertCircle size={18} aria-hidden="true" />
        <span>Nenhum flow carregado.</span>
      </div>
    );
  }

  return (
    <div className="assets-body catalog-body">
      <input
        ref={catalogImportInputRef}
        type="file"
        accept="application/json,.json,.afcatalog"
        className="visually-hidden catalog-import-input"
        onChange={(event) => {
          const file = event.target.files?.[0];
          event.currentTarget.value = "";
          if (file) {
            onImportPackageFile(file);
          }
        }}
      />
      <input
        ref={catalogConflictReviewInputRef}
        type="file"
        accept="application/json,.json,.afcatalog-conflicts,.afcatalog-conflicts.json"
        aria-label="Comparar revisão governada de conflitos do catálogo"
        className="visually-hidden"
        onChange={(event) => {
          const file = event.target.files?.[0];
          event.currentTarget.value = "";
          if (file) {
            void onCompareSharedCatalogConflictReviewFile(file);
          }
        }}
      />
      <section className="asset-section">
        <div className="asset-metadata-title">
          <strong>Catálogo local</strong>
          <span>{catalog?.path ?? ".agent-flow/catalog/registry.json"}</span>
        </div>
        <PanelNotice state={loadState} />
        <div className="catalog-toolbar catalog-search-toolbar">
          <label className="catalog-search">
            <span>Busca</span>
            <input
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Nome, descrição ou tag"
              aria-label="Buscar no catálogo"
            />
          </label>
          <label>
            <span>Tipo</span>
            <select value={kindFilter} onChange={(event) => setKindFilter(event.target.value as LocalCatalogItemKind | "")}>
              <option value="">Todos</option>
              {catalogKindOptions.map((kind) => (
                <option value={kind} key={kind}>
                  {catalogKindLabel(kind)}
                </option>
              ))}
            </select>
          </label>
          <label>
            <span>Origem</span>
            <select
              value={sourceFilter}
              aria-label="Filtrar origem do catálogo"
              onChange={(event) => setSourceFilter(event.target.value as LocalCatalogItem["source"] | "")}
            >
              <option value="">Todas</option>
              <option value="builtin">Embutidos</option>
              <option value="local">Locais</option>
            </select>
          </label>
          <label>
            <span>Tag</span>
            <select value={tagFilter} onChange={(event) => setTagFilter(event.target.value)}>
              <option value="">Todas</option>
              {availableTags.map((tag) => (
                <option value={tag} key={tag}>
                  {tag}
                </option>
              ))}
            </select>
          </label>
          <button type="button" className="command-button" onClick={onRefresh}>
            <RefreshCw size={16} aria-hidden="true" />
            Atualizar
          </button>
          <button
            type="button"
            className="command-button"
            onClick={() => {
              setKindFilter("");
              setSourceFilter("");
              setTagFilter("");
              setQuery("");
            }}
            disabled={!kindFilter && !sourceFilter && !tagFilter && !query}
          >
            <Search size={16} aria-hidden="true" />
            Limpar
          </button>
        </div>
        {libraryGovernanceReport ? (
          <CatalogLibraryGovernancePanel
            report={libraryGovernanceReport}
            onExport={() => handleExportCatalogLibraryGovernance(libraryGovernanceReport)}
          />
        ) : null}
        <div className="catalog-shared-sync">
          <div>
            <strong>Biblioteca compartilhada</strong>
            <span>{sharedSyncSummary || "Sem sincronização compartilhada nesta sessão."}</span>
            {centralStatus ? (
              <small>
                Central:{" "}
                {centralStatus.invalidReason
                  ? `inválida (${centralStatus.invalidReason})`
                  : centralStatus.configured
                    ? "configurada"
                    : "desligada"}{" "}
                · env {centralStatus.governance.configuredUrlEnv} · token{" "}
                {centralStatus.tokenConfigured ? "configurado" : "off"} · timeout {centralStatus.timeoutMs}ms · token só no header
                {centralStatus.lastSyncedAt
                  ? ` · ${centralStatus.pushedItemCount ?? 0}/${centralStatus.pulledItemCount ?? 0} item(ns) em ${formatDateTime(centralStatus.lastSyncedAt)}`
                  : ""}
              </small>
            ) : null}
            <div className="catalog-shared-curator" aria-label="Curadoria local do catálogo compartilhado">
              <label>
                <span>Curador</span>
                <input
                  aria-label="Nome do curador local do catálogo"
                  value={curatorName}
                  onChange={(event) => onCuratorNameChange(event.target.value)}
                />
              </label>
              <label>
                <span>Papel</span>
                <select
                  aria-label="Papel do curador local do catálogo"
                  value={curatorRole}
                  onChange={(event) => onCuratorRoleChange(event.target.value as StudioAnnotationReviewerRole)}
                >
                  <option value="owner">Owner</option>
                  <option value="reviewer">Reviewer</option>
                  <option value="viewer">Viewer</option>
                </select>
              </label>
            </div>
          </div>
          <button type="button" className="command-button" onClick={onLoadSharedCatalog} disabled={sharedSyncing}>
            <RefreshCw size={16} aria-hidden="true" />
            Carregar compartilhado
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSyncSharedCatalog}
            disabled={sharedSyncing || !catalog?.items.some((item) => item.source === "local")}
          >
            <Upload size={16} aria-hidden="true" />
            Sincronizar compartilhado
          </button>
          <button type="button" className="command-button" onClick={onLoadCentralCatalogStatus} disabled={sharedSyncing}>
            <ShieldCheck size={16} aria-hidden="true" />
            Central
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSyncCentralCatalog}
            disabled={
              sharedSyncing ||
              (centralStatus !== null && !centralStatus.configured) ||
              !catalog?.items.some((item) => item.source === "local")
            }
          >
            <RefreshCw size={16} aria-hidden="true" />
            Sync central
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onExportSharedCatalogConflictReview}
            disabled={sharedSyncing}
          >
            <Download size={16} aria-hidden="true" />
            Exportar revisão
          </button>
          <button
            type="button"
            className="command-button"
            onClick={() => catalogConflictReviewInputRef.current?.click()}
            disabled={sharedSyncing}
          >
            <GitCompare size={16} aria-hidden="true" />
            Comparar revisão
          </button>
        </div>
        {openSharedCatalogConflicts.length ? (
          <div className="schema-pattern-conflicts catalog-shared-conflicts" aria-label="Conflitos compartilhados do catálogo">
            {openSharedCatalogConflicts.slice(0, 4).map((conflict) => (
              <div className="schema-pattern-conflict-card" key={conflict.id}>
                <div>
                  <span>{catalogKindLabel(conflict.kind)} em conflito</span>
                  <strong>{conflict.incomingSnapshot.name}</strong>
                  <small>{conflict.reason}</small>
                </div>
                <dl>
                  <div>
                    <dt>Atual</dt>
                    <dd>
                      rev. {conflict.existingSnapshot.revision} · {conflict.existingSnapshot.contentHash || conflict.existingSnapshot.itemHash || "sem hash"}
                    </dd>
                  </div>
                  <div>
                    <dt>Recebido</dt>
                    <dd>
                      rev. {conflict.incomingSnapshot.revision} · {conflict.incomingSnapshot.contentHash || conflict.incomingSnapshot.itemHash || "sem hash"}
                    </dd>
                  </div>
                  <div>
                    <dt>Decisão</dt>
                    <dd>{catalogConflictDecisionHint(conflict)}</dd>
                  </div>
                </dl>
                <div className={`schema-pattern-curation-thread ${conflict.curationThread?.status ?? "unassigned"}`}>
                  <span>{catalogConflictCurationStatusLabel(conflict)}</span>
                  <small>{catalogConflictCurationDetail(conflict)}</small>
                  {conflict.curationThread?.note ? <small>{conflict.curationThread.note}</small> : null}
                  {conflict.curationThread?.events?.slice(0, 3).map((event) => (
                    <small key={event.id}>
                      {formatDateTime(event.at)} · {event.actor} · {event.role} · {catalogConflictCurationEventLabel(event.action)}
                      {event.assignee ? ` · ${event.assignee}` : ""}
                    </small>
                  ))}
                </div>
                <small>{catalogConflictResolutionPreview(conflict)}</small>
                <button
                  type="button"
                  className="command-button"
                  onClick={() => onUpdateSharedCatalogConflictCuration(conflict, "assign")}
                  disabled={
                    sharedSyncing ||
                    !curatorCanResolve ||
                    conflict.curationThread?.assignee === normalizedCatalogCuratorName
                  }
                >
                  <UserCheck size={14} aria-hidden="true" />
                  Assumir
                </button>
                <button
                  type="button"
                  className="command-button"
                  onClick={() => onUpdateSharedCatalogConflictCuration(conflict, "release")}
                  disabled={sharedSyncing || !curatorCanResolve || !conflict.curationThread?.assignee}
                >
                  <Undo2 size={14} aria-hidden="true" />
                  Liberar
                </button>
                <button
                  type="button"
                  className="command-button"
                  onClick={() => onResolveSharedCatalogConflict(conflict, "keep_library")}
                  disabled={sharedSyncing || !curatorCanResolve}
                >
                  <CheckCircle2 size={14} aria-hidden="true" />
                  Manter biblioteca
                </button>
                <button
                  type="button"
                  className="command-button"
                  onClick={() => onResolveSharedCatalogConflict(conflict, "use_incoming")}
                  disabled={sharedSyncing || !curatorCanResolve}
                >
                  <CheckCircle2 size={14} aria-hidden="true" />
                  Aceitar recebido
                </button>
                <button
                  type="button"
                  className="command-button"
                  onClick={() => onResolveSharedCatalogConflict(conflict, "restore_existing_snapshot")}
                  disabled={sharedSyncing || !curatorCanResolve}
                >
                  <Undo2 size={14} aria-hidden="true" />
                  Voltar anterior
                </button>
              </div>
            ))}
          </div>
        ) : null}
        {sharedCatalogResolutionHistory.length ? (
          <div className="schema-pattern-conflicts catalog-resolution-history" aria-label="Histórico de resolução do catálogo">
            <div className="schema-pattern-conflict-card">
              <div>
                <span>Histórico de resolução</span>
                <strong>{sharedCatalogResolutionHistory.length} decisão(ões) governada(s)</strong>
                <small>
                  Snapshots descartados idênticos não reabrem o conflito quando retornam por sync; o histórico não inclui
                  conteúdo bruto do catálogo.
                </small>
              </div>
              {sharedCatalogResolutionHistory.slice(0, 4).map((record) => (
                <small key={record.resolutionId}>
                  {formatDateTime(record.resolvedAt)} · {record.resolvedBy || "local-studio"} · {catalogKindLabel(record.kind)}{" "}
                  {record.itemId} · {catalogConflictResolutionLabel(record.resolution)} · descartado(s){" "}
                  {record.discardedSnapshots.length}
                </small>
              ))}
            </div>
          </div>
        ) : null}
        <div className="catalog-toolbar">
          <button type="button" className="command-button" onClick={onSavePrompt} disabled={!selectedPromptId}>
            <Save size={16} aria-hidden="true" />
            Salvar prompt atual
          </button>
          <button type="button" className="command-button" onClick={onSaveSchema} disabled={!selectedSchemaId}>
            <Save size={16} aria-hidden="true" />
            Salvar schema atual
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSaveTool}
            disabled={!selectedNodeId || selectedNodeId === "start" || selectedNodeId === "end"}
          >
            <Save size={16} aria-hidden="true" />
            Salvar tool atual
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSaveToolBlock}
            disabled={selectedBlockNodeCount < 2}
            title={`${selectedBlockNodeCount} nó(s), ${selectedBlockEdgeCount} aresta(s) internas`}
          >
            <Save size={16} aria-hidden="true" />
            Salvar bloco tool
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSaveSkill}
            disabled={!selectedNodeId || selectedNodeId === "start" || selectedNodeId === "end"}
          >
            <Save size={16} aria-hidden="true" />
            Salvar skill atual
          </button>
          <button
            type="button"
            className="command-button"
            onClick={onSaveSkillBlock}
            disabled={selectedBlockNodeCount < 2}
            title={`${selectedBlockNodeCount} nó(s), ${selectedBlockEdgeCount} aresta(s) internas`}
          >
            <Save size={16} aria-hidden="true" />
            Salvar bloco skill
          </button>
          <button type="button" className="command-button" onClick={() => catalogImportInputRef.current?.click()}>
            <Upload size={16} aria-hidden="true" />
            Importar pacote
          </button>
        </div>
      </section>

      <section className="asset-section">
        <div className="asset-metadata-title">
          <strong>Itens reutilizáveis</strong>
          <span>
            {items.length}/{totalItems}
          </span>
        </div>
        {items.length ? (
          <div className="catalog-list">
            {items.map((item) => {
              const itemKey = localCatalogItemKey(item);
              const createsBlock = catalogItemCreatesBlock(item);
              const visualSummary = catalogItemVisualSummary(item);
              const governanceReport = buildCatalogGovernanceReport(item, visualSummary);
              const revisions = catalogRevisionTimeline(item);
              const compareRevision =
                revisions.find((revision) => revision.revision === compareRevisionByItem[itemKey]) ?? revisions[0] ?? null;
              const revisionDiff = compareRevision ? catalogRevisionDiff(compareRevision, item) : [];
              return (
                <article className="catalog-card" key={`${item.kind}-${item.id}`}>
                  <div className="catalog-card-header">
                    <Library size={16} aria-hidden="true" />
                    <span>{catalogKindLabel(item.kind)}</span>
                    <small>{item.source === "builtin" ? "embutido" : "local"}</small>
                  </div>
                  <strong>{item.name}</strong>
                  <p>{item.description || item.id}</p>
                  <div className="catalog-card-meta">
                    <span>v{item.version}</span>
                    <span>rev. {item.revision}</span>
                    <span>{item.contentHash}</span>
                  </div>
                  {visualSummary ? (
                    <details className="catalog-block-preview">
                      <summary>
                        <GitBranch size={14} aria-hidden="true" />
                        <span>{catalogVisualSummaryHeadline(visualSummary)}</span>
                      </summary>
                      <div className="catalog-block-stats">
                        {visualSummary.nodes.length ? (
                          <>
                            <span>{visualSummary.entryNodeIds.length || visualSummary.nodes.length} entrada(s)</span>
                            <span>{visualSummary.exitNodeIds.length || visualSummary.nodes.length} saída(s)</span>
                          </>
                        ) : null}
                        <span>{visualSummary.promptCount} prompt(s)</span>
                        <span>{visualSummary.schemaCount} schema(s)</span>
                      </div>
                      {visualSummary.nodes.length ? (
                        <>
                          <ol className="catalog-block-node-list" aria-label={`Etapas de ${item.name}`}>
                            {visualSummary.nodes.slice(0, 8).map((node, index) => (
                              <li key={`${itemKey}-node-${node.id}-${index}`}>
                                <strong>{node.id}</strong>
                                <small>{node.type}</small>
                                {node.description ? <span>{node.description}</span> : null}
                                {node.promptId ? <span>prompt: {node.promptId}</span> : null}
                                {node.outputSchema ? <span>schema: {node.outputSchema}</span> : null}
                              </li>
                            ))}
                          </ol>
                          {visualSummary.nodes.length > 8 ? (
                            <div className="catalog-block-more">+{visualSummary.nodes.length - 8} etapa(s)</div>
                          ) : null}
                        </>
                      ) : null}
                      {visualSummary.edges.length ? (
                        <div className="catalog-block-edge-list" aria-label={`Conexões de ${item.name}`}>
                          {visualSummary.edges.slice(0, 6).map((edge, index) => (
                            <code key={`${itemKey}-edge-${index}`}>
                              {edge.from} -&gt; {edge.to}
                              {edge.condition ? ` | ${edge.condition}` : ""}
                            </code>
                          ))}
                        </div>
                      ) : null}
                      {visualSummary.targetPatchKeys.length ? (
                        <div className="catalog-block-assets">
                          <span>Patch alvo</span>
                          {visualSummary.targetPatchKeys.slice(0, 6).map((key) => (
                            <code key={`${itemKey}-patch-${key}`}>{key}</code>
                          ))}
                        </div>
                      ) : null}
                      <pre className="catalog-block-json">{visualSummary.jsonPreview}</pre>
                    </details>
                  ) : null}
                  {compareRevision ? (
                    <details className="catalog-history">
                      <summary>
                        <GitCompare size={14} aria-hidden="true" />
                        <span>
                          Histórico {item.history.length}: rev. {compareRevision.revision} para {item.revision}
                        </span>
                      </summary>
                      <div className="catalog-history-meta">
                        <span>Comparando rev. {compareRevision.revision}</span>
                        <span>v{compareRevision.version}</span>
                        <span>{compareRevision.contentHash}</span>
                      </div>
                      <div className="catalog-history-list">
                        {revisions.map((revision) => (
                          <div
                            className={`catalog-history-item ${revision.revision === compareRevision.revision ? "selected" : ""}`}
                            key={`${item.id}-revision-${revision.revision}`}
                          >
                            <div>
                              <strong>rev. {revision.revision}</strong>
                              <span>
                                v{revision.version} | {revision.contentHash}
                              </span>
                            </div>
                            <div className="catalog-history-actions">
                              <button
                                type="button"
                                className="command-button"
                                onClick={() =>
                                  setCompareRevisionByItem((current) => ({
                                    ...current,
                                    [itemKey]: revision.revision,
                                  }))
                                }
                                disabled={revision.revision === compareRevision.revision}
                              >
                                <GitCompare size={14} aria-hidden="true" />
                                Comparar
                              </button>
                              <button type="button" className="command-button" onClick={() => onRestoreRevision(item, revision)}>
                                <RefreshCw size={14} aria-hidden="true" />
                                Restaurar
                              </button>
                            </div>
                          </div>
                        ))}
                      </div>
                      {revisionDiff.length ? (
                        <div className="catalog-diff">
                          {revisionDiff.map((row, index) => (
                            <code className={`catalog-diff-row ${row.kind}`} key={`${item.id}-diff-${index}`}>
                              <span>{row.kind === "added" ? "+" : "-"}</span>
                              {row.text || " "}
                            </code>
                          ))}
                        </div>
                      ) : (
                        <div className="catalog-diff-empty">Sem mudanças de conteúdo</div>
                      )}
                    </details>
                  ) : null}
                  <div className="catalog-tags">
                    {item.tags.slice(0, 4).map((tag) => (
                      <span key={`${item.id}-${tag}`}>{tag}</span>
                    ))}
                  </div>
                  {editDraft?.itemKey === itemKey ? (
                    <CatalogItemEditor
                      draft={editDraft}
                      onDraftChange={setEditDraft}
                      onSave={handleSaveCatalogEdit}
                      onCancel={() => setEditDraft(null)}
                      saving={editSaving}
                    />
                  ) : null}
                  <CatalogGovernancePanel
                    report={governanceReport}
                    onExport={() => handleExportCatalogGovernance(item, visualSummary)}
                  />
                  <div className="catalog-card-actions">
                    <button type="button" className="command-button" onClick={() => onExportItem(item)}>
                      <Download size={16} aria-hidden="true" />
                      Exportar
                    </button>
                    {item.source === "local" ? (
                      <button type="button" className="command-button" onClick={() => setEditDraft(catalogEditDraftFromItem(item))}>
                        <Pencil size={16} aria-hidden="true" />
                        Editar item
                      </button>
                    ) : null}
                    {item.kind === "agent_template" ? (
                      <button type="button" className="command-button" onClick={() => onCreateAgentTemplate(item)}>
                        <Plus size={16} aria-hidden="true" />
                        Criar flow
                      </button>
                    ) : (
                      <>
                        <button type="button" className="command-button" onClick={() => onApply(item)}>
                          <Plus size={16} aria-hidden="true" />
                          {createsBlock ? "Criar bloco" : item.kind === "tool" ? "Criar nó" : "Adicionar"}
                        </button>
                        <button
                          type="button"
                          className="command-button"
                          onClick={() => onApply(item, selectedNodeId)}
                          disabled={!selectedNodeId}
                          title={selectedNodeId ? `Aplicar em ${selectedNodeId}` : "Selecione um nó para aplicar diretamente"}
                        >
                          <Sparkles size={16} aria-hidden="true" />
                          {createsBlock ? "Anexar ao nó" : "Usar no nó"}
                        </button>
                      </>
                    )}
                  </div>
                </article>
              );
            })}
          </div>
        ) : (
          <div className="runtime-item">
            <strong>Nenhum item encontrado</strong>
            <span>Altere o filtro ou salve um prompt/schema atual no catálogo local.</span>
          </div>
        )}
      </section>
    </div>
  );
}

function CatalogLibraryGovernancePanel({
  report,
  onExport,
}: {
  report: CatalogLibraryGovernanceReport;
  onExport: () => void;
}) {
  const { summary } = report;
  const statusLabel = summary.warningCount ? `${summary.warningCount} item(ns) com aviso` : "biblioteca pronta";
  return (
    <section className="catalog-library-governance-panel" role="region" aria-label="Governança da biblioteca do catálogo">
      <div className="catalog-governance-header">
        <div>
          <ShieldCheck size={14} aria-hidden="true" />
          <strong>Governança da biblioteca</strong>
          <span>{statusLabel}</span>
        </div>
        <button
          type="button"
          className="command-button"
          onClick={onExport}
          aria-label="Exportar governança da biblioteca do catálogo"
        >
          <Download size={14} aria-hidden="true" />
          Exportar governança
        </button>
      </div>
      <div className="catalog-governance-grid">
        <span>
          <strong>{summary.itemCount}</strong>
          itens
        </span>
        <span>
          <strong>{summary.localCount}</strong>
          locais
        </span>
        <span>
          <strong>{summary.builtinCount}</strong>
          embutidos
        </span>
        <span>
          <strong>{summary.readyCount}</strong>
          prontos
        </span>
        <span>
          <strong>{summary.portablePackageReadyCount}</strong>
          portáveis
        </span>
      </div>
      <div className="catalog-governance-detail">
        {catalogKindOptions.map((kind) => (
          <span key={kind}>
            {catalogKindLabel(kind)}: {summary.kindCounts[kind]}
          </span>
        ))}
      </div>
      {Object.keys(summary.warningCheckCounts).length ? (
        <div className="catalog-governance-checks" aria-label="Avisos da biblioteca do catálogo">
          {Object.entries(summary.warningCheckCounts).map(([checkId, count]) => (
            <span className="catalog-governance-check warn" key={checkId}>
              <AlertCircle size={12} aria-hidden="true" />
              {catalogGovernanceCheckLabel(checkId)}: {count}
            </span>
          ))}
        </div>
      ) : null}
    </section>
  );
}

function CatalogGovernancePanel({
  report,
  onExport,
}: {
  report: CatalogGovernanceReport;
  onExport: () => void;
}) {
  const { summary } = report;
  const statusLabel = summary.warningCount ? `${summary.warningCount} aviso(s)` : "pronto para reuso";
  return (
    <section
      className={`catalog-governance-panel ${summary.status}`}
      role="region"
      aria-label={`Governança do item do catálogo ${report.item.name}`}
    >
      <div className="catalog-governance-header">
        <div>
          <ShieldCheck size={14} aria-hidden="true" />
          <strong>Governança</strong>
          <span>{statusLabel}</span>
        </div>
        <button type="button" className="command-button" onClick={onExport} aria-label="Exportar governança do item">
          <Download size={14} aria-hidden="true" />
          Exportar governança
        </button>
      </div>
      <div className="catalog-governance-grid">
        <span>
          <strong>{summary.nodeCount}</strong>
          nós
        </span>
        <span>
          <strong>{summary.edgeCount}</strong>
          arestas
        </span>
        <span>
          <strong>{summary.promptAssetCount}</strong>
          prompts
        </span>
        <span>
          <strong>{summary.schemaAssetCount}</strong>
          schemas
        </span>
        <span>
          <strong>{summary.revisionHistoryCount}</strong>
          histórico
        </span>
        <span>
          <strong>{summary.tagCount}</strong>
          tags
        </span>
      </div>
      <div className="catalog-governance-checks" aria-label={`Checks de governança de ${report.item.name}`}>
        {report.checks.map((check) => (
          <span className={`catalog-governance-check ${check.status}`} key={check.id} title={check.detail}>
            {check.status === "pass" ? <CheckCircle2 size={12} aria-hidden="true" /> : <AlertCircle size={12} aria-hidden="true" />}
            {check.label}
          </span>
        ))}
      </div>
      <div className="catalog-governance-detail">
        <span>
          Conteúdo: {summary.contentMode}
          {summary.contentFormat ? ` (${summary.contentFormat})` : ""}
        </span>
        <span>
          Patch: {summary.nodePatchKeyCount} campo(s) direto(s), {summary.targetPatchKeyCount} campo(s) alvo
        </span>
      </div>
    </section>
  );
}

interface CatalogEditDraft {
  itemKey: string;
  id: string;
  kind: LocalCatalogItemKind;
  name: string;
  version: string;
  description: string;
  tagsText: string;
  content: string;
  nodePatchText: string;
}

interface CatalogEditableContent {
  nodes: Array<{ id: string; type: string; description: string; promptId: string; outputSchema: string }>;
  edges: Array<{ from: string; to: string; condition: string }>;
  prompts: Array<{ id: string; path: string; content: string }>;
  schemas: Array<{ id: string; path: string; content: string }>;
  contentError: string;
}

const CATALOG_NODE_TYPES = [
  "start",
  "end",
  "llm_prompt",
  "llm_structured",
  "code",
  "switch",
  "human_input",
  "safety_gate",
  "http_request",
  "transform_json",
  "database_query",
  "database_save",
  "file_extract",
  "rag_retrieval",
  "approval_gate",
  "scoring",
  "analytics",
] as const;

interface CatalogEditorValidation {
  errors: string[];
  warnings: string[];
}

function CatalogItemEditor({
  draft,
  onDraftChange,
  onSave,
  onCancel,
  saving,
}: {
  draft: CatalogEditDraft;
  onDraftChange: (draft: CatalogEditDraft) => void;
  onSave: () => void;
  onCancel: () => void;
  saving: boolean;
}) {
  const editableContent = catalogEditableContent(draft);
  const nodePatchError = catalogNodePatchDraftError(draft);
  const validation = catalogEditorValidation(draft, editableContent, nodePatchError);
  const saveDisabled = saving || validation.errors.length > 0;
  const showNodePatchEditor = Boolean(draft.nodePatchText.trim()) || (!draft.content.trim() && draft.kind === "tool");
  const canEditStructuredContent = !editableContent.contentError
    && Boolean(draft.content.trim())
    && (draft.kind === "tool" || draft.kind === "skill" || draft.kind === "agent_template");
  const nextNodeId = uniqueCatalogNodeId(editableContent.nodes.map((node) => node.id), "catalog_step");
  const canEditInternalAssets = !editableContent.contentError
    && Boolean(draft.content.trim())
    && (draft.kind === "skill" || draft.kind === "agent_template");
  const nextPromptId = uniqueCatalogAssetId(editableContent.prompts.map((asset) => asset.id), "catalog_prompt");
  const nextSchemaId = uniqueCatalogAssetId(editableContent.schemas.map((asset) => asset.id), "catalog_schema");

  return (
    <div className="catalog-item-editor">
      <div className="asset-metadata-title">
        <strong>Curadoria local</strong>
        <span>{draft.kind}:{draft.id}</span>
      </div>
      <div className="catalog-edit-grid">
        <label>
          <span>Nome do item</span>
          <input value={draft.name} onChange={(event) => onDraftChange({ ...draft, name: event.target.value })} />
        </label>
        <label>
          <span>Versão do item</span>
          <input value={draft.version} onChange={(event) => onDraftChange({ ...draft, version: event.target.value })} />
        </label>
        <label className="catalog-editor-wide">
          <span>Descrição do item</span>
          <textarea value={draft.description} onChange={(event) => onDraftChange({ ...draft, description: event.target.value })} />
        </label>
        <label className="catalog-editor-wide">
          <span>Tags do item</span>
          <input value={draft.tagsText} onChange={(event) => onDraftChange({ ...draft, tagsText: event.target.value })} />
        </label>
      </div>

      {editableContent.contentError ? <div className="catalog-editor-error">{editableContent.contentError}</div> : null}

      {canEditStructuredContent ? (
        <div className="catalog-edit-subsection">
          <div className="catalog-edit-heading">
            <strong>Etapas</strong>
            <button type="button" className="command-button" onClick={() => onDraftChange(addCatalogDraftNode(draft, nextNodeId))}>
              <Plus size={14} aria-hidden="true" />
              Adicionar etapa
            </button>
          </div>
          <div className="catalog-edit-node-grid">
            {editableContent.nodes.map((node, index) => (
              <fieldset key={`${draft.itemKey}-edit-node-${node.id}-${index}`}>
                <legend>{node.id || `etapa ${index + 1}`}</legend>
                <div className="catalog-edit-row-actions" aria-label={`Ações da etapa ${node.id || index + 1}`}>
                  <button
                    type="button"
                    className="icon-button"
                    title={`Subir etapa ${node.id}`}
                    aria-label={`Subir etapa ${node.id}`}
                    onClick={() => onDraftChange(moveCatalogDraftNode(draft, index, -1))}
                    disabled={index === 0 || saving}
                  >
                    <ArrowUp size={14} aria-hidden="true" />
                  </button>
                  <button
                    type="button"
                    className="icon-button"
                    title={`Descer etapa ${node.id}`}
                    aria-label={`Descer etapa ${node.id}`}
                    onClick={() => onDraftChange(moveCatalogDraftNode(draft, index, 1))}
                    disabled={index === editableContent.nodes.length - 1 || saving}
                  >
                    <ArrowDown size={14} aria-hidden="true" />
                  </button>
                  <button
                    type="button"
                    className="icon-button danger"
                    title={`Remover etapa ${node.id}`}
                    aria-label={`Remover etapa ${node.id}`}
                    onClick={() => onDraftChange(removeCatalogDraftNode(draft, index))}
                    disabled={saving}
                  >
                    <Trash2 size={14} aria-hidden="true" />
                  </button>
                </div>
                <label>
                  <span>ID da etapa {node.id || index + 1}</span>
                  <input
                    value={node.id}
                    onChange={(event) => onDraftChange(updateCatalogDraftNodeId(draft, index, event.target.value))}
                  />
                </label>
                <label>
                  <span>Tipo da etapa {node.id}</span>
                  <select
                    value={node.type}
                    onChange={(event) => onDraftChange(updateCatalogDraftNodeField(draft, index, "type", event.target.value))}
                  >
                    <option value="">Selecione</option>
                    {CATALOG_NODE_TYPES.map((type) => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </select>
                </label>
                <label>
                  <span>Descrição da etapa {node.id}</span>
                  <textarea
                    value={node.description}
                    onChange={(event) => onDraftChange(updateCatalogDraftNodeField(draft, index, "description", event.target.value))}
                  />
                </label>
                <label>
                  <span>Prompt da etapa {node.id}</span>
                  <input
                    value={node.promptId}
                    onChange={(event) => onDraftChange(updateCatalogDraftNodeField(draft, index, "promptId", event.target.value))}
                  />
                </label>
                <label>
                  <span>Schema da etapa {node.id}</span>
                  <input
                    value={node.outputSchema}
                    onChange={(event) => onDraftChange(updateCatalogDraftNodeField(draft, index, "outputSchema", event.target.value))}
                  />
                </label>
              </fieldset>
            ))}
          </div>
        </div>
      ) : null}

      {canEditStructuredContent ? (
        <div className="catalog-edit-subsection">
          <div className="catalog-edit-heading">
            <strong>Conexões internas</strong>
          </div>
          {editableContent.nodes.length >= 2 ? (
            <div className="catalog-edit-edge-composer">
              <label>
                <span>Origem da nova conexão</span>
                <select defaultValue={editableContent.nodes[0]?.id ?? ""} data-catalog-edge-from>
                  {editableContent.nodes.map((node) => (
                    <option key={`edge-from-${node.id}`} value={node.id}>{node.id}</option>
                  ))}
                </select>
              </label>
              <label>
                <span>Destino da nova conexão</span>
                <select defaultValue={editableContent.nodes[1]?.id ?? editableContent.nodes[0]?.id ?? ""} data-catalog-edge-to>
                  {editableContent.nodes.map((node) => (
                    <option key={`edge-to-${node.id}`} value={node.id}>{node.id}</option>
                  ))}
                </select>
              </label>
              <label>
                <span>Condição opcional</span>
                <input placeholder="Ex.: state.approved == true" data-catalog-edge-condition />
              </label>
              <button
                type="button"
                className="command-button"
                onClick={(event) => {
                  const container = event.currentTarget.closest(".catalog-edit-edge-composer");
                  const from = container?.querySelector<HTMLSelectElement>("[data-catalog-edge-from]")?.value ?? "";
                  const to = container?.querySelector<HTMLSelectElement>("[data-catalog-edge-to]")?.value ?? "";
                  const conditionInput = container?.querySelector<HTMLInputElement>("[data-catalog-edge-condition]");
                  onDraftChange(addCatalogDraftEdge(draft, from, to, conditionInput?.value ?? ""));
                  if (conditionInput) {
                    conditionInput.value = "";
                  }
                }}
                disabled={saving || editableContent.nodes.length < 2}
              >
                <Plus size={14} aria-hidden="true" />
                Adicionar conexão
              </button>
            </div>
          ) : null}
          <div className="catalog-edit-edge-grid">
            {editableContent.edges.map((edge, index) => (
              <fieldset key={`${draft.itemKey}-edit-edge-${edge.from}-${edge.to}-${index}`}>
                <legend>{edge.from} {"->"} {edge.to}</legend>
                <div className="catalog-edit-row-actions" aria-label={`Ações da conexão ${edge.from} para ${edge.to}`}>
                  <button
                    type="button"
                    className="icon-button danger"
                    title={`Remover conexão ${edge.from} para ${edge.to}`}
                    aria-label={`Remover conexão ${edge.from} para ${edge.to}`}
                    onClick={() => onDraftChange(removeCatalogDraftEdge(draft, index))}
                    disabled={saving}
                  >
                    <Trash2 size={14} aria-hidden="true" />
                  </button>
                </div>
                <label>
                  <span>Origem da conexão {index + 1}</span>
                  <select
                    value={edge.from}
                    onChange={(event) => onDraftChange(updateCatalogDraftEdgeEndpoint(draft, index, "from", event.target.value))}
                  >
                    {catalogEdgeEndpointOptions(editableContent.nodes, edge.from).map((nodeId) => (
                      <option key={`edge-${index}-from-${nodeId}`} value={nodeId}>{nodeId}</option>
                    ))}
                  </select>
                </label>
                <label>
                  <span>Destino da conexão {index + 1}</span>
                  <select
                    value={edge.to}
                    onChange={(event) => onDraftChange(updateCatalogDraftEdgeEndpoint(draft, index, "to", event.target.value))}
                  >
                    {catalogEdgeEndpointOptions(editableContent.nodes, edge.to).map((nodeId) => (
                      <option key={`edge-${index}-to-${nodeId}`} value={nodeId}>{nodeId}</option>
                    ))}
                  </select>
                </label>
                <label>
                  <span>Condição da conexão {edge.from} para {edge.to}</span>
                  <input
                    value={edge.condition}
                    placeholder="Sem condição"
                    onChange={(event) => onDraftChange(updateCatalogDraftEdgeCondition(draft, index, event.target.value))}
                  />
                </label>
              </fieldset>
            ))}
          </div>
          {!editableContent.edges.length ? <p className="catalog-edit-empty">Nenhuma conexão interna.</p> : null}
        </div>
      ) : null}

      {canEditInternalAssets ? (
        <div className="catalog-edit-subsection">
          <div className="catalog-edit-heading">
            <strong>Assets internos</strong>
            <div className="catalog-edit-heading-actions">
              <button type="button" className="command-button" onClick={() => onDraftChange(addCatalogDraftAsset(draft, "prompts", nextPromptId))}>
                <Plus size={14} aria-hidden="true" />
                Adicionar prompt
              </button>
              <button type="button" className="command-button" onClick={() => onDraftChange(addCatalogDraftAsset(draft, "schemas", nextSchemaId))}>
                <Plus size={14} aria-hidden="true" />
                Adicionar schema
              </button>
            </div>
          </div>
          <div className="catalog-edit-asset-grid">
            {editableContent.prompts.map((asset, index) => (
              <fieldset key={`${draft.itemKey}-prompt-${asset.id}-${index}`}>
                <legend>Prompt {asset.id || index + 1}</legend>
                <div className="catalog-edit-row-actions" aria-label={`Ações do prompt ${asset.id || index + 1}`}>
                  <button
                    type="button"
                    className="icon-button danger"
                    title={`Remover prompt ${asset.id}`}
                    aria-label={`Remover prompt ${asset.id}`}
                    onClick={() => onDraftChange(removeCatalogDraftAsset(draft, "prompts", index))}
                    disabled={saving}
                  >
                    <Trash2 size={14} aria-hidden="true" />
                  </button>
                </div>
                <label>
                  <span>ID do prompt {asset.id || index + 1}</span>
                  <input
                    value={asset.id}
                    onChange={(event) => onDraftChange(updateCatalogDraftAssetField(draft, "prompts", index, "id", event.target.value))}
                  />
                </label>
                <label>
                  <span>Path do prompt {asset.id || index + 1}</span>
                  <input
                    value={asset.path}
                    onChange={(event) => onDraftChange(updateCatalogDraftAssetField(draft, "prompts", index, "path", event.target.value))}
                  />
                </label>
                <label>
                  <span>Conteúdo do prompt {asset.id || index + 1}</span>
                  <textarea
                    className="catalog-editor-code"
                    value={asset.content}
                    onChange={(event) => onDraftChange(updateCatalogDraftAssetField(draft, "prompts", index, "content", event.target.value))}
                  />
                </label>
              </fieldset>
            ))}
            {editableContent.schemas.map((asset, index) => (
              <fieldset key={`${draft.itemKey}-schema-${asset.id}-${index}`}>
                <legend>Schema {asset.id || index + 1}</legend>
                <div className="catalog-edit-row-actions" aria-label={`Ações do schema ${asset.id || index + 1}`}>
                  <button
                    type="button"
                    className="icon-button danger"
                    title={`Remover schema ${asset.id}`}
                    aria-label={`Remover schema ${asset.id}`}
                    onClick={() => onDraftChange(removeCatalogDraftAsset(draft, "schemas", index))}
                    disabled={saving}
                  >
                    <Trash2 size={14} aria-hidden="true" />
                  </button>
                </div>
                <label>
                  <span>ID do schema {asset.id || index + 1}</span>
                  <input
                    value={asset.id}
                    onChange={(event) => onDraftChange(updateCatalogDraftAssetField(draft, "schemas", index, "id", event.target.value))}
                  />
                </label>
                <label>
                  <span>Path do schema {asset.id || index + 1}</span>
                  <input
                    value={asset.path}
                    onChange={(event) => onDraftChange(updateCatalogDraftAssetField(draft, "schemas", index, "path", event.target.value))}
                  />
                </label>
                <CatalogInternalSchemaEditor
                  asset={asset}
                  draft={draft}
                  index={index}
                  onDraftChange={onDraftChange}
                  saving={saving}
                />
              </fieldset>
            ))}
          </div>
          {!editableContent.prompts.length && !editableContent.schemas.length ? (
            <p className="catalog-edit-empty">Nenhum prompt ou schema interno.</p>
          ) : null}
        </div>
      ) : null}

      {showNodePatchEditor ? (
        <label className="catalog-editor-wide">
          <span>Patch JSON do nó</span>
          <textarea
            className="catalog-editor-code"
            value={draft.nodePatchText}
            onChange={(event) => onDraftChange({ ...draft, nodePatchText: event.target.value })}
          />
        </label>
      ) : null}
      {nodePatchError ? <div className="catalog-editor-error">{nodePatchError}</div> : null}

      <div className={`catalog-editor-validation ${validation.errors.length ? "invalid" : "valid"}`} role="status">
        <strong>{validation.errors.length ? "Ajustes necessários antes de salvar" : "Pronto para salvar"}</strong>
        {validation.errors.length ? (
          <ul>
            {validation.errors.map((error) => <li key={`catalog-editor-error-${error}`}>{error}</li>)}
          </ul>
        ) : null}
        {validation.warnings.length ? (
          <ul>
            {validation.warnings.map((warning) => <li key={`catalog-editor-warning-${warning}`}>{warning}</li>)}
          </ul>
        ) : null}
      </div>

      <div className="catalog-editor-actions">
        <button type="button" className="command-button primary" onClick={onSave} disabled={saveDisabled}>
          <Save size={16} aria-hidden="true" />
          {saving ? "Salvando" : "Salvar curadoria"}
        </button>
        <button type="button" className="command-button" onClick={onCancel} disabled={saving}>
          <X size={16} aria-hidden="true" />
          Cancelar
        </button>
      </div>
    </div>
  );
}

function catalogEditDraftFromItem(item: LocalCatalogItem): CatalogEditDraft {
  return {
    itemKey: localCatalogItemKey(item),
    id: item.id,
    kind: item.kind,
    name: item.name,
    version: item.version,
    description: item.description,
    tagsText: item.tags.join(", "),
    content: item.content ?? "",
    nodePatchText: item.nodePatch ? `${JSON.stringify(item.nodePatch, null, 2)}\n` : "",
  };
}

function catalogEditableContent(draft: CatalogEditDraft): CatalogEditableContent {
  if (!draft.content.trim() || (draft.kind !== "tool" && draft.kind !== "skill" && draft.kind !== "agent_template")) {
    return { nodes: [], edges: [], prompts: [], schemas: [], contentError: "" };
  }
  const parsed = catalogDraftParsedContent(draft);
  if (!parsed) {
    return { nodes: [], edges: [], prompts: [], schemas: [], contentError: "Conteúdo estruturado inválido; cancele ou restaure uma revisão antes de editar." };
  }
  const root = catalogDraftContentRoot(parsed);
  const nodes = Array.isArray(root.nodes)
    ? root.nodes.flatMap((rawNode) => {
        if (!isRecord(rawNode) || typeof rawNode.id !== "string") {
          return [];
        }
        return [{
          id: rawNode.id,
          type: typeof rawNode.type === "string" ? rawNode.type : "",
          description: typeof rawNode.description === "string" ? rawNode.description : "",
          promptId: typeof rawNode.promptId === "string" ? rawNode.promptId : "",
          outputSchema: typeof rawNode.outputSchema === "string" ? rawNode.outputSchema : "",
        }];
      })
    : [];
  const edges = Array.isArray(root.edges)
    ? root.edges.flatMap((rawEdge) => {
        if (!isRecord(rawEdge) || typeof rawEdge.from !== "string" || typeof rawEdge.to !== "string") {
          return [];
        }
        return [{
          from: rawEdge.from,
          to: rawEdge.to,
          condition: typeof rawEdge.condition === "string" ? rawEdge.condition : "",
        }];
      })
    : [];
  const prompts = catalogEditableAssets(parsed.prompts);
  const schemas = catalogEditableAssets(parsed.schemas);
  return { nodes, edges, prompts, schemas, contentError: "" };
}

function catalogEditableAssets(value: unknown): Array<{ id: string; path: string; content: string }> {
  if (!Array.isArray(value)) {
    return [];
  }
  return value.flatMap((rawAsset) => {
    if (!isRecord(rawAsset)) {
      return [];
    }
    return [{
      id: typeof rawAsset.id === "string" ? rawAsset.id : "",
      path: typeof rawAsset.path === "string" ? rawAsset.path : "",
      content: typeof rawAsset.content === "string" ? rawAsset.content : "",
    }];
  });
}

function catalogNodePatchDraftError(draft: CatalogEditDraft): string {
  if (!draft.nodePatchText.trim()) {
    return "";
  }
  try {
    const parsed = JSON.parse(draft.nodePatchText);
    return isRecord(parsed) ? "" : "Patch JSON do nó precisa ser objeto.";
  } catch {
    return "Patch JSON do nó é inválido.";
  }
}

function catalogEdgeEndpointOptions(
  nodes: CatalogEditableContent["nodes"],
  selectedId: string,
): string[] {
  const ids = nodes.map((node) => node.id).filter(Boolean);
  if (selectedId && !ids.includes(selectedId)) {
    return [selectedId, ...ids];
  }
  return ids;
}

function catalogEditorValidation(
  draft: CatalogEditDraft,
  editableContent: CatalogEditableContent,
  nodePatchError: string,
): CatalogEditorValidation {
  const errors: string[] = [];
  const warnings: string[] = [];
  if (!draft.name.trim()) {
    errors.push("Informe o nome do item.");
  }
  if (!draft.version.trim()) {
    errors.push("Informe a versão do item.");
  }
  if (editableContent.contentError) {
    errors.push(editableContent.contentError);
  }
  if (nodePatchError) {
    errors.push(nodePatchError);
  }
  if (!editableContent.contentError && draft.content.trim()) {
    const idCounts = new Map<string, number>();
    for (const node of editableContent.nodes) {
      const id = node.id.trim();
      if (!id) {
        errors.push("Toda etapa precisa ter ID.");
      } else {
        idCounts.set(id, (idCounts.get(id) ?? 0) + 1);
        if (!/^[A-Za-z][A-Za-z0-9_-]*$/.test(id)) {
          errors.push(`ID da etapa "${id}" deve começar com letra e usar apenas letras, números, "_" ou "-".`);
        }
      }
      if (!node.type.trim()) {
        errors.push(`Etapa "${id || "sem ID"}" precisa ter tipo.`);
      } else if (!CATALOG_NODE_TYPES.includes(node.type as typeof CATALOG_NODE_TYPES[number])) {
        errors.push(`Tipo "${node.type}" da etapa "${id || "sem ID"}" não é suportado.`);
      }
    }
    for (const [id, count] of idCounts) {
      if (count > 1) {
        errors.push(`ID de etapa duplicado: "${id}".`);
      }
    }
    const nodeIds = new Set(editableContent.nodes.map((node) => node.id));
    const edgeKeys = new Set<string>();
    for (const edge of editableContent.edges) {
      if (!nodeIds.has(edge.from)) {
        errors.push(`Conexão referencia origem inexistente: "${edge.from}".`);
      }
      if (!nodeIds.has(edge.to)) {
        errors.push(`Conexão referencia destino inexistente: "${edge.to}".`);
      }
      if (edge.from && edge.from === edge.to) {
        warnings.push(`Conexão "${edge.from} -> ${edge.to}" aponta para a própria etapa.`);
      }
      const edgeKey = `${edge.from}->${edge.to}`;
      if (edgeKeys.has(edgeKey)) {
        warnings.push(`Conexão duplicada: "${edge.from} -> ${edge.to}".`);
      }
      edgeKeys.add(edgeKey);
    }
    validateCatalogEditorAssets(editableContent.prompts, "prompt", "prompts", errors);
    validateCatalogEditorAssets(editableContent.schemas, "schema", "schemas", errors);
  }
  return {
    errors: Array.from(new Set(errors)),
    warnings: Array.from(new Set(warnings)),
  };
}

function validateCatalogEditorAssets(
  assets: Array<{ id: string; path: string; content: string }>,
  label: "prompt" | "schema",
  prefix: "prompts" | "schemas",
  errors: string[],
): void {
  const seenIds = new Map<string, number>();
  const seenPaths = new Map<string, number>();
  for (const [index, asset] of assets.entries()) {
    const number = index + 1;
    const id = asset.id.trim();
    const path = catalogNormalizedAssetPath(asset.path);
    if (!id) {
      errors.push(`Asset ${label} ${number} precisa ter ID.`);
    } else {
      seenIds.set(id, (seenIds.get(id) ?? 0) + 1);
      if (!/^[A-Za-z0-9][A-Za-z0-9_-]*$/.test(id)) {
        errors.push(`ID do ${label} "${id}" deve usar apenas letras, números, "_" ou "-".`);
      }
    }
    if (!path) {
      errors.push(`Asset ${label} "${id || number}" precisa ter path.`);
    } else {
      seenPaths.set(path, (seenPaths.get(path) ?? 0) + 1);
      if (path === "agent.flow.json" || path.includes("\0") || path.split("/").includes("..") || /^[A-Za-z]:\//.test(path) || path.startsWith("/")) {
        errors.push(`Path do ${label} "${id || number}" é inválido.`);
      }
      if (path !== prefix && !path.startsWith(`${prefix}/`)) {
        errors.push(`Path do ${label} "${id || number}" deve ficar em ${prefix}/.`);
      }
    }
    if (!asset.content.trim()) {
      errors.push(`Asset ${label} "${id || number}" precisa ter conteúdo.`);
    }
    if (label === "schema" && asset.content.trim()) {
      try {
        const parsedSchema = JSON.parse(asset.content) as unknown;
        if (!isRecord(parsedSchema)) {
          errors.push(`Conteúdo do schema "${id || number}" precisa ser um objeto JSON Schema.`);
        } else {
          for (const issue of validateSchemaSemantics(parsedSchema)) {
            if (issue.severity === "error") {
              errors.push(`Schema "${id || number}": ${issue.path} - ${issue.message}`);
            }
          }
        }
      } catch {
        errors.push(`Conteúdo do schema "${id || number}" precisa ser JSON válido.`);
      }
    }
  }
  for (const [id, count] of seenIds) {
    if (count > 1) {
      errors.push(`ID de ${label} duplicado: "${id}".`);
    }
  }
  for (const [path, count] of seenPaths) {
    if (count > 1) {
      errors.push(`Path de ${label} duplicado: "${path}".`);
    }
  }
}

function uniqueCatalogNodeId(existingIds: string[], baseId: string): string {
  const existing = new Set(existingIds);
  if (!existing.has(baseId)) {
    return baseId;
  }
  for (let index = 2; index < 1_000; index += 1) {
    const candidate = `${baseId}_${index}`;
    if (!existing.has(candidate)) {
      return candidate;
    }
  }
  return `${baseId}_${Date.now()}`;
}

function uniqueCatalogAssetId(existingIds: string[], baseId: string): string {
  return uniqueCatalogNodeId(existingIds, baseId);
}

function updateCatalogDraftNodeField(
  draft: CatalogEditDraft,
  index: number,
  field: "type" | "description" | "promptId" | "outputSchema",
  value: string,
): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.nodes) || !isRecord(root.nodes[index])) {
      return;
    }
    setDraftRecordStringField(root.nodes[index], field, value, field === "type");
  });
}

function updateCatalogDraftNodeId(draft: CatalogEditDraft, index: number, value: string): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.nodes) || !isRecord(root.nodes[index])) {
      return;
    }
    const node = root.nodes[index];
    const previousId = typeof node.id === "string" ? node.id : "";
    setDraftRecordStringField(node, "id", value, true);
    const nextId = typeof node.id === "string" ? node.id : "";
    if (!previousId || !nextId || previousId === nextId || !Array.isArray(root.edges)) {
      return;
    }
    for (const edge of root.edges) {
      if (!isRecord(edge)) {
        continue;
      }
      if (edge.from === previousId) {
        edge.from = nextId;
      }
      if (edge.to === previousId) {
        edge.to = nextId;
      }
    }
  });
}

function addCatalogDraftNode(draft: CatalogEditDraft, nodeId: string): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    const nodes: unknown[] = Array.isArray(root.nodes) ? root.nodes : [];
    root.nodes = nodes;
    const previousNode = nodes.length ? nodes[nodes.length - 1] : undefined;
    const previousPosition = isRecord(previousNode) && isRecord(previousNode.position)
      ? previousNode.position
      : undefined;
    nodes.push({
      id: nodeId,
      type: "code",
      description: "Nova etapa do bloco.",
      position: {
        x: typeof previousPosition?.x === "number" ? previousPosition.x + 220 : nodes.length * 220,
        y: typeof previousPosition?.y === "number" ? previousPosition.y : 0,
      },
    });
  });
}

function moveCatalogDraftNode(draft: CatalogEditDraft, index: number, direction: -1 | 1): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.nodes)) {
      return;
    }
    const nextIndex = index + direction;
    if (nextIndex < 0 || nextIndex >= root.nodes.length) {
      return;
    }
    const [node] = root.nodes.splice(index, 1);
    root.nodes.splice(nextIndex, 0, node);
  });
}

function removeCatalogDraftNode(draft: CatalogEditDraft, index: number): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.nodes) || !isRecord(root.nodes[index])) {
      return;
    }
    const nodeId = typeof root.nodes[index].id === "string" ? root.nodes[index].id : "";
    root.nodes.splice(index, 1);
    if (!Array.isArray(root.edges) || !nodeId) {
      return;
    }
    root.edges = root.edges.filter((edge) => !isRecord(edge) || (edge.from !== nodeId && edge.to !== nodeId));
  });
}

function updateCatalogDraftEdgeCondition(draft: CatalogEditDraft, index: number, value: string): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.edges) || !isRecord(root.edges[index])) {
      return;
    }
    setDraftRecordStringField(root.edges[index], "condition", value, false);
  });
}

function updateCatalogDraftEdgeEndpoint(
  draft: CatalogEditDraft,
  index: number,
  field: "from" | "to",
  value: string,
): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.edges) || !isRecord(root.edges[index])) {
      return;
    }
    setDraftRecordStringField(root.edges[index], field, value, true);
  });
}

function addCatalogDraftEdge(draft: CatalogEditDraft, from: string, to: string, condition: string): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    const edges: unknown[] = Array.isArray(root.edges) ? root.edges : [];
    root.edges = edges;
    const edge: Record<string, unknown> = { from, to };
    setDraftRecordStringField(edge, "condition", condition, false);
    edges.push(edge);
  });
}

function removeCatalogDraftEdge(draft: CatalogEditDraft, index: number): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root) => {
    if (!Array.isArray(root.edges)) {
      return;
    }
    root.edges.splice(index, 1);
  });
}

function updateCatalogDraftAssetField(
  draft: CatalogEditDraft,
  collection: "prompts" | "schemas",
  index: number,
  field: "id" | "path" | "content",
  value: string,
): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (root, parsed) => {
    const targetRoot = isRecord(parsed) ? parsed : root;
    if (!Array.isArray(targetRoot[collection]) || !isRecord(targetRoot[collection][index])) {
      return;
    }
    const asset = targetRoot[collection][index];
    const previousId = field === "id" && typeof asset.id === "string" ? asset.id : "";
    setDraftRecordStringField(asset, field, field === "path" ? catalogNormalizedAssetPath(value) : value, true);
    if (field === "id") {
      const nextId = typeof asset.id === "string" ? asset.id : "";
      if (previousId && nextId && previousId !== nextId) {
        remapCatalogDraftAssetRefs(root, collection, previousId, nextId);
      }
    }
  });
}

function addCatalogDraftAsset(
  draft: CatalogEditDraft,
  collection: "prompts" | "schemas",
  assetId: string,
): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (_root, parsed) => {
    const targetRoot = isRecord(parsed) ? parsed : _root;
    const assets: unknown[] = Array.isArray(targetRoot[collection]) ? targetRoot[collection] : [];
    targetRoot[collection] = assets;
    assets.push({
      id: assetId,
      path: collection === "prompts" ? `prompts/${assetId}.md` : `schemas/${assetId}.schema.json`,
      content: collection === "prompts"
        ? `# ${assetId}\n\nDescreva o comportamento esperado deste prompt.\n`
        : `${JSON.stringify({ type: "object", properties: {} }, null, 2)}\n`,
    });
  });
}

function removeCatalogDraftAsset(
  draft: CatalogEditDraft,
  collection: "prompts" | "schemas",
  index: number,
): CatalogEditDraft {
  return updateCatalogDraftContent(draft, (_root, parsed) => {
    const targetRoot = isRecord(parsed) ? parsed : _root;
    if (!Array.isArray(targetRoot[collection])) {
      return;
    }
    targetRoot[collection].splice(index, 1);
  });
}

function remapCatalogDraftAssetRefs(
  root: Record<string, unknown>,
  collection: "prompts" | "schemas",
  previousId: string,
  nextId: string,
): void {
  const field = collection === "prompts" ? "promptId" : "outputSchema";
  if (Array.isArray(root.nodes)) {
    for (const node of root.nodes) {
      if (isRecord(node) && node[field] === previousId) {
        node[field] = nextId;
      }
    }
  }
  if (isRecord(root.targetNodePatch) && root.targetNodePatch[field] === previousId) {
    root.targetNodePatch[field] = nextId;
  }
}

function catalogNormalizedAssetPath(value: string): string {
  return value.trim().replaceAll("\\", "/").replace(/^\.\/+/, "");
}

function updateCatalogDraftContent(
  draft: CatalogEditDraft,
  updater: (root: Record<string, unknown>, parsed: Record<string, unknown>) => void,
): CatalogEditDraft {
  const parsed = catalogDraftParsedContent(draft);
  if (!parsed) {
    return draft;
  }
  const root = catalogDraftContentRoot(parsed);
  updater(root, parsed);
  return {
    ...draft,
    content: `${JSON.stringify(parsed, null, 2)}\n`,
  };
}

function catalogDraftParsedContent(draft: CatalogEditDraft): Record<string, unknown> | null {
  try {
    const parsed = JSON.parse(draft.content);
    return isRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function catalogDraftContentRoot(parsed: Record<string, unknown>): Record<string, unknown> {
  return isRecord(parsed.flow) ? parsed.flow : parsed;
}

function setDraftRecordStringField(
  record: Record<string, unknown>,
  field: string,
  value: string,
  required: boolean,
): void {
  const normalized = value.trim();
  if (normalized || required) {
    record[field] = normalized;
  } else {
    delete record[field];
  }
}

function catalogRevisionTimeline(item: LocalCatalogItem): LocalCatalogRevision[] {
  return [...(item.history ?? [])].sort((left, right) => right.revision - left.revision);
}

function localCatalogItemKey(item: Pick<LocalCatalogItem, "kind" | "id">): string {
  return `${item.kind}:${item.id}`;
}

function catalogItemCreatesBlock(item: LocalCatalogItem): boolean {
  if (!item.content || (item.kind !== "tool" && item.kind !== "skill")) {
    return false;
  }
  try {
    const parsed = JSON.parse(item.content) as { format?: unknown; nodes?: unknown };
    if (item.kind === "tool") {
      return parsed.format === "agent-flow-builder.tool-bundle.v1" && Array.isArray(parsed.nodes);
    }
    return parsed.format === "agent-flow-builder.skill.v1" && Array.isArray(parsed.nodes) && parsed.nodes.length > 0;
  } catch {
    return false;
  }
}

interface CatalogVisualSummary {
  label: string;
  nodes: Array<{ id: string; type: string; description?: string; promptId?: string; outputSchema?: string }>;
  edges: Array<{ from: string; to: string; condition?: string }>;
  promptCount: number;
  schemaCount: number;
  targetPatchKeys: string[];
  entryNodeIds: string[];
  exitNodeIds: string[];
  jsonPreview: string;
}

function catalogItemVisualSummary(item: LocalCatalogItem): CatalogVisualSummary | null {
  if (!item.content || (item.kind !== "tool" && item.kind !== "skill" && item.kind !== "agent_template")) {
    return null;
  }
  try {
    const parsed = JSON.parse(item.content) as unknown;
    if (!isRecord(parsed)) {
      return null;
    }
    const contentRoot = item.kind === "agent_template" && isRecord(parsed.flow) ? parsed.flow : parsed;
    const nodes = catalogVisualNodes(contentRoot.nodes);
    const edges = catalogVisualEdges(contentRoot.edges, nodes);
    const promptCount = Array.isArray(parsed.prompts) ? parsed.prompts.length : 0;
    const schemaCount = Array.isArray(parsed.schemas) ? parsed.schemas.length : 0;
    const targetPatchKeys = isRecord(parsed.targetNodePatch) ? Object.keys(parsed.targetNodePatch).sort() : [];
    if (!nodes.length && !targetPatchKeys.length) {
      return null;
    }
    return {
      label: catalogVisualSummaryLabel(item, parsed.format, nodes.length),
      nodes,
      edges,
      promptCount,
      schemaCount,
      targetPatchKeys,
      entryNodeIds: catalogEntryNodeIds(nodes, edges),
      exitNodeIds: catalogExitNodeIds(nodes, edges),
      jsonPreview: catalogVisualJsonPreview(parsed),
    };
  } catch {
    return null;
  }
}

function catalogVisualSummaryLabel(item: LocalCatalogItem, format: unknown, nodeCount: number): string {
  if (item.kind === "agent_template") {
    return "Template visual";
  }
  if (format === "agent-flow-builder.tool-bundle.v1") {
    return "Tool composta";
  }
  if (item.kind === "skill") {
    return nodeCount ? "Skill composta" : "Skill reutilizável";
  }
  return catalogKindLabel(item.kind);
}

function catalogVisualSummaryHeadline(summary: CatalogVisualSummary): string {
  if (summary.nodes.length) {
    return `${summary.label}: ${summary.nodes.length} nós, ${summary.edges.length} aresta(s)`;
  }
  return `${summary.label}: ${summary.targetPatchKeys.length} campo(s) do nó`;
}

function buildCatalogGovernanceReport(
  item: LocalCatalogItem,
  visualSummary: CatalogVisualSummary | null = catalogItemVisualSummary(item),
): CatalogGovernanceReport {
  const summary = collectCatalogGovernanceSummary(item, visualSummary);
  const checks = catalogGovernanceChecks(item, summary);
  const warningCount = checks.filter((check) => check.status === "warn").length;
  summary.warningCount = warningCount;
  summary.status = warningCount ? "warning" : "ready";
  summary.portablePackageReady = ["versioning", "content", "portability"].every((checkId) =>
    checks.some((check) => check.id === checkId && check.status === "pass"),
  );
  const base = {
    format: "agent-flow-builder.catalog-governance.v1" as const,
    exportedAt: new Date().toISOString(),
    item: {
      id: item.id,
      kind: item.kind,
      name: item.name,
      source: item.source,
      version: item.version,
      revision: item.revision,
      contentHash: item.contentHash,
      createdAt: item.createdAt,
      updatedAt: item.updatedAt,
      descriptionPresent: Boolean(item.description.trim()),
      tags: item.tags,
    },
    summary,
    checks,
    governance: {
      excludesRawCatalogContent: true,
      excludesSecretValues: true,
      source: "catalog-panel" as const,
    },
  };
  return {
    ...base,
    packageHash: simpleHash(stableStringify(base)),
  };
}

function collectCatalogGovernanceSummary(
  item: LocalCatalogItem,
  visualSummary: CatalogVisualSummary | null,
): CatalogGovernanceSummary {
  const contentInfo = catalogGovernanceContentInfo(item);
  return {
    status: "ready",
    warningCount: 0,
    revisionHistoryCount: item.history.length,
    tagCount: item.tags.length,
    contentMode: contentInfo.mode,
    contentFormat: contentInfo.format,
    nodeCount: visualSummary?.nodes.length ?? 0,
    edgeCount: visualSummary?.edges.length ?? 0,
    entryNodeCount: visualSummary?.entryNodeIds.length ?? 0,
    exitNodeCount: visualSummary?.exitNodeIds.length ?? 0,
    promptAssetCount: visualSummary?.promptCount ?? contentInfo.promptAssetCount,
    schemaAssetCount: visualSummary?.schemaCount ?? contentInfo.schemaAssetCount,
    nodePatchKeyCount: isRecord(item.nodePatch) ? Object.keys(item.nodePatch).length : 0,
    targetPatchKeyCount: visualSummary?.targetPatchKeys.length ?? contentInfo.targetPatchKeyCount,
    createsBlock: catalogItemCreatesBlock(item),
    portablePackageReady: false,
  };
}

function catalogGovernanceContentInfo(item: LocalCatalogItem): {
  mode: CatalogGovernanceSummary["contentMode"];
  format: string | null;
  promptAssetCount: number;
  schemaAssetCount: number;
  targetPatchKeyCount: number;
} {
  const trimmedContent = item.content?.trim() ?? "";
  if (!trimmedContent) {
    return { mode: "empty", format: null, promptAssetCount: 0, schemaAssetCount: 0, targetPatchKeyCount: 0 };
  }
  const shouldParseJson =
    trimmedContent.startsWith("{") ||
    trimmedContent.startsWith("[") ||
    item.kind === "schema" ||
    item.kind === "agent_template";
  if (!shouldParseJson) {
    return { mode: "text", format: null, promptAssetCount: 0, schemaAssetCount: 0, targetPatchKeyCount: 0 };
  }
  try {
    const parsed = JSON.parse(trimmedContent) as unknown;
    if (!isRecord(parsed)) {
      return { mode: "json", format: null, promptAssetCount: 0, schemaAssetCount: 0, targetPatchKeyCount: 0 };
    }
    return {
      mode: "json",
      format: typeof parsed.format === "string" ? parsed.format : null,
      promptAssetCount: Array.isArray(parsed.prompts) ? parsed.prompts.length : 0,
      schemaAssetCount: Array.isArray(parsed.schemas) ? parsed.schemas.length : 0,
      targetPatchKeyCount: isRecord(parsed.targetNodePatch) ? Object.keys(parsed.targetNodePatch).length : 0,
    };
  } catch {
    return { mode: "invalid_json", format: null, promptAssetCount: 0, schemaAssetCount: 0, targetPatchKeyCount: 0 };
  }
}

function catalogGovernanceChecks(item: LocalCatalogItem, summary: CatalogGovernanceSummary): CatalogGovernanceCheck[] {
  const hasVersioning = Boolean(item.version.trim()) && item.revision > 0 && Boolean(item.contentHash.trim());
  const hasReusablePayload =
    (summary.contentMode !== "empty" && summary.contentMode !== "invalid_json") ||
    summary.nodePatchKeyCount > 0 ||
    summary.targetPatchKeyCount > 0 ||
    summary.nodeCount > 0;
  const hasGraphOrPatch =
    item.kind === "prompt" ||
    item.kind === "schema" ||
    summary.nodeCount > 0 ||
    summary.nodePatchKeyCount > 0 ||
    summary.targetPatchKeyCount > 0;
  return [
    {
      id: "versioning",
      label: "Versionamento",
      status: hasVersioning ? "pass" : "warn",
      detail: hasVersioning
        ? `v${item.version}, rev. ${item.revision}, hash ${item.contentHash}`
        : "Inclua versão, revisão e hash de conteúdo antes de tratar como pacote estável.",
    },
    {
      id: "metadata",
      label: "Metadados",
      status: item.description.trim() && item.tags.length ? "pass" : "warn",
      detail: item.description.trim() && item.tags.length
        ? `${item.tags.length} tag(s) e descrição preenchida.`
        : "Descrição e tags ajudam busca, curadoria e reuso por outros flows.",
    },
    {
      id: "content",
      label: "Conteúdo",
      status: hasReusablePayload ? "pass" : "warn",
      detail: summary.contentMode === "invalid_json"
        ? "O conteúdo parece JSON, mas não pôde ser analisado."
        : hasReusablePayload
          ? "Há conteúdo, patch ou subgrafo suficiente para reuso."
          : "Sem conteúdo ou patch reutilizável detectado.",
    },
    {
      id: "reuse-shape",
      label: "Forma de reuso",
      status: hasGraphOrPatch ? "pass" : "warn",
      detail: hasGraphOrPatch
        ? `${summary.nodeCount} nó(s), ${summary.edgeCount} aresta(s), ${summary.nodePatchKeyCount + summary.targetPatchKeyCount} campo(s) de patch.`
        : "Tools, skills e templates devem expor subgrafo ou patch aplicável.",
    },
    {
      id: "history",
      label: "Histórico",
      status: summary.revisionHistoryCount ? "pass" : "warn",
      detail: summary.revisionHistoryCount
        ? `${summary.revisionHistoryCount} revisão(ões) anterior(es) disponíveis para comparação/restauração.`
        : "Ainda não há revisão anterior para comparação ou rollback.",
    },
    {
      id: "portability",
      label: "Portabilidade",
      status: hasVersioning && Boolean(item.id.trim()) && Boolean(item.name.trim()) ? "pass" : "warn",
      detail: hasVersioning
        ? "Pode gerar pacote de catálogo com identidade, versão, revisão e hash."
        : "Pacotes portáteis precisam de identidade, versão, revisão e hash.",
    },
  ];
}

function buildCatalogLibraryGovernanceReport(catalog: LocalCatalog): CatalogLibraryGovernanceReport {
  const itemReports = catalog.items.map((item) => buildCatalogGovernanceReport(item));
  const items: CatalogLibraryGovernanceItem[] = itemReports.map((report) => ({
    id: report.item.id,
    kind: report.item.kind,
    name: report.item.name,
    source: report.item.source,
    version: report.item.version,
    revision: report.item.revision,
    contentHash: report.item.contentHash,
    packageHash: report.packageHash,
    summary: report.summary,
    checks: report.checks,
  }));
  const kindCounts: Record<LocalCatalogItemKind, number> = {
    prompt: 0,
    schema: 0,
    tool: 0,
    agent_template: 0,
    skill: 0,
  };
  const warningCheckCounts: Record<string, number> = {};
  for (const item of items) {
    kindCounts[item.kind] += 1;
    for (const check of item.checks) {
      if (check.status === "warn") {
        warningCheckCounts[check.id] = (warningCheckCounts[check.id] ?? 0) + 1;
      }
    }
  }
  const base = {
    format: "agent-flow-builder.catalog-library-governance.v1" as const,
    exportedAt: new Date().toISOString(),
    catalog: {
      path: catalog.path,
    },
    summary: {
      itemCount: items.length,
      localCount: items.filter((item) => item.source === "local").length,
      builtinCount: items.filter((item) => item.source === "builtin").length,
      readyCount: items.filter((item) => item.summary.status === "ready").length,
      warningCount: items.filter((item) => item.summary.status === "warning").length,
      portablePackageReadyCount: items.filter((item) => item.summary.portablePackageReady).length,
      kindCounts,
      warningCheckCounts,
    },
    items,
    governance: {
      excludesRawCatalogContent: true,
      excludesSecretValues: true,
      source: "catalog-panel" as const,
    },
  };
  return {
    ...base,
    packageHash: simpleHash(stableStringify(base)),
  };
}

function catalogGovernanceCheckLabel(checkId: string): string {
  switch (checkId) {
    case "versioning":
      return "Versionamento";
    case "metadata":
      return "Metadados";
    case "content":
      return "Conteúdo";
    case "reuse-shape":
      return "Forma de reuso";
    case "history":
      return "Histórico";
    case "portability":
      return "Portabilidade";
    default:
      return checkId;
  }
}

function catalogVisualNodes(value: unknown): CatalogVisualSummary["nodes"] {
  if (!Array.isArray(value)) {
    return [];
  }
  return value.flatMap((rawNode) => {
    if (!isRecord(rawNode) || typeof rawNode.id !== "string") {
      return [];
    }
    return [{
      id: rawNode.id,
      type: typeof rawNode.type === "string" ? rawNode.type : "node",
      description: typeof rawNode.description === "string" ? rawNode.description : undefined,
      promptId: typeof rawNode.promptId === "string" ? rawNode.promptId : undefined,
      outputSchema: typeof rawNode.outputSchema === "string" ? rawNode.outputSchema : undefined,
    }];
  });
}

function catalogVisualEdges(value: unknown, nodes: CatalogVisualSummary["nodes"]): CatalogVisualSummary["edges"] {
  if (!Array.isArray(value)) {
    return [];
  }
  const nodeIds = new Set(nodes.map((node) => node.id));
  return value.flatMap((rawEdge) => {
    if (!isRecord(rawEdge) || typeof rawEdge.from !== "string" || typeof rawEdge.to !== "string") {
      return [];
    }
    if (!nodeIds.has(rawEdge.from) || !nodeIds.has(rawEdge.to)) {
      return [];
    }
    return [{
      from: rawEdge.from,
      to: rawEdge.to,
      condition: typeof rawEdge.condition === "string" ? rawEdge.condition : undefined,
    }];
  });
}

function catalogEntryNodeIds(nodes: CatalogVisualSummary["nodes"], edges: CatalogVisualSummary["edges"]): string[] {
  const targeted = new Set(edges.map((edge) => edge.to));
  return nodes.map((node) => node.id).filter((id) => !targeted.has(id));
}

function catalogExitNodeIds(nodes: CatalogVisualSummary["nodes"], edges: CatalogVisualSummary["edges"]): string[] {
  const sourced = new Set(edges.map((edge) => edge.from));
  return nodes.map((node) => node.id).filter((id) => !sourced.has(id));
}

function catalogVisualJsonPreview(value: unknown): string {
  const text = JSON.stringify(value, null, 2) ?? "";
  const lines = text.split("\n");
  const preview = lines.slice(0, 18).join("\n");
  return lines.length > 18 ? `${preview}\n...` : preview;
}

function catalogRevisionDiff(
  previous: Pick<LocalCatalogRevision, "content" | "nodePatch">,
  current: Pick<LocalCatalogItem, "content" | "nodePatch">,
): Array<{ kind: "added" | "removed"; text: string }> {
  const previousLines = catalogRevisionSnapshot(previous).split("\n");
  const currentLines = catalogRevisionSnapshot(current).split("\n");
  const rows: Array<{ kind: "added" | "removed"; text: string }> = [];
  const limit = Math.max(previousLines.length, currentLines.length);
  for (let index = 0; index < limit; index += 1) {
    const previousLine = previousLines[index] ?? "";
    const currentLine = currentLines[index] ?? "";
    if (previousLine === currentLine) {
      continue;
    }
    if (previousLine) {
      rows.push({ kind: "removed", text: previousLine });
    }
    if (currentLine) {
      rows.push({ kind: "added", text: currentLine });
    }
    if (rows.length >= 8) {
      break;
    }
  }
  return rows;
}

function catalogRevisionSnapshot(value: Pick<LocalCatalogItem | LocalCatalogRevision, "content" | "nodePatch">): string {
  if (typeof value.content === "string") {
    return value.content.trimEnd();
  }
  if (value.nodePatch) {
    return JSON.stringify(value.nodePatch, null, 2);
  }
  return "";
}

function GovernanceMetricCard({ label, value, detail, tone = "default" }: { label: string; value: string; detail: string; tone?: "default" | "ok" | "warn" }) {
  return (
    <div className={`metric-card ${tone !== "default" ? tone : ""}`}>
      <span>{label}</span>
      <strong>{value}</strong>
      <small>{detail}</small>
    </div>
  );
}

