  onStartBuilderOidcLogout: () => void;
  onClearBuilderAuthSession: () => void;
  onRefreshBuilderAuth: () => void;
  onProbeBuilderAuthExternalIntegrations: () => void;
  onHomologateBuilderAuthCorporateIntegrations: () => void;
  onExportBuilderAuthAudit: () => void;
  onBuilderAuthAuditFilterChange: (field: keyof BuilderAuthAuditFilterForm, value: string) => void;
  onResetBuilderAuthAuditFilters: () => void;
  onBuilderAuthRotationActorIdChange: (value: string) => void;
  onBuilderAuthRotationRoleChange: (value: string) => void;
  onBuilderAuthRotationAreasChange: (value: string) => void;
  onBuilderAuthRotationScopesChange: (value: string) => void;
  onBuilderAuthRotationExpiresAtChange: (value: string) => void;
  onGenerateBuilderAuthKey: () => void;
  onDisableBuilderAuthKey: (keyId: string) => void;
  onRefresh: () => void;
  onRefreshCollaborationConflicts: () => void;
  onCollaborationConflictFilterChange: (field: keyof CollaborationConflictFilterForm, value: string) => void;
  onResetCollaborationConflictFilters: () => void;
  onExportCollaborationConflictOverview: () => void;
  onCompareCollaborationConflictOverview: () => void;
  onSave: () => void;
  onMerge: () => void;
  onExport: () => void;
