  studioExperimentDashboardSnapshots,
  studioExperimentDashboardHistoryState,
  studioScenarioUseNodePins,
  studioScenarioRegressionThresholds,
  studioScenarioBatchResults,
  studioScenarioBatchApproval,
  studioAnnotationQueue,
  studioAnnotationQueueConflicts,
