              replayGovernanceHistoryConflicts={selectedScenarioReplayGovernanceConflicts}
              replayGovernanceHistoryResolutionHistory={selectedScenarioReplayGovernanceResolutionHistory}
              replayGovernanceHistoryCentralStatus={studioReplayGovernanceHistoryCentralStatus}
