function buildDockerAgentOperationalSummaries(
  agents: DockerRuntimeAgent[],
  entries: DockerRuntimeHistoryEntry[],
  currentOperation: DockerRuntimeOperationResult | null,
): Map<string, DockerAgentOperationalSummary> {
  const sortedEntries = [...entries].sort((left, right) => dockerHistoryEntryTime(right) - dockerHistoryEntryTime(left));
  const latestInvalidatingTime = latestDockerAgentSmokeInvalidatingTime(sortedEntries, currentOperation);
  const currentEvidence = currentOperation ? dockerAgentSmokeEvidencesFromOperation(currentOperation) : [];
  const historicalEvidence = sortedEntries.flatMap(dockerAgentSmokeEvidencesFromHistoryEntry);
  const evidence = [...currentEvidence, ...historicalEvidence].sort((left, right) => smokeEvidenceTime(right) - smokeEvidenceTime(left));
  const summaries = new Map<string, DockerAgentOperationalSummary>();
  for (const agent of agents) {
    const agentEvidence = evidence.find((candidate) => dockerAgentSmokeEvidenceMatchesAgent(candidate, agent));
    if (!agentEvidence) {
      summaries.set(agent.id, defaultDockerAgentOperationalSummary(agent));
      continue;
    }
    const evidenceTime = smokeEvidenceTime(agentEvidence);
    if (agentEvidence.ok && evidenceTime > 0 && latestInvalidatingTime > evidenceTime) {
      summaries.set(agent.id, {
        level: "warning",
        statusLabel: "desatualizado",
        detail: "Smoke passou, mas houve mudança de porta, build ou subida depois dele.",
        finishedAt: agentEvidence.finishedAt,
        basePath: agentEvidence.basePath,
        sessionId: agentEvidence.sessionId,
        transcriptCount: agentEvidence.transcriptCount,
        eventsCount: agentEvidence.eventsCount,
        jobsOperations: agentEvidence.jobsOperations,
      });
      continue;
    }
    summaries.set(agent.id, {
      level: agentEvidence.ok ? "ok" : "error",
      statusLabel: agentEvidence.ok ? "validado" : "erro",
      detail: agentEvidence.ok ? "Smoke deste agente executou metadata, sessão, turno, transcript e eventos." : agentEvidence.message,
      finishedAt: agentEvidence.finishedAt,
      basePath: agentEvidence.basePath,
      sessionId: agentEvidence.sessionId,
      transcriptCount: agentEvidence.transcriptCount,
      eventsCount: agentEvidence.eventsCount,
      jobsOperations: agentEvidence.jobsOperations,
    });
  }
  return summaries;
}

function defaultDockerAgentOperationalSummary(agent: DockerRuntimeAgent): DockerAgentOperationalSummary {
  return {
    level: "pending",
    statusLabel: "pendente",
    detail: "Smoke deste agente ainda não foi executado neste histórico.",
    finishedAt: null,
    basePath: joinRuntimePath(agent.routePrefix, agent.resourceName),
    sessionId: null,
    transcriptCount: null,
    eventsCount: null,
    jobsOperations: null,
  };
}

function latestDockerAgentSmokeInvalidatingTime(
  entries: DockerRuntimeHistoryEntry[],
  currentOperation: DockerRuntimeOperationResult | null,
): number {
  const invalidatingOperations = new Set<DockerRuntimeOperation>(["configure_ports", "setup_models", "build", "up"]);
  const historyTime = entries
    .filter((entry) => invalidatingOperations.has(entry.operation))
    .reduce((latest, entry) => Math.max(latest, dockerHistoryEntryTime(entry)), 0);
  if (!currentOperation || !invalidatingOperations.has(currentOperation.operation)) {
    return historyTime;
  }
  const operationTime = currentOperation.updatedAt ? Date.parse(currentOperation.updatedAt) : 0;
  return Math.max(historyTime, Number.isFinite(operationTime) ? operationTime : 0);
}

function dockerAgentSmokeEvidencesFromHistoryEntry(entry: DockerRuntimeHistoryEntry): DockerAgentSmokeEvidence[] {
  const finishedAt = entry.finishedAt;
  return [
    ...(entry.smoke ? [dockerAgentSmokeEvidenceFromResult(entry.smoke, true, entry.message, finishedAt)] : []),
    ...(entry.smokeFailure ? [dockerAgentSmokeEvidenceFromFailure(entry.smokeFailure, finishedAt)] : []),
    ...(entry.smokeAll?.results ?? []).map((result) => dockerAgentSmokeEvidenceFromResult(result, true, entry.message, finishedAt)),
    ...(entry.smokeAll?.failures ?? []).map((failure) => dockerAgentSmokeEvidenceFromFailure(failure, finishedAt)),
  ];
}

function dockerAgentSmokeEvidencesFromOperation(operation: DockerRuntimeOperationResult): DockerAgentSmokeEvidence[] {
  if (operation.operation !== "smoke") {
    return [];
  }
  const finishedAt = operation.updatedAt ?? null;
  return [
    ...(operation.smoke ? [dockerAgentSmokeEvidenceFromResult(operation.smoke, true, operation.message, finishedAt)] : []),
    ...(operation.smokeFailure ? [dockerAgentSmokeEvidenceFromFailure(operation.smokeFailure, finishedAt)] : []),
    ...(operation.smokeAll?.results ?? []).map((result) => dockerAgentSmokeEvidenceFromResult(result, true, operation.message, finishedAt)),
    ...(operation.smokeAll?.failures ?? []).map((failure) => dockerAgentSmokeEvidenceFromFailure(failure, finishedAt)),
  ];
}

function dockerAgentSmokeEvidenceFromResult(
  result: DockerRuntimeSmokeResult,
  ok: boolean,
  message: string,
  finishedAt: string | null,
): DockerAgentSmokeEvidence {
  return {
    agentId: result.agentId ?? null,
    routePrefix: result.routePrefix ?? "",
    resourceName: result.resourceName,
    basePath: result.basePath,
    ok,
    message,
    finishedAt,
    sessionId: result.sessionId,
    transcriptCount: result.transcriptCount,
    eventsCount: result.eventsCount,
    jobsOperations: extractRuntimeJobsOperations(result.agentMetadata ?? result.metadata),
  };
}

function dockerAgentSmokeEvidenceFromFailure(
  failure: DockerRuntimeSmokeFailure,
  finishedAt: string | null,
): DockerAgentSmokeEvidence {
  return {
    agentId: failure.agentId,
    routePrefix: failure.routePrefix,
    resourceName: failure.resourceName,
    basePath: failure.basePath,
    ok: false,
    message: failure.message,
    finishedAt,
    sessionId: null,
    transcriptCount: null,
    eventsCount: null,
    jobsOperations: null,
  };
}

function dockerAgentSmokeEvidenceMatchesAgent(evidence: DockerAgentSmokeEvidence, agent: DockerRuntimeAgent): boolean {
  if (evidence.agentId && evidence.agentId === agent.id) {
    return true;
  }
  return (
    evidence.basePath === joinRuntimePath(agent.routePrefix, agent.resourceName) ||
    (normalizeManifestRoutePrefix(evidence.routePrefix) === normalizeManifestRoutePrefix(agent.routePrefix) &&
      evidence.resourceName === agent.resourceName)
  );
}

function extractRuntimeJobsOperations(metadata: unknown): RuntimeJobsOperationsSummary | null {
  const root = isRecord(metadata) ? metadata : null;
  const operations = root && isRecord(root.operations) ? root.operations : null;
  const jobs = operations && isRecord(operations.jobs) ? operations.jobs : null;
  if (!jobs) {
    return null;
  }
  const worker = isRecord(jobs.worker) ? jobs.worker : {};
  const retention = isRecord(jobs.retention) ? jobs.retention : {};
  const schedules = isRecord(jobs.schedules) ? jobs.schedules : {};
  return {
    workerCommand: runtimeMetadataString(worker.command) || "python -m app.worker",
    intervalSeconds: runtimeMetadataNumber(worker.interval_seconds),
    limit: runtimeMetadataNumber(worker.limit),
    retryDelaySeconds: runtimeMetadataNumber(worker.retry_delay_seconds),
    leaseSeconds: runtimeMetadataNumber(worker.lease_seconds),
    multiworkerClaims: runtimeMetadataBoolean(worker.multiworker_claims),
    cleanupEnabled: runtimeMetadataBoolean(retention.automatic_cleanup_enabled),
    cleanupOlderThanHours: runtimeMetadataNumber(retention.older_than_hours),
    cleanupLimit: runtimeMetadataNumber(retention.limit),
    cleanupStatuses: runtimeMetadataStringArray(retention.statuses),
    terminalStatuses: runtimeMetadataStringArray(retention.terminal_statuses),
    schedules: runtimeMetadataScheduleLabels(schedules),
  };
}

function runtimeMetadataString(value: unknown): string | null {
  return typeof value === "string" && value.trim() ? value.trim() : null;
}

function runtimeMetadataNumber(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === "string" && value.trim() && Number.isFinite(Number(value))) {
    return Number(value);
  }
  return null;
}

function runtimeMetadataBoolean(value: unknown): boolean {
  if (typeof value === "boolean") {
    return value;
  }
  if (typeof value === "string") {
    return value.trim().toLowerCase() === "true";
  }
  return false;
}

function runtimeMetadataStringArray(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return [];
  }
  return value.map((item) => runtimeMetadataString(item)).filter((item): item is string => Boolean(item));
}

function runtimeMetadataScheduleLabels(value: Record<string, unknown>): string[] {
  const labels: string[] = [];
  if (runtimeMetadataBoolean(value.interval)) {
    labels.push("intervalo");
  }
  if (runtimeMetadataString(value.cron)) {
    labels.push("cron básico");
  }
  if (runtimeMetadataBoolean(value.event)) {
    labels.push("evento");
  }
  return labels;
}

function runtimeJobsOperationsLabel(summary: RuntimeJobsOperationsSummary | null): string {
  if (!summary) {
    return "não verificado";
  }
  const interval = summary.intervalSeconds !== null ? `${formatRuntimeOperationNumber(summary.intervalSeconds)}s` : "-";
  const limit = summary.limit !== null ? String(formatRuntimeOperationNumber(summary.limit)) : "-";
  const lease = summary.leaseSeconds !== null ? `${formatRuntimeOperationNumber(summary.leaseSeconds)}s` : "-";
  const cleanup = summary.cleanupEnabled ? "cleanup automático ativo" : "cleanup automático off";
  return `${summary.workerCommand}; ciclo ${interval}; lote ${limit}; lease ${lease}; ${cleanup}`;
}

function runtimeJobsRetentionLabel(summary: RuntimeJobsOperationsSummary | null): string {
  if (!summary) {
    return "não verificado";
  }
  const age = summary.cleanupOlderThanHours !== null ? `${formatRuntimeOperationNumber(summary.cleanupOlderThanHours)}h` : "-";
  const limit = summary.cleanupLimit !== null ? String(formatRuntimeOperationNumber(summary.cleanupLimit)) : "-";
  const statuses = summary.cleanupStatuses.length ? summary.cleanupStatuses.join(", ") : "-";
  return `${statuses}; idade ${age}; limite ${limit}`;
}

function runtimeJobsRetryConcurrencyLabel(summary: RuntimeJobsOperationsSummary | null): string {
  if (!summary) {
    return "não verificado";
  }
  const retry = summary.retryDelaySeconds !== null ? `${formatRuntimeOperationNumber(summary.retryDelaySeconds)}s` : "-";
  const concurrency = summary.multiworkerClaims ? "claim/lease ativo" : "claim/lease não declarado";
  return `retry ${retry}; ${concurrency}`;
}

function runtimeJobsSchedulesLabel(summary: RuntimeJobsOperationsSummary | null): string {
  return summary?.schedules.length ? summary.schedules.join(", ") : "não verificado";
}

function RuntimeJobsOperationsDetails({
  summary,
  ariaLabel = "Resumo operacional de jobs",
}: {
  summary: RuntimeJobsOperationsSummary | null;
  ariaLabel?: string;
}) {
  return (
    <div className="runtime-job-breakdown" aria-label={ariaLabel}>
      <span>Worker: {runtimeJobsOperationsLabel(summary)}</span>
      <span>Retry/concorrência: {runtimeJobsRetryConcurrencyLabel(summary)}</span>
      <span>Retenção: {runtimeJobsRetentionLabel(summary)}</span>
      <span>Schedules: {runtimeJobsSchedulesLabel(summary)}</span>
    </div>
  );
}

function formatRuntimeOperationNumber(value: number): string {
  return Number.isInteger(value) ? String(value) : value.toFixed(2).replace(/\.?0+$/, "");
}

function smokeEvidenceTime(evidence: DockerAgentSmokeEvidence): number {
  const parsed = evidence.finishedAt ? Date.parse(evidence.finishedAt) : 0;
  return Number.isFinite(parsed) ? parsed : 0;
}

function buildDockerOperationAlerts(entries: DockerRuntimeHistoryEntry[]): DockerOperationAlert[] {
  const sortedEntries = [...entries].sort((left, right) => dockerHistoryEntryTime(right) - dockerHistoryEntryTime(left));
  const latestByOperation = new Map<DockerCriticalOperation, DockerRuntimeHistoryEntry>();
  dockerCriticalOperationOrder.forEach((operation) => {
    const entry = sortedEntries.find((candidate) => candidate.operation === operation);
    if (entry) {
      latestByOperation.set(operation, entry);
    }
  });
  return dockerCriticalOperationOrder.map((operation, index) => {
    const entry = latestByOperation.get(operation) ?? null;
    const previousOperation = index > 0 ? dockerCriticalOperationOrder[index - 1] : null;
    const previousEntry = previousOperation ? latestByOperation.get(previousOperation) ?? null : null;
    return dockerOperationAlert(operation, entry, previousOperation, previousEntry, sortedEntries);
  });
}

function buildRuntimeDeliveryChecklist(
  listing: GeneratedArtifactListing,
  dockerStatus: DockerRuntimeStatus | null,
  alerts: DockerOperationAlert[],
): RuntimeDeliveryStep[] {
  const paths = new Set(listing.files.map((file) => file.path));
  const hasRuntimeFiles = artifactLooksLikeDockerRuntime(listing);
  const hasApproval = paths.has(".agent-flow/langgraph-sandbox-approval.json");
  const alertByOperation = new Map(alerts.map((alert) => [alert.operation, alert]));
  const modelSetupStep = runtimeDeliveryModelSetupStep(dockerStatus, alertByOperation.get("setup_models"));
  const buildStep = runtimeDeliveryStepFromAlert("build", "Build Docker", "build", alertByOperation.get("build"));
  const apiRunning = dockerStatusHasRunningApi(dockerStatus);
  const upStep = apiRunning
    ? {
        id: "up",
        label: "API em execução",
        level: "ok" as const,
        statusLabel: "running",
        detail: "O serviço api está em execução no Docker Compose inspecionado.",
        action: "up" as const,
      }
    : runtimeDeliveryStepFromAlert("up", "Subir API", "up", alertByOperation.get("up"));
  const smokeStep = runtimeDeliveryStepFromAlert("smoke", "Smoke test", "smoke", alertByOperation.get("smoke"));
  const exportReady =
    hasRuntimeFiles &&
    modelSetupStep.level === "ok" &&
    buildStep.level === "ok" &&
    upStep.level === "ok" &&
    smokeStep.level === "ok";

  return [
    {
      id: "artifact",
      label: "Aprovação embarcada",
      level: hasRuntimeFiles && hasApproval ? "ok" : hasRuntimeFiles ? "warning" : "error",
      statusLabel: hasRuntimeFiles && hasApproval ? "ok" : hasRuntimeFiles ? "sem comprovante" : "incompleto",
      detail: hasRuntimeFiles && hasApproval
        ? "Runtime final contém Dockerfile, Compose, metadata e comprovante de aprovação."
        : "Confira se o runtime foi gerado a partir de uma versão aprovada do sandbox.",
      action: null,
    },
    {
      id: "env",
      label: "Ambiente local",
      level: dockerStatus?.envFile ? "ok" : "pending",
      statusLabel: dockerStatus?.envFile ? ".env pronto" : "pendente",
      detail: dockerStatus?.envFile
        ? "Arquivo .env local encontrado para o runtime final."
        : "Prepare o .env local a partir do .env.example antes de subir a API.",
      action: "prepare_env",
    },
    modelSetupStep,
    buildStep,
    upStep,
    smokeStep,
    {
      id: "export",
      label: "Exportar pacote",
      level: exportReady ? "ok" : "pending",
      statusLabel: exportReady ? "pronto" : "aguardando validação",
      detail: exportReady
        ? "O ZIP exportado contém o runtime validado para rodar fora do Builder."
        : "Finalize build, subida da API e smoke test antes de usar o pacote como entrega final.",
      action: "download",
    },
  ];
}

function runtimeDeliveryModelSetupStep(
  dockerStatus: DockerRuntimeStatus | null,
  alert: DockerOperationAlert | undefined,
): RuntimeDeliveryStep {
  if (!dockerStatus) {
    return {
      id: "setup_models",
      label: "Modelos locais",
      level: "pending",
      statusLabel: "status pendente",
      detail: "Atualize o status para detectar se o docker-compose.yml declara modelos Ollama locais.",
      action: "refresh",
    };
  }
  if (!dockerStatus.modelSetup.required) {
    return {
      id: "setup_models",
      label: "Modelos locais",
      level: "ok",
      statusLabel: "não requer",
      detail: "Este runtime não declara serviços de download de modelo local no Compose.",
      action: null,
    };
  }
  const step = runtimeDeliveryStepFromAlert("setup_models", "Modelos locais", "setup_models", alert);
  const models = dockerStatus.modelSetup.models.length ? dockerStatus.modelSetup.models.join(", ") : "modelos declarados";
  return {
    ...step,
    detail: step.level === "ok"
      ? `Modelos preparados: ${models}.`
      : `${step.detail} Modelos detectados: ${models}.`,
  };
}

function runtimeDeliveryStepFromAlert(
  id: DockerCriticalOperation,
  label: string,
  action: Exclude<RuntimeDeliveryAction, "refresh" | "prepare_env" | "download" | null>,
  alert: DockerOperationAlert | undefined,
): RuntimeDeliveryStep {
  if (!alert) {
    return {
      id,
      label,
      level: "pending",
      statusLabel: "pendente",
      detail: `${label} ainda não foi executado.`,
      action,
    };
  }
  return {
    id,
    label,
    level: alert.level,
    statusLabel: alert.statusLabel,
    detail: alert.finishedAt ? `${alert.title} Última execução: ${formatDateTime(alert.finishedAt)}.` : alert.title,
    action,
  };
}

function dockerStatusHasRunningApi(status: DockerRuntimeStatus | null): boolean {
  return (status?.inspection?.containers ?? []).some((service) => {
    const serviceName = `${service.service ?? ""} ${service.name ?? ""}`.toLowerCase();
    const serviceState = `${service.state ?? ""} ${service.status ?? ""}`.toLowerCase();
    return serviceName.includes("api") && (serviceState.includes("running") || serviceState.includes("up"));
  });
}

function selectRuntimeDeliveryNextStep(steps: RuntimeDeliveryStep[]): RuntimeDeliveryStep | null {
  const nextBlockingStep = steps.find((step) => step.id !== "export" && step.level !== "ok" && step.action);
  if (nextBlockingStep) {
    return nextBlockingStep;
  }
  return steps.find((step) => step.id === "export") ?? null;
}

function buildRuntimeDeliveryAgents(
  listing: GeneratedArtifactListing,
  dockerStatus: DockerRuntimeStatus | null,
): DockerRuntimeAgent[] {
  const statusAgents = dockerStatus?.agents ?? [];
  if (statusAgents.length) {
    return statusAgents;
  }
  const target = dockerStatus?.target ?? listing.exportAudit.target;
  if (target !== "fastapi-runtime") {
    return [];
  }
  const runbookAgent = listing.exportAudit.runbook.agents[0] ?? null;
  const agentId = dockerStatus?.flowId?.trim() || runbookAgent?.id || artifactBaseName(listing.outDir);
  const resourceName = dockerStatus?.resourceName?.trim() || runbookAgent?.resourceName || "sessions";
  return [
    {
      id: agentId,
      flowId: dockerStatus?.flowId?.trim() || agentId,
      flowName: agentId,
      flowVersion: dockerStatus?.flowVersion ?? "",
      flowHash: dockerStatus?.flowHash ?? null,
      routePrefix: runbookAgent?.routePrefix ?? "",
      runtimeDir: ".",
      resourceName,
      contract: "sessions-v1",
    },
  ];
}

function buildRuntimeDeliveryOrchestrationReport(
  dockerStatus: DockerRuntimeStatus | null,
  orchestrationHistory: OrchestrationDebugHistoryEntry[],
  selectedOrchestrationResult: RuntimeOrchestrationRunResult | null,
): RuntimeDeliveryReport["orchestration"] {
  const available = dockerStatus?.target === "runtime-manifest-bundle";
  const latestRun = selectedOrchestrationResult ?? orchestrationHistory[0]?.result ?? null;
  const previousRun = latestRun
    ? orchestrationHistory.find((entry) => entry.result.debug_trace.run_id !== latestRun.debug_trace.run_id)?.result ?? null
    : null;
  const comparison = latestRun && previousRun ? compareOrchestrationDebugRuns(latestRun, previousRun) : null;
  return {
    available,
    historyCount: available ? orchestrationHistory.length : 0,
    latestRun: available && latestRun ? runtimeDeliveryOrchestrationRunSummary(latestRun) : null,
    comparison,
    governance: {
      source: available ? "local_orchestration_debug_history" : "not_applicable",
      excludesRawInput: true,
      excludesSharedMemory: true,
      excludesStepPayloads: true,
      excludesRawTimeline: true,
      includesOnlySummary: true,
    },
  };
}

function runtimeDeliveryOrchestrationRunSummary(
  result: RuntimeOrchestrationRunResult,
): NonNullable<RuntimeDeliveryReport["orchestration"]["latestRun"]> {
  const summary = result.debug_trace.summary ?? {};
  return {
    runId: result.debug_trace.run_id,
    status: result.status,
    mode: result.mode,
    entryAgentId: result.entry_agent_id,
    startedAt: result.debug_trace.started_at || null,
    finishedAt: result.debug_trace.finished_at || null,
    stepCount: readNumberValue(summary.step_count) || result.steps.length,
    timelineEvents: readNumberValue(summary.timeline_events) || result.debug_trace.timeline.length,
    handoffDecisions: readNumberValue(summary.handoff_decisions),
    matchedHandoffs: readNumberValue(summary.matched_handoffs),
    memoryEntries: readNumberValue(summary.memory_entries),
    errorMessage: result.error?.message || null,
  };
}

function buildRuntimeDeliveryReport(
  listing: GeneratedArtifactListing,
  dockerStatus: DockerRuntimeStatus | null,
  checklist: RuntimeDeliveryStep[],
  alerts: DockerOperationAlert[],
  agentSummaries: Map<string, DockerAgentOperationalSummary> = new Map(),
  orchestrationHistory: OrchestrationDebugHistoryEntry[] = [],
  selectedOrchestrationResult: RuntimeOrchestrationRunResult | null = null,
): RuntimeDeliveryReport {
  const deliveryAgents = buildRuntimeDeliveryAgents(listing, dockerStatus);
  const filePaths = new Set(listing.files.map((file) => file.path));
  const blockers = checklist
    .filter((step) => step.level !== "ok" && step.id !== "export")
    .map((step) => `${step.label}: ${step.detail}`);
  const exportStep = checklist.find((step) => step.id === "export");
  if (!blockers.length && exportStep && exportStep.level !== "ok") {
    blockers.push(`${exportStep.label}: ${exportStep.detail}`);
  }

  return {
    format: "agent-flow-builder.runtime-delivery-report.v1",
    exportedAt: new Date().toISOString(),
    outDir: listing.outDir,
    ready: checklist.length > 0 && checklist.every((step) => step.level === "ok"),
    blockers,
    artifact: {
      totalSizeBytes: listing.totalSizeBytes,
      fileCount: listing.files.length,
      requiredFiles: dockerRuntimeRequiredArtifactFiles.map((filePath) => ({
        path: filePath,
        present: filePaths.has(filePath),
      })),
    },
    approval: {
      embedded: filePaths.has(".agent-flow/langgraph-sandbox-approval.json"),
    },
    docker: {
      target: dockerStatus?.target ?? null,
      runtimeUrl: dockerStatus?.runtimeUrl ?? null,
      envFile: dockerStatus?.envFile ?? false,
      modelSetup: dockerRuntimeModelSetupForReport(dockerStatus),
      lastOperation: dockerStatus?.lastOperation ?? null,
      lastStatus: dockerStatus?.lastStatus ?? null,
      apiRunning: dockerStatusHasRunningApi(dockerStatus),
      docsUrl: dockerStatus?.docsUrl ?? null,
      openapiUrl: dockerStatus?.openapiUrl ?? null,
    },
    agents: dockerStatus?.agents ?? [],
    agentOperations: deliveryAgents.map((agent) => {
      const summary = agentSummaries.get(agent.id) ?? defaultDockerAgentOperationalSummary(agent);
      return {
        agentId: agent.id,
        routePrefix: agent.routePrefix,
        resourceName: agent.resourceName,
        basePath: summary.basePath,
        status: summary.level,
        statusLabel: summary.statusLabel,
        detail: summary.detail,
        lastRunAt: summary.finishedAt,
        jobsOperations: summary.jobsOperations,
        jobsOperationsLabels: {
          worker: runtimeJobsOperationsLabel(summary.jobsOperations),
          retryConcurrency: runtimeJobsRetryConcurrencyLabel(summary.jobsOperations),
          retention: runtimeJobsRetentionLabel(summary.jobsOperations),
          schedules: runtimeJobsSchedulesLabel(summary.jobsOperations),
        },
      };
    }),
    orchestration: buildRuntimeDeliveryOrchestrationReport(dockerStatus, orchestrationHistory, selectedOrchestrationResult),
    checklist,
    operations: alerts.map((alert) => ({
      operation: alert.operation,
      level: alert.level,
      statusLabel: alert.statusLabel,
      title: alert.title,
      finishedAt: alert.finishedAt,
    })),
    runbook: listing.exportAudit.runbook,
    export: {
      archiveFileName: `${artifactBaseName(listing.outDir)}.zip`,
      detachedFromBuilder: true,
      excludesBuilderHistory: true,
      includesEnvValues: filePaths.has(".env"),
    },
  };
}

function dockerRuntimeModelSetupForReport(dockerStatus: DockerRuntimeStatus | null): DockerRuntimeStatus["modelSetup"] {
  return dockerStatus?.modelSetup ?? {
    required: false,
    profile: "model-setup",
    services: [],
    models: [],
    command: null,
    execution: {
      cpuCommand: "docker compose up -d --build",
      gpuCommand: null,
      gpuComposeFile: false,
      hostGpuDetected: false,
      hostGpuDevices: [],
      dockerGpuRuntimeAvailable: false,
      dockerGpuRuntimeDetails: [],
      dockerGpuRuntimeError: null,
      recommendedProfile: "cpu",
      reason: "Status Docker ainda não carregado; modelos locais não requeridos pelo relatório.",
      checkedAt: new Date().toISOString(),
    },
    distribution: {
      modelImageComposeFile: false,
      modelImageDockerfile: false,
      modelImageCommand: null,
      modelImageTag: null,
      modelImageArchivePath: null,
      modelImageExportCommand: null,
      modelImageLoadCommand: null,
      modelImagePushCommand: null,
    },
  };
}

function buildRuntimeAgentRunbook(
  listing: GeneratedArtifactListing,
  dockerStatus: DockerRuntimeStatus | null,
  agent: DockerRuntimeAgent,
  summary: DockerAgentOperationalSummary,
  runtimeBaseUrl: string,
  checklist: RuntimeDeliveryStep[],
): RuntimeAgentRunbook {
  const metadataPath = joinRuntimePath(agent.routePrefix, "metadata");
  const sessionsPath = joinRuntimePath(agent.routePrefix, agent.resourceName);
  const metadataUrl = joinRuntimeUrl(runtimeBaseUrl, metadataPath);
  const sessionsUrl = joinRuntimeUrl(runtimeBaseUrl, sessionsPath);
  const docsUrl = dockerStatus?.docsUrl ?? joinRuntimeUrl(runtimeBaseUrl, "docs");
  const openapiUrl = dockerStatus?.openapiUrl ?? joinRuntimeUrl(runtimeBaseUrl, "openapi.json");

  return {
    format: "agent-flow-builder.runtime-agent-runbook.v1",
    exportedAt: new Date().toISOString(),
    outDir: listing.outDir,
    runtimeBaseUrl,
    agent,
    endpoints: {
      metadataPath,
      metadataUrl,
      sessionsPath,
      sessionsUrl,
      docsUrl,
      openapiUrl,
    },
    smoke: {
      status: summary.level,
      statusLabel: summary.statusLabel,
      detail: summary.detail,
      lastRunAt: summary.finishedAt,
      basePath: summary.basePath,
      sessionId: summary.sessionId,
      transcriptCount: summary.transcriptCount,
      eventsCount: summary.eventsCount,
      jobsOperations: summary.jobsOperations,
      jobsOperationsLabels: {
        worker: runtimeJobsOperationsLabel(summary.jobsOperations),
        retryConcurrency: runtimeJobsRetryConcurrencyLabel(summary.jobsOperations),
        retention: runtimeJobsRetentionLabel(summary.jobsOperations),
        schedules: runtimeJobsSchedulesLabel(summary.jobsOperations),
      },
    },
    commands: [
      {
        id: "metadata",
        label: "Verificar metadata do agente",
        command: `curl ${metadataUrl}`,
        detail: "Confirma que a rota montada do agente responde fora do Builder.",
      },
      {
        id: "create-session",
        label: "Criar sessão do agente",
        command: `curl -X POST ${sessionsUrl} -H "content-type: application/json" -d '{"metadata":{"source":"manual-agent-runbook"},"max_turns":2}'`,
        detail: "Cria uma sessão nova no recurso do agente; use o session_id retornado nos passos seguintes.",
      },
      {
        id: "start",
        label: "Iniciar sessão",
        command: `curl -X POST ${sessionsUrl}/{session_id}/start -H "content-type: application/json" -d "{}"`,
        detail: "Executa a etapa inicial da sessão criada.",
      },
      {
        id: "turn",
        label: "Enviar turno",
        command: `curl -X POST ${sessionsUrl}/{session_id}/turn -H "content-type: application/json" -d '{"user_message":"Smoke manual do agente."}'`,
        detail: "Valida o caminho conversacional básico do agente fora do Builder.",
      },
      {
        id: "evidence",
        label: "Consultar evidências",
        command: `curl ${sessionsUrl}/{session_id}/events && curl ${sessionsUrl}/{session_id}/transcript`,
        detail: "Confere eventos e transcript para registrar a evidência da execução.",
      },
    ],
    checklist,
    governance: {
      includesEnvValues: false,
      includesSecrets: false,
      detachedFromBuilder: listing.exportAudit.detachedFromBuilder,
      packageType: listing.exportAudit.packageType,
    },
  };
}

