    if (!Array.isArray(parsed)) {
      return [];
    }
    return syncStudioScenarioDatasets(
      parsed
        .map(normalizeStudioScenarioDataset)
        .filter((item): item is StudioScenarioDataset => item !== null),
      scenarios,
    );
