function containsRawLocalCatalogConflictReviewPayload(value: unknown): boolean {
  const rawKeys = new Set([
    "items",
    "item",
    "content",
    "nodePatch",
    "history",
    "sharedLibrary",
    "catalog",
    "payload",
    "input",
    "output",
    "secret",
    "secrets",
  ]);
  const visit = (entry: unknown): boolean => {
    if (Array.isArray(entry)) {
      return entry.some(visit);
    }
    if (!isRecord(entry)) {
      return false;
    }
    return Object.entries(entry).some(([key, item]) => rawKeys.has(key) || visit(item));
  };
  return visit(value);
}

function containsRawSchemaPatternConflictReviewPayload(value: unknown): boolean {
  const rawKeys = new Set([
    "schema",
    "items",
    "item",
    "payload",
    "input",
    "output",
    "rawSchemaTextDiff",
    "leftText",
    "rightText",
    "secret",
    "secrets",
  ]);
  const visit = (entry: unknown): boolean => {
    if (Array.isArray(entry)) {
      return entry.some(visit);
    }
    if (!isRecord(entry)) {
      return false;
    }
    return Object.entries(entry).some(([key, item]) => rawKeys.has(key) || visit(item));
  };
  return visit(value);
}

function containsRawCollaborationConflictOverviewPayload(value: unknown): boolean {
  const rawKeys = new Set([
    "authorization",
    "body",
    "header",
    "headers",
    "input",
    "output",
    "payload",
    "prompt",
    "prompts",
    "raw",
    "request",
    "response",
    "schema",
    "schemas",
    "secret",
    "secrets",
    "token",
    "tokens",
  ]);
  const sensitiveStringPattern = /\b(authorization|bearer|password|secret|api[_-]?key|token)\b/i;
  const visit = (entry: unknown): boolean => {
    if (typeof entry === "string") {
      return sensitiveStringPattern.test(entry);
    }
    if (Array.isArray(entry)) {
      return entry.some(visit);
    }
    if (!isRecord(entry)) {
      return false;
    }
    return Object.entries(entry).some(([key, item]) => rawKeys.has(key.trim().toLowerCase()) || visit(item));
  };
  return visit(value);
}

function catalogPackageFileName(itemPackage: LocalCatalogItemPackage): string {
  return localCatalogId("catalog", `${itemPackage.item.kind}-${itemPackage.item.id}`);
}

function catalogConflictReviewFileName(review: LocalCatalogConflictReviewPackage): string {
  return localCatalogId("catalog-conflicts", review.packageHash);
}

function catalogConflictReviewDiffFileName(diff: LocalCatalogConflictReviewDiffPackage): string {
  return localCatalogId("catalog-conflicts-diff", diff.packageHash);
}

function schemaPatternConflictReviewFileName(review: SchemaPatternConflictReviewPackage): string {
  return localCatalogId("schema-pattern-conflicts", review.packageHash);
}

function schemaPatternConflictReviewDiffFileName(diff: SchemaPatternConflictReviewDiffPackage): string {
  return localCatalogId("schema-pattern-conflicts-diff", diff.packageHash);
}

function collaborationConflictOverviewFileName(overview: CollaborationConflictOverview): string {
  return localCatalogId("collaboration-conflicts", overview.packageHash);
}

function collaborationConflictOverviewDiffFileName(diff: CollaborationConflictOverviewDiffPackage): string {
  return localCatalogId("collaboration-conflicts-diff", diff.packageHash);
}

function catalogGovernanceFileName(report: CatalogGovernanceReport): string {
  return localCatalogId("catalog-governance", `${report.item.kind}-${report.item.id}-${report.packageHash}`);
}

function catalogLibraryGovernanceFileName(report: CatalogLibraryGovernanceReport): string {
  return localCatalogId("catalog-library-governance", report.packageHash);
}

function sanitizeFileNamePart(value: string): string {
  const sanitized = value.trim().toLowerCase().replace(/[^a-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "");
  return sanitized || "fixture";
}

function downloadBlobFile(fileName: string, blob: Blob): void {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.append(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function errorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}
